window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-010.json"] = [{"name":"加岛哀鸽","english_name":"Galapagos Dove","scientific_name":"Zenaida galapagoensis","overview":"加岛哀鸽（英文名：Galapagos Dove，学名：Zenaida galapagoensis），是鸽形目鸠鸽科哀鸠属的鸟类。广泛分布在加拉帕戈斯群岛（科隆群岛）的开放和半开放环境，尤其是群岛干旱低地。相当常见的鸟类。","appearance":"体长18至23厘米，体重约67至92克。头部和颈部呈深红褐色，胸部粉棕色渐变为腹部淡黄色。下体灰色，眼圈深蓝至紫蓝色，脸部下方和后方有白色条纹环绕黑边。颈侧有粉色和青铜色光泽斑块，翅膀和背部暗棕色，翼上有黑白相间的条纹，翼折处有白色斑点，尾羽中央棕色边缘灰色，脚腿紫色带红。","call":"发出柔和而深沉的“bob-bob-bob-rurururr-bububurr”叫声，有时也会发出类似咕噜声的“bororororororrr”或“wuk ... r-r-r-r-r-ruu”，间歇重复。","habits":"偏好干燥、岩石、干旱和半干旱低地，散布着树木、灌木和仙人掌的环境。主要以种子为食，湿季时会食用毛虫和仙人掌花，长而向下弯曲的喙有助于挖掘和获取种子。有时会在地面或旧的加拉帕戈斯模仿鸟巢中筑巢。","breeding":"繁殖季节通常从一月至十一月，但具体时间因岛屿而异，主要集中在三月至六月。巢由松散的树枝构成，有时衬有根须和草，平均离地75厘米。每窝产两枚白色蛋，孵化期约13天，幼鸟13至17天后离巢。","identification":"与同类相比，加岛哀鸽具有独特的红褐色头部和胸部，蓝色眼圈，红色腿部，以及翼部和头部大胆的黑白标记。","protection":"IUCN：NT（近危）","distribution":"分布于南美的厄瓜多尔科隆群岛，即加拉帕戈斯群岛。","other":"尽管岛屿间存在地理隔离，但频繁的岛屿间迁移导致基因流活跃，使得物种在群岛间保持相对一致性。"},{"name":"白翅哀鸽","english_name":"White-winged Dove","scientific_name":"Zenaida asiatica","overview":"白翅哀鸽（英文名：White-winged Dove，学名：Zenaida asiatica），是鸽形目鸠鸽科哀鸠属的鸟类。体型较大的鸽子，主要分布在北美西南部至巴拿马，包括美国西南部至中美洲以及大安的列斯群岛。这种鸽子以其独特的白翼斑块著称，通常在城市和郊区的开放树林中可见。","appearance":"白翅哀鸽长约30厘米，翼展50厘米，重约170克。其上体为灰褐色，下体灰色，最显著的特征是翅膀上的白色斑块，形成明显的白色线条或在飞行时显现为白色翼斑。头部下侧有蓝色裸皮环绕眼睛，脸颊上有黑色斑点。脚部红色，喙黑色。幼鸟颜色较为暗淡，缺乏成鸟的光泽，虹膜为棕色而非红色。","call":"白翅哀鸽的叫声被形象地描述为类似英语短语'who cooks for you'，在繁殖季节尤其频繁，通常在黎明前或傍晚时分发出。","habits":"白翅哀鸽适应多种环境，包括沙漠边缘、农田、城市社区、牧场、草地和疏林地带。它们主要以种子为食，偶尔也会吃蜗牛或昆虫。为了帮助消化，它们会吞食小石子和沙子。在城市中，它们会在地面或喂鸟器周围寻找食物，偏好松果、枫香树种子、美洲商陆种子、苋菜种子、金丝雀虉草种子、玉米、芝麻和小麦。","breeding":"白翅哀鸽在温暖月份进行繁殖，雄鸟通过鸣叫吸引雌鸟，建立领地。巢建于树上，由小树枝、针叶或草叶构成，相当脆弱。每窝产2枚小白蛋，孵化期约两周。父母共同照顾幼鸟，提供鸽乳直至幼鸟长出羽毛，约需11至15天。幼鸟在21天大时能够独立，约85天大时可开始繁殖。","identification":"与其他哀鸽相比，白翅哀鸽具有更明显的白色翼斑，体形更为健硕，尾巴较短。与灰斑鸠相比，白翅哀鸽的翅膀和尾巴对比更明显，颜色更深。","protection":"IUCN：LC（无危）","distribution":"白翅哀鸽的繁殖区域覆盖美国西南部至巴拿马，包括大安的列斯群岛。在美国，它们的历史分布限于德克萨斯州南部、新墨西哥州、亚利桑那州和加利福尼亚州的南部地区。近年来，其分布已扩展至美国南部大部分地区，北至俄克拉荷马州。","other":"白翅哀鸽是北美最受欢迎的猎鸟之一，同时也是重要的授粉者，尤其是在沙漠环境中，为德州油柱（Carnegiea gigantea）授粉。"},{"name":"南美哀鸽","english_name":"West Peruvian Dove","scientific_name":"Zenaida meloda","overview":"南美哀鸽（英文名：West Peruvian Dove，学名：Zenaida meloda），是鸽形目鸠鸽科哀鸠属的鸟类。眼周环绕着紫蓝色的眼环。分布于南美，从厄瓜多尔至智利北部的沙漠低地及丘陵地带。","appearance":"体长约25至33厘米，体重约216克。相比白翅哀鸽，颜色更灰淡，头部和颈背无粉红色调，而是灰色，脸部和颈部亦为灰色，尾羽尖端呈灰色。喙较厚实，虹膜为灰褐色，眼周皮肤亮蓝色。两性相似。","call":"发出低沉而有节奏的单调咕噜声，如'Who..huLOO..hu..huLOO..hu..huLOO'，重复播放，每个短语长度大约5到6秒。有时短语更简单，例如'Who...huLOO'。","habits":"广泛出现在各种开放和半开放生境，包括城市街道、花园、农田和棕榈绿洲。在智利北部的阿利卡，常见于城市公园。偶尔在秘鲁高达2000米的地方发现。","breeding":"在厄瓜多尔西南部，以分散的配对形式繁殖，不在群体中筑巢。每窝产2枚白色而非淡黄色的蛋。筑巢材料来自Cordia lutea等树种，巢高1.2至5.8米，孵化期13至15天，雏鸟期11至15天。","identification":"与白翅哀鸽相比，南美哀鸽更灰淡，缺乏粉红色调，眼周有紫蓝色环，尾羽尖端灰色，喙更粗壮，虹膜灰褐色而非红色。遗传数据支持其为独立物种。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲太平洋沿岸，从厄瓜多尔西南部至智利北部（阿利卡至科金博）。在阿根廷拉里奥哈省安第斯山脉东侧发现一小群，来源不明。","other":"曾被认为与白翅哀鸽同种，遗传数据显示其为独立物种，且与白翅哀鸽关系最近。"},{"name":"尼柯巴鸠","english_name":"Nicobar Pigeon","scientific_name":"Caloenas nicobarica","overview":"尼柯巴鸠（英文名：Nicobar Pigeon，学名：Caloenas nicobarica），是鸽形目鸠鸽科尼柯巴鸠属的鸟类。大型鸽类，以其独特的颈部长羽和白尾著称。体长可达32-38厘米，分布于印度的安达曼群岛和尼科巴群岛，向东延伸至菲律宾、印尼群岛、新几内亚及周边岛屿，直至所罗门群岛和Palau。被列入《濒危野生动植物种国际贸易公约》附录I。","appearance":"尼柯巴鸠体型健壮，体长32-38厘米，体重雄鸟460-525克，雌鸟490-600克。头部和颈部覆有黑灰带紫银光泽的长羽，上体呈现深绿或铜绿色，下体深绿或蓝绿，带有金属光泽。尾部极短，全白。喙为重黑，带有增大的鼻甲，腿脚呈紫红色。雌鸟相似，但颈羽较短，下体偏棕色。幼鸟缺乏颈羽，全身棕色，包括尾部。","call":"通常沉默，偶尔发出低沉重复的喉音或类似猪的哼声，有时能听到深沉低沉的\"rrr-rrr-rrr-rrr...\"。","habits":"偏好小而森林茂密的岛屿，常栖息于离岸岛屿，尤其在森林覆盖率较高的大型陆地附近。能在红树林、灌木丛、低地和山脚森林中找到，海拔至少到700米。会成群迁徙，有时飞越1500公里的距离。飞行高度常在60米以上，以小群出现，飞行姿态独特，长颈、宽翼和短尾明显。以地面的落果和种子为主食，偶尔食用昆虫，消化大种子时会摄入沙砾辅助。","breeding":"繁殖季节延长，可在6月开始聚集筑巢，持续到次年1月；在安达曼群岛和尼科巴群岛，繁殖期为1月至3月/4月。在马来西亚半岛近海岛屿，繁殖记录在4月和9月。成群繁殖，有时与Ducula imperial-pigeons共栖。巢为粗糙的树枝平台，直径约30厘米，深度23厘米，通常位于2米至树冠下的12米高处。每窝产一枚椭圆形淡蓝白色的蛋，由两性共同孵化，孵化出的雏鸟无绒毛，由双亲共同抚养，大约一个月后离巢。","identification":"通过其独特的长颈羽和纯白尾部易于识别。与之相比，幼鸟的尾部为黑色，缺乏金属光泽。不同亚种间差异微小，pelewensis亚种稍小，颈羽更短且更钝，颜色更蓝而非绿色。","protection":"IUCN：NT（近危）；被列入CITES附录I。","distribution":"分布于远东和澳新界，从安达曼群岛和尼科巴群岛至菲律宾、印尼群岛、新几内亚的俾斯麦群岛卫星岛、所罗门群岛和Palau（加罗林群岛西部，密克罗尼西亚西部）。","other":"其殖民式繁殖习性使其易受干扰，由于栖息的小型隔离岛屿开发增加，人口数量受到威胁。历史上曾因狩猎和宠物贸易而数量锐减，目前在一些地区仍面临严重的捕猎压力。"},{"name":"点斑绿鸠","english_name":"Spotted Green Pigeon","scientific_name":"Caloenas maculata","overview":"点斑绿鸠（英文名：Spotted Green Pigeon，学名：Caloenas maculata），是鸽形目鸠鸽科尼柯巴鸠属的鸟类。亦被称为利物浦鸠，可能已灭绝的鸽子，最早由约翰·拉瑟姆于1783年描述。其分类一度模糊不清，最终确认与尼柯巴鸠关系密切，归入同一属Caloenas。现存唯一标本保存于利物浦世界博物馆，2008年被IUCN红名单认定为已灭绝物种。原产地可能位于南太平洋或印度洋的某个岛屿，有猜测它可能是塔希提岛民所称的‘titi’。","appearance":"该鸟体长约32厘米，具有深褐色带绿色光泽的羽毛，颈部羽毛细长，上身和翅膀的大部分羽毛尖端带有黄白色斑点。黑色喙尖带黄色，尾羽末端有一淡色带。腿短，翅长，区别于主要栖息于地面的尼柯巴鸠，点斑绿鸠似乎更适应树栖生活，以果实为食。","habits":"基于其生理特征，推测点斑绿鸠可能栖息于森林的密集树冠层，偏好树栖而非地面活动，主要以软果为食。其生存环境可能局限于偏远小岛，这解释了为何其原产地至今不明。","identification":"与尼柯巴鸠相比，点斑绿鸠具有更长的尾羽、较短的腿，以及独特的羽毛斑点，表明其生活方式和生态位的不同。","protection":"IUCN：EX（灭绝）","distribution":"原产地可能位于南太平洋或印度洋的某个岛屿，具体位置未知。","other":"关于其灭绝原因，推测可能由于过度猎杀和外来物种的捕食导致，大约在19世纪20年代消失。"},{"name":"黄胸鸡鸠","english_name":"Sulawesi Ground Dove","scientific_name":"Gallicolumba tristigmata","overview":"黄胸鸡鸠（英文名：Sulawesi Ground Dove，学名：Gallicolumba tristigmata），是鸽形目鸠鸽科鸡鸠属的鸟类。中等体型的橄榄棕色地面栖息的鸽子，长约35厘米，具有金色的额头、黄色的胸部、红色的腿脚、蓝绿色带紫色斑点的虹彩冠羽、深棕色的尾巴和白色的腹部。雌雄相似，主要分布于印度尼西亚苏拉威西岛的原始雨林中，是该地特有种。","appearance":"体形结实，尾部较短，头部具有独特的识别图案，前额明亮金黄色，后颈上部绿松石色，颈部有一条宽大的紫色项圈。脸和喉咙淡灰色，上胸部和颈侧较暗的灰色，带有绿金色调；下胸部呈浅奶油金色，腹部和臀部逐渐变为白色；两胁呈肉桂色；背部和肩部橄榄棕色，带有强烈的红紫色或青铜绿色金属光泽；其余上部暖橄榄棕色，翅膀覆羽和外侧次级飞羽变成红棕色；初级飞羽较暗的棕色；翼下覆羽棕色和白色；脚趾紫红色；喙深紫灰色。雌雄相似，但雌鸟略显暗淡。幼鸟主要呈褐色，羽毛边缘锈色，白色或金色部位呈锈色奶油色；颈部环带暗紫棕色。bimaculata亚种的颈部紫色项圈分为颈两侧的两个斑块；auripectus亚种相似，但胸部和腹部中间的金色更深。","call":"发出深沉的重复呼呼声“whoo-whoo-whoo..”","habits":"栖息于低地、丘陵和山地的原始森林，海拔高度从海平面至2000米。几乎完全在陆地上活动，当受惊时，仅以沉重的拍翅飞行短距离，然后步行逃离。据报道以种子和果实为主食，如同属其他成员一样，也会食用一些昆虫和其他无脊椎动物。在地上觅食，通常单独或成对出现。","breeding":"已知的繁殖信息仅限于11月报告的巢穴和蛋，雌鸟产一枚白色蛋。","identification":"在苏拉威西岛上没有其他类似物种，其独特的头颈颜色模式使其易于辨认。","protection":"IUCN：LC（无危）","distribution":"分布局限于印度尼西亚的苏拉威西岛，属于澳新界的分布范围。"},{"name":"红喉鸡鸠","english_name":"Cinnamon Ground Dove","scientific_name":"Gallicolumba rufigula","overview":"红喉鸡鸠（英文名：Cinnamon Ground Dove，学名：Gallicolumba rufigula），是鸽形目鸠鸽科鸡鸠属的鸟类。中等体型的地面栖息鸽，显著特征为头部的红褐色斑纹，腹部中央的黄色标记，以及白底黑边的胸部。广泛分布于新几内亚的低地森林和丘陵地带。","appearance":"红喉鸡鸠长约22至24厘米，体重介于121至137克之间。额头呈红褐色，面部为淡粉色，眼上方和后方有蓝灰色条带；上身和胸侧为酒红色至红棕色；翅膀覆羽边缘灰白色形成闭合翅膀上的条纹；喉咙、胸部和下体为白色，胸部中央有一抹金黄色；翼下覆羽黑白相间；中央尾羽为紫栗色，外侧尾羽灰色，带有宽广的栗色和黑色中央条带；虹膜紫色；喙暗紫色；腿和脚紫红色。雌雄相似，但雌鸟胸部和额头略浅。幼鸟胸部中心为红棕色，翅膀覆羽有淡红褐色边缘。亚种差异主要体现在头部颜色和翅膀条纹的色调上。","call":"发出深沉的颤音叫声，起始高昂而后渐低，终至柔和。","habits":"栖息于原始雨林和季风林，海拔从海平面至1000米，偶尔可达1700米。几乎完全在地面活动，仅在筑巢和栖息时位于低矮植被中。快速行走于森林地面，头部频繁上下摆动；受惊时迅速着陆并继续逃跑。饮食以种子、落果和昆虫为主，被认为是比和褐背金鸠更倾向于食虫的物种。在某些地区，数量会因野竹种子的丰富而激增。","breeding":"繁殖季节似乎延长，从旱季后期至雨季；筑巢记录显示，通常由少量树枝和树叶搭建，放置于坚实的基础之上，如棕榈叶或鸟巢蕨上，高度记录在0.9至2.7米。产一枚蛋，淡奶油色带白色。雏鸟覆盖独特的淡肉桂色绒毛；一窝中，雏鸟约9天即可全羽，可能已具备飞行能力，但在约16天时仍留在巢中；成鸟在巢附近非常羞怯，被惊扰时，孵卵的亲鸟会做出翅膀拍打的分散注意力的行为。","identification":"通过背部和翅膀上的红褐色与蓝灰色斜向条纹，以及胸部中心的杂乱橙黄色斑点来辨识。与其他地面鸽的区别在于翅膀上明显的浅色斜向条纹。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界的新几内亚和一些卫星岛屿。"},{"name":"吕宋鸡鸠","english_name":"Luzon Bleeding-heart","scientific_name":"Gallicolumba luzonica","overview":"吕宋鸡鸠（英文名：Luzon Bleeding-heart，学名：Gallicolumba luzonica），是鸽形目鸠鸽科鸡鸠属的鸟类。其最显著的特征是胸前有一片醒目的鲜红色斑块，仿佛鲜血流淌，这一特征在吕宋鸡鸠中最为突出。广泛分布于菲律宾吕宋岛的森林地带，从低地到较低的山脉，海拔可达1400米。此物种被列为近危状态。","appearance":"吕宋鸡鸠是一种中等体型的地面鸽，体长28至30厘米，体重133至184克。头部和背部呈蓝灰色，前额淡灰色，翅膀黑色，肩部和翼带淡灰色，胸部中央有鲜明的血红色斑块。喉部、胸部和腹部白色，胸下部略带粉红，紧邻血斑处更显粉红。虹膜蓝色，眼周皮肤灰色，喙黑色基部灰色，腿和脚红色。雌雄相似，但雌鸟虹膜可能为紫色或灰紫色。幼鸟特征尚不明确。","call":"吕宋鸡鸠的叫声为哀怨的呼啸声，先升后降，持续约1.2秒。","habits":"栖息于吕宋岛的原始和次生森林，海拔高度从海平面至1400米。主要在地面觅食种子、落地浆果、昆虫、蠕虫和其他无脊椎动物。飞行距离短，受惊后通常步行逃离。","breeding":"繁殖信息较少，已知在吕宋岛5月有幼鸟的巢穴报告。圈养条件下，一对会使用绿色植被，尤其是大叶子，筑巢。每窝产2枚蛋，孵化期17天，幼鸟12天首次飞行，此时尾羽尚未明显生长。","identification":"吕宋鸡鸠的‘出血’特征在所有种类的鸡鸠中最为明显，红色延伸至腹部，增强了出血的错觉。与亚洲绿鸠相比，若良好观察，不会混淆。","protection":"IUCN：NT（近危）","distribution":"吕宋鸡鸠仅分布于菲律宾吕宋岛及附近Polillo群岛，包括三个亚种：G. l. luzonica、G. l. griseolateralis和G. l. rubiventris，其中rubiventris亚种极为罕见，可能濒临灭绝或已灭绝。","other":"吕宋鸡鸠因其独特的外观而受到当地人的猎捕，用于食用和宠物贸易，导致其数量稀少。"},{"name":"巴氏鸡鸠","english_name":"Mindanao Bleeding-heart","scientific_name":"Gallicolumba crinigera","overview":"巴氏鸡鸠（英文名：Mindanao Bleeding-heart，学名：Gallicolumba crinigera），是鸽形目鸠鸽科鸡鸠属的鸟类。中等体型的地面鸽，以独特的红斑胸部特征而得名。分布于菲律宾的米沙鄢群岛东部、棉兰老岛及Jolo等地，为易危物种。","appearance":"头部、背部及胸侧呈蓝灰色，翅膀黑色，肩部和翼条淡灰色，喉部和胸侧白色，腹部淡粉色，胸部中央有一显著的暗红色斑块。背部有鳞片状花纹，东方中部亚种胸部有更多灰色。雄雌相似，幼鸟主要为红褐色，无蓝灰色羽毛，翼覆羽有棕褐色条纹。","call":"叫声为低沉、上扬的单音呼噜声，雌鸟较为安静。","habits":"栖息于海拔100至600米的原始和次生森林地面，可能为留鸟，以森林地面的食物为主食。","breeding":"繁殖行为观察到于五月，巢由松散的树枝和竹子构成，位于1.3米高处，含一枚新产的奶油色蛋。圈养条件下产一窝一枚蛋。","identification":"与吕宋鸡鸠相比，头部、颈部和肩部的虹彩更偏向青铜绿色而非紫色，前额较深灰色，背部、内翼覆羽、次级飞羽和中央尾羽为栗色，胸部红斑更大，由粗糙的红色羽毛组成。雄雌相似，但雌鸟的虹膜呈紫色。与亚洲翡翠鸽相比，若近距离观察不会混淆。","protection":"IUCN：VU（易危）","distribution":"分布于菲律宾的米沙鄢群岛东部，包括Samar、Leyte、Basilan、Mindanao、Bohol和Dinagat岛屿，主要栖息于热带低地雨林。","other":"受到森林砍伐和过度猎捕用于食物和宠物贸易的威胁，估计全球数量在1500至4000只之间。"},{"name":"民都洛鸡鸠","english_name":"Mindoro Bleeding-heart","scientific_name":"Gallicolumba platenae","appearance":"民都洛鸡鸠高约26至30厘米，头部前额呈深灰色，逐渐过渡到头部、颈背的虹彩绿色。其背部呈现鲜艳的红紫色，翅膀黑色带白色三角形斑点，胸部中央有一小块红色“出血心”标记，下体白色，腹部微泛奶油色，两胁灰白。雌鸟与雄鸟相似，但眼睛呈紫色，体型略小。幼鸟羽毛未有详细描述。","call":"据信发出低沉的“croo croo”叫声，与内格罗斯鸡鸠相似，但具体声音记录稀少。","habits":"栖息于低海拔森林底层，偏好干燥林地，竹子和藤蔓茂密的地面，有时出现在石灰岩露头和岩石间。倾向于奔跑躲避危险，仅在必要时短距离飞行。以果食为主，曾见于无花果树上与绿鸽共食。","breeding":"繁殖期从二月至五月，巢由树枝、叶子和细根构成，位于离地1.5至2米的水平树枝上，每巢产两枚淡奶油色蛋，雌鸟会进行假伤诱敌行为保护巢穴。","identification":"与亚洲翡翠鸽相比，民都洛鸡鸠有独特的胸斑，颜色更偏向橙色，且较小，不易混淆。","protection":"IUCN：CR（极危）","distribution":"仅分布于菲律宾民都洛岛，主要在低地森林，偶尔出现在高达750至800米的地带。","other":"面临非法伐木、大理石爆破和陷阱捕猎的威胁，栖息地严重缩减，仅剩闭冠森林面积不足120平方公里。"},{"name":"内格罗斯鸡鸠","english_name":"Negros Bleeding-heart","scientific_name":"Gallicolumba keayi","overview":"内格罗斯鸡鸠（英文名：Negros Bleeding-heart，学名：Gallicolumba keayi），是鸽形目鸠鸽科鸡鸠属的珍稀中型地面鸠，仅见于菲律宾中部的内格罗斯岛和班乃岛。拥有蓝绿色金属光泽的头部和胸部两侧，上背有鳞状图案，翅膀呈棕色。其最显著特征是胸前中央的红色‘出血之心’。由于数量极其稀少，被列为极度濒危物种。","appearance":"体长约25-26厘米，头、颈侧、上背及颈部内侧羽毛具有绿蓝色金属光泽，背部上方有鳞片状图案，翅膀棕色。胸部至腹部有狭窄的白色底色，胸部两侧和翼部有明显的白色新月形标记。最引人注目的是位于胸部中央的血红色‘出血之心’。雄雌外观相似，但在繁殖季节，雄鸟红胸条纹颜色更鲜艳、更深。幼鸟上体呈红褐色，耳羽黑色，有两道淡黄色翼带，胸部无橙色斑块。","call":"鸣唱为一连串约20-25个低音的泡泡声，持续约2秒，开始时音调和音量逐渐增加，然后稍微下降，形成独特的‘wup..pu-pu-pu-pu-pu-pu-pu-pu-pu’声。","habits":"栖息于原始森林和次生林的林地，活动于林地地面，高度敏感于栖息地扰动，偏好在海拔900-1200米的山林中生活，以果实为主食，如Arisaema sp.、Amorphophallus campanulatus、Ficus spp.和Pinanga cf. philippinensis等，同时可能在林地地面寻找昆虫。","breeding":"繁殖期记录有限，巢筑于树蕨或鸟巢蕨上，离地约70厘米至1米处，由松散的细枝构成，直径约25厘米，内含两枚光滑的白色蛋。","identification":"与同属的其他种类相比，内格罗斯鸡鸠的胸部血红色斑块更大，且雄鸟在繁殖季节颜色更加鲜艳。区别于亚洲翡翠鸽，后者也是可能从地面起飞的鸽子。","protection":"IUCN：CR（极危）。19世纪在内格罗斯岛上似乎较为常见，但目前估计每岛仅存数百只，总成熟个体数不足250。森林覆盖率急速下降，非法狩猎压力大，严重威胁其生存。","distribution":"分布于菲律宾中部的内格罗斯岛和班乃岛，主要栖息于海拔900-1200米的山区，部分记录显示曾在海拔约600米的地方出现。","other":"在2007年首次在人工环境中繁殖成功，截至2013年，圈养群体已达18只，其中14只为从非法鸟类交易中解救而来。"},{"name":"塔维鸡鸠","english_name":"Sulu Bleeding-heart","scientific_name":"Gallicolumba menagei","overview":"塔维鸡鸠（英文名：Sulu Bleeding-heart，学名：Gallicolumba menagei），是鸽形目鸠鸽科鸡鸠属的鸟类。特有于菲律宾苏禄群岛中的塔维塔维岛及其周边小岛。极为罕见，自1891年采集到两份标本以来，再无确切记录，可能已濒临灭绝。","appearance":"塔维鸡鸠是一种中等体型的鸽子，拥有短尾巴。头部至背部呈蓝灰色，胸前有一条不完整的环带。翅膀黑色，腹部至喉咙为白色，尾羽基部下方淡黄色，尾羽下侧灰白色，胸前显眼的红色斑点如同一颗“滴血的心”。雄雌外观相似，幼鸟的羽毛特征未知。","call":"塔维鸡鸠的鸣叫声尚未被记录。","habits":"栖息于原始森林和次生林的密闭树冠下层，以地面为活动范围，仅作短距离飞行。当受惊时，会迅速跑入附近的灌木丛中躲避。它在树上停留仅限于筑巢或休息。","breeding":"关于塔维鸡鸠的繁殖信息缺乏具体记录。","identification":"与亚洲翡翠鸽相比，塔维鸡鸠的肩部斑块较小，超级眉纹不明显，下体颜色较深。与同属的其他种类如吕宋鸡鸠和棉兰老鸡鸠的区别在于，前者没有紫色的颈背，后者没有明显的灰色翼条和橙色腹部。","protection":"IUCN：CR（极危）","distribution":"分布于菲律宾南部的苏禄群岛中的塔维塔维岛及其周边小岛，如Tandubatu、Dundangan和Baliungan。19世纪有未经证实的目击报告来自苏禄群岛中心的Jolo岛。","other":"最后一次确凿记录是在1891年，之后虽有报道指其在附近小岛上仍有生存，但2009年的考察未能再次发现。"},{"name":"韦岛鸡鸠","english_name":"Wetar Ground Dove","scientific_name":"Pampusana hoedtii","overview":"韦岛鸡鸠（英文名：Wetar Ground Dove，学名：Pampusana hoedtii），是鸽形目鸠鸽科Pampusana的鸟类。中等体型的森林鸽，主要分布在印度尼西亚的帝汶岛和Wetar岛。雄鸟个体头部淡灰色，胸部奶油色，腹部黑褐色；雌鸟整体呈棕色，头部、颈部和尾巴较其余部位更红褐色。在低海拔的森林地带常见。","appearance":"韦岛鸡鸠体长约27厘米，雄鸟头部蓝灰，喉咙灰白，胸脯淡奶油色，腹部黑褐色，背部和臀部红褐色。雌鸟头部、颈部和胸部锈色栗，上身和腹部橄榄棕色。两性均具黑色喙，脚和腿呈红紫。雌鸟头颈胸锈色，上体和腹橄榄棕带红晕，尾羽栗色，仅存暗亚端斑。","call":"发出重复的单音短呼，约0.3秒，音调平缓后略微上扬，如'whooOh...'，也有重复的双音符（首短后长），总时长约0.6秒，如'hu-whooOh...'。","habits":"栖息于低地森林和山地季雨林，最高可达950米（帝汶）和250米（Wetar）。主要为树栖，在高大森林树冠觅食，偶尔降地觅食如无花果。在Wetar，常见于画廊森林中的溪流或峡谷。","breeding":"繁殖信息有限，已知在树冠高处筑巢，至少在旱季有繁殖迹象。","identification":"与Little和Timor Cuckoo-Doves相比，尾部较短，眼睛深色，无横纹。雌鸟与雄鸟颜色差异明显。","protection":"IUCN：EN（濒危）","distribution":"分布于帝汶岛和Wetar岛，帝汶岛可见于高达950米的低地至山地季雨林，Wetar岛则限于低地画廊森林。","other":"历史上，Wetar岛的种群较为丰富，而帝汶岛的种群数量较少，分布零散。"},{"name":"白胸鸡鸠","english_name":"White-breasted Ground Dove","scientific_name":"Pampusana jobiensis","overview":"白胸鸡鸠（英文名：White-breasted Ground Dove，学名：Pampusana jobiensis），是鸽形目鸠鸽科Pampusana的鸟类。中等体型的地面栖息鸽类。以暗色的身体、背部和肩部带有紫色光泽、独特的白色喉部和胸部以及眉纹而著称。分布于新几内亚、俾斯麦群岛以及所罗门群岛的部分地区。","appearance":"成年白胸鸡鸠长约24至25厘米，体重126至158克。头部和面部呈灰黑色，有一条宽阔的白色眼上纹，延伸至眼睛上方和后方；喉咙和胸部为白色；颈背、颈侧、肩羽和紧邻白色喉部及胸部的区域呈现紫色；其余上体和紫色羽毛基部为石板黑色，背部、臀部和内侧次级飞羽有微弱的绿色光泽；尾巴为石板黑色，外侧羽毛有灰色尖端；下体自白色胸部以下非常深的石板灰色。虹膜深棕色，喙黑色，脚和腿为深紫红色。雌鸟相似，但白色胸部可能带有些许黄褐色或灰粉色；除紧邻胸盾的暗区外，下体颜色较淡的石板灰色；上体羽毛的紫色尖端较为有限，给人以紫色区域斑驳的绿黑色印象。幼鸟呈暗棕灰色，多数羽毛边缘呈锈色；在某些个体中，第一次换羽时会出现白色或奶油色的胸部羽毛；在其他个体中，首次胸部羽毛为灰白色（雄鸟）或暗灰色（雌鸟）。亚种chalconota的特征在于喙稍粗重，上体的紫色仅限于上背的一条横带和较小的翼盖。","call":"声音为一系列低沉、平坦的‘hoop-hoop’音符，以及类似蛙鸣的呱呱声。","habits":"栖息于雨林、季风林、次生林和灌木丛花园，海拔高度可达2300米（在新几内亚）和至少1500米（在新不列颠）。至少部分游荡，仅在野生竹子大量结籽时出现在某些区域。饮食以果实和种子为主，偶尔也会吃昆虫。与同属的一些物种相比，它不完全是陆栖，有时会在高达12至20米的果树林或攀缘竹子的树冠中觅食。","breeding":"野生状态下的筑巢习性未被描述。两个7月采集的雄鸟样本睾丸略有增大。在圈养条件下，会产下2枚卵。","identification":"雄鸟型个体很容易识别。幼年型与灰喉鸡鸠相似，但白胸鸡鸠体型更大，尾巴更长。雌鸟和幼鸟的辨识要点在于色彩的细微差异，尤其是紫色区域的分布和颜色深浅。","protection":"IUCN：LC（无危）。尽管总体上稀少，但在丘陵地带可能局部常见。在一些动物园和收藏中被饲养。","distribution":"分布于澳新界的新几内亚和部分俾斯麦群岛卫星岛屿，以及东部和所罗门群岛。","other":"该物种曾归入Alopecoenas属，但于2019年更改为Pampusana属，因后者具有命名优先权。"},{"name":"特岛鸡鸠","english_name":"White-fronted Ground Dove","scientific_name":"Pampusana kubaryi","overview":"特岛鸡鸠（英文名：White-fronted Ground Dove，学名：Pampusana kubaryi），是鸽形目鸠鸽科Pampusana的鸟类。拥有美丽的暗绒色羽毛，面部、喉咙和胸部纯白无瑕，为密克罗尼西亚丘克州和Pohnpei特有种。主要栖息于森林地带，包括受人类活动影响的农业边缘林区。","appearance":"体长约28厘米，前额、脸颊、喉咙和胸部为白色，后冠、颈背及眼后条纹为黑色；背部和翼覆羽呈现金属光泽的红紫色，飞羽和尾羽呈石板黑色；腹部深灰黑色；虹膜深棕色；喙黑色；腿脚紫红色。雌雄相似，但雌鸟下体羽尖带浅褐色，显得较为淡雅。幼鸟全身暗锈褐色，羽缘金红，羽基橄榄色。","call":"据报告会发出低沉的哀怨咕咕声，以及一种哨音叫声，具体声音特征记录不详。","habits":"栖息于刷木沟壑和低地森林，包括红树林地带。偏好有大花芙蓉（Hibiscus tiliaceus）形成密集灌丛的沟壑，这类生境靠近人类居住区，受到干扰和改造。在丘克州，可见于各种生境，从环礁到农业森林，至海拔较高处的原生森林，最高可达180米。常在地面或底层灌木活动。","breeding":"在丘克州，发现2月、4月、6月和9月有筑巢行为；在Pohnpei，11月至12月观察到雄鸟生殖腺增大。巢为脆弱的树枝平台，直径约23厘米，位于3至10米高的灌木、树木或树蕨上。每次产一枚白色卵。关于孵化期和亲鸟抚育的信息尚无记录。","identification":"与近缘种Alopecoenas xanthonurus（北方马里亚纳群岛的种类）相比，飞行距离短且无声，不会飞越树冠层。在行走时，动作笨拙，类似家养鸡。","protection":"IUCN：EN（濒危）。自1970年代以来，丘克州的数量可能严重下降，而在Pohnpei近期访问中，仅在红树林中检测到少量个体。猎杀、外来捕食者的威胁及生境因耕作而丧失构成严重威胁。","distribution":"分布于太平洋的丘克州和Pohnpei，这两个地方分别位于加罗林群岛中部和东部，属于密克罗尼西亚中部区域。","other":"此物种原归于Alopecoenas属，2019年基于优先权原则改名为Pampusana属。"},{"name":"白领鸡鸠","english_name":"Polynesian Ground Dove","scientific_name":"Pampusana erythroptera","overview":"白领鸡鸠（英文名：Polynesian Ground Dove，学名：Pampusana erythroptera），是鸽形目鸠鸽科Pampusana的鸟类。原生自法属波利尼西亚的土阿莫土群岛和过去的社会群岛。这种地栖性的鸟类体型圆胖，通常以奔跑而非飞行逃避威胁。雄鸟具有独特的外观，暗色的身体上带有紫色肩部光泽，明亮的白色胸部和脸部，以及延伸至颈部的黑色冠斑。雌鸟相似，但腹部、胸部和头部呈米色，眼后有一暗斑。全球仅存约200只，分散于极小的亚群，栖息在无人居住的小岛上。","appearance":"雄性白领鸡鸠拥有白色的前额、脸颊、喉咙和胸部，灰色的头冠、颈背和耳羽条并不深沉，部分雄鸟的头部全白。上体为深橄榄灰，后颈和翼羽覆羽带有紫色或褪色后变为栗红色的金属光泽，下体为黑色。雌鸟全身呈鲜艳的红棕色，强烈地带有红紫色的头冠、颈和翼羽覆羽，肩胛、背部、臀部和内侧翼羽覆羽为较暗的橄榄色，胸部有模糊的淡色护盾。幼鸟整体红色，许多羽毛边缘为肉桂色，雄鸟幼鸟比雌鸟更早显现出胸部护盾和肩胛及较小翼羽覆羽的紫色边缘。","call":"广告叫声是一种持续约0.6秒的粗哑滚动咕咕声，音调几乎不变，每秒约1个音符，声音为“rrruuh...rrruuh...rrruuh...”。","habits":"白领鸡鸠偏爱热带森林环境，尤其是在有Pandanus tectorius、Pisonia grandis和灌木丛的地方，但也在椰子树下的密集灌木丛中被发现。它主要以地面上的种子为食，如Morinda和Tournefortia植物的种子，也会在树上和灌木中觅食Portulaca的花蕾、Digitaria的种子和Euphorbia的叶子。","breeding":"关于其繁殖行为的信息极少。已知唯一的巢穴位于Pandanus树上，蛋壳呈淡蓝色，带有浅棕色斑点。1月和4月观察到过幼鸟。然而，在2015年6月的Tenararo观察中并未发现巢穴或雏鸟，且幼鸟大多独立于父母，这表明在此地的繁殖可能是季节性的。","identification":"雄性白领鸡鸠与A. kubaryi非常相似，但头部、颈背和耳羽条的灰色不如后者深沉，一些雄鸟头部全白。雌鸟与雄鸟显著不同，全身红棕色，强带红紫，肩部、背部、臀部和内侧翼羽覆羽为较暗的橄榄色。幼鸟与成鸟颜色鲜明，整体红色，许多羽毛边缘为肉桂色。","protection":"IUCN：CR（极危）。全球种群估计约为200只，分布在极小的亚群中，仅限于微小的林木岛屿。由于引入的鼠类、猫类和蚂蚁的威胁，以及疾病和栖息地退化，导致种群数量急剧下降。","distribution":"原生于法属波利尼西亚的土阿莫土群岛和过去的社会群岛。目前，大多数现存个体集中在南土阿莫土群岛，特别是在Acteon群岛附近，尤其是Tenararo岛，2015年在此地发现了健康种群，估计有190只（160-240）。也有少量个体报告出现在Vahanga、Morane和Tenarunga的南土阿莫土群岛，以及北部的Rangiroa环礁。","other":"通过2015年至2017年的鼠害根除运动，白领鸡鸠得以在Tenarunga重新建立种群，这是数十年来首次实现。"},{"name":"白喉鸡鸠","english_name":"White-throated Ground Dove","scientific_name":"Pampusana xanthonura","overview":"白喉鸡鸠（英文名：White-throated Ground Dove，学名：Pampusana xanthonura），是鸽形目鸠鸽科Pampusana的鸟类。曾被归类于Alopecoenas属，后于2019年调整至Pampusana属。雄鸟拥有独特的白色头部和胸部，而雌鸟全身呈褐色。分布于北马里亚纳群岛和密克罗尼西亚联邦的雅浦岛，曾在关岛存在但现已灭绝。","appearance":"白喉鸡鸠长约25厘米，体重雄鸟117-154克，雌鸟58-150克。性别羽色差异显著。雄鸟头顶、颈背、耳羽浅粉红栗色，头颈胸白色，带有鲑粉色晕染，背部有紫色带，翼覆羽紫色，下体灰黑色边缘暗红棕色，尾巴深棕灰色。雌鸟整体呈暗褐色，上部橄榄青铜色，下部土红色边缘。虹膜灰或棕色，眼周皮肤黄白色，喙黑或深棕色，腿脚紫红色。幼鸟因羽毛边缘明亮的红棕色而显得格外鲜艳。年轻雄鸟比雌鸟的红棕色羽毛更宽更丰富。","call":"发出连续的单个哀伤的呼叫声，持续约1秒，音调几乎不变，'whooooh...whoooh...'。也会发出持续约1.5秒的嘶哑咆哮声，'rrreeh'。","habits":"栖息于各种森林环境，包括原生森林和次生或农业森林。在马里亚纳群岛上，经常在树冠上方进行长距离的单独飞行，这是一种不同于属内其他物种的行为。主要以果实为食，但也吃种子、花朵，偶尔吃叶子。在马里亚纳群岛上，该物种主要在灌木和树木中觅食，而非地面。","breeding":"在关岛，筑巢时间记录于1月至3月、5月和8月，9月和11月观察到求偶和交配行为。雄鸟在4月至7月有扩大的生殖腺。基于证据，繁殖可能全年至少在关岛上发生。巢穴建在大树上，高度从1.5米至更高，由双亲共同建造。已知一窝两枚蛋的记录，但另一巢穴仅由雄鸟照料。","identification":"雄鸟与雌鸟的羽色差异明显，雄鸟具有独特的白色头部和胸部，而雌鸟则为单一的褐色调。与属内其他物种相比，白喉鸡鸠在马里亚纳群岛上主要在灌木和树木中觅食。","protection":"IUCN：NT（近危）","distribution":"分布于北马里亚纳群岛，包括关岛（已灭绝）、罗塔岛、塞班岛和阿古伊根岛；以及密克罗尼西亚联邦的雅浦岛。在关岛因入侵的棕色树蛇Boiga irregularis的捕食而灭绝。","other":"白喉鸡鸠数量自1982年以来在阿古伊根岛有所增加，2008年估计为548只。尽管受到低水平猎杀，但适应次生栖息地的能力似乎使其短期内不受威胁。"},{"name":"诺福克鸡鸠","english_name":"Norfolk Ground Dove","scientific_name":"Pampusana norfolkensis","overview":"诺福克鸡鸠（英文名：Norfolk Ground Dove，学名：Pampusana norfolkensis），是鸽形目鸠鸽科Pampusana的已灭绝鸠类，曾特有于太平洋中的诺福克岛（澳大利亚远东）。该物种在欧洲人于18世纪晚期定居后不久，因引入的掠食者而迅速消失。","appearance":"由于缺乏保存完好的标本，诺福克鸡鸠的详细外形特征难以详述。已知的信息主要来源于一幅由John Hunter在1790年绘制的插图。","habits":"诺福克鸡鸠是一种小型陆地鸽，历史上常见且温顺。它们的生活习性大部分信息缺失，但据推测其可能有着鸽子典型的栖息和觅食模式。","identification":"与常见的翡翠鸽和白头鸽不同，诺福克鸡鸠的独特性在于它仅存在于诺福克岛上的记录，尽管具体区别细节未知。","protection":"IUCN：EX（已灭绝）","distribution":"诺福克鸡鸠仅在澳大利亚远东的诺福克岛（Norfolk Island）有记录，这是一个位于太平洋的岛屿。","other":"该物种的科学命名经历了多次变更，最初被Latham描述为Columba norfolciensis，后被ICZN于2010年废止，由Joseph Forshaw于2015年重新命名为Alopecoenas norfolkensis，最终于2019年确定为。"},{"name":"睦鸡鸠","english_name":"Tongan Ground Dove","scientific_name":"Pampusana stairi","overview":"睦鸡鸠（英文名：Shy Ground Dove，学名：Pampusana stairi），是鸽形目鸠鸽科Pampusana的鸟类。体型圆胖，腿部短小，通常以奔跑而非飞行的方式逃避危险。这种鸟分布于斐济、Wallis和Futuna群岛、萨摩亚、美属萨摩亚以及汤加等地，偏好低地雨林和竹林环境。","appearance":"雄性睦鸡鸠拥有独特的深紫色背部、翅膀和腹部，胸部有一弯白色的月牙形斑纹，头部和胸部呈淡灰色。雌鸟外观与雄鸟相似，但部分个体的体色为紫棕色，胸部和头部颜色更为红润。幼鸟呈现红棕色，羽毛边缘颜色较浅。成年鸟的尺寸约为25至26厘米，体重约171克。","call":"睦鸡鸠的叫声是一系列低沉、节奏均匀的咕哝声，每秒大约1.5个音符，叫声的节奏可能在整个系列中逐渐加快或减慢。","habits":"睦鸡鸠常栖息于多种森林环境中，包括低地雨林、竹林和画廊森林，海拔可达至少1500米。它们更倾向于通过奔跑而不是飞行来逃离威胁，但在必要时能够快速而有力地飞行。食物来源多样，包括种子、果实、花蕾、嫩叶、昆虫和蜗牛。","breeding":"筑巢记录显示，繁殖期从7月至次年1月。巢由交织的枝条、藤蔓和细根构成，通常位于离地面1至3米的小树丛中，或树蕨的冠层中。每次产1至2枚纯白色蛋。","identification":"雄鸟和雌性睦鸡鸠的辨识主要基于颜色差异，雌鸟存在两种形态，一种与雄鸟非常相似，另一种全身呈棕色，仅胸部有微弱的淡色盾状斑。在斐济，两种雌鸟形态的数量大致相等；而在汤加和萨摩亚，几乎所有的雌鸟都与雄鸟相似。","protection":"IUCN：LC（无危）","distribution":"睦鸡鸠广泛分布于太平洋地区，包括斐济、Wallis和Futuna群岛、萨摩亚的Savaii、Upolu和Aleipata岛屿、美属萨摩亚的Manua群岛以及汤加。","other":"曾归属于Alopecoenas属，2019年根据优先权原则改名为Pampusana属。"},{"name":"圣岛鸡鸠","english_name":"Santa Cruz Ground Dove","scientific_name":"Pampusana sanctaecrucis","overview":"圣岛鸡鸠（英文名：Santa Cruz Ground Dove，学名：Pampusana sanctaecrucis），是鸽形目鸠鸽科Pampusana的鸟类。体型圆胖、腿短的地面栖息鸽类，通常受惊时选择奔跑而非飞行。雄鸟具深色体羽，肩部有粉紫色金属光泽斑块，胸部呈奶油色，头部灰色。雌鸟头部和胸部呈红褐色，背部和翅膀橄榄绿色。幼鸟全身暗棕色。偏好成熟的原始森林环境，海拔可达1000米。叫声记录较少，包括典型的鸽类重复加速的'whoot'声。","appearance":"圣岛鸡鸠的雄鸟拥有暗色的身体，肩部有独特的粉紫色闪光斑块，胸部为奶油色，头部呈灰色。雌鸟的头部和胸部为红褐色，背部和翅膀为橄榄绿色。幼鸟全身覆盖着暗棕色的羽毛。它们的腿短而粗，适应地面奔跑。","call":"圣岛鸡鸠的叫声记录有限，主要包括低沉响亮的‘woot’声，单调重复多达15次，声音频率在结尾时会加速。","habits":"圣岛鸡鸠偏好成熟的原始森林环境，活动范围可达海拔1000米。它们主要在地面活动，受惊时倾向于奔跑而非飞行。","identification":"圣岛鸡鸠与A. canifrons的叫声相似，但可通过其特有的粉紫色肩部斑块和地面奔跑的习惯进行区分。","protection":"IUCN：EN（濒危）","distribution":"圣岛鸡鸠仅分布在所罗门群岛东南部的Tinakula和Utupua（Temotu=Santa Cruz Is.），以及瓦努阿图北部的Santo。2017年Tinakula的火山爆发对其种群造成严重影响，但仍有至少15只幸存。Espiritu Santo岛上的分布密度较低，面临森林破坏、狩猎和外来哺乳动物捕食的威胁。","other":"2017年Tinakula的火山爆发前，非法捕鸟活动导致大量圣岛鸡鸠被捕获，约109只现处于圈养状态。"},{"name":"塔岛鸡鸠","english_name":"Tanna Ground Dove","scientific_name":"Pampusana ferruginea","overview":"塔岛鸡鸠（英文名：Tanna Ground Dove，学名：Pampusana ferruginea），是鸽形目鸠鸽科 Pampusana 属的一种已灭绝鸠类。其分类地位一度存疑，最初由Wagler在1829年归入Gallicolumba属，后来被认为可能与圣岛鸡鸠关系密切。该物种仅在太平洋岛屿瓦努阿图的塔纳岛（Tanna）发现，当地人以Kwamera语言称其为mahk。","appearance":"塔岛鸡鸠的外观仅通过两个现已遗失的标本得以了解。雌鸟标本长约27厘米，头部和胸部呈锈褐色，背部为深红至紫色，翅膀带有暗绿色调，初级飞羽为棕色灰色，腹部为灰色。雄鸟标本的额头、眉纹、头部下半部、喉咙和胸部为白色，腹部为红黑色，喙为黑色，脚为红色，虹膜呈黄色。","habits":"对于塔岛鸡鸠的生活习性所知甚少。根据Forster父子的观察，它可能食用野肉豆蔻(Myristica inutilis)，这一树种在塔纳岛的森林中并不罕见，但因其体型较小而容易被忽视。","identification":"由于标本遗失，其与同属或相近物种的区别特征难以详述。","protection":"IUCN：EX（已灭绝）","distribution":"该物种仅在太平洋岛屿瓦努阿图的塔纳岛（Tanna）发现。","other":"塔岛鸡鸠的灭绝时间不明，但据信不晚于19世纪初。其灭绝原因未知，但引入的鼠类可能是主要原因之一。"},{"name":"厚嘴鸡鸠","english_name":"Thick-billed Ground Dove","scientific_name":"Pampusana salamonis","overview":"厚嘴鸡鸠（英文名：Thick-billed Ground Dove，学名：Pampusana salamonis），是鸽形目鸠鸽科Pampusana的已灭绝鸠类。仅有的两个标本分别采集于1882年的马基拉岛（原名圣克里斯托瓦尔）和1927年的拉莫斯岛（位于圣伊莎贝尔岛和马莱塔岛之间，面积约为4公顷），这使得对其了解十分有限。","appearance":"厚嘴鸡鸠体长约26厘米，头部、喉咙及胸部呈现米黄色调，上半身则是栗色，双翼上的淡紫色光泽与巧克力色腹部形成鲜明对比。","habits":"厚嘴鸡鸠偏好栖息在所罗门群岛马基拉岛及拉莫斯岛的干燥沙滩森林环境中。它们筑巢于地面，使其成为入侵物种如大家鼠、野猪、野猫及野狗的易受攻击目标。低地森林的砍伐和过度猎杀是导致其灭绝的关键因素。","protection":"IUCN：EX（已灭绝）","distribution":"该物种的分布限于所罗门群岛的东南部，具体包括马基拉岛和拉莫斯岛（北部，圣伊莎贝尔岛附近）。尽管最后一次被目击是在1927年，但在20世纪后期的多次调查未能发现其踪迹，直至2004年在拉莫斯岛的搜寻失败后，它于2005年正式被宣布为已灭绝。"},{"name":"灰头鸡鸠","english_name":"Marquesan Ground Dove","scientific_name":"Pampusana rubescens","overview":"灰头鸡鸠（英文名：Marquesan Ground Dove，学名：Pampusana rubescens），是鸽形目鸠鸽科Pampusana的鸠类。名称来源于其灰色头部和地面活动的习性。这种鸟主要分布在法属波利尼西亚的马克萨斯群岛，特别是在Fatu Uku和Hatutaa两个岛屿上。该物种曾被归类为濒临灭绝。","appearance":"灰头鸡鸠是一种圆胖、短腿的地面栖息鸽子，通常以奔跑而非飞行的方式逃避危险。腹部为石板灰色，与较浅的灰色胸部和头部形成对比，肩膀和背部呈现紫罗兰色。雌雄成鸟相似，但雌鸟翅膀和尾部的白色较少，上体绿色光泽更广泛；幼鸟翅膀和尾羽几乎无白色，比成鸟更暗淡，羽毛边缘呈锈褐色。","call":"鸣叫声记录有限，但已知雄鸟会发出嘶哑、咆哮的声音，而雌鸟偶尔会发出咕咕声。","habits":"灰头鸡鸠栖息于从海岸到山顶的各种生境，包括悬崖，偏好混合苔原草地和灌木丛。它主要在地上觅食，偶尔也会在树上。食物主要包括Pisonia种子和蚂蚁。","breeding":"关于繁殖的信息尚不充分，但已知其受干旱影响，导致极端的人口波动。","identification":"在其范围内无类似物种，通过其独特的颜色组合和地面活动模式很容易识别。","protection":"IUCN：EN（濒危）","distribution":"仅限于太平洋的Fatu Uku和Hatutaa两个岛屿（马克萨斯群岛，法属波利尼西亚东北部）。"},{"name":"灰喉鸡鸠","english_name":"Bronze Ground Dove","scientific_name":"Pampusana beccarii","overview":"灰喉鸡鸠（英文名：Bronze Ground Dove，学名：Pampusana beccarii），是鸽形目鸠鸽科Pampusana的鸟类。原置于Alopecoenas属下，2019年因属名优先原则调整至Pampusana属。广泛分布在新几内亚的山脉、俾斯麦群岛东部以及所罗门群岛，栖息于海拔1200至2900米的高山森林，但在某些地区可低至390米。其特征为圆胖的体型，短腿，通常奔跑而非飞行，拥有蓝灰色头部和胸部，背部橄榄绿带青铜光泽。","appearance":"成年雄性灰喉鸡鸠体长18至20厘米，体重84至104克，雌鸟体重约59克。头部和胸部淡蓝灰色，颈部至背部暗紫绿色，腹部黑灰，翅膀和背部橄榄绿带青铜光泽。雄鸟肩部有粉色闪光，眼圈白色显眼，特别是在所罗门群岛的种群中。雌鸟头部和上胸部暗灰色，下身黄褐色，翅膀和胸部缺乏紫色。幼鸟全身暖棕色，翅羽和胸羽边缘锈红色。","call":"鸣声为典型的鸽子‘woo-oop’声，深沉单调，由一系列五声清晰、音调均匀的‘woo-oop’组成，有时从低枝或地面发出。叫声较为安静，容易被忽视。","habits":"栖息于海拔1200至2900米的高山森林，以落地果、种子和昆虫为食，偏好在天堂鸟和园丁鸟的地面领地觅食。常在野竹开花时大量出现。主要在地上活动，偶尔在低枝上停留。通常单独或成对出现。","breeding":"筑巢记录显示在1月和8月有繁殖行为。巢为脆弱的平台状，由枯枝落叶构成，建于地面、树干或离地3米内的植被中，如幼小的棕榈或攀缘竹。每窝产一枚白色蛋，无更多繁殖信息。","identification":"雄鸟与雌鸟的颜色差异明显，尤其是眼圈的颜色和胸部的色带。与同属物种相比，其腹部颜色较暗，翼部光泽更显青铜色。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚山脉、俾斯麦群岛东部和所罗门群岛，尤其在新几内亚的Huon半岛，可能因缺乏竞争的低地鸽种而分布较低至至少390米。","other":"种群数量未知，总体稀缺，但在野竹开花时局部常见。"},{"name":"灰额鸡鸠","english_name":"Palau Ground Dove","scientific_name":"Pampusana canifrons","overview":"灰额鸡鸠（英文名：Palau Ground Dove，学名：Pampusana canifrons），是鸽形目鸠鸽科Pampusana的鸟类。仅见于太平洋上的帕劳群岛。其最显著的特征是头部和胸部的蓝灰色调，以及独特的淡肉桂色颈项和头部。分布区域狭窄，仅限于帕劳群岛的森林地带。","appearance":"灰额鸡鸠体长约22厘米，头部和胸部呈蓝灰色，顶部颜色较深，而上胸部颜色较浅；喉咙部分白色；下胸部带有粉红色调，胸盾后缘有一条白色边缘；其余下体部位为暗灰棕色；颈背、上背部和颈部两侧为赤褐色，当飞行远离时尤为显眼；小翼羽为丰富紫色；其余上体部位为橄榄绿色，带有青铜光泽，大多数羽毛边缘为赤褐色；眼睛深棕色；眼周皮肤粉红；喙黑色；腿和脚粉色。雌雄外观相似。幼鸟羽毛细节未知。","call":"灰额鸡鸠发出一系列大约10至20个短暂、略微上升的咕哝声，每秒约1.5个音符，整个序列可能逐渐加速：\"whuU..whuU...\"。每个音节持续约0.30至0.35秒。","habits":"独居物种，主要在地面的落叶层中寻找种子和果实。它在清晨和傍晚时分在同一地点发出单调的咕咕声，持续时间可达两分钟。还发出哀怨的叫声。其繁殖习性尚不清楚。","breeding":"目前关于其繁殖习性的信息未知。","identification":"灰额鸡鸠具有独特的淡肉桂色颈项和头部，以及蓝灰色的头部和胸部，这在它的分布范围内没有相似物种。","protection":"IUCN：EN（濒危）","distribution":"灰额鸡鸠仅分布于太平洋的帕劳群岛，从Babelthuap岛南部到Angaur岛，包括帕劳的岩岛群。","other":"灰额鸡鸠曾被归类于Gallicolumba和Alopecoenas属，2019年改名为Pampusana属。"},{"name":"冕鸠","english_name":"Choiseul Pigeon","scientific_name":"Microgoura meeki","overview":"冕鸠（英文名：Choiseul Pigeon，学名：Microgoura meeki），是鸽形目鸠鸽科冕鸠属的已灭绝鸟类。原生于所罗门群岛东北部的舒瓦瑟尔岛。以蓝灰色为主色调，腹部呈橙色，拥有独特的蓝灰色毛发状冠羽。由于仅在1904年有六份标本和一枚蛋的记录，其生态和习性知之甚少。","appearance":"冕鸠长约31至35厘米，头部前额和面部黑色，头顶蓝灰色逐渐变深至背部和胸部；眼睛下方有粉红色斑块；头部有簇状向后指的毛发状冠羽；下背和臀部棕色；下体暗黄褐色；翅膀深棕色；上喙黑色，下喙红色；额头盾状结构淡蓝色；虹膜颜色不确定，可能是深柠檬色或棕色；腿紫色。","call":"当地居民报告称，冕鸠在晚上休息地点发出美妙的起伏哨声。","habits":"冕鸠可能栖息于沿海低洼森林，包括沼泽地带，可能大部分时间生活在地面，靠近森林底层觅食和筑巢。有报告称它以小群体形式栖息。","breeding":"一枚暗奶油色的卵被报道相对较小，放置于地面。","identification":"冕鸠的独特特征在于其蓝灰色的头部和毛发状的冠羽，以及下体的橙色。与其它鸽子的区别在于其特定的冠羽结构和色彩模式。","protection":"IUCN：EX（灭绝）","distribution":"冕鸠仅知分布于所罗门群岛中的舒瓦瑟尔岛。","other":"冕鸠最后一次确认的目击是在1904年，之后的多次搜寻均未发现其踪迹。"},{"name":"雉鸠","english_name":"Pheasant Pigeon","scientific_name":"Otidiphaps nobilis","overview":"雉鸠（英文名：Pheasant Pigeon，学名：Otidiphaps nobilis），是鸽形目鸠鸽科雉鸠属的鸟类。分布在新几内亚及周边岛屿的丘陵和低山森林地带。以独特的雉鸡般侧扁尾巴和黄色腿脚著称。","appearance":"雉鸠拥有侧扁的雉鸡似尾部，由20-22根羽毛组成，长而细的黄色腿。头部、胸部和背部呈黑色，翅膀和背部具栗色，尾部黑色。颈部背面有绿色或紫色光泽，下背至臀部有金色青铜或粉紫斑块，翼展184-219毫米。成年个体体长42-50厘米，体重约500克。两性相似，幼鸟色泽较暗，毛绒状。四亚种在细节上有所不同。","call":"雉鸠发出响亮、远传的‘wu-huwoooaaa’鸣叫声，音调起伏，尾声拖长，持续1.4-2秒，间隔8-10秒重复。展示时，雄鸟会发出简单的‘woooou’声和猫似的尖叫‘crrouwwwwwww’。","habits":"雉鸠栖息于丘陵和低山雨林，有时出现在低地，最高可达1900米海拔。它们主要在地面觅食，以种子和落果为食，偶尔造访威氏极乐鸟的展示场寻找吐出的种子。它们通常独居，有时成对出现。","breeding":"雉鸠在3月到10月间繁殖，巢建于灌木或树根下，由35-50根细枝搭建，产单枚蛋，孵化期23-26天，由双亲轮流孵育。雄鸟在孵化初期提供全部的食物。","identification":"雉鸠与其它鸽类显著不同，其侧扁的雉鸡似尾部和长腿是主要识别特征。四亚种在冠羽、颈部斑纹颜色和光泽上有细微差异。","protection":"IUCN：VU（易危）","distribution":"雉鸠主要分布在新几内亚山脉，包括Batanta、Waigeo和Yapen岛，以及西新几内亚的山脉。","other":"尽管全球未受威胁，但雉鸠在其大范围内（约26万平方公里）可能局部常见，也可能稀少或罕见。"},{"name":"蓝凤冠鸠","english_name":"Western Crowned Pigeon","scientific_name":"Goura cristata","overview":"蓝凤冠鸠（英文名：Western Crowned Pigeon，学名：Goura cristata），是鸽形目鸠鸽科凤冠鸠属的大型鸟类。其身长约70厘米，体重约2.1公斤，拥有独特的蓝色扇状冠羽，通体蓝灰色，眼睛周围有深色羽毛环绕。分布于新几内亚西北部的低地雨林，是该地区的特有种。","appearance":"蓝凤冠鸠整体呈现中至深灰蓝色调，头部有侧压的蓝灰色蕾丝状羽毛组成的冠羽，带银色光泽；翅膀和尾巴色调更深，带有板岩色；尾部末端有灰蓝色条纹；上背部和大部分翼覆羽为暗紫红色；大覆羽外侧白色尖端，形成闭合翅膀上的醒目白斑；从喙基部延伸至眼周的宽阔黑条纹；虹膜红色，喙黑色，腿和脚为深红色。雄雌外观相似，但雄鸟通常更大。幼鸟的冠羽较短，尾部条纹不明显，翅膀斑点奶油色，整体色彩较为暗淡。","call":"发出深沉回响的‘hoom-hoom-hoom-hoom-hoom’声，由5至6个音符组成，具有鼓声质感，迅速连续，声音听起来比实际位置更远。觅食时或突然飞起时，可能发出低沉的‘hooom’声，仅近距离可闻。","habits":"栖息于低地雨林内部，也出现在沼泽和半淹没地区，以及红树林中，高度至少达到500米。在瓦吉奥、巴坦塔、萨拉瓦蒂和密索尔等岛屿，高度可达150米。大部分时间在森林地面活动，夜间在树上休息。","breeding":"繁殖季节性未知，但有记录显示雄鸟在4月有大型睾丸，9月在沃格尔角半岛发现带蛋的巢。巢由树枝搭建，位于离地高达10米的水平枝上，通常靠近溪流或干涸河床。产一枚白色大蛋，孵化期28-29天，离巢期30-36天，双亲共同孵卵和喂养雏鸟。","identification":"与其他凤冠鸠的区别在于缺乏胸部的紫红色，且拥有独特的白色肩部斑点。在分布范围内无其他凤冠鸠种类。","protection":"IUCN：VU（易危）","distribution":"分布于新几内亚西北部的低地雨林，包括四王群岛（西北部新几内亚）和鸟头半岛及颈部（新几内亚西北部）。","other":"受到《濒危物种国际贸易公约》（CITES）附录II的保护。"},{"name":"紫胸凤冠鸠","english_name":"Scheepmaker's Crowned Pigeon","scientific_name":"Goura scheepmakeri","overview":"紫胸凤冠鸠（英文名：Scheepmaker's Crowned Pigeon，学名：Goura scheepmakeri），是鸽形目鸠鸽科凤冠鸠属的大型陆栖鸟类，体长约70厘米，重约2.25千克，仅次于蓝凤冠鸠，是世界第二大鸽种。拥有蓝色灰色的羽毛，胸前呈深紫色，头部有精致的蓝色羽冠，虹膜红色，两性外观相似。","appearance":"紫胸凤冠鸠体型庞大，约71至79厘米长，肩部和喉咙均为蓝灰色，胸部呈现醒目的暗紫色。翅膀上有一道明显的白色标记，但不如斯克莱特凤冠鸠的明亮。羽毛细节上，背部和翼覆羽为均匀的蓝灰色，有时带黑色边缘，较大的翼覆羽更接近珍珠白而非奶油白。颈前部为深蓝灰色，腹部暗紫色逐渐变灰。尾巴下方的覆羽为灰或黑色。翼展长度为370至380毫米。虹膜红色，喙为深蓝灰色，腿和脚为紫红色。幼鸟与成鸟相似，但翼部为奶油灰色，成鸟的暗紫色被栗色取代。","call":"发出类似心跳节奏的深沉鼓声，'Boom-boom, Boom-boom...'，声音与大鸟类似。","habits":"栖息于新几内亚东南部的低地和山麓雨林，偶尔可达海拔800米。通常成小群在地面觅食，以种子、浆果和掉落的果实为主食，包括其他鸽子打落地面的果实。群体大小通常为3至7只，偶尔可观察到10至30只的大群。","breeding":"繁殖生态信息有限，曾有记录显示在8月初有鸟从巢中惊飞。其繁殖生态可能与斯克莱特凤冠鸠类似。","identification":"与斯氏凤冠鸠相比，其胸腹部的暗棕色更广泛，翼部特征不同，背部羽毛不具淡灰色斑点，腹部颜色更暗更灰。与蓝凤冠鸠的区别在于胸部和腹部为深紫色或栗色，背部和较小的翼覆羽为灰蓝色，翼部斑纹灰白色，羽冠更长且更细腻。","protection":"IUCN：VU（易危）。CITES II级。估计数量不足10,000只成熟个体。在人类居住区附近几乎绝迹，仅在部分潜在分布区内（如霍尔湾和埃帕山以东至奥兰热里湾）仍有记录。","distribution":"分布于新几内亚东南部的低地森林，从莱克卡穆盆地、霍尔湾和埃帕山向东至奥兰热里湾。","other":"在历史上，曾与斯氏凤冠鸠视为同一物种，现已确认为独立物种。"},{"name":"斯氏凤冠鸠","english_name":"Sclater's Crowned Pigeon","scientific_name":"Goura sclaterii","overview":"斯氏凤冠鸠（英文名：Sclater's Crowned Pigeon，学名：Goura sclaterii），是鸽形目鸠鸽科凤冠鸠属的鸟类。大型陆生鸽子，主要栖息于新几内亚中南部的低地雨林，曾与紫胸凤冠鸠被视为同一物种，称为‘南方凤冠鸠’。其特征为蓝灰色的羽毛，带有精致的蓝色花边状头冠，深红色的胸部，以及醒目的红眼。","appearance":"斯氏凤冠鸠体长66至73厘米，体重2.00至2.24公斤，体型巨大。全身覆盖着蓝灰色的羽毛，头部、颈背及颈侧为蓝灰色，眼周黑色，逐渐过渡到深蓝灰色。肩部至胸下部呈丰富的紫红色，与淡灰色的腹部形成鲜明对比。翅膀上有一大块白色斑点，边缘由深蓝色灰色的羽毛环绕。尾羽深蓝灰色，尖端略浅。虹膜血红色，脚和腿紫色。","call":"发出深沉空洞的心跳节奏般的‘boom-boom，boom-boom…’鼓声，类似食火鸡的叫声。","habits":"栖息于未受干扰的干燥和水淹森林，海拔高度至500米，主要以地面觅食为主，食物包括种子和落地果实，也会在泥泞的河岸边觅食，甚至被观察到食用小蟹。通常成群结队在地面觅食，数量在2至10只之间，有时可达30只，夜宿于树上。","breeding":"巢由结实的树枝、茎、棕榈叶、藤蔓或粗大的枯草构成，位于距地面3.5至15米处。雏鸟皮肤呈暗灰色。圈养的个体从15个月开始繁殖，每次产一枚蛋，孵化期28至30天，孵化后持续照料幼鸟数月，幼鸟离巢时间为28至36天。","identification":"与最明显的区别在于后者翼部的白色斑点上方由深红色的小羽盖和深红色的喉部和胸部，而斯氏凤冠鸠的胸部和腹部颜色转为灰蓝色。","protection":"IUCN：NT（近危）；CITES: 附录II。据估计，新几内亚在1972年至2002年间净损失了约15%的森林，主要原因是伐木，另有8.8%的森林在同一时期退化，尽管在许多地方，斯氏凤冠鸠似乎能够忍受伐木。","distribution":"主要分布在新几内亚中南部，具体范围从Mimika河东至Fly河和Strickland河，可能甚至远至Hegigo河。在Fly河和Purari河之间的Goura种群身份未知，可能是本种或紫胸凤冠鸠。","other":"历史上，斯氏凤冠鸠因肉质美味和羽毛美观而遭受过度猎杀。目前，通过远程感应分析估计，新几内亚在1972年至2002年期间，森林覆盖率减少了约15%，主要是由于伐木活动，另有8.8%的森林在同一时期遭受退化。然而，在许多地区，该物种似乎能够忍受适度的伐木。"},{"name":"渡渡鸟","english_name":"Dodo","scientific_name":"Raphus cucullatus","overview":"渡渡鸟（英文名：Dodo，学名：Raphus cucullatus），是鸽形目鸠鸽科渡渡鸟属的已灭绝鸟类。又称: 毛里求斯渡渡鸟、愚鸠、孤鸽、嘟嘟鸟，不会飞的鸟类。原产于印度洋毛里求斯岛，高达一米，以水果为食，栖息于陆地。自被人类发现后的短短两个世纪内，因人类的捕杀和活动影响而彻底灭绝。","appearance":"渡渡鸟体形大于吐绶鸡，体重可达23公斤。体羽呈蓝灰色，头部较大，嘴长23厘米，颜色淡黑，末端具淡红色鞘形成钩状。翅膀小，无法飞行。脚部强壮，黄色，脚后端高处有一束弯曲的羽毛。据现有化石和残存标本，渡渡鸟在演化过程中逐渐失去了飞行能力。","habits":"渡渡鸟栖息于毛里求斯岛上的森林中，偏好干燥沿海地区的树林地带。它可能依赖丰富的水果、坚果、种子、球茎和根茎为食，也有可能食用蟹类和贝类。具有发达的嗅觉，有助于寻找食物。在毛里求斯，渡渡鸟没有天敌。","breeding":"关于渡渡鸟的繁殖习性信息有限。据记载，它可能在地上筑巢，每次产一枚白色的蛋。幼鸟可能由父母提供嗉囊乳喂养。","identification":"渡渡鸟与罗德里格斯渡渡鸟亲缘关系最近，但体形更粗壮，嘴部更大，尾部羽毛较少。两者在生存环境和生态位上可能存在差异。","protection":"IUCN：EX (已灭绝)","distribution":"渡渡鸟原产于印度洋的毛里求斯岛(Mascarenes)中部。","other":"渡渡鸟的灭绝发生在人类发现后的不到一个世纪内，这一事件引发了对人类活动对物种灭绝影响的关注。"},{"name":"罗德里格斯渡渡鸟","english_name":"Rodrigues Solitaire","scientific_name":"Pezophaps solitaria","overview":"罗德里格斯渡渡鸟（英文名：Rodrigues Solitaire，学名：Pezophaps solitaria），是鸽形目鸠鸽科罗岛渡渡鸟属的鸟类。与渡渡鸟同属Raphinae亚科。曾广泛存在于印度洋的罗德里格斯岛上，体形巨大，外观似天鹅，不会飞行。雄鸟可达30至35英寸高，重62磅；雌鸟较小，高25至28英寸，重37磅。这种鸟在18世纪晚期因人类狩猎和外来物种的威胁而灭绝。","appearance":"罗德里格斯渡渡鸟拥有灰色和棕色的羽毛，雌鸟颜色更淡。其喙略带钩状，颈和腿较长。头部有一黑色条纹，两性皆有巨大的腕骨结节，用于争斗。雄鸟体型庞大，高达30至35英寸，体重62磅；雌鸟较小，高25至28英寸，重37磅。这种鸟具有显著的性别二型性，雄鸟明显大于雌鸟。","habits":"生活在罗德里格斯岛的森林地带，以果实和种子为食，利用胃石帮助消化。它们具有强烈的领地意识，会用翅膀上的结节进行战斗。这种鸟不会飞，但在地面行动迅速。","breeding":"每年仅产一卵，孵化周期约为七周，双亲轮流孵化。幼鸟在数月内无法独立生存，需父母照料。","identification":"与渡渡鸟相比，罗德里格斯渡渡鸟更高瘦，喙和颅顶更平，眼眶更大，颈腿比例更长，且拥有独特的腕骨结节。","protection":"IUCN：EX (已灭绝)","distribution":"仅限于印度洋的罗德里格斯岛，位于毛里求斯东侧。"},{"name":"齿嘴鸠","english_name":"Tooth-billed Pigeon","scientific_name":"Didunculus strigirostris","overview":"齿嘴鸠（英文名：Tooth-billed Pigeon，学名：Didunculus strigirostris），是鸽形目鸠鸽科齿嘴鸠属的鸟类。该属唯一现存物种，体型中等，约31厘米长，仅分布于太平洋萨摩亚的Savaii和Upolu两岛的原始雨林，是萨摩亚的国鸟。因其稀少，被昵称为‘萨摩亚渡渡鸟’，且在2008/2011系列的20 tālā纸币和50 sene硬币上均有其形象。据估计，全球仅存数百只。","appearance":"齿嘴鸠身长约31至38厘米，体重约400克，体型健硕，尾部较短，最显著特征为其独特的喙：粗壮弯曲，基部红色，两侧各有两槽和三个突起，喙呈黄色，根部红色；头部、颈部、胸部和肩部呈黑绿色光泽，背部和翅膀为赤褐色；眼周、腿和脚均为红色。雌鸟相似，但颈部光泽较少。幼鸟喙色暗淡，羽毛边缘深色，外观重叠鳞片状，头部至胸部缺乏绿色光泽。","call":"齿嘴鸠的鸣叫极为罕见，由雄鸟在高树顶发出，为悠长的‘oooo’声，音调时升时降，持续约1.5秒，重复多达87次，间隔6至10秒，每声鸣叫伴有短暂的鞠躬动作。雌鸟声音类似但音调更高。","habits":"齿嘴鸠栖息于原生森林和次生森林，偏好中海拔森林，高度从300米至1600米，不适应云雾林或异种树种植区。飞行强烈有力，地面起飞时翅膀拍击声大，随后长滑翔。以Dysoxylum spp.的果实为主食，尤其是野桃花心木，利用其强健的喙锯开果壳，去除果肉；亦食用多种其他水果，如Rhus和Myristica。有时在森林中层觅食，偶尔在地面谨慎觅食。通常独行或小群体活动，过去曾记录到10至20只的群集。","breeding":"繁殖活动时间跨度从3月至11月，主要集中于4月至9月。巢穴藏于茂密枝叶中，离地5至12米，有报道在Ficus树上发现巢穴高达25米。据报每窝产卵2枚，但具体繁殖细节未知。","identification":"与其他鸽子相比，齿嘴鸠的喙独特，呈锯齿状，颜色鲜明，且体型较大。幼鸟与成鸟区别在于喙色和头部光泽差异。","protection":"IUCN：CR（极危）","distribution":"齿嘴鸠仅分布于萨摩亚的Savaii和Upolu两个岛屿，主要在中海拔的原始雨林。","other":"齿嘴鸠自19世纪以来遭受栖息地破坏和狩猎威胁，加之自然灾害影响，数量急剧下降。目前面临的主要威胁包括栖息地丧失、猎杀、外来物种（如鼠、猪、猫）的捕食，以及极端天气事件。保护措施包括森林保护与恢复、禁止狩猎、控制捕食者，以及针对关键食物来源Dysoxylum的分布研究。"},{"name":"小褐果鸠","english_name":"White-eared Brown Dove","scientific_name":"Phapitreron leucotis","overview":"小褐果鸠（英文名：White-eared Brown Dove，学名：Phapitreron leucotis），是鸽形目鸠鸽科褐果鸠属的鸟类。此物种主要分布在菲律宾，避开巴拉望群岛，常见于低地至较低山地的森林地带。成年个体具有独特的黑色眼线下纹，从喙基延伸至颈背，随后是一条白色纹路。头部灰或粉红色，颈部和背部有蓝绿色光泽，腹面淡粉色，尾部末端呈白色。性别相似，幼鸟颜色更浅，翼羽边缘锈色。","appearance":"体长23-24厘米，体重82-158克。头部灰色渐变为酒红棕色，其余羽毛棕色，下方较淡，喉部锈色，颈背具青铜绿和紫色光泽，中央尾羽深紫棕色，端部灰暗，外侧尾羽有淡色尖端和暗紫褐色次终端带，下尾覆羽淡灰色。面部有黑色纹线，下方一条白色纹线从喙基经过眼下方延伸至颈背，裸露皮肤蓝绿色，脚或腿粉红或红色，喙黑色。两性相似，幼鸟更淡更红，翼羽边缘锈色，颈部光泽和面部标记不如成鸟明显。","call":"鸣唱为一系列加速上升的“wup”音符，开始时断断续续，之后逐渐加快，音调上升，最终逐渐减弱。","habits":"栖息于茂密的森林、开阔林地及耕作区边缘，海拔高度可达1500米。偏好450至1125米之间的高度（在吕宋岛的伊萨罗格山）。在次生林、山地森林和农田边缘活动，主要在约1600米以下，但记录到在内格罗斯的坎拉翁山高达2300米。","breeding":"繁殖季节主要为3月至6月，但也有2月和10月发现生殖腺增大的记录。巢由小枝条和卷曲的藤蔓组成，位于小树的水平分叉处，高1至6米（偶尔可能高达12米）的地面以上，通常在靠近溪流的茂密植被中，每次产两个光洁的白色卵。","identification":"与大褐果鸠区别在于后者颈部背面有蓝色光泽，尾根下方白色，而小褐果鸠的这些特征较为淡色。幼鸟在色彩和光泽上与成鸟有差异。","protection":"IUCN：LC（无危）","distribution":"分布在菲律宾北部（吕宋、波利洛、阿拉巴特、卡坦杜安内斯、卢邦、韦尔德、民都洛和马林杜克）和中部东部（塔布拉斯、西布延、蒂奥、马斯巴特、班乃、卡拉尼亚安、吉马拉斯、内格罗斯和宿务）。","other":"在多个岛屿上仍然被认为是常见或非常常见的物种，适应性较强，能在一定程度上适应人类改造的环境。"},{"name":"大褐果鸠","english_name":"Amethyst Brown Dove","scientific_name":"Phapitreron amethystinus","overview":"大褐果鸠（英文名：Amethyst Brown Dove，学名：Phapitreron amethystinus），是鸽形目鸠鸽科褐果鸠属的鸟类。特征在于上部呈棕色，头部、胸部和腹部灰褐色，尾部末端淡灰色，眼下方有淡色条纹，面部皮肤粉红。分布于菲律宾的多个岛屿，包括吕宋、波利略群岛、卡坦端内斯、萨马、保和和棉兰老岛。物种较为罕见。","appearance":"中等体型的鸽子，体长26-27厘米，体重81.8-178克。上体和头部棕色，胸腹部灰褐色，腹部带有鳞状图案，尾羽下覆羽淡黄色。颈后部有紫色光泽，下尾基部浅色。成年个体的腿和脚为深粉色，喙黑色。幼鸟颜色较淡，颈部光泽减少，翼覆羽边缘红棕色，面部标记不如成鸟明显。","call":"发出深沉的‘hoop’声，单个或连续两三个，有时也会发出低沉的咆哮声。","habits":"栖息于丘陵和山地森林中，常出现在潮湿的森林和茂密的次生林内，海拔高度从500米至2500米，偶尔低至200米。通常单独或成对出现，有时会在果实丰富的树上聚集小群。以果实和种子为食。","breeding":"繁殖季节在2月至7月间，雄鸟在求偶时会展示胸部羽毛和扇形尾羽。","identification":"与小褐果鸠相似，但颈后部有紫罗兰色光泽，尾羽下覆羽颜色更浅，下颌部呈淡黄色。与P. maculipectus的区别在于下体颜色更深，胸部无斑点，平均体型较小。","protection":"IUCN：NT（近危）。物种因持续的森林破坏和栖息地退化而数量下降。","distribution":"分布于菲律宾除巴拉望群岛和苏禄群岛之外的地区，包括吕宋、波利略群岛、卡坦端内斯、萨马、保和和棉兰老岛。","other":"在系统分类史上，曾被认为与大褐果鸠同种，但最近的研究将其视为独立物种。"},{"name":"棕耳褐果鸠","english_name":"Tawitawi Brown Dove","scientific_name":"Phapitreron cinereiceps","overview":"棕耳褐果鸠（英文名：Tawitawi Brown Dove，学名：Phapitreron cinereiceps），是鸽形目鸠鸽科褐果鸠属的鸟类。以其橙桃色胸部著称。特有于菲律宾苏禄群岛的Tawi-Tawi岛和Sanga-Sanga岛的森林，曾被认为与棉兰老岛褐果鸠同种，统称为棉岛褐果鸠。由于森林破坏威胁，其生存状态曾在2007年从极危降至濒危。","appearance":"体型中等，上身深褐色，头部灰色，颈部背面有紫色光泽，喉咙至腹部红褐色，尾巴底部白色，尾尖浅灰色。眼睛亮黄色至橙红色，嘴黑色，腿脚脏紫色。两性相似，幼鸟未知。与多数同属物种的区别在于缺乏白色耳纹，下体带有更多紫红色调。","call":"广告鸣声类似于，但更长更慢，深沉而回响，加速至尾声，像乒乓球落在桌面上的声音。","habits":"栖息于低地森林，包括海滨红树林，常见于森林边缘和次生林，而非原始森林。在重度砍伐的森林中也很常见，显示了对生境退化有相当的容忍度。食物以多种果实和种子为主，已知胃中含有榕树果实。","identification":"与棉岛褐果鸠相比，头顶灰而不是棕色，腹部锈色而非酒红色，下尾覆羽灰色而非淡黄色，背部更偏橄榄色。与和区别明显。","protection":"IUCN：EN（濒危）。仅限于Tawi-Tawi岛和Sanga-Sanga岛，后者几乎已经灭绝。由于森林砍伐和无节制的狩猎，过去十年中种群数量急剧下降，预计将持续。","distribution":"分布在菲律宾南部的苏禄群岛，具体为Tawi-Tawi岛，Sanga-Sanga岛上可能已灭绝。","other":"自2004年至2007年，栖息地丧失率显著降低，因此其IUCN状态从极危降级为濒危。"},{"name":"棕头绿鸠","english_name":"Cinnamon-headed Green Pigeon","scientific_name":"Treron fulvicollis","overview":"棕头绿鸠（英文名：Cinnamon-headed Green Pigeon，学名：Treron fulvicollis），是鸽形目鸠鸽科绿鸠属的鸟类。雄鸟头部和颈部呈锈紫色栗色，雌鸟头部和前额至胸部为暗橄榄绿色。该物种主要分布于马来半岛、苏门答腊岛、婆罗洲等地的沿海森林、红树林和潮湿地带，偶尔可见于开阔的灌木丛。数量较为稀少，且性格羞怯，不易观察。","appearance":"雄性棕头绿鸠的头部和颈部为粉橙色，胸部变为暗绿色，肩部和小翼羽为深红色，腹部为暗淡的黄绿色至灰色，两胁带绿色。胫部羽毛为淡黄色，翼羽为黑色，边缘鲜黄，次级飞羽、臀部和中央尾羽为橄榄绿色，外侧尾羽为灰绿色，带有黑色亚端斑和淡灰色末端斑。雌鸟相似，但上体为暗橄榄绿色，胸部黄色，额头和头顶灰色，下尾羽白色或奶油色，有绿色标记。幼鸟外观与雌鸟相似。","call":"发出一系列持续约5至6秒的变调哨音，由14至16个较短或较长、音高相对稳定的悦耳音符组成。","habits":"生活在海岸森林、红树林、沼泽森林及相邻的灌木丛，海拔高度可达200米。以果实为主食，通常在小型树木上觅食。","breeding":"在苏门答腊，繁殖季节为2月至4月，筑巢于灌木或小树中，使用活枝条搭建典型的鸽子巢，巢有时几乎完全隐藏在离地面约5米高的枯死蕨类植物茎干中。一对成鸟共同承担筑巢任务，每次产下2枚白色卵。","identification":"雄性棕头绿鸠的头部颜色独特，而雌鸟则需通过红白相间的喙、深色眼睛和广泛苍白的翼羽边缘来识别。与同类相比，其特征明显。","protection":"IUCN：VU（易危）","distribution":"主要分布于马来半岛、苏门答腊岛和婆罗洲。在泰国南部近期记录较少，可能一直是罕见居民。在加里曼丹中部和南部比大巽他群岛其他地方更常见。","other":"绿鸠在秋冬季会垂直迁移至低海拔山区，此时更容易被观察到。"},{"name":"小绿鸠","english_name":"Little Green Pigeon","scientific_name":"Treron olax","overview":"小绿鸠（英文名：Little Green Pigeon，学名：Treron olax），是鸽形目鸠鸽科绿鸠属的鸟类。是最小型的绿鸠，主要分布在文莱、印度尼西亚、马来西亚、新加坡和泰国的亚热带或热带潮湿低地森林。雄鸟拥有蓝灰色头颈，橙色胸部，紫红背部，绿色腹部的独特外观；雌鸟则为橄榄绿色上方，黄绿色下方，灰额头和冠，与雄鸟形成鲜明对比。","appearance":"小绿鸠体长约21-22厘米，体重约77克，体态丰满紧凑，尾部较短。雄鸟头部、上半颈部和颈背呈深蓝灰色，前额和下巴变浅至淡蓝灰色；胸部为深橙金色，向下渐变为黄绿色至腹部；两胁灰色；胫部羽毛栗色和灰色；长尾下覆羽暗栗色；肩部和较小的内侧翼覆羽深紫红色；其余翅膀黑色，有窄边的淡黄色边缘至大覆羽和次级飞羽；下翼、臀部和尾上覆羽灰色；尾羽灰黑，有窄边的淡灰色末端带（中央一对微弱）。眼周皮肤淡蓝色或蓝绿色；喙白色，淡绿色或黄绿色，基部和蜡膜淡蓝或蓝绿色；脚红色或紫红色。雌鸟缺乏紫色、橙色或栗色羽毛，上部暗橄榄绿，下部黄绿色，额头和冠灰色，腹下部淡色和深绿色，下尾覆羽淡色。幼鸟类似雌鸟，但雄鸟幼鸟的内侧翼覆羽和肩部有栗色边缘。","call":"小绿鸠的鸣声为一系列节奏感强、音调较高的悦耳滑音哨声，完整的歌声持续大约5-6秒。典型的模式由三个滑音哨声开始，接着是一些低沉的呻吟音符，最后以三个滑音哨声结束。","habits":"小绿鸠主要栖息于森林、公园、花园和次生林，最高可达海拔1400米，可能在低地和山麓森林最为常见。它们夜间迁徙，曾在马来西亚弗雷泽山的观测点记录到其迁徙行为，迁徙记录发生在四月至五月、八月至九月和十一月的1960年代晚期。它们主要以果实为食，已知食用野生无花果，但饮食细节尚未详尽。通常以至多8只的小群体出现，从林中层到树冠处觅食。","breeding":"关于小绿鸠的繁殖信息有限，记录显示在二月于南婆罗洲、四月和六月在苏门答腊、六月在婆罗洲有繁殖活动。它们建造由活枝构成的脆弱巢穴，与该属其他物种相似，雄鸟为主要筑巢者。通常产2枚白色蛋。","identification":"小绿鸠通过其独特的大小、蓝灰色头冠和对比明显的黄绿色胸部，与其它绿鸠种类区分开来。雌鸟的橄榄绿色和黄绿色，灰额头和冠，也是辨别特征。","protection":"IUCN：LC（无危）","distribution":"小绿鸠分布于马来半岛、苏门答腊（包括Riau群岛、邦加岛和勿里洞岛）、婆罗洲（包括纳土纳岛）和爪哇西部。"},{"name":"红颈绿鸠","english_name":"Pink-necked Green Pigeon","scientific_name":"Treron vernans","overview":"红颈绿鸠（英文名：Pink-necked Green Pigeon，学名：Treron vernans），是鸽形目鸠鸽科绿鸠属的鸟类。又名: 粉颈绿鸠，常见的东南亚鸟类，分布于缅甸南部至菲律宾及印尼的广大区域。雄鸟以独特的粉紫颈部和橙色胸部著称，雌鸟则呈现较为平淡的绿色调。广泛适应森林、边缘地带及人类改造环境。","appearance":"红颈绿鸠体长25至30厘米，重约105至160克。雄鸟头部灰色，颈部粉紫色，上胸橙色，背部橄榄绿，翅膀黑绿相间，翼上有黄色条纹，腹部黄绿色，两翼灰绿，尾巴末端有黑色带纹。雌鸟体型较小，颜色较淡，腹部和喉部呈黄色，冠部和颈背绿色。幼鸟与雌鸟相似，但上体更显灰色。","call":"通常不特别鸣叫，但在发现食物或于群居栖息地时，会发出低沉的三音节哨声，有时伴随类似咕咕的叫声。","habits":"红颈绿鸠栖息于各种森林环境，包括原始森林边缘、次生林和沿海红树林。常见于低地，偶尔可达山脚。适应性强，能在花园、种植园和农田等人类活动区域生存。以果食为主，尤其偏好无花果。","breeding":"繁殖期不固定，全年皆有可能，巢由雄鸟收集材料，雌鸟搭建，位于树、灌木或篱笆中，距地面1至10米。每窝产两枚白色蛋，孵化期和育雏细节尚不明晰。","identification":"与橙胸绿鸠等近似种相比，红颈绿鸠的颈部颜色更为粉紫，雄鸟的胸部橙色更加鲜明。","protection":"IUCN：LC（无危）","distribution":"分布于东南亚，从缅甸南部、泰国、柬埔寨、越南，穿过马来半岛至印尼各大岛屿，包括苏拉威西、小巽他群岛西部和中部，以及菲律宾和印尼摩鹿加群岛北部。","other":"已成功适应城市环境，在新加坡等地公园和大花园中常见。"},{"name":"橙胸绿鸠","english_name":"Orange-breasted Green Pigeon","scientific_name":"Treron bicinctus","overview":"橙胸绿鸠（英文名：Orange-breasted Green Pigeon，学名：Treron bicinctus），是鸽形目鸠鸽科绿鸠属的鸟类。体型粗壮的森林型绿鸠，雄鸟具亮橙色胸羽，上胸带粉红色，颈背呈粉蓝色；雌鸟几乎通体绿色，颈背灰蓝色斑块较雄鸟淡。该种常与红颈绿鸠混群活动，分布于印度次大陆、斯里兰卡、海南、爪哇及巴厘岛等地。","appearance":"体长约29厘米，体重155–194克。雄鸟：头顶至枕部及颈背呈粉蓝色；额、面及喉部黄绿色；上胸中央乳白至淡粉红色，向下渐变为亮橙色，形成明显的橙胸；腹部淡黄绿色；尾羽黑色，外侧尾羽具宽阔淡灰色次端带。雌鸟：通体绿色，颈背及后颈淡灰蓝色，尾羽斑纹与雄鸟相似。喙较粗厚，略大于红颈绿鸠。","call":"鸣唱独特而略显怪诞：先发出一长而逐渐升高的哨音，紧接着是一连串带鼻音的咕噜咕噜颤音，全程约5–6秒。","habits":"主要栖息于森林、次生林及人工林，亦见于沿海红树林及低地，在喜马拉雅山麓可达海拔1500米。为留鸟，但会因食物丰歉作季节性局部移动。常成群觅食，尤其喜在结果树上与红颈绿鸠等其他鸠鸽共聚；食物以各种果实及浆果为主，如无花果、番石榴、榕树果、肉桂果、马缨丹果及野生棕榈果，偶入果园取食。","breeding":"繁殖期印度为3–9月，高峰期4–6月；斯里兰卡全年均可繁殖，以12月为高峰；爪哇记录仅3月；巴厘岛5月见有依亲幼鸟。巢为细枝搭成的脆弱平台，置于树或灌木2–8米处，常靠近林缘空地、小径等开阔处。每窝产卵2枚，白色；双亲共同筑巢与孵卵，孵化期约12–14天。","identification":"与红颈绿鸠极为相似，但体型稍大，喙更粗壮；雄鸟面及喉部黄绿色，上胸紫粉红色块较小且不延伸至颈部；尾羽斑纹不同，外侧尾羽黑色具宽阔淡灰次端带。雌鸟具灰色颈背及后颈，尾羽斑纹与雄鸟一致。","protection":"IUCN: LC（无危）。全球不濒危，但爪哇亚种数量已下降，被视为稀有，1988年才在爪哇重新发现，现为巴鲁兰国家公园内最常见的绿鸠；巴厘岛亦在1989年首次记录，1995年在西巴厘岛国家公园内尚属常见。","distribution":"繁殖区域：印度次大陆（自北阿坎德向东至阿萨姆的喜马拉雅山麓、果阿以南的西高止山、东高止山及印度东部半岛自中央邦向南）、缅甸、泰国（除中部）、老挝、越南中南部、马来半岛。非繁殖/常驻：斯里兰卡、海南、爪哇、巴厘岛。近期在印度拉贾吉国家公园的观察显示其分布已向西延伸至北阿坎德。","other":"目前认可四个亚种，体型与羽色差异细微，变异呈渐变趋势，其有效性仍需进一步验证。"},{"name":"斯里兰卡绿鸠","english_name":"Sri Lanka Green Pigeon","scientific_name":"Treron pompadora","overview":"斯里兰卡绿鸠（英文名：Sri Lanka Green Pigeon，学名：Treron pompadora），是鸽形目鸠鸽科绿鸠属的鸟类。主要分布在斯里兰卡的森林地带。其最显著的外部特征是黄色的脸部和翅膀上的黄色线条，雄鸟的背部呈现深紫色，而雌鸟则是绿色。","appearance":"该鸟体长约27至28厘米。额头、面部、喉咙为明亮的黄绿色，胸部和腹部颜色较淡，呈柔和的绿色，颈部后方为灰绿色。头部顶部为蓝灰色，肩部、翼盖和较小的翼羽为暗紫色栗色；其余翅膀黑色，中翼覆羽和二级飞羽边缘黄色；臀部和中央尾羽橄榄绿；外侧尾羽深灰色，基部泛橄榄色，有黑色中央带和宽阔的淡灰色末端带；尾下覆羽白色，带有灰绿色标记；眼圈绿色；喙蓝灰色或浅灰色，基部绿色；腿和脚红色或紫红色。雌鸟比雄鸟颜色更偏橄榄绿，与雄鸟的紫色栗色区分开来。幼鸟与成年雌鸟非常相似，但色彩较为暗淡，黄色喉部斑块较小，后冠和肩部颜色更深，三级飞羽更绿色，翼羽边缘更宽大且更圆润，初级飞羽外缘的白色部分更为明显。","call":"斯里兰卡绿鸠发出一系列拉长的哨声，其鸣唱是一种长时间波动的、温和的人类似的口哨声，包含3至4个延长的低音符与7至9个快速凸起的音符交替，最高音位于系列音符中间，以一个强调音符突然结束，持续时间约7至8秒，每秒1至2个音符，每组之间有几秒钟的停顿。","habits":"斯里兰卡绿鸠居住在森林和林地，也出现在有高树的开阔地带和种植园中，海拔范围从低地到山脚，最高可达1000米，尤其在干燥区域较为常见。它们的飞行迅速直接，受惊时可能会做出急剧转弯的动作。以果实为食，偏好无花果和Zizyphus等植物的果实，通常在树上活动，形成小群，多达12只以上，但在丰富食物源或栖息地时会聚集更大的群体。","breeding":"繁殖季节主要在12月至6月。巢穴建在中等大小的树上，高度通常低于4米，较为暴露；雄鸟和雌鸟共同筑巢。每次产两枚白色的卵，孵化期为12至14天，由双方轮流孵化。","identification":"雄性斯里兰卡绿鸠的深紫色背部是与相似物种区分的重要标志。雌鸟的尾下覆羽带有明显的绿色和白色标记，不同于橙胸绿鸠较为平淡的红棕色尾下覆羽，或黄脚绿鸠的红棕色标记。此外，其腿和脚为红色，也是辨识特征之一。与灰额绿鸠相比，斯里兰卡绿鸠的前额为黄色而非白色，雄鸟的尾下覆羽为白色而非奶油棕色，背部颜色更暗，臀部为绿色，以及有显著不同的鸣叫声。","protection":"IUCN：LC（无危）","distribution":"斯里兰卡绿鸠主要分布在斯里兰卡，遍布岛上的低地、山脚至中等海拔（高达1000米）的森林地带。","other":"该物种传统上被认为包含八个或更多的亚种，但最近的研究建议将其重组为六个物种，包括灰头绿鸠、安达曼绿鸠、菲律宾绿鸠、布鲁绿鸠以及灰额绿鸠。"},{"name":"灰额绿鸠","english_name":"Grey-fronted Green Pigeon","scientific_name":"Treron affinis","overview":"灰额绿鸠（英文名：Grey-fronted Green Pigeon，学名：Treron affinis），是鸽形目鸠鸽科绿鸠属的鸟类。以其独特的外观和色彩而著称，雄鸟具有深紫色背羽和灰色蓝色头顶，而雌鸟则呈现橄榄绿色背部和较为局限的灰色头冠。主要分布于印度半岛的低地和山林地带。","appearance":"灰额绿鸠长约27厘米，体态较小，尾巴较短。其特征包括白色的前额，明显的灰色头冠，黄色绿色的眉毛和脸部，淡黄色喉咙，黄绿色臀部和尾巴，以及鲜亮的黄绿色下体。雄鸟拥有非常深的紫红色肩部，绿黑相间的三级飞羽，腹部和大腿处有浓重的暗绿色和黄色条纹，尾下覆羽呈中等的栗色。雌鸟的灰色头冠不如雄鸟明显，上体颜色均匀呈深橄榄色，腹部和大腿有白色和暗绿色条纹，尾下覆羽有绿色的横斑。幼鸟外观类似雌鸟，但整体颜色稍显暗淡，翼覆羽有宽大的圆形浅黄色尖端，腹面为淡黄色，初级飞羽外缘有明显的白色边缘。","call":"灰额绿鸠的鸣唱与众不同，由一段长长的上升音调开始，随后是高音波动的吱吱声和气泡般的声响，类似于老旧收音机的调谐声，独特而不似典型鸽子叫声。","habits":"灰额绿鸠栖息于原始和次生的常绿及湿润落叶林中，海拔高度从海平面至1000米。相较于橙胸绿鸠，它较少出现在沿海地带。主要以各种果实、核果和浆果为食，偶尔也吃白蚁；已知其偏好无花果（Moraceae）和枣树（Rhamnaceae）。有时会在地面寻找野生草莓。通常以12只以上的小群体出现，但在丰富食物源或栖息地时可能形成大群。会访问盐舔。","breeding":"灰额绿鸠在树上搭建枝条巢，每窝产两枚白色蛋。","identification":"雄性灰额绿鸠的紫红色肩部和奶油棕色尾下覆羽，以及比斯里兰卡绿鸠更明亮的棕色背部和绿色臀部，是其显著的辨识特征。此外，其较短的喙、尾巴和跗蹠，以及更长、更圆的翅膀也是识别要点。叫声上也有显著差异。","protection":"IUCN：LC（无危）","distribution":"分布于印度半岛的西部和南部，具体而言，从印度马哈拉施特拉邦北部南至喀拉拉邦，以及东南部的帕尔孔达山脉。","other":"曾被认为与斯里兰卡绿鸠同种，现已确认为独立物种。"},{"name":"灰头绿鸠","english_name":"Ashy-headed Green Pigeon","scientific_name":"Treron phayrei","overview":"灰头绿鸠（英文名：Ashy-headed Green Pigeon，学名：Treron phayrei），是鸽形目鸠鸽科绿鸠属的鸟类。俗名: 灰头山鸠、灰额绿鸠，体型中等的绿鸠。其显著特征是头部的银灰色冠羽，分布于南亚至东南亚，包括印度东北部、孟加拉国、中国南部至中南半岛。该物种在低地森林中较为常见。","appearance":"灰头绿鸠长约27厘米，拥有厚重的喙。成年雄鸟绿色，胸部橙色，肩部暗肉桂色，尾下橙色斑块鲜明。雌鸟整体更绿，无橙色部分。两性均有银色冠羽，黑色翼尖，飞行羽有复杂的黄色标记。雄鸟背部有栗色斑块，下体黄绿色带橙色胸带；雌鸟较小，背部灰绿，下体白绿色带淡黄色大腿，尾下覆羽白色（中央绿色条纹多隐蔽）。","call":"发出较高音调的哨音般的咕咕声，节奏通常是‘wa-whee-wah-woo’。","habits":"偏好低地森林，偶尔出现在山区，高度不超过1000米（喜马拉雅山脉可达1500米）。以多种果实为食，常与同属其他绿鸠混群觅食。在树上觅食，也会落地饮水或摄入盐分。","breeding":"繁殖期为4-8月，可能一年产两窝。巢筑于林间乔木或灌木枝杈上，距地面不超过4米。巢简单，由小枯枝搭建。每窝产2枚白色卵。","identification":"与厚嘴绿鸠的区别在于更明显的灰色冠羽，黄色眼圈不显，喙较细，基部淡色。雄鸟胸部无紫色彩饰，与橙胸绿鸠区别明显。","protection":"IUCN：NT（近危）。中国国家重点保护等级：二级，自1989年生效。中国濒危动物红皮书等级：稀有，自1996年生效。","distribution":"分布于亚洲东南部，中国南部，可能西至印尼。在中国，主要分布于云南等地。","other":"之前曾被视为pompadour绿鸠复合体的一部分，现已独立为一物种。"},{"name":"安达曼绿鸠","english_name":"Andaman Green Pigeon","scientific_name":"Treron chloropterus","overview":"安达曼绿鸠（英文名：Andaman Green Pigeon，学名：Treron chloropterus），是鸽形目鸠鸽科绿鸠属的大型绿鸠。其主要特征是厚实的淡色喙和灰色额头，常见于安达曼群岛和尼科巴群岛的热带森林中。","appearance":"体型较大，羽毛呈暗绿色，喙部较粗，基部颜色深。头部顶部为非常淡的灰色，肩部有一小块暗紫红色斑点，背部呈现亮丽的橄榄黄色或青绿色。翅膀上有宽阔的亮黄色边缘，尾羽基部为深绿色，尾部中央有一条明显的灰色带。雌鸟的肩部和背部颜色更接近深绿色。幼鸟颜色较为暗淡，翼羽尖端呈圆形黄色，次级飞羽边缘明亮黄色，初级飞羽外侧有明显的白色部分。","call":"鸣叫声独特，是一种低沉、鼻音浓厚的哨声。","habits":"常群居，数量可观，栖息于热带雨林和森林边缘，以树冠层的果实和无花果为食。飞行快速直接，翅膀偶尔会做出快速的拍打动作。","breeding":"繁殖期在2月至3月间，通常在大尼科巴岛上的Syzygium samarangense和Macaranga peltata树的亚树冠层中筑巢，巢直径约143毫米，距地面平均6米。每窝产两枚白色卵，大小约为34毫米×27毫米，重量约12.3克，由双亲共同孵化，孵化期大约为18天。","identification":"与同属物种的区别在于肩部的绿色斑块而非紫红色，头部顶部颜色更淡，尾部中央有灰色带，翼部和臀部有更多黄色。雄鸟和雌鸟在肩部颜色上有所差异。","protection":"IUCN：NT（近危）","distribution":"分布于安达曼群岛和尼科巴群岛，包括Coco Island。在南安达曼群岛和中安达曼群岛较为常见，但在尼科巴群岛因猎杀而较少见。","other":"其种群数量未知，可能少于10,000只成熟个体。森林生境虽然广泛但面临人类活动增长带来的农业、放牧、伐木和开发项目的压力，因此物种被认为正在减少。"},{"name":"菲律宾绿鸠","english_name":"Philippine Green Pigeon","scientific_name":"Treron axillaris","overview":"菲律宾绿鸠（英文名：Philippine Green Pigeon，学名：Treron axillaris），是鸽形目鸠鸽科绿鸠属的鸟类。中型鸽子，常见于菲律宾低地和山麓森林树冠层。其显著特征包括绿色的下体、头部和臀部，灰色的冠羽，黄色的翼条和飞羽边缘，白色的腹部以及尾基部下方的白色。具有独特的白色喙，基部呈红色，蓝眼睛。雄鸟拥有紫红色的肩部和背部，而雌鸟则为绿色，与雄鸟明显不同。","appearance":"菲律宾绿鸠体长约28厘米，体重介于108.2至257.1克之间，因亚种而异。雄鸟的额部和冠羽为珍珠灰，颈背至腹部为黄绿色，翼下覆羽白色，翼缘和最长的尾羽有暗灰色的纵纹。上体有宽阔的紫红色带横跨肩部和小翼羽，背部橄榄绿，尾中央的羽毛和中央尾羽为橄榄绿，而外侧尾羽为灰色，有宽黑亚端斑。翅膀的飞羽黑色，内侧次级飞羽和中翼羽、大翼羽有鲜明的黄色边缘形成两道明显的翼条。雌鸟背部无紫红色，整体较深的黄绿色。","call":"发出哀怨的‘咕’声，以及一系列调制的、柔和的哨音，这是绿鸠典型的叫声。","habits":"栖息于原始和次生常绿森林，海拔高度可达约1000米。进行高程移动，主要响应于高山和低地树木的果实期，例如在保和岛，推测仅在较高海拔处筑巢，繁殖后会下降到低地，形成大群。以果实为食，大型群体可能在9月至次年1月聚集在结果树上。","breeding":"在树上建造枝条巢，每次产两枚白色蛋，具体繁殖细节未知。","identification":"雄性菲律宾绿鸠与厚嘴绿鸠区别在于喙较薄，眼周无绿色皮肤。雌鸟与雌性红颈绿鸠相似，但后者翼缘仅有黄色标记。幼鸟与成年雌鸟类似。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾（除巴拉望群岛外）的森林中。","other":"过去曾被认为是Pompadour Green Pigeon复合体的一部分，现已确认为独立物种。"},{"name":"布鲁绿鸠","english_name":"Buru Green Pigeon","scientific_name":"Treron aromaticus","overview":"布鲁绿鸠（英文名：Buru Green Pigeon，学名：Treron aromaticus），是鸽形目鸠鸽科绿鸠属的鸟类。以其鲜亮的绿色羽毛而著称。该物种仅限于印尼摩鹿加群岛中的布鲁岛，具有独特的外观和生态习性。","appearance":"布鲁绿鸠是一种中等体型的绿鸠，约28厘米长，拥有灰色的冠羽和白色前冠。其翅膀和飞羽边缘明亮黄色，胸部和腹部呈黄色，下尾覆羽一般为白色。腿和脚呈红紫色，蜡膜和喙基部颜色深暗而非红色。雄鸟的背部为有限的深紫红色，而雌鸟的背部则与主体颜色一致，为绿色。","call":"目前关于布鲁绿鸠的叫声描述尚未被记录。","habits":"栖息于森林、森林边缘及高至730米的高大次生林中，以单独、成对或小群的形式出现。它们的饮食主要包括榕树（Ficus）和其他树木及灌木的果实。","breeding":"关于布鲁绿鸠的繁殖信息目前未知。","identification":"与相关物种相比，布鲁绿鸠拥有更亮和更黄的绿色区域，次级飞羽的翼覆羽大部分为深灰色，上背有明显的灰色带纹，翼覆羽和次级飞羽的黄色边缘尤为发达。雄鸟的背部颜色更为局限和深沉，雌鸟的背部为绿色，这有助于区分性别。","protection":"IUCN：NT（近危）。估计种群数量超过10,000只，但因栖息地减少和质量下降，以及可能受到的狩猎压力，种群数量可能正在下降。","distribution":"分布于远东地区的印尼布鲁岛（印尼摩鹿加群岛中西部），在繁殖季节和非繁殖季节均在此地活动。","other":"历史上曾被认为与斯里兰卡绿鸠同种，但因其独特的特征和分布而被视为独立物种。"},{"name":"厚嘴绿鸠","english_name":"Thick-billed Green Pigeon","scientific_name":"Treron curvirostra","overview":"厚嘴绿鸠（英文名：Thick-billed Green Pigeon，学名：Treron curvirostra），是鸽形目鸠鸽科绿鸠属的鸟类。俗名: 青咖追，最显著的特征是厚实的淡绿色喙，带有红色基部，以及独特的双色喙和明亮的绿色眼环。分布于印度东北至东南亚，包括东部喜马拉雅山脉至婆罗洲和苏门答腊。在中国大陆，常见于云南、广西等地。","appearance":"体长22.5-31厘米，体重112-186克。头部前额和冠部蓝灰色，面部、喉咙、颈部、腹部、臀部和中央尾羽呈浅绿色，臀部和胸腹部泛金，颈后和腹部泛灰。两胁、胫羽和较短的下尾羽深绿色，边缘广泛白尖形成斑点状效果；长下尾羽淡肉桂色；翼羽黑色或深绿色，具宽黄边形成明显黄条纹；外尾羽基部深灰，尖端浅灰，中央有黑带。雌鸟背部暗橄榄绿，下体比雄鸟浅，下尾羽暗绿带白斑。雏鸟类似雌鸟，但更暗淡、灰色，翼覆羽具黄色边缘。","call":"发出一系列悠长、悦耳、鸽子般的哨声，哨声明显过滑，中间突然频率上下波动。菲律宾的叫声被描述为柔和的‘咕’声。","habits":"栖息于各种森林类型，包括常绿林、混合落叶林和红树林，以及次生林，海拔可达约1500米。以果实为主食，特别喜爱无花果。通常成群10-40只在树上觅食，有时在地面寻找野生草莓和其他地面植物。偶尔也会食用稻谷和小米。","breeding":"繁殖季节从3月底至8月，在印度东北部，高峰在5月；在苏门答腊，1月开始筑巢；在马来西亚，1月、2月底和6月发现有带卵的巢。巢为简单的树枝平台，置于小树或竹子的枝叉处；雌雄共同筑巢；有时多个巢相距几米。产两枚白色卵，孵化期约14天，由双方共同承担。","identification":"与同属其他绿鸠的区别在于其独特的双色喙和明亮的绿色眼环，以及背部颜色（雄鸟为暗栗色，雌鸟为暗橄榄绿色）。","protection":"IUCN：LC（无危）。在中国，国家重点保护等级为二级，自1989年起生效；中国濒危动物红皮书等级为易危，自1996年起生效。被列入联合国《濒危野生动物名录》。","distribution":"分布于东洋界，包括印度东北至东南亚，覆盖孟加拉国、不丹、文莱、柬埔寨、香港、印度、印度尼西亚、老挝、马来西亚、缅甸、尼泊尔、菲律宾、新加坡、泰国、西藏和越南。在中国，主要见于云南、广西等地。","other":"厚嘴绿鸠在某些地区被认为是常见的，特别是在泰国的内陆森林中和苏门答腊及其周边岛屿，但在菲律宾较为罕见。"},{"name":"灰颊绿鸠","english_name":"Grey-cheeked Green Pigeon","scientific_name":"Treron griseicauda","overview":"灰颊绿鸠（英文名：Grey-cheeked Green Pigeon，学名：Treron griseicauda），是鸽形目鸠鸽科绿鸠属的鸟类。体型健硕的绿鸠，其最显著的特点是眼周一圈鲜亮的青绿色，如同戴着一副逗趣的‘护目镜’，搭配着粗厚的白色喙。雄鸟拥有深紫红色的背部和肩部，这一特征在雌鸟身上缺失。两性共有的银灰色前额和头顶是其辨识标志之一。灰颊绿鸠广泛分布于印尼的爪哇岛和苏拉威西岛南部，从低地至山脚的多种林地环境都有它们的身影。","appearance":"雄性灰颊绿鸠具有独特的粉金色颈侧斑块，胸部中央区域保持绿色，而雌鸟则不具备这些特征，但头部和上喉部的灰色延伸至面部。两性的虹膜颜色为绿色或黑褐色，有时顶部带有淡黄色斑点。幼鸟的外观可能与成年雌鸟相似。不同亚种间存在细微差异，如vordermani亚种颈部呈黄色，胸部带有紫色调；wallacei亚种胸部两侧的斑点更偏橙色；而sangirensis亚种则较暗淡，绿色偏黄。","call":"灰颊绿鸠的叫声包括一系列悠长的颤音咕咕声，以及更为均匀的咕咕声和奇特的咯咯声。","habits":"灰颊绿鸠偏好开放地带、森林边缘和散布树木的耕作区，高度范围从低地到山区，最高可达海拔1000米。它们通常成对活动，但在果实丰富的树上会聚集形成大群。尤其喜爱无花果，常与其他鸽类如、鹦鹉和杜鹃雀一起在果树上觅食，主要在树冠层活动。偶尔会在果实丰盛的树上见到上百只的群体。","breeding":"在爪哇和巴厘岛，繁殖期大约在1月至8月之间。它们筑造的巢穴由细枝构成，相当简陋。每窝产下2枚白色蛋。","identification":"雌性灰颊绿鸠与雌性红颈绿鸠和橙胸绿鸠容易混淆，但通过观察其灰色的头顶、眼周的绿色环和鲜亮的黄绿色翼羽衬里可以加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于印尼的爪哇岛和苏拉威西岛，从低地至海拔1000米的山脚区域。在爪哇和巴厘岛较为常见，广泛分布于华莱士区的大部分地区，尽管在桑吉赫岛上相对较少。","other":"在印尼的爪哇，人们常用尼龙线猎捕灰颊绿鸠，这种狩猎方式被称为racik。"},{"name":"松巴绿鸠","english_name":"Sumba Green Pigeon","scientific_name":"Treron teysmannii","appearance":"成鸟约28厘米长，整体呈柔和的灰绿色，头部至喉部、臀部及尾上覆羽变为明亮的黄绿色。雄鸟的下背为紫色栗色，雌鸟则无此特征，全身绿色。外侧中覆羽和大覆羽以及次级飞羽黑色，边缘为亮丽的黄色；初级飞羽灰色带白色窄边；腹部、胫羽和下尾覆羽绿色泛黄；中央尾羽黄绿色，外侧尾羽基部深灰色，中央具模糊暗纹，末端半部灰白。雌鸟翼部标记为黄白色而非亮黄色。幼鸟与成年雌鸟相似。","call":"发出温和的‘woop-woop’声，伴有哼鸣音和微弱上升的哨音。","habits":"栖息于低地原始森林、选择性砍伐后的森林和高大的次生林，海拔可达约800米，偏好封闭树冠的森林环境。以单个或成对出现，有时小群体聚集在结果树上，如Streblus asper和Ficus benjamina。成对保卫其进食领地，防御同种和异种鸟类，如和短尾辉椋鸟。","breeding":"繁殖信息有限，已知在五月有产卵记录，但巢穴和繁殖行为描述尚缺。","identification":"在松巴岛范围内，通过其独特的黄绿色标记和栗色背（雄鸟）易于识别，无其他绿鸠相混淆。","protection":"IUCN：NT（近危）","distribution":"分布于澳新界的印尼松巴岛（小巽他群岛西南部）。"},{"name":"绿鸠","english_name":"Flores Green Pigeon","scientific_name":"Treron floris","overview":"绿鸠（英文名：Flores Green Pigeon，学名：Treron floris），是鸽形目鸠鸽科绿鸠属的鸟类。一种小型绿色鸠鸽，主要分布于印度尼西亚的小巽他群岛，包括龙目岛至Alor等地。其最显著的外部特征是翼部大胆而散乱的淡色斑纹，成鸟喙部多呈淡色，而幼鸟喙部较暗。在多数分布区域内是唯一的Treron属绿色鸠鸽。","appearance":"绿鸠长约28厘米，通体呈现柔和的绿色，腹部和胸部略带黄色调。额部、脸部和头顶为浅灰色，背部隐约可见紫铜色光泽。翅膀的腕缘和最内侧次级飞羽为深灰色，覆羽和次级飞羽灰黑色，边缘泛黄。初级飞羽为灰黑色，胫部羽毛白色。臀部和尾下覆羽白底绿斑，中央尾羽黄绿色，外侧尾羽基部淡灰色，中央具暗灰色条带，末端灰白色。雌鸟与雄鸟相似，但背部缺少紫铜色光泽。幼鸟外观大致与成年雌鸟相似。","call":"鸣唱为一系列柔和的哨音，以\"woo-wo-OW\"结尾，音调逐渐升高。也会发出较为粗哑的喉音。","habits":"绿鸠栖息于低地原始森林、高大的次生林和沿海森林及灌木丛，海拔高度从海平面至1000米不等，偏好干燥的森林环境。通常以5到10只的小群体活动，偶尔会形成20只左右的大群，亦常见单独或成对出现。","breeding":"关于生长繁殖的信息在当前资料中未提及。","identification":"与其他Treron属绿鸠相比，绿鸠翼部具有广泛的淡色标记，且胸部缺乏粉橙色斑块，这是与红颈绿鸠的主要区别。","protection":"IUCN：VU（易危）。全球估计不超过5000只个体。主要威胁是栖息地丧失，但能容忍部分次生栖息地，狩猎压力较低。","distribution":"分布于澳新界，具体而言，从龙目岛至Alor（小巽他群岛西部、中部），包括Lombok、Sumbawa、Flores、Solor、Lembata、Pantar和Alor诸岛屿。","other":"绿鸠主要以果实为食，森林是其生存的关键环境。"},{"name":"帝汶绿鸠","english_name":"Timor Green Pigeon","scientific_name":"Treron psittaceus","overview":"帝汶绿鸠（英文名：Timor Green Pigeon，学名：Treron psittaceus），是鸽形目鸠鸽科绿鸠属的鸟类。其色彩如同绿色芒果，以果实为食，栖息于森林中。在帝汶岛和小巽他群岛东部的Roti、Semau及Atauro等地可见其踪迹。","appearance":"帝汶绿鸠长约31至33厘米，整体呈柔和而略带灰色的绿色，喉咙、臀部和尾上覆羽颜色更为鲜亮。翼下的次级飞羽边缘深灰，中央覆羽、大覆羽和外侧次级飞羽为灰黑色，边缘泛黄；初级飞羽为灰黑色，胫羽白色；腹部和尾下覆羽白色，带有绿色斑点；中央尾羽黄绿色，外侧尾羽基部淡灰色，中央有一暗灰色条纹，末端灰白色；眼周皮肤淡蓝绿色；喙角质色，基部半部分呈暗蓝色；脚为深紫红色。雌鸟较雄鸟颜色更暗淡，翅膀标记黄色更浅。幼鸟与成年雌鸟相似。","call":"帝汶绿鸠发出不规则的咕咕声，常被描述为‘u-wop, u-wop...’，还发出类似咆哮、咕噜和哽咽的叫声，猎人能模仿吸引鸟群。","habits":"栖息于低地的季风森林，偏好有高大树木的原始森林、季风林和次生林，高度可达160米。以果实为主食，曾记录到食用无花果。","breeding":"相关信息缺失。","identification":"帝汶绿鸠全身绿色的羽毛使其容易与帝国鸽和果鸠区分开来。在帝汶岛上是唯一的绿鸠种类。","protection":"IUCN：EN（濒危）。全球估计成熟个体数量为600至2000只，因森林清除和狩猎压力而迅速减少。在印尼西帝汶可能已灭绝，在东帝汶虽然较为常见，但数量正在下降。","distribution":"分布于小巽他群岛的Roti、Semau、帝汶岛和Atauro。在东帝汶的某些地区局部但常见，曾观察到大型群体。","other":"相关信息缺失。"},{"name":"大绿鸠","english_name":"Large Green Pigeon","scientific_name":"Treron capellei","overview":"大绿鸠（英文名：Large Green Pigeon，学名：Treron capellei），是鸽形目鸠鸽科绿鸠属的鸟类。绿鸠属中体型最大的成员，体长35–36厘米，体重411–500克。通体呈浅灰橄榄绿色，雄鸟胸部具暗金色至暗橙黄斑，雌鸟胸部为绿黄色且斑较小。分布于马来半岛、苏门答腊及其附近岛屿、婆罗洲和爪哇的低地及丘陵原始林中，海拔上限约1300米。因大规模森林砍伐导致数量锐减，目前全球估计仅存1.5–3万只。","appearance":"雄鸟整体为浅灰橄榄绿色，下体色最浅，背部及翼覆羽最深；中覆羽、大覆羽及次级飞羽深灰色，初级飞羽黑灰色；中覆羽及内侧大覆羽外缘、内侧次级飞羽外缘呈亮黄色，形成闭翼时显著的亮黄色条纹；胸部呈暗金色或暗橙黄色；外侧尾羽深灰色具浅灰色端带，中央尾羽橄榄绿；胁羽端部浅黄褐色；长形尾下覆羽深栗色；眼周皮肤淡黄至金黄色；喙尖端呈绿白色至淡绿色，基部及蜡膜深绿色；腿脚黄色。雌鸟与雄鸟相似，但胸部为绿黄色，尾下覆羽浅黄褐并带绿灰色调。幼鸟似雌鸟，但雄幼鸟胸部更黄，尾下覆羽呈浅栗色。","call":"发出一连串拉长而低沉、带鼻音的起伏咕咕声，每个音节具独特的鼻音咆哮质感，多为下滑音调。","habits":"主要栖息于原始低地及丘陵森林，也见于林缘斑块，海拔可达1300米。通常成小群活动，记录最多12只；觅食时常见倒挂在细枝末端取食果实。食性为果食性，以无花果（榕属Ficus）为主。","breeding":"暂无繁殖相关信息。","identification":"体型明显大于同属其他绿鸠；胸斑颜色与大小与橙胸绿鸠及粉红颈果鸠不同，后两者体型更小、羽色更鲜亮且体侧具其他鲜艳斑块。雌鸟胸部斑更小更淡，且整体体型远大于其他绿鸠。","protection":"IUCN: VU（易危）。曾因森林砍伐而被列为近危，现已升级。","distribution":"繁殖与非繁殖区域一致：马来半岛经苏门答腊及其附属岛屿（尼亚斯岛、特洛岛、西比路岛、林加群岛）至婆罗洲和爪哇。在中国境内无记录。","other":"曾被归入单型属Butreron，现认为与亚洲绿鸠主支系关系更近，而非针尾或楔尾类群。地理变异轻微，可能呈渐变型，有学者建议视为单型种。"},{"name":"黄脚绿鸠","english_name":"Yellow-footed Green Pigeon","scientific_name":"Treron phoenicopterus","overview":"黄脚绿鸠（英文名：Yellow-footed Green Pigeon，学名：Treron phoenicopterus），是鸽形目鸠鸽科绿鸠属的鸟类。俗名: 普通绿鸠，是广泛分布于印度次大陆和东南亚的常见鸟类。印度马哈拉施特拉邦的州鸟。在不同的地区，有着不同的地方名称，如Marathi中的Haroli或Hariyal，以及Upper Assam的Haitha和Lower Assam的Haitol。该物种以多种Ficus属果实为食，常结群觅食。适应力强，既可见于茂密的森林，也能在城市绿化区中生存，目前其数量正在增加。","appearance":"成年黄脚绿鸠身长约为33厘米，体重介于226至248克之间。头部顶部、颈背和脸颊呈蓝灰色，前额带有黄绿色，喉咙和颈部为鲜亮的芥末黄色，后颈颜色较暗。背部有浅灰色带，将深黄色后颈与黄绿色上体分开。翼肩有淡紫色斑块，初级和次级飞羽为黑色，边缘泛黄。较大的翼覆羽有黄色边缘。尾羽基部泛黄绿色，其余部分为板岩灰色。除胸部外的下体呈淡蓝灰色，混有黄绿色，侧腹羽毛边缘为白色或黄色。胫骨和上跗跖为黄色，尾下覆羽呈紫栗色，尖端宽大且呈黄褐色。尾巴基部一半为黑色，远端为银灰色。眼周皮肤为淡绿色或淡灰色，喙灰白色、淡灰色或淡绿色，基部较暗，腿和脚为鲜艳的黄色或黄橙色。雌鸟类似但颜色稍暗，肩部的淡紫色斑块较小。幼鸟比成鸟更暗淡和苍白，肩部几乎没有或完全没有淡紫色。","call":"黄脚绿鸠的鸣叫声记录不多，其叫声通常为一系列调制柔和的口哨声，有时会发出短暂上升的口哨声，紧接着是一个较长的下降音。","habits":"黄脚绿鸠栖息于丘陵和山脚平原的低海拔常绿阔叶林及灌丛中，偏好榕树等果实丰富的树木，偶尔出现在林缘的耕地。它们单独或成对活动，有时形成5至6只的小群，最多可达10余只。清晨和傍晚常在树顶枝头鸣叫，声音为连续的圆润悦耳、抑扬顿挫的哨音，响亮而音调低沉。它们主要在树上活动，偶尔会下到地面饮水或觅食。食物以榕树果实为主，也食用其他植物果实、玉米、谷粒等农作物种子和嫩芽，以及地面上的砂粒和含盐泥土。","breeding":"繁殖期为3月至8月，可能每年繁殖两次。求偶活动始于3月，雄鸟通过挺胸、低垂双翅、点头和围绕雌鸟走动等动作，同时发出\"咕咕\"的叫声。雌鸟以类似动作回应。巢穴简单，由枯枝搭建，呈浅盘状，位于树上的枝杈处。每窝产卵2枚，极少数情况下产卵1或3枚。孵化期为14天，由雄鸟和雌鸟轮流孵化。","identification":"黄脚绿鸠与其他绿鸠的区别在于其独特的黄色腿部和\"肩带\"般的灰色标记，以及明显的区域变异性，特别是在东南亚和南亚的色彩差异。","protection":"IUCN：LC（无危）","distribution":"分布于东洋界，从印度延伸至东南亚，常见于低海拔的森林地带。在中国，主要分布在云南的西部和西南部，多见于雨林及季雨林中。","other":"在中国，黄脚绿鸠曾因栖息地破坏和过度捕猎而数量减少，但在自然保护区仍有一定数量。其在中国的保护等级为二级，自1989年起生效。"},{"name":"黄腹绿鸠","english_name":"Bruce's Green Pigeon","scientific_name":"Treron waalia","overview":"黄腹绿鸠（英文名：Bruce's Green Pigeon，学名：Treron waalia），是鸽形目鸠鸽科绿鸠属的鸟类。最显著的特征是灰绿色头部、颈部和胸部，橄榄绿色背部和黄色腹部。分布广泛，自非洲西部的塞内加尔和冈比亚东至厄立特里亚，南至乌干达，同时在阿拉伯半岛西南部也有记录。","appearance":"体长28-30厘米，体重251-268克。头、颈和胸呈淡绿灰色；背、翼覆羽和次级飞羽内侧为淡黄橄榄绿色；下胸中央和腹部鲜黄色，两侧灰绿色；胁部和胫羽深绿色，边缘白色；长尾下覆羽栗色或橄榄栗色，端部宽而浅灰色；肩部小翼覆羽大多为淡紫色，形成明显的翼肩斑；主飞羽、次级飞羽外缘和大翼覆羽外侧黑色，前者狭边黄色，后者宽边黄色，形成闭合翅膀上的显著条纹；尾羽暗灰色，常带有绿色光泽，末端宽而浅灰色；喙蓝白色或淡蓝灰色，基部暗紫色；腿和脚黄色或橙色，爪淡色。雌雄相似，但雌鸟略小且颜色较暗。幼鸟起初灰暗，羽毛绒软，翼弯处仅见紫色痕迹。","call":"发出较为刻板但略有变化的叫声，通常以加速的呱呱声开始，随后是一连串悠长悦耳的哨音，结尾为两声类似打嗝的声音，接着是一系列双音节音符与短促的哼声交替，整个叫声持续约8秒。","habits":"栖息于密林山谷、靠近水塘的森林斑块，以及萨赫勒地带的稀树草原和荆棘灌木丛，海拔范围从海平面至2000米。主要以各种无花果属（Moraceae）果实为食，尤其是Ficus platyphylla和苏丹的Ficus sycamorus；也会食用Podocarpus和Zizyphus的果实。主要在树冠层觅食，很少落地，除饮水外。会以50只以上的大型群体聚集在结果的树木上。","breeding":"繁殖季节记录显示，西非为12月至次年9月；北非东部11月至次年5月；东非其余地区为4月至5月；在阿拉伯南部，幼鸟在巢中时间为5月至6月，但7月也有发现鸟蛋的记录。巢为脆弱的枝条平台，建于树或灌木上，常位于浓密树木的顶端细枝，高度2.5至8米；在索科特拉岛上，最常见于枣椰树丛中筑巢。每窝产1-2枚光滑的白色卵。","identification":"与非洲绿鸠相似，但通过其鲜明的黄色腹部容易区分。","protection":"IUCN：LC（无危）；CITES III在加纳。","distribution":"分布于非洲的塞内加尔至冈比亚、东至厄立特里亚、埃塞俄比亚、索马里，阿拉伯半岛西南部、索科特拉岛和乌干达。在阿拉伯半岛，常见于沙特阿拉伯西南部和阿曼西部（Dhofar）。","other":"尽管分布广泛，但据报告在20世纪前半叶更为常见。在冈比亚并不罕见，在加纳、多哥和尼日利亚普遍可见。遭受严重猎杀压力，导致物种变得害羞和胆怯。"},{"name":"马岛绿鸠","english_name":"Madagascar Green Pigeon","scientific_name":"Treron australis","overview":"马岛绿鸠（英文名：Madagascar Green Pigeon，学名：Treron australis），是鸽形目鸠鸽科绿鸠属的鸟类。包括刺林、干落叶林、雨林、村落和灌木丛，通常在低海拔至中海拔区域。在西部马达加斯加的干燥生境中最为常见。","appearance":"成鸟头部、颈部和胸部呈鲜亮的黄绿色，带橄榄色调，侧翼转为灰绿色；腹部和胫羽有暗绿色和黄色斑驳；上身灰绿色；翼肩淡紫罗兰色；次级和初级飞羽黑色；外侧中覆羽和大覆羽边缘淡黄色，形成闭合翼上的黄色条纹；中央尾羽蓝灰色，外侧尾羽具不规则黑褐色中线和宽阔的淡灰色末端带；下尾覆羽栗色，尖端淡黄色；喙淡蓝灰色，基部较深，蜡膜粉红或深红色；眼睛蓝色或蓝白色；腿和脚黄色或橙黄色。两性相似。幼鸟喙较暗，尖端淡色。","call":"发出一系列低沉、柔和的哀鸣声，持续5至10秒，通常在结尾处逐渐减慢，音调变化多样，如‘krrrrr ... tiuuu-kirriouu-tuwhip-kirriu-tuwhip-krrrr-whup-kirriwhip-kirriwhip-ker-whip-kurrr-whup-whup-kurrrrr-pop-whurrrr’，比科摩罗绿鸠更高更急促。","habits":"栖息于多种林地和森林类型，从海岸林到刺林，甚至城市花园，高度从海平面至1150米，但在1000米以上罕见。以水果为食，包括无花果和其他果实，如Ordia、Uapaca、Abrus、Morus和Phyllanthus seyrigii。在树冠层觅食，通常成对或小群体活动，偶尔多达70只。","breeding":"繁殖季节报道在9月至12月间。筑巢由两性共同完成，巢为松散构造的平盘状，由树枝和苔藓构成，位于森林或种植园中的水平树叉上，约13.5米高。通常产白蛋2枚（范围1-3枚），尺寸34-36mm x 24-27.3mm。","identification":"与科摩罗绿鸠的区别在于头部和颈部颜色（绿色vs灰绿色）、下尾覆羽颜色（栗色与宽奶油色边缘vs全栗色）、腿和脚颜色（橙黄色vs紫红色）以及声音（更高更急促）。","protection":"IUCN：LC（无危）","distribution":"主要分布在马达加斯加，包括西北部Nosy Hara群岛的小岛屿；偶尔出现在科摩罗群岛和马约特岛。"},{"name":"科摩罗绿鸠","english_name":"Comoro Green Pigeon","scientific_name":"Treron griveaudi","overview":"科摩罗绿鸠（英文名：Comoro Green Pigeon，学名：Treron griveaudi），是鸽形目鸠鸽科绿鸠属的鸟类。体型中等，主要呈现淡绿色，翅膀黑色，翼上有浅色条纹。飞行快速直接。广泛分布但数量不稳定，与果实丰富程度紧密相关。主要栖息于科摩罗群岛Mohéli岛的湿润森林、次生林和椰子种植园。","appearance":"体长约32厘米，头部、颈部及背部比更偏灰色（淡灰绿色），上背、肩羽、上覆羽和背部强烈带有蓝灰色调。胸部、腹部和尾上覆羽深黄绿色，侧腹灰暗，下巴和喉部黄色较淡；长尾下覆羽栗色，无白色尖端；喙和蜡膜灰色，眼蓝色至深蓝色，外圈红紫到米色，腿和脚红色紫色。","call":"一系列低沉、柔和的哀婉哨音，如'whirr...tiwiorrr...whip...tiwiorrr...whip-por-whip koorr'及其变体，持续5至15秒，也有描述为长拖音的哨声颤音，随后是三个音调更高、更短的哨音，有时这三个音符单独出现，没有前面的颤音。","habits":"栖息于常绿森林的树冠层、次生林和椰子(Cocos nucifera)种植园，海拔高达790米，偶尔降至海平面附近。主要食物为果实。","identification":"与马岛绿鸠相比，头部和颈部更灰，尾下覆羽全为栗色，腿和脚红色紫色而非黄橙色，蜡膜灰色而非红色，声音更低沉、缓慢且不那么悦耳。","protection":"IUCN：EN（濒危）","distribution":"仅限于科摩罗群岛的Mohéli岛，过去可能也在Ngazidja（Grand Comoro）和Ndzuani（Anjouan）存在。","other":"曾被认为是马岛绿鸠的同种异名，现已确认为独立物种。"},{"name":"非洲绿鸠","english_name":"African Green Pigeon","scientific_name":"Treron calvus","overview":"非洲绿鸠（英文名：African Green Pigeon，学名：Treron calvus），是鸽形目鸠鸽科绿鸠属的鸟类。与中国的楔尾绿鸠、针尾绿鸠、厚嘴绿鸠同属。这体型圆胖的绿鸠，翅膀和背部呈绿色，肩部暗红，喙基部红色，喙尖白色。广泛分布于非洲的森林和较浓密的林地，常在结果实的树上集结，尤其是无花果树。其叫声独特，包含嘶鸣、咔哒声、哨音、咯咯声和低吼。","appearance":"成年非洲绿鸠体长25至30厘米，雄鸟体重160至285克，雌鸟130至225克。头部至腹部橄榄绿色，略带黄色；颈后有模糊的灰色斑块，上背有深紫色斑点；次级飞羽和初级飞羽黑色，外缘有明显的淡黄色边缘；大腿羽毛黄色；较长的尾下覆羽栗色，尖端白；中央尾羽蓝灰色，有时微绿；外侧尾羽暗灰，有时微绿，有宽灰终带；尾下黑底灰尖；喙灰色，尖端较浅；喙基和蜡膜红或深粉；腿脚黄色、深黄或橙黄色。雌雄相似，但雌鸟蜡膜较小、颜色较暗，羽毛稍显暗淡。幼鸟似成鸟，但腹部更黄，缺乏翼上的紫色斑点，上体羽毛显得更柔软，边缘黄绿，整体比成鸟灰。","call":"广告叫声独特，非典型鸽子声。起始于柔和的笛音颤音，突然上升又下降，结尾处喉音咕噜，伴有嘎吱、犬吠和低吼，由多达20个音符组成，持续5至15秒，有时一分钟内重复多次。","habits":"栖息于多种森林和灌木丛生的草原环境，包括河岸无花果林、Brachystegia和Combretum灌木林、常绿森林边缘、草原中的树木群落和红树林。主要在低地活动，但也出现在山脚地带，如乌桑巴拉山脉北部的坦桑尼亚。食物以各种果实和浆果为主，特别喜爱无花果和Syzygium，偶尔吃肉片和干血。群体通常3至50只，但在丰富食物源处可达150只以上，如马拉维和赞比亚的无花果树旁。很少单独活动，极少地面觅食。","breeding":"繁殖几乎全年皆有可能，主要在一月到四月/八月期间。巢建在叶茂的树叉上，平台式，由粗枝搭建，宽度13至15厘米，深度3至4厘米，高度2.5至21米。每窝产2枚白色卵，间隔1至2天产出，孵化期13至14天，由双亲共同孵育。雏鸟出生时皮肤粉色，覆盖稀疏的稻草色绒毛，约11至13天离巢，由双亲喂养。","identification":"与黄腹绿鸠的区别在于后者腹部明亮黄色。各亚种间差异主要体现在脚色、尾巴颜色、蜡膜大小等方面。","protection":"IUCN：LC（无危）","distribution":"广泛分布于撒哈拉以南非洲，包括安哥拉、贝宁、博茨瓦纳、布基纳法索、布隆迪等国。","other":"非洲绿鸠在其广泛范围内频繁至局部丰盛，但部分地区因栖息地破坏而数量减少，如冈比亚和圣普岛。"},{"name":"奔巴绿鸠","english_name":"Pemba Green Pigeon","scientific_name":"Treron pembaensis","overview":"奔巴绿鸠（英文名：Pemba Green Pigeon，学名：Treron pembaensis），是鸽形目鸠鸽科绿鸠属的鸟类。体型中等偏大，具有橄榄绿色背部和灰色头部与腹部。主要分布在非洲坦桑尼亚的奔巴岛上，是该岛屿特有种。","appearance":"拥有橄榄绿色的背部，头部和腹部呈现灰绿色调，肩部有暗紫色斑块。上身呈灰橄榄绿色，臀部和上尾覆羽颜色更为鲜艳。喙尖灰色白色，基部和蜡膜呈暗红色；腿脚黄色或橙色。雌鸟可能比雄鸟稍显暗淡，幼鸟羽毛未详述。","call":"鸣声为一系列低沉而狂乱的喷嚏声、哨音和咯咯声，与同类绿鸠的叫声相似。","habits":"主要栖息于原生森林，但也可见于次生林、丁香树种植园和花园中。以水果为食，偏爱槟榔的嫩果和无花果，也会在芒果树和翼豆树上觅食。通常在树冠层小群体活动。","breeding":"繁殖期报道为10月至次年2月，但在其他时间也可能繁殖。巢为由树枝搭建的脆弱平台，常建于树枝末端附近，有时需建2至3个巢才选定最终位置。每次产2枚白色蛋，双亲共同筑巢。巢和蛋常被强风吹毁。","identification":"与非洲绿鸠相似，但体型较小，颜色较暗。通过范围容易区分，因为它是Pemba岛上唯一的绿鸠。","protection":"IUCN：VU（易危）。受限于Pemba岛及其珊瑚礁的树木茂密区域，因栖息地丧失和退化导致种群数量可能正在下降。","distribution":"仅分布于非洲坦桑尼亚的奔巴岛及其周边珊瑚礁，主要在两个剩余的原生森林Ngezi和Msitu Mkuu。"},{"name":"圣多美绿鸠","english_name":"Sao Tome Green Pigeon","scientific_name":"Treron sanctithomae","overview":"圣多美绿鸠（英文名：Sao Tome Green Pigeon，学名：Treron sanctithomae），是鸽形目鸠鸽科绿鸠属的鸟类。体型中等、较为粗壮的绿鸠属鸟类，背部呈绿色，腹部灰色，肩部紫色，喙白色基部红色。快速直接的飞行方式，常见于雨林冠层，次生林及种植园，尤其在中海拔地区最为常见。","appearance":"长约30厘米，头部、颈部和大部分下体暗灰绿色，腹侧和胫羽亮黄和深绿色，翼折处有暗紫斑，初级和次级飞羽黑色，覆羽边缘淡黄色，尾羽灰色带橄榄色调，下尾覆羽栗色尖端奶油色。喙厚重且拱形，性别相似，幼鸟羽毛未详述。","call":"声音记录不多，已知的叫声包括初始加速的咔哒声，随后是拉长的哨音，以两次类似打嗝的声音结束，伴随几声短促的咕哝和一系列的咔哒声。","habits":"主要栖息于原始森林，但也出现在次生林和种植园，高度可达1600米，常见于300米以上。通常定居，偶尔做局部高程移动。以果实为食，常在树冠层12米以上觅食，如香蕉、无花果和Musanga果实。","breeding":"繁殖期从11月底至4/5月，巢为简单的枝条平台，已知一巢位于2.5米高的可可树上，含一枚新鲜蛋，最终窝卵数未知。","identification":"易于识别，因其是圣多美岛上唯一的绿色鸽子，与非洲绿鸠较暗色型的区别在于其厚重且强烈拱形的喙和较小的蜡膜。","protection":"IUCN：EN（濒危），曾因栖息地破坏在罗拉斯岛灭绝，全球数量估计为37,007-109,255只，但正在迅速减少，受到栖息地退化和狩猎压力的影响。","distribution":"仅分布于非洲的圣多美岛（几内亚湾南部岛屿），在岛上森林环境和种植园中均有发现。","other":"受人类狩猎影响显著，尤其是在容易到达的地区几乎消失，与潜在狩猎压力指数负相关。"},{"name":"针尾绿鸠","english_name":"Pin-tailed Green Pigeon","scientific_name":"Treron apicauda","overview":"针尾绿鸠（英文名：Pin-tailed Green Pigeon，学名：Treron apicauda），是鸽形目鸠鸽科绿鸠属的鸟类。中等体型的鸟类，分布于东南亚地区，包括印度北部至东南亚。体重约185至255克，雄鸟体长32至36厘米，雌鸟略小。其最显著的特征是极长且尖锐的中央尾羽，全身泛着亮丽的黄绿色，胸部带有金色或粉金色光泽。","appearance":"针尾绿鸠体色鲜亮，呈黄绿色，腹部颜色较淡，翅膀覆羽和肩羽颜色较深。雄鸟胸部带有金黄色或粉金色，雌鸟色泽较暗淡，胸无明显金色。中央尾羽异常长且尖锐，基部蓝灰色，尖端绿染，其余尾羽蓝灰色带黑根。两性相似，但雄鸟胸部有淡淡的橙色斑点，雌鸟则无。幼鸟与成年雌鸟类似，但中央尾羽更短，翼上有不同的黄色边缘模式。种族lowei具有更亮的绿色臀部，但总体较暗，尾部、喉咙和胸部的绿色更深，没有橙色晕染。","call":"鸣唱为一系列松散发出的丰富、音调均匀的哨声，通常成对出现。叫声包括柔软的ku-koo声，随后是更高音的huu声，重复且速度逐渐加快。偶尔会发出高音的‘doo！’声，之后是两到三个更深沉的咕咕声。","habits":"居住于山地森林和次生林，最高可达约1800米，偶尔在平原的树木区域活动至300米以下。针尾绿鸠为留鸟，在某些地区，会根据食物供应进行局部游荡。在越南中部，旱季时会下降至平原觅食。飞行迅速而直线，产生金属般的嗡嗡声。主要以各种水果和浆果为食，包括大型果实，能整吞食用。会降落至地面访问盐舔。群体觅食，常形成10至30只的小群。","breeding":"繁殖季节主要在4月至6月，但在东南亚可能全年都有繁殖活动。巢为简单的平台型，由细枝搭建，离地面1.5至6米高。每窝产卵2枚白色蛋。巢址常见于竹林、树木或灌木中。双方共同孵化和喂养幼鸟。","identification":"与黄腹针尾绿鸠和白腹针尾绿鸠有密切关联，这三个物种可能构成了非洲和亚洲其他Treron物种之间的过渡。识别关键在于其非常长的尖尾和胸部的橙色斑点（仅雄鸟可见）。种族lowei与指名亚种和laotianus在胸斑、臀部颜色、裸眼区羽毛化程度及部分初级飞羽结构上有所不同。","protection":"IUCN：LC（无危）；在中国被列为国家二级重点保护动物；属于联合国《濒危野生动物名录》之一。","distribution":"分布于东洋界，从印度北部至东南亚。具体包括孟加拉国、不丹、柬埔寨、中国南部、印度、老挝、缅甸、尼泊尔、泰国和越南。在泰国相对少见，尼泊尔低地稀缺，中国南方有分布。","other":"过去曾被归入Sphenurus属，现已确认属于Treron属。"},{"name":"黄腹针尾绿鸠","english_name":"Sumatran Green Pigeon","scientific_name":"Treron oxyurus","overview":"黄腹针尾绿鸠（英文名：Sumatran Green Pigeon，学名：Treron oxyurus），是鸽形目鸠鸽科绿鸠属的鸟类。分布于印尼苏门答腊岛山区和爪哇岛西部。该鸟种为中型绿鸠，具有独特的长楔形尾巴，雄鸟带有淡橙色胸部斑纹，两性皆可见蓝绿色喙部和眼周‘护目镜’。仅在苏门答腊山林和爪哇西部的特定地区发现。","appearance":"黄腹针尾绿鸠体长约30至34厘米，雄鸟体型略大。头部和身体呈深绿色，腹部下方和尾下覆羽呈现亮丽的黄色，尾部暗灰色。雄鸟的胸部带有微弱的橙色晕染，但在某些个体上可能难以察觉。雌鸟色彩较为暗淡，尾下覆羽呈黄褐色并伴有深色条纹。幼鸟类似雌鸟，但边缘和翼尖颜色较浅。该物种的面部有明显的蓝绿色裸露皮肤。","call":"发出一系列高低起伏的高音咕咕声，常带有噎住或抽泣般的特质。","habits":"栖息于苏门答腊和爪哇的山地森林中，海拔高度从350米到1800米不等，爪哇可达3000米。以果实为主食，包括无花果，通常群居活动。偶尔会迁移到低地森林觅食。","breeding":"繁殖信息有限，记录显示繁殖季节可能在1月（苏门答腊）、6月（爪哇）和9月（苏门答腊）。巢由双亲共同建造，一般位于树上，高2.5至6米，通常含有一至两个蛋，双亲轮流孵育。","identification":"与楔尾绿鸠相比，黄腹针尾绿鸠体形更为修长，尾巴更短且尖锐，翅膀颜色较暗，腹部黄色区域更为显著，而后者体型更为粗壮，尾巴较短。","protection":"IUCN：NT（近危）","distribution":"分布在印尼的苏门答腊山区和爪哇岛西部，特别是在巴里桑山脉和爪哇西部山脉。","other":"该物种的种群数量正在因栖息地退化而持续减少，目前在苏门答腊变得稀少，在爪哇极为罕见。"},{"name":"白腹针尾绿鸠","english_name":"Yellow-vented Green Pigeon","scientific_name":"Treron seimundi","overview":"白腹针尾绿鸠（英文名：Yellow-vented Green Pigeon，学名：Treron seimundi），是鸽形目鸠鸽科绿鸠属的鸟类。分布于东南亚的马来西亚、泰国、越南和老挝等地。其自然生境包括热带湿润低地森林、红树林和山地森林。","appearance":"这是一种颜色较深的绿色鸠鸽，翅膀橄榄绿色，翼尖黑色，尾部长而尖锐，形似针尾。两性均具有腹部下方的白色斑块和鲜黄色的肛周羽毛。与之相似的针尾绿鸠虽尾部同样修长，但整体色彩更浅，胸部带有温暖的橙黄色调，翅膀上的黄色更为鲜艳。","call":"它的鸣声是一系列悦耳但杂乱的高音哨鸣，音调响亮且略显高亢。","habits":"主要栖息于山地和丘陵森林，偶尔出现在沿海低地。在森林树冠层较高处觅食，通常数量稀少至罕见。","identification":"与针尾绿鸠相比，白腹针尾绿鸠色彩更深，腹部具白色斑块，肛周鲜黄。","protection":"IUCN：LC（无危）。曾被认为接近受威胁，但由于严重森林砍伐在其有限分布范围内，实际状况可能更严峻。","distribution":"分布于东南亚，包括越南南部和中部，马来西亚（罕见），老挝（在Nam Theun流域似乎规律出现），泰国。"},{"name":"楔尾绿鸠","english_name":"Wedge-tailed Green Pigeon","scientific_name":"Treron sphenurus","overview":"楔尾绿鸠（英文名：Wedge-tailed Green Pigeon，学名：Treron sphenurus），是鸽形目鸠鸽科绿鸠属的鸟类。又名: 绿斑鸠，色彩鲜艳。体长30-33厘米，体重205-214克，头部和颈部为亮丽的淡黄绿色，并带有橙棕色。分布于远东地区的印度北部至中国中部，东南亚，巴厘岛和龙目岛。在中国，主要见于西南部的四川、云南、西藏等省区，是罕见的留鸟。","appearance":"楔尾绿鸠拥有亮黄色的头部、颈部和下体，顶部逐渐变为铜金色，胸部羽毛为鲑鱼粉红色，仅在尖端为金色；两胁和腹面带有淡黄色和深绿色条纹；长长的下尾覆羽为淡黄色栗色；后颈为鲜绿色，上背变为酒红色灰色；内翼覆羽和部分肩羽、背部为深紫红色；其余上体为深绿色或灰绿色；外侧次级飞羽和初级飞羽为黑色，具有窄边的黄色大覆羽、次级飞羽和初级飞羽；尾巴呈钝楔形；中央尾羽与背部同色；外侧尾羽为灰色，带黑色亚端带；下尾为浅灰色；眼周皮肤为浅蓝色；喙基部为浅蓝色，尖端为白蓝或灰色；脚为鲜红或深粉色。雌鸟全身为淡黄绿色，上体为深绿色，缺乏雄鸟的酒红色和金色，下尾覆羽为淡黄色，带深绿色中央条纹。幼鸟似雌鸟但更为暗淡；年轻的雄鸟在完全成熟前会先长出一些酒红色羽毛。","call":"楔尾绿鸠发出一系列流畅上升的呼呼声，随后是一连串含糊的高音调音符，形成其特有的旋律。","habits":"楔尾绿鸠主要栖息于海拔3000米以下的山地阔叶林或混交林中，常单个、成对或成小群活动，尤其在清晨和黄昏较为活跃。它们主要在树冠层活动和觅食，以树木和其他植物的果实与种子为食，偶尔下地取食。叫声悦耳动听，富有箫笛般的音韵。","breeding":"繁殖期为4月至7月，雄鸟通过点头、挺胸、张翅、展尾和围绕雌鸟跳跃的求偶行为，同时发出\"咕咕\"的叫声，雌鸟以相同的动作和叫声回应。巢建于森林中的高大树上，呈平盘状，结构简单，通常由少量枯枝构成。每窝产卵2枚，白色。孵化期大约为13-14天，雏鸟为晚成性，经过亲鸟约12天的抚育后即可离巢。","identification":"雌鸟和雄性楔尾绿鸠在颜色上有明显差异，雌鸟缺乏雄鸟的橙色胸部斑块和酒红色翅膀斑点。与相似的针尾绿鸠相比，楔尾绿鸠的尾巴更短，末端呈圆形。","protection":"IUCN：LC（无危）；在中国，楔尾绿鸠为国家二级保护动物。","distribution":"分布于北印度至中国中部，东南亚，巴厘岛和龙目岛（小巽他群岛西部）。在中国主要分布于西南部的四川、云南、西藏等地。"},{"name":"红顶绿鸠","english_name":"Taiwan Green Pigeon","scientific_name":"Treron formosae","overview":"红顶绿鸠（英文名：Whistling Green Pigeon，学名：Treron formosae），是鸽形目鸠鸽科绿鸠属的鸟类。俗名: 台湾绿鸠。雄鸟头顶金铜色，上体深绿，胸腹淡黄带绿纹，尾下覆羽长而具黑绿色中纹；雌鸟缺少雄鸟的头顶金铜色及翼弯紫斑。分布于台湾山地与兰屿，以及北菲律宾部分岛屿。","appearance":"雄鸟体长约25–26厘米，体重177–303克，通体深绿，头顶从额至枕呈金铜色，胸腹淡黄，各羽具黑绿中纹；尾方形，尾下覆羽长，几乎达尾端。雌鸟体型略小，无金铜冠羽及翼弯紫斑，头顶暗绿，翼覆羽绿褐色，下体色较暗。幼鸟描述不详，可能胸至腹呈乳白。","call":"雄鸟的广告鸣声为悠长、哀怨而带笛音的“po-aa-poaaoo”，尾音上扬颤抖，似日本尺八，连续重复；雌鸟鸣声略低沉，变化较少。北菲律宾亚种叫声被形容为怪诞拖长的“aaa-oooooohhhhh”，持续1–2秒后接数个短促的“wuufp”音。","habits":"栖息于亚热带常绿阔叶林及其边缘、林缘耕地与村落有树处；台湾主见于低山及中海拔山区至2000 米，兰屿及菲律宾岛屿则多见于低地。留鸟，台湾族群不迁徙；北菲律宾亚种干季时离开繁殖地，雨季返回。性隐蔽，常在树冠层取食。","breeding":"台湾繁殖记录极少，菲律宾亚种繁殖期3–6月，3月中旬成鸟已具繁殖状态。琉球群岛种群4月起繁殖，领域鸣唱始于2月中，巢筑于离地3 m以内之木麻黄等树，通常产2枚卵。","identification":"与琉球绿鸠地理隔离，雄鸟头顶橙褐而非绿色，翼弯斑鲜红紫而非暗褐，尾较短；与体型较大的红翅绿鸠相比，后者腹白，脸胸鲜黄，翼覆羽暗栗。雌鸟与雌Ptilinopus leclancheri易混淆，但后者体型更小，羽色更暗。","protection":"IUCN: NT（近危）。","distribution":"繁殖区：台湾山地及兰屿；北菲律宾巴丹群岛（Itbayat、Batan、Sabtang）、巴布烟群岛（Babuyan Claro、Calayan、Dalupiri）及Camiguin Norte。","other":"种内分化为台湾亚种（formosae）与菲律宾亚种（filipinus）以及琉球亚种（permagnus、medioximus）。"},{"name":"琉球绿鸠","english_name":"Ryukyu Green Pigeon","scientific_name":"Treron permagnus","overview":"琉球绿鸠（英文名：Ryukyu Green Pigeon，学名：Treron permagnus），是鸽形目鸠鸽科绿鸠属的鸟类。日本琉球群岛的特有种，原先被认为是红顶绿鸠的一个亚种，但系统发育证据表明它们是不同的物种，因此被IUCN红色名录、国际鸟盟和国际鸟类学家联盟分别列为独立物种。该物种的自然栖息地为亚热带或热带湿润低地森林、种植园和农村花园。由于栖息地丧失，琉球绿鸠面临威胁。继小笠原杂色林鸽和银斑黑林鸽灭绝后，是目前唯一已知特有于日本的鸠类。","appearance":"琉球绿鸠体长约33至35厘米，是一种体型大、形态均匀且重的绿鸠。成鸟全身呈深绿色，肩部为深红棕色，翅膀黑色带有绿色边缘，次级飞羽略带紫红色调，腹羽黑色带黄边，尾下覆羽长且几乎延伸至尾尖，中央为深黑绿色，边缘为窄黄色。尾巴宽圆，翅膀稍圆。喙蓝灰色，眼深红色，周围有深蓝色眼圈，腿脚为淡粉色。","call":"琉球绿鸠的叫声与台湾绿鸠相似，广告鸣声悠长而哀怨，具笛音质感，结尾上扬并波动，例如“po-aa-poaaoo”或“po-po-pe-puu”，通常连续重复数次。两个亚种的鸣叫声相近，也发出断续的“puppoopupupupu”声。","breeding":"在琉球群岛，繁殖季节从4月开始，2月中旬即有领地叫声，5月初发现鸟巢。已知的巢穴位于离地面高达3米的树木中，如桉树林。一窝通常产卵两枚。","identification":"琉球绿鸠与其近缘种的主要区别在于雄性的头部绿色与橙色冠部的连续过渡、肩部红棕色与次级覆羽的红紫色差异，以及较长的尾巴。两个亚种间的差异细微，如指名亚种的肩部斑块较大且颜色更绿，而medioximus亚种的斑块则较小且偏灰，尾下覆羽的深绿色中心条纹在medioximus中更宽，留下较窄的淡稻草色边缘。","protection":"IUCN：NT（近危）。","distribution":"欧亚：琉球群岛（日本南部）。","other":"现为红顶绿鸠亚种。"},{"name":"黑背果鸠","english_name":"Banded Fruit Dove","scientific_name":"Ptilinopus cinctus","overview":"黑背果鸠（英文名：Banded Fruit Dove，学名：Ptilinopus cinctus），是鸽形目鸠鸽科果鸠属的鸟类。大型果鸠，身长38至44厘米，体重450至570克。头部、颈部和上胸部呈白色，背部和上翼黑色渐变为臀部的灰色，尾部黑色带有宽广的灰色终端条纹，下体灰色，与头部白色明显区隔。分布于巴厘岛及小巽他群岛的季风雨林。","appearance":"成年黑背果鸠体长32至34厘米。头部和颈部黄色或灰白色，逐渐变为纯白色至胸部；上体深绿色至黑色，尾部末端有灰色条纹；尾羽覆羽深灰色；胸部有一条黑色横带；腹部和腹侧灰色至黄绿色；喙灰色至黄橙色；腿紫色至红色。雌鸟相似，但头部和颈部可能有细小的灰色斑点。幼鸟上体暗色羽毛边缘黄色，头部、颈部和胸部的淡色羽毛上有绿灰色斑点。不同亚种在颜色和条纹宽度上有所差异。","call":"广告叫声为一系列深沉的“hoo”音符，在巴厘岛可能类似，而亚种albocinctus发出深沉缓慢的‘hwooa’、‘how-wow’或‘coowoop’声，叫声中间略有上升，常以每三秒一次的频率连续发出。","habits":"栖息于原始和高大的次生森林及林木地带，包括海岸附近的卡苏里纳树林，主要在较高海拔处活动，如龙目岛高达1300米，弗洛雷斯岛1800米，松巴哇岛1700米，帝汶岛1200米。飞行有力、起伏，被惊飞时翅膀拍打声音响亮。食物主要包括从树枝上取食的果实和浆果，常与其他食果鸟一同在丰富食物源附近聚集。","breeding":"繁殖季节报道在龙目岛、松巴哇岛和弗洛雷斯岛为4月至7月，帝汶岛曾于5月初采集到幼鸟。已知的繁殖记录显示，孵化期为21天，离巢期为14天；离巢时，幼鸟约成鸟大小的三分之一，羽毛中仍残留绒毛痕迹；未观察到成鸟喂养离巢雏鸟。","identification":"黑背果鸠与其他果鸠的主要区别在于其特有的黑色胸带和下体颜色，幼鸟和亚种在羽毛细节上有所不同，如lettiensis和ottonis亚种具有更宽、更白的尾端条纹。","protection":"IUCN：LC（无危）","distribution":"分布于巴厘岛和小巽他群岛，包括龙目岛、弗洛雷斯岛、松巴哇岛、帝汶岛等地。","other":"黑背果鸠在当地可能面临一定的狩猎压力，特别是在达马尔岛，但蓝尾皇鸠更受猎人青睐。在Damar和Terbang岛，亚种albocinctus被认为局部丰盛。"},{"name":"黑斑果鸠","english_name":"Black-banded Fruit Dove","scientific_name":"Ptilinopus alligator","overview":"黑斑果鸠（英文名：Black-banded Fruit Dove，学名：Ptilinopus alligator），是鸽形目鸠鸽科果鸠属的鸟类。身长可达38-44厘米，体重450-570克。以其独特的黑白相间外观著称，头部、颈部和上胸部白色，黑色背部和上翼逐渐过渡至灰色臀部，腹部灰色，与白色头部和颈部以黑色宽带区分。","appearance":"成鸟具有黄色偏白的头部和胸部，黑色的胸部宽带，灰色的腹部，深灰色的背部和翅膀，黑色尾巴带有宽阔的灰白色尖端。喙绿黄色，尖端黄色，腿红色。幼鸟较成鸟颜色暗淡，带绿色调，羽毛边缘较淡，喙蓝灰色，约60天开始变为成鸟颜色。","call":"发出一系列低沉的咕咕声，大约每秒一个音符，持续6到9次。","habits":"栖息于阿纳姆陆地砂岩悬崖边缘的季风雨林残余区域。似乎定居，飞行强健有力，呈波浪状。主要以森林中的果实为食，包括无花果、乌木、野生烟草等。单独、成对或小群出现。","breeding":"繁殖期为5月底至7月初和9月，筑巢于灌木或小树上，高度在2.5至4米之间，巢由树枝搭建的开放平台组成。每次产卵一枚。巢中孵化的雏鸟出生时覆盖着稀疏的浅灰色绒毛，30天时已换上完整的幼鸟羽毛，非常活跃；从幼鸟到成鸟的换羽始于约65天，至150天时完成。","identification":"与托雷斯海峡帝王鸽相比，后者几乎全身白色，仅翼端和尾尖黑色。","protection":"IUCN：LC（无危）。该物种分布范围狭窄，栖息地受限，人口数量估计超过1000只，但由于栖息地难以接近，确切数字未知。","distribution":"仅分布于澳大利亚，具体在阿纳姆陆地悬崖的西部边缘，中北领地的Top End中部，澳大利亚中北部。","other":"长期生存可能受铀矿开采和旅游业发展威胁。"},{"name":"红枕果鸠","english_name":"Red-naped Fruit Dove","scientific_name":"Ptilinopus dohertyi","overview":"红枕果鸠（英文名：Red-naped Fruit Dove，学名：Ptilinopus dohertyi），是鸽形目鸠鸽科果鸠属的鸟类。下颈部至胸部为淡粉色，边缘带有淡黄色，最显著的特征是颈背上的大块鲜红色斑块。仅分布于印尼的松巴岛，栖息于低地和山地森林的较高层次。","appearance":"成鸟的头和上颈部为奶油色，下颈部至胸部为淡粉色，边缘带有一圈淡黄白色边框。颈背处有一大片鲜艳的红色斑块，羽毛质地毛茸茸且略显伸长。上体羽毛为深蓝色或蓝紫色，多数边缘镶嵌着深青铜绿色，这是背部和翼内侧覆羽的主要颜色。胸部有一条宽阔的深紫色带，腹部和两胁为灰绿色。尾下覆羽带有绿色和黄色的条纹，中央尾羽和外侧尾羽的外网为深紫色。下翼和尾下为灰黑色。喙灰色，尖端黄色，腿为紫灰色。雄雌相似。幼鸟（以单一雌鸟标本为依据）：成鸟中呈粉白的部位在幼鸟中为绿白色，微带淡橄榄色条纹；上体为暗青铜绿色，羽毛边缘窄黄色；下体在成鸟中为绿色的部位，在幼鸟中为浅绿色，在成鸟中为紫色的部位，在幼鸟中为青铜绿色。","call":"广告叫声为单一的呼噜声，间隔约2至3秒重复。这种呼噜声的长度和音调可能从短暂而有力的“wUw”（约0.3秒）到较长、音量在后半部分增强的呼噜声“uuuuwUUw”（约1.1秒）不等。","habits":"栖息于森林地带，主要在低地和山地的较高层次。已知在海拔500米处被采集过，最低记录至160米，但主要分布在更高海拔区域。","breeding":"观察到8月时有求偶行为。","identification":"红枕果鸠与同属的其他果鸠相比，其独特的红颈斑块和色彩组合是最明显的辨识特征。","protection":"IUCN：VU（易危）","distribution":"红枕果鸠分布于印尼的小巽他群岛西南部的松巴岛。"},{"name":"粉红颈果鸠","english_name":"Pink-headed Fruit Dove","scientific_name":"Ptilinopus porphyreus","overview":"粉红颈果鸠（英文名：Pink-headed Fruit Dove，学名：Ptilinopus porphyreus），是鸽形目鸠鸽科果鸠属的色彩斑斓的小型鸽类。其分布局限于印尼的苏门答腊、爪哇及巴厘岛的山地森林，海拔高度约在1000至2200米之间。","appearance":"雄鸟具有醒目的紫粉色头部、颈部及喉咙，胸中部加深为红色，被白色带状条纹环绕，边缘泛着绿黑色光泽；背部呈绿色，翼羽和外侧次级飞羽带有绿色调的黑褐色；腹部灰白，尾下覆羽黄色；中央尾羽橄榄绿色，外侧尾羽绿黑，末端有灰色横带；喙绿色，脚粉色。雌鸟较雄鸟颜色略淡，头部及胸部粉红较弱，胸带模糊。幼鸟通体绿色，羽毛边缘微黄，随成长逐渐消退。","call":"广告鸣叫为短暂的单声低沉呼噜声，间隔约3.5至5.5秒。有时，单声呼噜后会紧接着一系列快速的气泡状短音，音调稍降。","habits":"偏好高于2000米的高山橡树月桂林和山地杜鹃花林。单独或成对出现，偶尔集结至17只的小群，主要在森林上层觅食，以无花果和小浆果为食。","breeding":"繁殖季节可能从10月至11月，但主要在3月至5月的旱季初期。巢穴结构简单，由树枝搭建，位于地面5至6米高处，每次产卵一枚，偶见三枚。孵化期约为20天，雏鸟离巢需15至16天。","identification":"雄鸟独特的亮粉色头部与黑白相间的胸部条纹，绿色背部，易于识别。雌鸟与幼鸟颜色较为暗淡，需通过颜色深浅和胸部条纹清晰度辨别。","protection":"IUCN：LC（无危）","distribution":"分布于苏门答腊、爪哇和巴厘岛的高山森林，仅限于海拔至少2000米的区域。"},{"name":"黑耳果鸠","english_name":"Flame-breasted Fruit Dove","scientific_name":"Ptilinopus marchei","overview":"黑耳果鸠（英文名：Flame-breasted Fruit Dove，学名：Ptilinopus marchei），是鸽形目鸠鸽科果鸠属的鸟类。大型鸟类。其特征为头部红锈色，胸膛橙红，腹部灰白，背部暗灰，翼部带有独特的红色斑块。仅分布于菲律宾吕宋岛山区，主要栖息于热带湿润森林的高海拔地带。","appearance":"体型较大，长度约34至38厘米，重量介于320至333克之间。额头、头顶、颈背及颊部呈红锈色；耳羽黑色，形成头侧大块黑色斑；颈侧至胸部淡灰色，背部暗灰，翼部内部覆羽由黑色渐变为深绿色；翼上具有一片由次级飞羽构成的鲜红色斑块；胸前有亮红橙色斑，边缘呈深红色；下体淡灰色，尾羽暗绿带淡色尖端；喙红色，尖端黄色；腿深红色。雌雄相似，但雌鸟臀部、尾羽、尾覆羽及翅膀绿色更明显。幼鸟通体暗绿至浅绿色，喉部棕色，缺乏成鸟的红色特征。","call":"发出重复的、单个低沉滑音‘whuUuh....whuUuh...’。","habits":"栖息于海拔450至1500米的低地和山地森林冠层，偶尔在高山苔藓森林被记录到。偏好原始森林，难以在次生林或选择性砍伐地区生存。","breeding":"繁殖资料不详，仅有记录显示繁殖可能发生在12月。","identification":"与栗耳果鸠相比，黑耳果鸠具有橙色而非黄色的胸斑，以及深粉色的头顶。雌雄差异主要在臀部、尾羽、尾覆羽及翅膀的绿色程度。","protection":"IUCN：VU（易危）","distribution":"仅分布于菲律宾吕宋岛北部的山区。","other":"根据菲律宾法律RA9147，猎捕、捕捉或圈养黑耳果鸠均属非法。"},{"name":"梅氏果鸠","english_name":"Cream-breasted Fruit Dove","scientific_name":"Ptilinopus merrilli","overview":"梅氏果鸠（英文名：Cream-breasted Fruit Dove，学名：Ptilinopus merrilli），是鸽形目鸠鸽科果鸠属的鸟类。以灰绿色身体、橘色翅膀和鲜紫色头冠为显著特征，其羽毛色彩与栖息地林地树叶相仿。主要分布于菲律宾北部吕宋岛的热带与亚热带森林。","appearance":"梅氏果鸠体长32至33厘米，体重约263克。全身羽毛深绿色，头部、颈部及胸部偏灰色并带绿晕，喉部白色，上胸的灰色与下胸及腹部的奶油色由一条狭窄的深绿色带分割。两翼绿色，外侧次级飞羽暗绿，边缘泛黄，主翼羽大多为绿黑色。中央次级飞羽上的毛发状羽支形成紫斑，正面观察时呈现鲜艳的红色。尾羽深绿色，下尾覆羽及胫羽绿中带白。尾羽底面浅灰色。喙基部红色，尖端淡黄色，腿脚暗红色。雌雄外观相似，faustinoi亚种具有红褐色冠羽。","call":"其鸣唱为一系列深沉、模糊的咕咕声，每秒大约一音符，音调在300至500赫兹之间，如“rrruuh...rrruuh...rrruuh...”。","habits":"栖息于低地至海拔1300米的原始森林及选择性采伐的森林。以果实为食，具体记录显示曾以Symplocos ahernii小树的果实为食。","breeding":"关于繁殖信息有限。已知一例记录，1997年5月发现的巢穴中含有一枚卵。","identification":"与黑颏果鸠相似，但梅氏果鸠具有一条狭窄的胸部带纹，且腹部为奶油色而非绿色。","protection":"IUCN：NT（近危）。由于栖息地遭受严重森林砍伐和猎捕，导致中等速度的种群下降。在1946年已被列为罕见物种，菲律宾的保护组织认为其处于濒危状态。然而，在Sierra Madre山脉和Patnanungan岛上局部常见。","distribution":"分布于远东地区的吕宋岛（菲律宾北部）。在繁殖季节，主要栖息于吕宋岛的Sierra Madre山脉。","other":"根据菲律宾法律RA 9147，狩猎、捕捉或饲养梅氏果鸠是非法的。"},{"name":"栗耳果鸠","english_name":"Yellow-breasted Fruit Dove","scientific_name":"Ptilinopus occipitalis","overview":"栗耳果鸠（英文名：Yellow-breasted Fruit Dove，学名：Ptilinopus occipitalis），是鸽形目鸠鸽科果鸠属的鸟类。在菲律宾当地被称为balorinay，特征为灰绿色身体，橘色翅膀，头冠鲜紫，与栖息林地的树叶色彩相呼应。主要栖息于热带和亚热带森林，尤其偏好低地和中海拔的原始森林，最高可达1800米。虽然IUCN将其列为无危，但由于栖息地丧失、狩猎和非法野生动物贸易，其数量正在减少。","appearance":"成年栗耳果鸠长约28至33厘米，雄鸟体重204至278克，雌鸟185至254克。面部前方、额头、头顶及胸部两侧呈现淡蓝灰色，略带黄色；脸颊、后头顶和颈背深紫栗色；胸中部为深赭黄色，下方有一片深红色斑块；腹部灰白色；两胁、下腹、肛门区及尾下覆羽绿而微带奶油白；背部暗绿色。雌雄相似。幼鸟缺乏红黄标记，全身绿和灰绿色，下体羽毛边缘黄色。","call":"广告叫声为重复的下滑音咕咕声（持续约0.4-0.5秒，最大音高约400-500Hz），如“wUw...wUw...”，每4-8秒重复一次；上扬音调不如黑颏果鸠明显。也会发出一系列较短、模糊、近乎咆哮的咕咕声，“rrhu...rrhu..rrhu..”，偶尔以较快节奏给出。","habits":"栖息于低地和中海拔的原始森林，最高可达1800米。也会出现在选择性砍伐的森林中。","breeding":"在萨马岛，4月和5月捕捉到的个体具有增大的生殖腺，表明繁殖季节可能在此期间。据估计，2月初孵化的蛋产生了一只幼鸟。在圈养条件下，孵化期为22天，离巢时间为17天。","identification":"与黑耳果鸠相似，但前胸为黄色而非橙色，眼睛前方有淡灰色。两个已知亚种的区别主要基于大小和羽毛颜色的细微差异，但可能更适合视为单一物种。","protection":"IUCN：LC（无危）。尽管在大部分范围内普遍，但在保和岛上罕见，最近才在帕奈岛发现。尽管宿务岛遭受严重森林砍伐，但该物种仍然存在。","distribution":"远东：菲律宾（除巴拉望群岛和苏禄群岛）。","other":"根据菲律宾法律RA 9147，猎杀、捕获或饲养栗耳果鸠均属非法。"},{"name":"费氏果鸠","english_name":"Red-eared Fruit Dove","scientific_name":"Ptilinopus fischeri","overview":"费氏果鸠（英文名：Red-eared Fruit Dove，学名：Ptilinopus fischeri），是鸽形目鸠鸽科果鸠属的鸟类。其最显著的特征是头部淡灰色带有独特的红面具，延伸至颈背形成黑色带状。分布于印尼苏拉威西岛的山区，栖息于海拔1000-3000米的热带湿润山地森林。","appearance":"成鸟头部呈淡灰色，两侧有暗红色斑块，通过黑色带连接至颈背。背部在中央和北部苏拉威西为绿色，南部为灰色。下体主要为浅灰色，尾下覆羽具灰绿与奶油色斑驳。上尾较深绿，外侧尾羽黑绿带宽灰端斑。喙绿色，腿脚紫色。幼鸟色泽较淡，红面具颜色暗淡，缺乏黑色颈带。两性相似。","call":"叫声为短促的'whoOP'声，结尾音量略增。","habits":"通常单独或成对出现，活动于林下层和树冠层。以果实为食，具体饮食细节未知。在近伐木区仍能生存。","breeding":"繁殖季节在北苏拉威西为10月至11月，在中部苏拉威西为2月至3月。巢由交错的细枝搭建，通常位于离地面约1米处，有时高达10米。每次产一枚卵，双亲共同筑巢。","identification":"与R. meridionalis和栗耳果鸠有明显区别，尤其是翼覆羽、次级飞羽、三级飞羽、背部和臀部的颜色差异。","protection":"IUCN：LC（无危）","distribution":"分布于印尼苏拉威西岛的Lompobattang山脉。","other":"曾被认为与R. meridionalis同种，但现在被视为独立物种。"},{"name":"粉头果鸠","english_name":"Jambu Fruit Dove","scientific_name":"Ptilinopus jambu","overview":"粉头果鸠（英文名：Jambu Fruit Dove，学名：Ptilinopus jambu），是鸽形目鸠鸽科果鸠属的鸟类。小型、色彩鲜艳的果鸠。该鸟种主要分布在泰国南部、马来西亚、印尼的加里曼丹、苏门答腊、爪哇等岛，以及新加坡和文莱。其最显著的特征是雄鸟的深红色面部、粉红色胸部斑点以及白色的胸部，雌鸟则呈现暗紫色面部和绿色下体。","appearance":"粉头果鸠长约23-27厘米，体重约42克。雄鸟拥有独特的深红色面部、黑色下巴、绿色背部、白色腹部、粉红色胸部斑点和棕色尾下覆羽。雌鸟面部为暗紫色，下体绿色，尾下覆羽肉桂色。幼鸟外观类似雌鸟，但面部为绿色，雄鸟在39周后换羽成成鸟装。所有个体都具有白色眼环、橙色喙和红色腿脚。","call":"发出一系列低沉的呼叫声，每秒大约一音符，与Treron绿鸽的叫声明显不同。","habits":"栖息于红树林沼泽和低地雨林，高度可达1500米。在印尼，偏好小岛屿，能跨岛飞行。迁徙模式复杂，至少部分迁徙，可能定期在马来半岛与苏门答腊之间迁徙。觅食时，通常单独或成对出现，偶尔会在果实丰富的树上聚集。直接在树上吃果实或地面觅食由猴子和犀鸟掉落的果子。","breeding":"繁殖期发生在11月至2月和7月。雌鸟在树上或灌木中建造典型的鸽子巢，产下1枚白色蛋，双亲共同孵化至少10天。","identification":"雄鸟的红色面部和粉色胸部斑点非常独特，雌鸟和幼鸟较难与雌鸟的黑项果鸠区分，可通过粉头果鸠的明亮白色眼环和橙色喙识别。","protection":"IUCN：NT（近危）","distribution":"分布于马来半岛、苏门答腊（包括尼亚斯岛、Riau群岛、邦加岛和勿里洞岛）、婆罗洲以及可能的西爪哇。","other":"粉头果鸠在当地某些地区被认为是常见的，但在西爪哇极为罕见。"},{"name":"暗颏果鸠","english_name":"Banggai Fruit Dove","scientific_name":"Ptilinopus subgularis","overview":"暗颏果鸠（英文名：Banggai Fruit Dove，学名：Ptilinopus subgularis），是鸽形目鸠鸽科果鸠属的鸟类。主要分布在印尼邦盖群岛，以其独特的灰绿色外观和鲜红的下腹而闻名。其自然栖息地位于亚热带或热带湿润低地森林，但由于栖息地丧失，这一物种正受到威胁。","appearance":"暗颏果鸠体长33至36厘米，重约142克。头部、颈部和大部分下体呈银灰色，后颈略带绿黄色；喉部上方有一小块深栗色斑块；胸部下方有大片淡色斑块，两胁绿色；肛周羽毛和下尾覆羽深栗色；胫部羽毛栗色和灰绿色；上体绿色，初级飞羽颜色更深，偏蓝；尾羽末端有不明显的窄浅色横纹。虹膜橙色、红色或橙棕色，眼周皮肤蓝色；喙鲜黄色；腿和脚红或紫红色。雌鸟与雄鸟相似，但颈部绿色更明显。幼鸟描述尚未公开。R. epius具有更大片的淡色胸斑，较淡的下尾覆羽，喙较小；苏拉果鸠下体呈淡绿色而非灰色，后颈更绿，下体羽毛尖端宽大，呈绿黄色。","call":"鸣唱为一连串约20个“呼噜”音符，节奏快速，每秒约8个“呼噜”声，每个音符持续约0.07秒，整首歌持续约2.7秒。","habits":"主要栖息于原始森林，但也频繁出现在次生林和受干扰区域，从低地到山区都有其踪迹。它们似乎会进入农业与退化森林交错地带，至少在Peleng岛上，记录显示其分布范围从近海平面到至少900米高处。","breeding":"已知会在五月初期在山地森林中以小树枝搭建简单的平台巢，由一只成鸟（性别未知）照料。","identification":"与其他果鸠相比，暗颏果鸠拥有独特的微型深红色下巴、黄色喙基部的红色和淡色的下体，这些特征在其有限的分布范围内独一无二。","protection":"IUCN：NT（近危）","distribution":"分布于印尼的邦盖群岛，具体位于苏拉威西岛东部。","other":"暗颏果鸠曾被认为与R. epius和苏拉果鸠同种，但近期研究发现它们在体型、色彩、叫声上有显著差异，确认了暗颏果鸠的独特性。"},{"name":"奥氏果鸠","english_name":"Oberholser's Fruit Dove","scientific_name":"Ptilinopus gularis","overview":"奥氏果鸠（英文名：Oberholser's Fruit Dove，学名：Ptilinopus gularis），是鸽形目鸠鸽科果鸠属的鸟类。特有于印尼苏拉威西岛。拥有一个独特的鲑鱼色腹部和深红葡萄酒色的尾部基部，头部和大部分下侧呈淡灰色。成鸟具有鲜明的特征，使其在其有限的分布范围内易于识别。","appearance":"奥氏果鸠是一种中等体型的绿色果鸠，尾部相对较长。前额、眼上区和头顶为淡灰蓝灰色，逐渐变为颈背和颈侧的绿调。背部至尾羽上覆羽为深绿色，翼覆羽明亮的绿色，初级飞羽黑蓝色。下体灰绿色，腹部变为较暗的色调。幼鸟色泽较为暗淡，头顶和颈后更偏绿色。喙鲜黄色，腿脚红色至紫红色。","call":"奥氏果鸠的鸣声是一系列断续的‘呼呼’音符，长度可变，通常表现为‘呼呼-呼呼-呼呼-呼呼-呼呼’的模式。","habits":"奥氏果鸠主要栖息于低海拔的密集原始森林和次生林中，偶尔可见于高达800米的地带。它们以果实为食，尤其是多种无花果种类，偶尔会形成小群体觅食。","breeding":"关于奥氏果鸠的繁殖信息较少，但基于其生态习性，可推测其繁殖行为与其他果鸠类似，包括筑巢、产卵和孵化。","identification":"与幼年的Ptilinopus temminckii相比，奥氏果鸠体型更大，尾巴较长，下体颜色更浅，尾下覆羽深栗色，而前者尾下覆羽大部白色，喙和身体有鳞片状斑纹。","protection":"IUCN：LC（无危）。尽管受到持续的森林砍伐威胁，但由于苏拉威西岛的森林损失相对较小，奥氏果鸠目前被列为无全球灭绝风险。物种在多个保护区中被记录，包括Dumoga-Bone、Lore Lindu和Bogani Nani Wartabone国家公园。","distribution":"奥氏果鸠仅分布于印尼的苏拉威西岛，包括其低地森林和丘陵地带。","other":"系统学历史显示，奥氏果鸠曾被认为与暗颏果鸠和苏拉果鸠同种，但现已确认为独立物种。"},{"name":"苏拉果鸠","english_name":"Sula Fruit Dove","scientific_name":"Ptilinopus mangoliensis","overview":"苏拉果鸠（英文名：Sula Fruit Dove，学名：Ptilinopus mangoliensis），是鸽形目鸠鸽科果鸠属的鸟类。体型较大的果鸠，拥有长尾，主要栖息于印尼苏拉群岛的低地森林中。其独特的外观特征和分布限制使其在同类中显得与众不同。","appearance":"苏拉果鸠体长33至36厘米，主要呈现绿色，具有灰色腹部和深栗色的下尾羽。头部小片暗红喉部斑块，其余部分呈灰色，带有绿色颈圈，颈部和下体为淡绿色，逐渐变为浅胸棕色。幼鸟特征尚未详述，但整体比P. epius和P. subgularis更小。","call":"其鸣唱为一系列柔和而深沉的'wooop'音符，通常连续发出约10次，每秒约3.5次，每次音符持续0.1秒，整首歌曲持续约3秒。","habits":"偏好居住在茂密的原始和次生森林中，偶尔出现在山脚地带，海拔高度可达1100米。以果实为食，常见于森林与农业区的交界地带。","identification":"与黑项果鸠相比，苏拉果鸠体形较小，尾巴较短，颈部有黑色斑块，雄鸟面部呈灰色，雌鸟和幼鸟头部完全绿色，下体主要为绿色，带有黄色橙色的下尾羽。","protection":"IUCN：NT（近危）。全球估计有15,000至30,000只个体，但因栖息地丧失和退化，尤其是Taliabu岛上大部分原始森林被破坏，物种数量可能正在减少。","distribution":"分布于印尼苏拉群岛，包括Mangole和Taliabu岛，位于苏拉威西岛东侧。","other":"曾被认为与R. epius和暗颏果鸠同种，但因其特有的下体颜色、颈圈特征和不同的鸣唱而被认定为独立物种。"},{"name":"黑颏果鸠","english_name":"Black-chinned Fruit Dove","scientific_name":"Ptilinopus leclancheri","overview":"黑颏果鸠（英文名：Black-chinned Fruit Dove，学名：Ptilinopus leclancheri），是鸽形目鸠鸽科果鸠属的中等体型鸟类，体长可达27厘米。雄鸟拥有独特的绿腹、绿翼和灰白色的头颈，雌鸟则全身呈暗苔绿色，嘴喙淡黄色，两者皆具鲜明特色。分布于热带低地森林树冠，常见于台湾和菲律宾的低地森林。","appearance":"雄性黑颏果鸠头部、颈部和上胸部为银灰色，微带绿色，颏部黑色，与灰绿色的腹部由宽黑色胸带隔开，尾下覆羽淡栗色，上体为鲜亮的绿色。雌鸟全身绿色调，额部和喉部灰绿色，下胸有深棕色窄带，羽毛有绿色、淡灰色和肉色斑点。幼鸟似雌鸟，但缺乏胸带，喉部仅有模糊暗斑。","call":"黑颏果鸠的鸣叫声为低沉、嘶哑的单音‘wUw’重复，音节持续约0.4秒，最高音调约为500Hz，传声不远。","habits":"栖息于低地森林及其茂密的次生林中，海拔高度至少可达700米。以果实为主食，具体饮食细节尚不清楚。行为隐秘，难以观察。","breeding":"繁殖期记录显示，黑颏果鸠在4月至6月筑巢，巢位于1.5至4.5米高的灌木或树上，每次产一枚白色蛋。","identification":"雄性黑颏果鸠头部和颈部的灰白色与深色身体形成鲜明对比，雌鸟独特的淡黄色嘴喙，以及两者特有的绿色调外观，使其易于识别。","protection":"IUCN：LC（无危）。尽管分布广泛，但在其范围内大多数岛屿上被认为是不常见的。在菲律宾宿务岛，尽管遭受严重森林砍伐，仍能发现其踪迹。","distribution":"分布于菲律宾和台湾的低地森林。在台湾，虽记录稀少，但确有存在。"},{"name":"红胸果鸠","english_name":"Scarlet-breasted Fruit Dove","scientific_name":"Ptilinopus bernsteinii","overview":"红胸果鸠（英文名：Scarlet-breasted Fruit Dove，学名：Ptilinopus bernsteinii），是鸽形目鸠鸽科果鸠属的鸟类。以其独特的红胸斑块和鲜艳的黄色腹部而著称。该鸟种由Hermann Schlegel在1863年命名，以纪念其收藏者Heinrich Agathon Bernstein。红胸果鸠分布于印尼北部摩鹿加群岛，栖息于低地至山地的森林环境中。","appearance":"红胸果鸠是一种体型较大的果鸠，身长可达28至29厘米，拥有长尾。全身主要呈丰富的绿色，头部为淡黄灰色，向颈部绿色渐变。雄鸟的下胸有一显著的红色斑块，雌鸟则无此特征。腹部为深色的黄金色，翼下覆羽呈金黄色，尾下覆羽为栗色。雌鸟的头部为灰绿相间，无红色胸斑。","call":"红胸果鸠的叫声为间隔重复的双音节，先短后长，音调大致相同，例如‘hu..whuUUuh’。","habits":"栖息于原始森林、邻近的次生林和密集的竹林中，从低地到最高峰均有分布，海拔高度从180米至2150米不等。红胸果鸠通常在树冠层和林下层觅食，以树木和藤蔓的果实为食。","breeding":"繁殖季节记录在3月、7月、8月和9月。巢为典型的鸽子平台式，由树枝构成，高度通常在1至2.5米之间，已知巢址包括蕨类植物叶片、小树和棕榈叶。每窝产一枚白色蛋，由双亲共同孵化。","identification":"红胸果鸠比当地其他果鸠种尾巴更长，雄鸟的红色胸斑是其最明显的辨识特征，而雌鸟可通过其灰绿色头部和缺乏红色胸斑来识别。","protection":"IUCN：LC（无危）","distribution":"红胸果鸠主要分布于印尼北部摩鹿加群岛，包括Obi、Halmahera和Bacan等岛屿。","other":"红胸果鸠在Halmahera岛上较为常见，但在Bacan和Obi的低地则较为罕见。"},{"name":"巨果鸠","english_name":"Wompoo Fruit Dove","scientific_name":"Ptilinopus magnificus","overview":"巨果鸠（英文名：Wompoo Fruit Dove，学名：Ptilinopus magnificus），是鸽形目鸠鸽科果鸠属的鸟类。是新几内亚和澳大利亚东部特有的一种大型果鸠。其特征为颈部至胸部的紫色羽毛，下腹呈黄色，背部及翅膀绿色。分布于新几内亚和澳大利亚东岸的雨林地带。","appearance":"巨果鸠体型大，长度可达45厘米，体重约150-500克。头部及颈部呈灰色到灰绿色，背部与翅膀上覆羽亮绿色带黄边。翅膀中央覆羽形成断续的翼条，喉部有窄紫色条纹，胸部与上腹部深紫色，下腹部、肛区和尾下覆羽主要为金黄色。尾巴长，下尾羽淡灰色，翼内侧橙黄色，具一些栗色于大覆羽。初级飞羽内侧绿色，外侧灰绿至栗色基部。喙橙红色尖端黄色，腿黄绿色。性别相似，幼鸟相比成鸟颜色较暗淡。","call":"发出低沉粗哑的\"wollack-a-woo\"或\"bok-bok-oo\"声，也有较轻的\"wompoo\"叫声，觅食时会发出短促尖锐的\"pack pack\"声音。","habits":"栖息于各种森林类型，包括原始和成熟的次生雨林、画廊森林和季风森林。在新几内亚，海拔高度从近海平面至1400米，常见于低海拔地区。以果实为食，食用多种水果，包括无花果、月桂、棕榈和Annonaceae科等植物。飞行快速但沉重，通常在树冠下层活动。","breeding":"主要繁殖季节为旱季中期至雨季早期，可能全年都有繁殖。巢由枝条和藤蔓构成，直径平均150毫米，位于3.6至7.6米高的水平叉或棕榈叶上。每次产一枚白色蛋，孵化期至少21天，雄鸟白天孵卵，雌鸟夜间。雏鸟孵化期超过13-14天。","identification":"与同属其他物种如玫瑰冠果鸠（Ptinilopus regina）相比，巨果鸠不会利用杂草性外来植被，因此不会从北部新南威尔士州的外来植物如樟脑月桂的增殖中获益。","protection":"IUCN：LC（无危）。在大部分地区广泛分布且数量较多，但最南端的亚种magnifica因栖息地丧失和过度狩猎而严重减少，估计新南威尔士州种群超过7000只。","distribution":"分布于新几内亚和澳大利亚东部，包括新几内亚和部分澳大利亚卫星岛屿。","other":"尽管体型较小，但能吞咽直径约2厘米的球形果实。"},{"name":"粉斑果鸠","english_name":"Pink-spotted Fruit Dove","scientific_name":"Ptilinopus perlatus","overview":"粉斑果鸠（英文名：Pink-spotted Fruit Dove，学名：Ptilinopus perlatus），是鸽形目鸠鸽科果鸠属的鸟类。广泛分布于新几内亚低地和山麓森林及周边岛屿的果鸠，独特的粉斑翅膀和橄榄绿头部是主要识别特征。","appearance":"粉斑果鸠长约25至27厘米，重约245至257克。头部呈黄绿色带橄榄色调，颈背有一条白带，与绿色上部形成鲜明对比，胸部橙棕色，翼上具独特的粉红色斑点。雌雄羽毛相似，幼鸟羽毛特征未详述。上体绿色，部分带有青铜色光泽，次级飞羽和大覆羽深蓝绿色，边缘黄色。尾巴白色，稀疏点缀着灰绿色标记，喙黄色到黄橄榄色或暗绿黄色，腿深红色。","call":"发出缓慢上升的呼呼声或一系列加速后逐渐减弱的较短'woop'音符。","habits":"栖息于森林边缘、受干扰区域、雨林、季风林和画廊森林，主要在低地和丘陵，局部可达1220米。集群在结果的无花果树上觅食，以无花果为主食，偶尔食用安诺树科和月桂科果实。具有游牧特性，数量随果实丰度波动。","breeding":"全年可能繁殖，已知的巢在6月和8月被发现。巢由细枝搭建，高3米左右，通常在细小树木中。每次产一枚白色蛋。","identification":"与丽色果鸠（装饰果鸠）相似，但粉斑果鸠缺乏暗红肩楔，尾尖绿色。亚种emzonurus/em尾端有淡绿色银边；emplumbeicollis/em头部灰色。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚和周边许多小岛。","other":"粉斑果鸠有三个亚种被认可。"},{"name":"丽色果鸠","english_name":"Ornate Fruit Dove","scientific_name":"Ptilinopus ornatus","overview":"丽色果鸠（英文名：Ornate Fruit Dove，学名：Ptilinopus ornatus），是鸽形目鸠鸽科果鸠属的鸟类，以其独特的色彩而著称。分布于新几内亚的山林地区，常见于热带雨林及附近的次生林中。","appearance":"体长约25厘米，体重约163克。头部至颈背橙黄带橄榄色调，颈带蓝灰，上下缘以深赭色渐变为紫棕色上背，下背更亮绿。肩羽金绿，具灰心形成斑点效果。终尾带强烈泛黄。性别相似。幼鸟比成鸟暗淡，紫色肩斑显著减小。","call":"声音缓慢但加速的一系列上升“woop”音符，类似于Pink-spotted Dove，但节奏较慢。","habits":"栖息于原始雨林及附近受扰动区域，海拔范围200-1350米，有时在低地甚至海平面附近出现。以水果为食，常成群觅食，数量可达50只以上，与其它物种共同在果树上觅食。","breeding":"繁殖季节在10月（东新几内亚）和2月（福贾山脉，西新几内亚）。巢由少数枝条构成，置于密林藤蔓中3米高处，也有报告在竹林筑巢。每次产一枚白色卵。","identification":"与Pink-spotted Dove相比，有暗红色肩部楔形斑和黄色尾尖。与粉斑果鸠的区别在于喉部和颈带的灰色范围较小，上胸金色范围更大，胸部青铜色更深，无翼上的粉色斑点，但有紫色肩部斑块。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的阿法克山脉和沃格尔角半岛的海岸之间，以及从西里伯斯山脉到奥尼半岛东侧的新几内亚山区。","other":"与粉斑果鸠生态位分离，但在地理上部分共存。"},{"name":"银肩果鸠","english_name":"Tanna Fruit Dove","scientific_name":"Ptilinopus tannensis","overview":"银肩果鸠（英文名：Tanna Fruit Dove，学名：Ptilinopus tannensis），是鸽形目鸠鸽科果鸠属的鸟类，以深松绿色羽毛、亮黄色斑点和头部黄粉饰为其显著特征。常见于瓦努阿图的热带雨林中，偏好成双或群聚于果实丰富的树木。","appearance":"体型较大，长度约28-30厘米。额头、头顶及脸部为暗绿黄色，逐渐过渡至身体的深绿色；翼部具明亮的黄色斑块；肩部有银白色边缘形成银斑；中央尾羽绿色，带有模糊的银绿色次端带；外侧尾羽为鲜亮的深绿色，银色次端带清晰可见；腹部和尾下覆羽有宽大的黄色尖端；喙蓝灰色，腿呈紫红色。雌鸟缺少肩部银斑，下腹更白而非黄色。幼鸟全身绿色，所有羽毛边缘黄色，呈现鳞片状效果。","call":"最常见叫声为一系列低沉上升的‘woot’声，间隔均匀，遍及其分布范围。","habits":"栖息于原始雨林及大型果树的退化环境，包括开阔的林地、公园、种植园和花园，常见于低地和丘陵，亦见于至少1500米的山区。为响应果实成熟而局部游荡，可能在岛屿间移动。以果实为食，包括大绞杀榕树和桃花心木树的果实，常在树冠觅食，单独、成对或小群体活动，通常藏匿于茂密的枝叶中。","breeding":"繁殖季节可能延长，巢为由细枝编织的脆弱平台，建于水平树叉上，高度位于树梢。产一枚白色蛋，双亲共同孵化和抚育幼鸟。","identification":"比红嘴果鸠大，雌鸟翼部有黄色斑点，是辨识要点。","protection":"IUCN：LC（无危）","distribution":"分布于班克斯群岛至瓦努阿图南部，包括城市区域。"},{"name":"橙额果鸠","english_name":"Orange-fronted Fruit Dove","scientific_name":"Ptilinopus aurantiifrons","overview":"橙额果鸠（英文名：Orange-fronted Fruit Dove，学名：Ptilinopus aurantiifrons），是鸽形目鸠鸽科果鸠属的鸟类。最显著的特征为明亮的橙色前额，灰绿色的身体，橘色的翅膀，以及头冠的鲜紫色。广泛分布于新几内亚（除休恩半岛）及其周边岛屿的低地森林和红树林地带。","appearance":"橙额果鸠体长约22至23厘米，体重约136克。头部特征鲜明，前额为亮橙色或橙黄色，喉部及面下部白色，头顶、颈背及上脸绿带青铜光泽。上胸部蓝灰色，环绕颈部形成带状。腹部淡黄绿色，尾下覆羽奶油白与暗绿色相间。其余羽毛绿带青铜光泽，除了深绿色的一级飞羽和外侧次级飞羽。翼覆羽和上背有蓝灰色基部形成的斑点。尾羽外侧末端灰色，内网白色。喙基部红色，余部黄色至绿黄色，腿脚亮紫红色。雌鸟色泽较暗淡。幼鸟羽毛描述未详。","call":"发出一系列柔和的‘hoo’音符，每一声略带上升的音调，以稳定速率或轻微加速发出。还有一种摇摆声，通常由六个音符组成，第一、三、五音上扬，其余下降。此外，还会发出从单一低音开始的系列声音，随后是音高逐渐降低的响亮序列。","habits":"栖息于次生林、林缘、海岸林木、红树林、画廊林、草原和城镇，常见于无花果树附近，偶尔进入原始雨林。活动范围从海平面至海拔300米。飞行迅速直接。主要以果实为食，偏爱Moraceae、Combretaceae和Arecaceae科植物。经常成群活动，也可见单只或成对觅食。","breeding":"繁殖记录显示，筑巢期可能从旱季中期持续至雨季早期，至少在9月至翌年4月。巢较为坚固，位于2.4至4.6米高的树木或灌木上。曾在一个低矮的Sonneratia caseolaris红树林中发现一个小巢。产一枚白色卵，孵化或育雏的成鸟不会紧贴着卵或雏鸟，当观察者接近至50米范围内时会离开。","identification":"与红顶果鸠相比，橙额果鸠更适应受干扰的栖息地，腹部为绿色而非黄色，且无暗红色带纹。","protection":"IUCN：LC（无危）。物种普遍较为常见，局部地区数量众多。能适应多种次生环境，包括城镇。","distribution":"分布于澳新界的新几内亚（除休恩半岛）及其周边许多卫星岛屿。"},{"name":"金肩果鸠","english_name":"Wallace's Fruit Dove","scientific_name":"Ptilinopus wallacii","overview":"金肩果鸠（英文名：Wallace's Fruit Dove，学名：Ptilinopus wallacii），是鸽形目鸠鸽科果鸠属的鸟类。大型、长尾的果鸠，最显著的特征包括灰蓝色的头部、颈部、胸部和背部，橙色的腹部，以及将腹部与胸部区隔开的白色带纹。该物种主要分布在印尼的摩鹿加群岛南部，小巽他群岛的远东部，阿鲁群岛的西南部，以及新几内亚的沿海西南部。被认为是‘最美丽的’果鸠之一。","appearance":"金肩果鸠体型较大，长度约为24至28厘米，具有长尾。头部的前额和头顶为暗红色，脸部下半部和喉咙为白色。头部其余部分、颈部、胸部和上背为淡蓝灰色。翅膀和下背为绿色，腹部橙色，与胸部之间有一条明显的白色带纹。肩部有金色青铜色斑块，翅膀内侧覆羽为蓝灰色，边缘黄色或青铜绿，形成鳞状外观。主要飞羽和次级飞羽为深绿色光泽，次级飞羽和大覆羽有狭窄的黄色边缘。背部、臀部和上尾覆羽为黄绿色，中央尾羽绿色，末端有淡色带纹，外侧尾羽较暗，末端带有灰白色带纹。喙为黄色或绿黄色，尖端较浅；腿为紫色或粉红色。雌鸟与雄鸟的区别在于橙色腹部斑块颜色较淡，灰色部位略带绿色。幼鸟的头部红色边缘和混合着深绿色，翼部和覆羽的羽毛为亮绿色，尖端黄色，胸部和腹部的灰色和橙色不同程度地带有绿色。","call":"金肩果鸠通常保持沉默，但偶尔会发出低沉的四音符‘hoo’系列叫声。","habits":"金肩果鸠栖息于河流附近的低地森林、海岸边的森林、红树林、森林边缘、邻近的草原和农业地带。它能够适应次生森林环境，这在其出现在人口密集岛屿上的现象中得到体现。它们以小浆果和水果为食，直接从树枝上取食。它们倾向于形成小群体，在寻找结果实的树木时进行迁徙。","breeding":"关于金肩果鸠的繁殖信息非常有限。它们会在树枝间搭建由细枝构成的简陋巢穴。已知的一个巢穴是在十一月被观察到的。","identification":"金肩果鸠与粉顶果鸠相似，但可以通过其明显的白色胸带加以区分。雌雄差异主要体现在橙色腹部斑块的强度和灰色部分的绿色调上。","protection":"IUCN：LC（无危）","distribution":"金肩果鸠分布于印尼的Banda群岛、Kai群岛、塔宁巴尔群岛和其间的小岛（摩鹿加群岛南部）、Babar（小巽他群岛远东部）、阿鲁群岛（位于新几内亚西南部）以及新几内亚的沿海西南部。","other":"金肩果鸠能够适应受扰动的生境，即使在人口密集的岛屿上也能生存，这表明它们有一定的适应能力。"},{"name":"华丽果鸠","english_name":"Superb Fruit Dove","scientific_name":"Ptilinopus superbus","overview":"华丽果鸠（英文名：Superb Fruit Dove，学名：Ptilinopus superbus），是鸽形目鸠鸽科果鸠属的鸟类。雌鸟则主要是绿色，腹部白色，翼尖蓝色，头部后方有小块深蓝斑点。本物种广泛分布于新几内亚、澳大利亚东部、所罗门群岛、菲律宾及印度尼西亚的苏拉威西岛。","appearance":"雄性华丽果鸠具有紫色头冠、橙红色颈背、橄榄绿耳羽、灰色胸部，以及一条宽阔的深蓝色带纹将胸部与腹部区分开。翅膀橄榄绿并布满暗色斑点，尾部带有白色尖端。雌鸟主要为绿色，腹部白色，翼尖蓝色，胸部淡蓝色，头后方有一小片深蓝色斑点。两性均有黄色眼睛和眼环。","call":"叫声通常是一系列平稳的‘咕咕咕咕’声，有时会加速。","habits":"栖息于多种森林环境中，包括红树林、农业林地、次生林和原始森林，海拔高度从海平面至1600米。在澳大利亚，常见于季雨林和中叶藤本森林，偶尔靠近溪流或湖泊。以小型至中型果实为主食，包括无花果、肉桂树果等。","breeding":"繁殖季节在新几内亚从9月至次年1月，澳大利亚则从6月至翌年2月，高峰在11月至12月。巢为简单平台状，由树枝构成，位于离地面5至30米处，雌鸟在此产一枚白色小蛋。","identification":"与粉顶果鸠相比，雄性华丽果鸠有更鲜明的黑色胸带和紫色头冠。雌鸟的区别在于其头部后方的深蓝色斑点较小。","protection":"IUCN：LC（无危）","distribution":"分布在苏拉威西岛至澳大利亚东部，包括俾斯麦群岛和所罗门群岛中东部。在澳大利亚，从新南威尔士南部的莫里亚镇延伸至昆士兰的开普约克半岛。","other":"在新南威尔士州南部边缘的分布范围内，估计数量少于500只，可能甚至不足100只，大多数为迷鸟。"},{"name":"多色果鸠","english_name":"Many-colored Fruit Dove","scientific_name":"Ptilinopus perousii","overview":"多色果鸠（英文名：Many-colored Fruit Dove，学名：Ptilinopus perousii），是鸽形目鸠鸽科果鸠属的鸟类。广泛分布于南太平洋的岛屿，如斐济、萨摩亚群岛和汤加，偏爱栖息在低地的亚热带或热带湿润森林中。其最显著的特征是雄鸟拥有红冠和红色背部条纹，雌鸟则呈现灰绿色，头部和胸部带有灰色调。在斐济和汤加，这种鸟最为常见。","appearance":"多色果鸠体长约23厘米，体重约90克。雄鸟主要为淡黄白色，具有醒目的红冠和背部红色条纹；雌鸟以绿色为主，背部较深，头部和胸部略显灰色，红冠是其特色之一，而下尾覆羽在萨摩亚为红色，在斐济和汤加则为黄色。幼鸟与雌鸟相似，但羽毛边缘黄色，腹部呈黄色，年轻的幼鸟缺乏彩色的冠羽。","call":"多色果鸠有两种主要的鸣叫声，一是持续约6秒的节奏性咕咕声，起始为4至5个拉长的、略有起伏的咕咕音节，随后是约10个加速并逐渐减弱的音符；另一种是连续重复的短句。","habits":"多色果鸠主要生活在森林树冠层，以果实和浆果为食，特别偏好榕树的果实。它们通常在成熟的森林中被发现，也会进入村庄觅食榕树果实。它们的飞行快速而直接，通常高于树冠层。在寻找喜爱的食物时可能广泛迁移。","breeding":"繁殖信息有限，似乎全年都可能发生筑巢行为。巢是由细枝搭建的脆弱平台，通常位于离地面较高的小末端树枝或枝叉上。每次产1至2枚纯白色的蛋，两性轮流孵卵和育雏。","identification":"雌鸟与紫额果鸠相似，但紫额果鸠的头部和颈部更绿，没有黄色带纹。此外，雌鸟与雄鸟在色彩上有明显区别，尤其是冠羽的颜色。","protection":"IUCN：LC（无危）。在萨摩亚较为罕见和局部分布，可能受到榕树损失和本土森林清理的威胁。由于其群聚特性，易受狩猎影响。","distribution":"多色果鸠分布于南太平洋的斐济（波利尼西亚西南部）、汤加和萨摩亚（波利尼西亚中部），主要在低地的亚热带或热带湿润森林中。","other":"在19世纪和20世纪初，多色果鸠在美属萨摩亚的图图伊拉岛数量众多，但自1970年代以来，其数量已显著减少。"},{"name":"紫顶果鸠","english_name":"Crimson-crowned Fruit Dove","scientific_name":"Ptilinopus porphyraceus","overview":"紫顶果鸠（英文名：Crimson-crowned Fruit Dove，学名：Ptilinopus porphyraceus），是鸽形目鸠鸽科果鸠属的鸟类。属于鸽形目(Columbidae)。其特征为银色的脸和胸，紫色的额头和明亮的黄色尾尖。分布于美国萨摩亚、斐济、马绍尔群岛、纽埃、萨摩亚、汤加及瓦利斯和富图纳群岛。生活在低地的亚热带或热带湿润森林及亚热带或热带红树林。","appearance":"紫顶果鸠体长22至24厘米，体重85.4至124克。上体暗绿，头部、颈部和胸部淡绿灰色，胸前有深绿条纹，前额和头顶亮紫，腹部颜色从黄到橙再到深紫不等，尾羽末端带黄至灰。眼睛黄色偏棕，喙绿色或灰绿，腿脚紫红或红紫。雌雄相似，雌鸟背部、颈背和下腹可能更橄榄色。幼鸟头部斑点小而模糊，尾端带状标记弱，腹部颜色均匀亮丽，翼覆羽和三级飞羽边缘黄色。","call":"通常发出两声低沉的咕咕声，随后是一连串加速的嘈杂音符。","habits":"适应性强，栖息于原生雨林、红树林、环礁森林、灌木丛和农林混交地。在某些岛屿上常见于村落附近，但通常更倾向于成熟森林。飞行迅速直接，可在树冠上下飞行。","breeding":"可能全年繁殖，巢为脆弱的枝条平台，位于3至10米高的小树或下层林中，产一枚白色卵。","identification":"与多色果鸠雌鸟相似，但前额红色更鲜明，颈部对比更少。与紫额果鸠和科岛果鸠相比，具有更明显的紫色头冠和更鲜艳的腹部色彩。","protection":"IUCN：LC（无危）","distribution":"分布在太平洋岛礁，包括斐济、瓦利斯和富图纳、汤加、萨摩亚和纽埃。","other":"历史上曾被认为与、和Ptilinopus fasciatus同种，但现在被视为独立物种。"},{"name":"紫额果鸠","english_name":"Purple-capped Fruit Dove","scientific_name":"Ptilinopus ponapensis","overview":"紫额果鸠（英文名：Purple-capped Fruit Dove，学名：Ptilinopus ponapensis），是鸽形目鸠鸽科果鸠属的色彩斑斓的果鸠，仅分布于加罗林群岛的丘克州和Pohnpei岛。其最显著的特征是头部的亮紫色冠羽，背部与翅膀呈叶绿色，尾部末端则呈现鲜亮的柠檬黄色。该物种在所栖息的岛屿上独树一帜，是当地唯一的果鸠种类。","appearance":"成年紫额果鸠体长约为22至24厘米，雄雌外观相似。其头部顶部为鲜明的紫色，背部与翅膀颜色类似树叶的绿色，尾巴末端的黄色宽大而醒目。幼鸟全身绿色，但翅膀颜色较深。与近缘种相比，紫额果鸠的冠羽更为紫色，腹部黄色斑块不那么明显，尾端黄色更宽且鲜艳，喉咙部分带有黄色，胸羽基部偏橄榄黄色，下腹部橄榄色更深，中央有一片暗靛紫色斑块，下覆羽黄色带绿调。","call":"紫额果鸠的鸣唱是一系列加速后渐弱的咕咕声，有时起始快速随后减速，有时缓慢开始后加速再减速，整个过程持续约8到16秒，偶尔会重复两遍。","habits":"紫额果鸠主要栖息于树木和灌木丛中，以果实为主食。它们的活动范围涵盖了低海拔至中海拔的亚热带或热带湿润森林，以及亚热带或热带红树林区。","identification":"紫额果鸠与和Ptilinopus fasciatus在形态上有明显差异，前者具有更鲜明的紫色头冠，黄色的尾尖，以及不同色调的胸部、颈部和背部。此外，幼鸟的绿色体羽和深色翅膀也便于区分。","protection":"IUCN：LC（无危）。尽管在1983年和1994年的调查中，紫额果鸠是Pohnpei岛上最常见的鸟类之一，但在1990年代中期之后，其遇见率下降了约85%，可能的原因包括外来捕食者的威胁、非法狩猎（现已禁止）和栖息地破坏。","distribution":"紫额果鸠的分布限于太平洋的丘克州（Truk，位于加罗林群岛中部）和Pohnpei岛（Ponape，位于加罗林群岛东部，密克罗尼西亚中部）。","other":"曾被认为是紫顶果鸠的亚种，现被认定为独立物种。"},{"name":"科岛果鸠","english_name":"Kosrae Fruit Dove","scientific_name":"Ptilinopus hernsheimi","overview":"科岛果鸠（英文名：Kosrae Fruit Dove，学名：Ptilinopus hernsheimi），是鸽形目鸠鸽科果鸠属的色彩鲜艳的果鸠，仅见于太平洋密克罗尼西亚中部的加罗林群岛东部Kosrae岛上。曾被视为紫额果鸠的亚种。","appearance":"成年科岛果鸠拥有鲜绿色的背部和翅膀，紫色的头部顶部，以及淡色的头部和胸部。体型介于22至24厘米之间，较紫额果鸠和紫顶果鸠更为小巧。其喉部颜色较淡，颈部后部偏灰色，胸部灰度较高，腹部斑块不明显或不存在，尾羽尖端更宽广且明亮的黄色。","call":"其鸣叫声由一系列咕咕声组成，起初缓慢，随后略微加速，部分咕咕声为双音符，带有抽噎感，整个系列持续约7秒，音调和音量保持一致。","habits":"在树上和灌木丛中觅食，以果实为主要食物来源。","identification":"与紫额果鸠相比，科岛果鸠腹部无明显的棕色模糊斑块，尾尖黄色，胸部、肩部和颈后部更偏向灰色，体型较小（包括喙较短）。","protection":"IUCN：LC（无危）。物种在Ebon已灭绝，目前估计的分布范围仅为110平方公里。","distribution":"分布于太平洋中的Kosrae岛，位于加罗林群岛东部，密克罗尼西亚中部。"},{"name":"帕劳果鸠","english_name":"Palau Fruit Dove","scientific_name":"Ptilinopus pelewensis","overview":"帕劳果鸠（英文名：Palau Fruit Dove，学名：Ptilinopus pelewensis），是鸽形目鸠鸽科果鸠属的鸟类。帕劳特有种，被尊为当地的国鸟。拥有鲜明的灰绿色身体，橘色的翅膀，以及鲜紫色的头冠，其羽毛色彩与栖息地林木的树叶极为相衬。广泛分布于帕劳的各个岛屿。","appearance":"帕劳果鸠长约23至25厘米，体重约93克。头部、颈部和胸部呈灰色，头冠为鲜艳的紫色，有一条黄色边界线。胸前有淡红色紫色斑纹，腹部有橙色带，逐渐变为黄色。背部、翅膀和尾巴为深橄榄绿色。尾部末端有黄色的标记。喙为暗灰色，尖端略带绿意；腿脚为深红色。两性外观相似。幼鸟缺少紫色头冠，上身绿色，边缘黄色，下身呈黄色。","call":"相当活跃的鸣叫者，包括夜间。其求偶叫声是一系列节奏性的咕咕声，开始由2至3个双音符组成，随后是一连串18至25个音符，音符逐渐减弱，总时长约为8至11秒。双音符由一个微弱的音符紧跟着一个更长的强调的咕咕声组成，后续音符短促而过度滑音。","habits":"栖息于多种森林环境，主要在树冠层觅食，偶尔会在灌木或地面植物中觅食。以果实为主食，胃中曾发现未破损的Pinanga insignis果实。在树冠层活动频繁，但也会在较低处寻找食物。","breeding":"已知的筑巢记录发生在9月，巢穴为脆弱的枝条平台，位于树上或灌木中。每次产一枚白色的蛋。","identification":"与紫顶果鸠相比，最明显的区别在于尾羽覆羽的颜色。幼鸟缺乏紫色的头冠，上半身绿色，边缘黄色，下半身黄色。","protection":"IUCN：LC（无危）。在帕劳的所有主要岛屿上都是数量最多的鸟类之一，1991年估计数量超过45,000只。受到法律保护，但偶尔会成为猎人寻找密克皇鸠的目标。","distribution":"分布于太平洋的帕劳（位于加罗林群岛西部，密克罗尼西亚西部），在所有岛上的主要栖息地中常见。","other":"1945年前因狩猎导致数量下降，但随着保护措施的实施，种群数量已经恢复。"},{"name":"拉罗果鸠","english_name":"Lilac-crowned Fruit Dove","scientific_name":"Ptilinopus rarotongensis","overview":"拉罗果鸠（英文名：Lilac-crowned Fruit Dove，学名：Ptilinopus rarotongensis），是鸽形目鸠鸽科果鸠属的鸟类。生活在太平洋Rarotonga和Atiu（库克群岛南部，波利尼西亚东部）。拥有鲜艳的羽毛，头部紫罗兰色的冠羽尤其引人注目。","appearance":"这种多彩的果鸠有着亮绿色的身体，淡灰色的颈部和胸部，黄色的下尾覆羽，以及灰色的尾尖。最显著的特征是其鲜亮的紫红色前额和胸部斑点。雄雌外观相似，幼鸟的头部和腹部斑块可能减小或缺失，下部和尾带更偏绿色。与之相似的P.porphyraceus相比，拉罗果鸠的头部、颈部和胸部色彩较为柔和。","call":"发出一系列典型的加速和缩短的‘咕’声，持续约7至9秒，起始音节逐渐变短，节奏加快，共有大约14至16个音符。第二种叫声是一连串两个‘咕’声（第二个略带双音节），连续重复，中间不停顿。","habits":"在Rarotonga仅见于密集的低海拔山林，而在Atiu则广泛出现在多种木本生境中，包括种植园边缘和岛内的makatea（礁石石灰岩）区域，一般避开人口稠密区。在岛屿上的所有海拔高度均有发现。以果实为主食，已知的食物包括榕树、Elaeocarpus和Pipturus等植物的果实，偶尔也会从树叶上啄食小型昆虫。通常在树木和灌木丛中觅食。","breeding":"繁殖季节的标本采集时间集中在7月和9月。具体繁殖行为和细节尚需更多研究。","identification":"与太平洋帝国鸽相比，拉罗果鸠体型较小，头部和颈部银色，无紫红色斑块。不同亚种间的区别在于Goodwini亚种的腹部斑块中心仅有少量橙色尖端的羽毛，而非紫罗兰色区域。","protection":"IUCN：NT（近危）。物种数量稳定，但不超过2500个体。由于其栖息地仅限于两个小岛，容易受到风暴、疾病、灾难和外来捕食者的威胁。","distribution":"主要分布在太平洋的Rarotonga和Atiu两岛，属于库克群岛南部，波利尼西亚东部。","other":"尽管目前种群状况被认为稳定，但考虑到其狭窄的分布范围和潜在的威胁因素，该物种的安全状态仍然堪忧。"},{"name":"马里岛果鸠","english_name":"Mariana Fruit Dove","scientific_name":"Ptilinopus roseicapilla","overview":"马里岛果鸠（英文名：Mariana Fruit Dove，学名：Ptilinopus roseicapilla），是鸽形目鸠鸽科果鸠属的鸟类。色彩斑斓的果鸠，体型小巧，长约24厘米，以绿色的身体、橙色的腹部、暗色的胸带、银亮的颈胸、白色眉纹和醒目的玫瑰红前额著称。广泛分布于太平洋的北马里亚纳群岛，包括塞班岛、天宁岛、阿吉关岛和罗塔岛，以及已灭绝的关岛。","appearance":"成年马里岛果鸠的前额、冠部和颊斑呈深玫瑰红色，头部、颈部、上背部和胸部为暗银灰色，其余部位为鲜绿色，下胸部有紫色斑块，逐渐过渡至较大的橙色斑块，腹部区域泛黄。下尾覆羽粉红或橙黄色，尾巴末端有宽广的灰白色带。虹膜黄色，喙暗绿色，腿深红色。雌雄相似，幼鸟羽毛边缘黄色，缺乏成鸟的鲜艳头饰。","call":"马里岛果鸠的叫声为典型的鸽子咕咕声，起始和结束缓慢，中间快速颤音。","habits":"栖息于多种森林环境，偏好成熟的原生森林，但也出现在被重度放牧的森林、引入的Leucaena树丛地、次生林等地。飞行迅速而直接，通常覆盖短距离，高度接近树冠。以果实为食，已知食用Triphasia、Guettarda、Scaevola、Ficus等多种植物，偶尔取食Cestrum叶子和Passiflora花朵。","breeding":"全年可能繁殖，巢筑于树叉处，离地1至7米，由40至50根裸露的小枝构成，直径约13厘米，深度1.5厘米。每窝产一枚白色蛋。","identification":"马里岛果鸠在其分布范围内具有独特性，通过其独特的颜色组合，如银灰色的头部和胸部、亮绿色的上体、橙色的腹部以及玫瑰红色的前额，与其它物种容易区分。","protection":"IUCN：NT（近危）","distribution":"分布于北马里亚纳群岛的塞班岛、天宁岛、阿吉关岛和罗塔岛，以及已灭绝的关岛。在塞班岛、天宁岛、罗塔岛和阿吉关岛仍有残存的种群。","other":"马里岛果鸠文化上是该地区的重要象征，是北马里亚纳群岛的官方鸟种。"},{"name":"粉顶果鸠","english_name":"Rose-crowned Fruit Dove","scientific_name":"Ptilinopus regina","overview":"粉顶果鸠（英文名：Rose-crowned Fruit Dove，学名：Ptilinopus regina），是鸽形目鸠鸽科果鸠属的鸟类。中等体型的果鸽。其最显著的特征是粉红的头顶，分布于澳大利亚北部、东部以及印尼的某些地区。此物种在多地广泛分布，数量较多。","appearance":"粉顶果鸠体长22-24厘米，重85-125克。头部前额至帽顶呈深粉红至紫红，边界为黄色；下巴和喉咙颜色从奶油白到黄色；头颈绿灰色，渐变为绿色的下颈和上体；翅膀绿色，羽缘苍白，初级覆羽中心深色，内侧三级飞羽尖端有大块深蓝斑点；胸部浅灰绿，有绿色斑点，中央有一大片粉紫到紫色斑纹；腹部及尾下覆羽橙色渐变至黄色；尾巴上绿下灰，末端有宽黄带；喙与腿灰绿。雌鸟较雄鸟色彩暗淡，幼鸟无紫色顶冠，羽色更显青绿。","call":"粉顶果鸠的叫声独特，开始缓慢重复类似'hook-coo'的音调，随后转为快速加速的断续'coo-coo-coo-coo'声，有时发出快速上升的'oo, uk-coo, uk-coo'。","habits":"栖息于多种森林类型，包括热带雨林、画廊森林、季风林和红树林。在澳大利亚，随季节迁移，偏好热带和亚热带雨林。飞行迅速，翼鸣明显。以多种果实为食，如蓝莓、无花果、棕榈果等，常倒挂于枝头觅食。通常成对或小群体活动。","breeding":"繁殖季节因地区而异，在新南威尔士州南部为10月至翌年2月，正值水果丰富时期。巢建于树上，高6至30米不等，由细枝构成。每次产一枚白色卵，孵化期16-18天，雏鸟出生时约7克，覆有白色绒毛，成长迅速，野外留巢时间仅7-8天。","identification":"与华丽果鸠区别在于后者有白色腹和泄殖腔区域，而粉顶果鸠的腹为橙色。不同亚种间的差异主要体现在顶冠和胸部斑点的颜色。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚的北部和东部，印尼的小巽他群岛中部、东部，以及北澳大利亚的季风森林和低地雨林。","other":"在一些地区，如华莱士区的小岛上，粉顶果鸠相当普遍，但在澳大利亚新南威尔士州数量较少，被列为脆弱物种。"},{"name":"银顶果鸠","english_name":"Silver-capped Fruit Dove","scientific_name":"Ptilinopus richardsii","overview":"银顶果鸠（英文名：Silver-capped Fruit Dove，学名：Ptilinopus richardsii），是鸽形目鸠鸽科果鸠属的色彩斑斓的鸟类。雄鸟头部和胸部闪耀着明亮的银色光泽，翅膀呈绿色，腹部和尾巴下方有着鲜艳的橙色。雌鸟整体更偏绿色，尾巴下方黄色，脸部略显灰色。该物种在所罗门群岛南部的低地森林中栖息。","appearance":"成年银顶果鸠约20至22厘米长，重约99克。雄鸟拥有银灰色的额头、王冠区和脸颊，边界处有一条不显眼的黄绿色线；喉咙淡黄色；头部、颈部、胸部和背部上方呈现银灰色，强烈地混杂着黄色；中央胸羽末端呈银绿光泽，基部黄绿色；腹部有大片明亮的橙色；胫部和腹部羽毛黄绿色，尖端橙色；尾下覆羽亮橙色，常带粉红色调；背部、臀部、上尾覆羽和内翼覆羽为苔绿色；外翼部分闪耀蓝绿色，次级飞羽边缘青铜黄色；肩胛部和最内侧次级飞羽上有亮粉色区域，形成翅膀内缘的亮点和条纹；尾部深绿色，带有浅绿色的终端条纹；喙基部暗绿色，尖端淡黄绿色；腿蓝色到紫红色。雌雄相似，但雌鸟的头部和颈部羽毛边缘黄色，除了头部和颈部外。幼鸟主要是绿色，前额带灰色色调；腹部和尾下覆羽黄色。","call":"银顶果鸠的叫声是一种典型的鸽子式的弹跳、咕咕声，被形容为笑声般的节奏。广告叫声是一段约8至9秒的有节奏的咕咕声。先发出一个长音，随后是1至3个较弱的短音，重复3至4次，之后以均匀的节奏连续发出大约六个短而沉闷的呼噜声，‘whoOo-hu.. whoOo-huhuhu.. whoOo-huhu..whoOo-hu-hu-hu-hu-hu-hu’。","habits":"银顶果鸠栖息于低地森林，包括受飓风破坏的森林；在Uki岛上，它会造访远离主森林区域的孤立树木。该物种能够进行岛屿间的飞行，飞行迅速且直线，头部保持低位。它是一种以果实为食的鸟类，主要食用小型水果和浆果。大量个体可能会聚集在结满果实的树上。","breeding":"繁殖季节未被记录，但在三月观察到了求偶展示。筑巢于约6米高的地面，巢为轻微平台状，典型果鸠属的巢型，每次产一枚白色蛋。","identification":"雄性银顶果鸠几乎不可能误认，其独特的银色头部和胸部，以及橙色的腹部是识别的关键。雌鸟更类似于其他果鸠属物种，但其灰色的脸部、黑色小眼睛和银灰色的喉咙是诊断特征。与红嘴果鸠、帕劳果鸠和紫顶果鸠相似，但遗传数据显示它与马里岛果鸠最为接近。","protection":"IUCN：LC（无危）。近年来关于银顶果鸠的信息很少，但在1950年代Uki岛上报告其数量丰富；似乎在Rennell岛上仍常见。由于其岛屿范围有限，大部分位于飓风带内，可能面临脆弱性。需要进行调查以确定当前状况和趋势，以及任何必要的保护措施。","distribution":"银顶果鸠分布在所罗门群岛南部，包括Uki和Rennell岛。","other":"属于大型物种群，以灰绿果鸠为中心；在其内部，作为以紫顶果鸠为中心的亚群的一部分。已知有两个亚种。"},{"name":"灰绿果鸠","english_name":"Grey-green Fruit Dove","scientific_name":"Ptilinopus purpuratus","overview":"灰绿果鸠（英文名：Grey-green Fruit Dove，学名：Ptilinopus purpuratus），是鸽形目鸠鸽科果鸠属的鸟类。以其亮银色头部、颈部和胸部，深绿色翅膀，淡绿色腹部，以及黄色前额边缘而著称。体型小巧，约20至24厘米长，重量在95至125克之间。分布于法属波利尼西亚的社会群岛，栖息于低地森林，偏好植被丰富的环境。","appearance":"该物种头部、颈部和胸部为银灰色，腹面呈淡黄色，翅膀深绿色，尾部带有明显的灰色终端带。额头边缘泛黄，喙部鲜艳的香蕉黄色。雌雄外观相似，但雌鸟头部和颈部的灰色略带绿色调。幼鸟色泽较暗，上体橄榄绿色，下体黄色，与成鸟区别明显。","call":"典型的鸽类咕咕声，起始于‘wooo wooo’，随后的声音类似嘲讽的笑声，声音清晰，间隔不规律。","habits":"栖息于低地森林，高度可达450米，偏好多样化的植被和茂密的下层植被，偶尔出现在部分耕作区。以果实为主食，包括辣椒、番石榴、无花果等，有时也会啄食昆虫。飞行强健直接，常作短暂滑翔。","breeding":"全年繁殖，巢筑于至少4米高的树上，由树枝搭建的简单平台构成。每次产一枚白色单卵，由双亲共同孵育。幼鸟出生时覆盖着灰色绒羽。","identification":"与灰绿果鸠相比，具有更明亮的头部颜色，黄色边界更宽且鲜艳，颈胸部偏灰白，下巴和喉咙黄色更深，腹部硫磺黄色，翼覆羽、三级飞羽和次级飞羽边缘更显黄色。","protection":"IUCN：LC（无危）","distribution":"分布于太平洋社会群岛东部，包括Maupiti、Bora Bora、Tahaa、Raiatea和Huahine诸岛。","other":"面临沼泽鹞的捕食威胁，栖息地质量因外来植物入侵而下降，可能受到狩猎影响。"},{"name":"马喀岛果鸠","english_name":"Makatea Fruit Dove","scientific_name":"Ptilinopus chalcurus","overview":"马喀岛果鸠（英文名：Makatea Fruit Dove，学名：Ptilinopus chalcurus），是鸽形目鸠鸽科果鸠属的鸟类。仅见于法属波利尼西亚的马喀岛（Makatea）。其体长约20厘米，主要羽毛呈绿色，头部及胸部银色，前额为紫红色，喙橙色，翼羽边缘黄色。","appearance":"该鸟体态相对修长，羽毛大多为绿色，腹部略显绿意，胸部和头部为银色，前额呈现醒目的紫红色，喙部橙色。翼羽边缘黄色，下胸部分羽毛产生行行影子，看似条纹状，下体黄色，带橙色前缘。","call":"其鸣声通常是由几声较长的“woo”音符组成，随后是一连串加速的类似笑声的音节。","habits":"栖息于亚热带或热带湿润的低地森林，亦常见于村庄附近。生活在面积仅为28平方公里的马喀岛上。","identification":"与土岛果鸠相似，但色彩更为鲜明，腿为深色而非粉色。两种果鸠不太可能在同一岛屿上共存。","protection":"IUCN：VU（易危）；据估计，1993年总数量不足1000只，至2009年，基于密度抽样的广泛估算，种群数量为444-2219只。由于单一小岛的特有性，物种特别容易受到栖息地破坏和外来掠食者的威胁。","distribution":"分布于太平洋地区的马喀岛（Makatea），位于土阿莫土群岛的西北部，波利尼西亚东北部。"},{"name":"土岛果鸠","english_name":"Atoll Fruit Dove","scientific_name":"Ptilinopus coralensis","overview":"土岛果鸠（英文名：Atoll Fruit Dove，学名：Ptilinopus coralensis），是鸽形目鸠鸽科果鸠属的鸟类。主要分布于法属波利尼西亚的土阿莫土群岛西部和东部（除Makatea）。以绿色为主色调，腹部黄色，翅膀绿色，颈部和胸部银色，雄鸟头部前额有一小块紫红色斑点。","appearance":"这种鸽子长约22至24厘米，体重约70至99克。它的上半身呈淡橄榄绿色，带铜色高光；头部基部几乎白色，靠近喙处，头顶呈淡紫色，后缘灰色泛黄；头和胸部灰色，向下逐渐变为灰绿色；腹部黄色；尾巴末端窄幅银白色；眼睛红色；喙黄色；腿珊瑚红色。雌雄相似，幼鸟缺少淡紫色的头顶和灰色的颈部，其冠羽、背部、较小的翼覆羽和胸部边缘为黄色。","call":"叫声是一系列起伏的典型鸽鸣，持续约7到8秒，开始时交替发出单一和略高的双声鸽鸣，最后以六个长度大致相等的鸽鸣结束，音调在微妙的高低之间交替。","habits":"土岛果鸠是唯一一种生活在低珊瑚环礁上的现存果鸠。它栖息于树林、灌木丛和老化的椰子种植园中，偏好在地面觅食昆虫、种子和果实，甚至观察到捕食小型蜥蜴。","breeding":"幼鸟在二月和五月被采集到，二月、三月、五月和九月观察到幼鸟换羽成成年羽毛。巢的描述不详，仅有一份报告提到旧巢，被当地居民确认属于这一物种，巢位于灌木丛中，据称产一枚浅棕色的蛋，但这一点需要确认。","identification":"与Makatea果鸠相似，但色彩更为柔和，腿部颜色为粉红而非深色。两种物种很少在同一岛屿上发现。","protection":"IUCN：NT（近危）。在无人居住的环礁上广泛分布且常见，但在有人居住的环礁上稀少。面临栖息地破坏的威胁，尤其是转化为椰子种植园，以及外来掠食者的威胁。","distribution":"土岛果鸠主要分布在法属波利尼西亚的土阿莫土群岛西部和东部，除了Makatea岛以外。","other":"在1999年的调查中，土岛果鸠在访问的八个岛屿中的五个上较为罕见，但在一些免受外来掠食者侵扰的环礁上却很丰富。"},{"name":"红嘴果鸠","english_name":"Red-bellied Fruit Dove","scientific_name":"Ptilinopus greyi","overview":"红嘴果鸠（英文名：Red-bellied Fruit Dove，学名：Ptilinopus greyi），是鸽形目鸠鸽科果鸠属的鸟类。广泛分布于太平洋岛屿，包括新喀里多尼亚、瓦努阿图、圣克鲁兹群岛及所罗门群岛的部分区域。其最显著的特征为头部紫红色，腹部有醒目的红斑。","appearance":"成年红嘴果鸠长约21-24厘米，全身大致呈灰绿色，头冠紫红边缘黄，背部、翅膀和尾巴鲜绿，喉部淡黄色，腹部有紫红色斑块，尾下覆羽橙粉色，胸部羽毛尖端银绿基部黄绿，翅膀覆羽和次级飞羽边缘黄，主飞羽深色，三级飞羽可能有大的粉紫色斑点，尾端灰，翼和尾底面灰。喙橄榄绿，腿暗红。雌雄相似，但雌鸟的红色胸部区域较小。幼鸟通体暗绿，羽毛边缘浅黄，头冠和腹部红羽少或无。","call":"发出典型的鸽类叫声，先是几声延长的‘woo’音，随后是一连串加速的类似笑声的声音。","habits":"栖息于森林密林层，也见于多种林木环境，包括退化森林、次生林、草原林地乃至农田、村落和城市花园。飞行迅速直接，贴近树冠或低空飞行。以果实为食，包括无花果、Meliaceae科植物、引入的Muntingia（大戟科）、茄科的Solanum torvum等，常从枝梢摘取果实，有时倒挂取食。","breeding":"繁殖季节在瓦努阿图为9月至翌年2月，在Lifou岛（Loyalty Is.）记录到8月，在新喀里多尼亚为9月至12月。巢为简单的枝条平台，常见于森林边缘、次生林或草原地带，离地面仅数米。每窝产1枚白色蛋，孵化期约18天，双亲共同抚育幼鸟。","identification":"与银肩果鸠雌鸟表面相似，但体型更小、圆润，缺乏后者明亮的黄色翼斑。","protection":"IUCN：LC（无危）。在瓦努阿图和圣克鲁兹群岛普遍常见，新喀里多尼亚状况需核实。在瓦努阿图合法狩猎时间为4月至6月。","distribution":"分布于澳新界，具体包括Ndai（=Gower，北部Malaita，所罗门群岛中南部）、Temotu（=Santa Cruz Is.，所罗门群岛东南部）、瓦努阿图至新喀里多尼亚（含新喀里多尼亚忠诚群岛）。"},{"name":"拉帕岛果鸠","english_name":"Rapa Fruit Dove","scientific_name":"Ptilinopus huttoni","overview":"拉帕岛果鸠（英文名：Rapa Fruit Dove，学名：Ptilinopus huttoni），是鸽形目鸠鸽科果鸠属的鸟类。仅分布于法属波利尼西亚的拉帕岛。这种鸟拥有色彩斑斓的羽毛，头部和颈部呈蓝灰色，身体和翅膀主要是鲜艳的绿色，腹部黄色，胸前带有粉色斑块。该物种已被列为极度濒危。","appearance":"成鸟全长约31厘米，体重约130克。前额、前冠、小颊斑、上腹部斑块及臀下覆羽呈粉紫红色；颈部和胸部银灰色，带绿色光泽；腹区黄色；背部、翅膀和尾部暗绿色，翼部渐变为蓝绿色；虹膜黄色；喙黄色，基部粉红；腿红色。雌雄相似。幼鸟缺乏鲜艳的冠羽，整体较暗淡，翅膀和上体羽毛边缘黄色。","call":"鸣声丰富，有时黄昏后亦鸣叫。广告叫声是一段长达约10秒的有节奏的咕咕声，开始以一声拉长的咕声，随后是短暂的颤音系列（约1秒），以一系列约40个音符结束，其间有多次加速和减速。","habits":"栖息于海拔40至450米的森林，偏好密集林区；访问多种树木，包括人类引入的多种树种；甚至有报告指出在单一种植的引进松树Pinus caribaea林中筑巢。在岛上频繁地在破碎的栖息地之间飞行。主要以果实为食，但也报道吃昆虫和Metrosideros花或花蜜；可能利用长喙在花中觅食，但需进一步验证。食物包括番石榴、咖啡豆、Meryta和Homalanthus果实。","breeding":"幼鸟在2月、4月和12月被采集到。具体繁殖细节未详。","identification":"其独特的粉紫色额头和胸前斑块，以及银灰色带绿的颈部和胸部，是辨识的关键特征。没有其他相似物种与其共存于同一范围内。","protection":"IUCN：CR（极危）。2017年估计总数量仅剩160只，十年内数量下降超过20%。主要威胁是栖息地丧失，由于山羊、牛、火灾和砍伐导致森林退化。现存潜在栖息地仅覆盖292公顷，不到岛屿面积的8%。","distribution":"分布于太平洋的拉帕岛（Tubuai=Austral Is.东部，波利尼西亚东南部）。","other":"保护建议包括围栏Hiti山谷森林以排除牛和山羊，恢复森林，控制草莓番石榴Psidium cattleianum的生长，以及控制放牧动物的数量。"},{"name":"白顶果鸠","english_name":"White-capped Fruit Dove","scientific_name":"Ptilinopus dupetithouarsii","overview":"白顶果鸠（英文名：White-capped Fruit Dove，学名：Ptilinopus dupetithouarsii），是鸽形目鸠鸽科果鸠属的鸟类。由法国自然学家Adolphe-Simon Neboux于1840年首次描述。特有于法属波利尼西亚的马克萨斯群岛。物种名纪念了法国海军将领兼植物学家Abel Aubert du Petit-Thouars。存在两个亚种，分布于群岛的不同岛屿上。","appearance":"白顶果鸠体长约20厘米，体重90至110克。背部、翼上覆羽为黄绿色，前额与头顶白色，边缘有一条狭窄的橙黄色线；两颊灰白色；颈背银灰色；胸前有银色斑块，羽毛分叉，基部淡绿黄色；腹部橙色；下尾覆羽鲜黄；尾羽深绿，末端宽大的黄白色带；喙绿色；腿红至紫红色。雌鸟相似但色彩较暗淡。幼鸟更暗淡，绿色更深，头部灰色边缘模糊，大多数轮廓羽有黄色边缘。亚种emviridior/em的灰色部分更泛绿黄色，绿色部位更偏黄，冠羽奶油色。","call":"广告叫声是一系列约14至17个哀婉的拖音‘咕’声，逐渐变短加速，总持续时间约为8至10秒，声音似“wooOoow..wooOoow..woOow..wOw..wuw..wuu.wu.wu.wuwuwuwuwu”。","habits":"适应性强，栖息于各种森林类型，包括农林复合生态区，遍布各海拔高度。主要在树冠层活动，也会进入小树和灌木丛觅食。会飞越山谷作长距离移动，飞行快速，翼拍时发出嘶嘶声。以果实为食，偏好榕树无花果，也吃Cananga（番荔枝科）、辣椒（胡椒科）、番石榴和咖啡豆（茜草科）。据报告，幼鸟会被喂食昆虫，而成鸟只食用果实。","breeding":"最近离巢的幼鸟全年均可观察到，唯独九月例外。巢筑于3至20米高的树木和灌木上，为脆弱的枝条平台。每次产一枚白色卵。","identification":"白顶果鸠的白色头冠与眼后红或黄色条纹是其显著特征，与其他果鸠种类的分布区域不重叠，因此辨识容易。亚种间的主要差异在于色彩的细微差别。","protection":"IUCN：LC（无危）。在马克萨斯群岛普遍常见至数量众多，但在Hivaoa岛，由于引入的美洲雕鸮导致许多本土鸟类数量下降。若其他岛屿引入此类或其它捕食者，可能会对该物种构成威胁。","distribution":"太平洋：马克萨斯群岛（法属波利尼西亚东北部）。亚种Ptilinopus d. dupetithouarsii见于Hiva Oa、Tahuata、Mohotani和Fatuhiva等南方岛屿；Ptilinopus d. viridior则见于Nuku Hiva、Ua Huka和Ua Pou等北方岛屿。","other":"白顶果鸠曾与现已灭绝的赤髯果鸠共存于同一岛屿，两者可能经历了微异域分化事件。"},{"name":"赤髯果鸠","english_name":"Red-moustached Fruit Dove","scientific_name":"Ptilinopus mercierii","overview":"赤髯果鸠（英文名：Red-moustached Fruit Dove，学名：Ptilinopus mercierii），是鸽形目鸠鸽科果鸠属的已灭绝鸟类。最显著的特征是头部、颈部和胸部的蓝灰色调，以及金黄色的下体羽毛。原生于法属波利尼西亚的马克萨斯群岛，尤其在较高海拔的森林中可见。","appearance":"赤髯果鸠体长约21至23厘米，体态丰满紧凑，尾部短而近似方形。其最具特色的外观是头部上方和颊纹处的鲜红色彩，其余部位的羽毛呈现橄榄绿，尾羽尖端带有淡黄色。雌鸟的灰绿色部分略带绿色调。幼鸟缺乏成鸟的红色头部特征，且上体羽毛边缘为黄色。亚种tristrami具有较小范围的红色头冠，边缘为黄色。","habits":"赤髯果鸠栖息于森林树冠层，偏好较高海拔环境，最高可达1370米。以果实为食，曾观察到与白顶果鸠一同觅食的现象。","breeding":"繁殖记录显示，赤髯果鸠在1月和11月处于繁殖状态，但更详细的繁殖生态学信息缺失。","identification":"与白顶果鸠相比，赤髯果鸠的红色头部特征更加鲜明，且分布于更高海拔的森林。亚种间差异主要体现在红色头冠的范围和边界颜色。","protection":"IUCN：EX (灭绝)","distribution":"赤髯果鸠原生于法属波利尼西亚的马克萨斯群岛，包括努库希瓦岛（Nuku Hiva）和希瓦奥阿岛（Hiva Oa）。最后一次记录出现在1922年的希瓦奥阿岛。"},{"name":"亨岛果鸠","english_name":"Henderson Fruit Dove","scientific_name":"Ptilinopus insularis","overview":"亨岛果鸠（英文名：Henderson Fruit Dove，学名：Ptilinopus insularis），是鸽形目鸠鸽科果鸠属的鸟类。色彩相对低调的果鸠，具有灰暗的胸部和脸部，黄色的眼圈，紫红色的前额斑块，以及主要绿色的翅膀和身体。在皮特凯恩中部的亨德森岛（Henderson）上广泛分布，该岛位于太平洋东南部波利尼西亚。适应性强的物种，在岛上所有海拔高度均可找到。","appearance":"体长约20至25厘米，体重95至105克。额头和头顶呈现明亮的紫红，边缘带有黄色；喉咙白色；颈背、头部两侧、颈部和胸部为银灰色，略带绿色；腹部有黄绿色斑块；下腹部区域为淡黄色；背部和翅膀为深橄榄绿色，翅膀边缘有黄色；尾羽末端有狭窄的灰黄色带，中央羽毛除外；虹膜颜色从黄色到红橙色；喙色从暗黄色到绿色；腿色为红色至粉红色。雌鸟相似，但灰色区域偏绿。幼鸟缺乏红色头顶，顶冠为青铜绿色；翅膀和胸部羽毛边缘呈黄色。","call":"典型的鸣叫是一系列长音的‘woot’音符，间隔良好，音调逐渐下降。","habits":"栖息于森林中密集的下层植被，尤其是岛上的中央高原。很少远行，似乎具有领地性，会响应播放的叫声；通常在森林树冠上方100至200米处飞行。主要以果实为食，胃内容物分析显示包含Nesoluma和Ixora的果肉和完整果实。Procris pedunculata的果实尤其在其饮食中占重要地位，但在果实稀缺时也会食用Phymatosorus scolopendria蕨类植物的嫩芽。","breeding":"在三月和四月期间，观察到换羽的成鸟和幼鸟；五月收集的标本显示有适度增大的生殖腺。没有更多信息。","identification":"在亨德森岛上，没有类似物种与其共享栖息地，因此容易区分。","protection":"IUCN：VU（易危）。据报道数量稳定，估计1990年约有3400只，1992年约为3600只。虽然随后评估表明略有增加，但数量可能受到岛上食物供应的限制。","distribution":"分布于太平洋的亨德森岛（Henderson），位于皮特凯恩群岛中部，波利尼西亚东南部。","other":"亨德森岛无人居住，偶尔由皮特凯恩岛居民的伐木活动不会威胁本地鸟类；然而，岛屿对害虫物种的引入，特别是黑鼠（Rattus rattus），通过未经授权的游艇登陆而变得脆弱。"},{"name":"浅紫顶果鸠","english_name":"Coroneted Fruit Dove","scientific_name":"Ptilinopus coronulatus","overview":"浅紫顶果鸠（英文名：Coroneted Fruit Dove，学名：Ptilinopus coronulatus），是鸽形目鸠鸽科果鸠属的鸟类。也被称为浅紫冠果鸠，主要分布于新几内亚及其周边的卫星岛屿，偏爱干燥的低地森林环境，特别是在丘陵地带。该鸟拥有独特的淡紫色头顶冠羽和绿色的头颈胸，腹部呈现黄色至橙色。","appearance":"浅紫顶果鸠体长18-21厘米，体重69-75克。羽毛呈绿色，胸部和侧翼带有金色黄的色调；头部顶部为淡紫色，边缘环绕着黄色；脸颊呈现蓝绿色；喉咙黄色，下胸至下腹部和尾下覆羽为淡紫色至橙色；肩羽和内侧次级飞羽边缘有明亮的黄色；喙绿色，腿脚深紫红色。雌雄相似，但雌鸟黄色区域通常更淡。幼鸟与成鸟相似，但颜色较暗淡，刚离巢时头部有淡紫色斑块，但很快会因磨损而消失。不同亚种主要在头部颜色的丰富度和腹部锈橙色的数量上有所不同。","call":"浅紫顶果鸠发出一系列高音的加速‘wooo’音符，起初升高随后下降。还有简单的双音节‘whoo-oh, whoo-oh’声调，首音较高，以及忧郁的‘hu-h-h-h-h, hoodle’叫声。","habits":"栖息于雨林、次生林边缘、季风林和画廊林。通常为低地物种，但在红顶果鸠不存在的区域，可达海拔1200米，偏好比红顶果鸠更干燥的位置。已知最高记录可达1700米。以果实为食，尤其是无花果、月桂和棕榈果实。在树的所有层级觅食，从林下层到上层树冠；与橙腹果鸠相比，它似乎较少局限于树冠层，两者经常共存。可以单独、成对或小群体觅食，容易在结果的树木中聚集与其他果鸠。","breeding":"繁殖期在新几内亚的Port Moresby地区为9月至次年4月，主要在晚旱季到晚雨季。巢由少量的树枝搭建在枯叶堆上，高度1.2-3米（范围0.6-4.6米），通常位于棕榈叶、低矮树苗顶部或类似的叶丛中。雄鸟收集树枝，雌鸟在巢址等待。每次产一枚白色卵，孵化期18天，白天由雄鸟孵化，夜间由雌鸟。孵化期间，鸟儿紧紧地坐着，将色彩鲜艳的头顶远离入侵者。在圈养条件下，幼鸟12天离巢，野外幼鸟在仅10天大时就能飞行以躲避危险；父母会在幼鸟离巢后继续照顾一段时间。巢穴的被捕食率非常高：观察到的16个巢中，只有2-3个成功。","identification":"浅紫顶果鸠的淡紫色头顶与绿色胸部组合是其独特之处，与其他小型果鸠有明显区别。","protection":"IUCN：LC（无危）。虽然细节不多，但在许多地区报道为常见。在红顶果鸠频繁出现的地区，本物种一般较为少见。广泛的分布范围结合报告中的丰度，表明物种相对安全。","distribution":"分布于新几内亚及其周边的卫星岛屿。"},{"name":"红顶果鸠","english_name":"Beautiful Fruit Dove","scientific_name":"Ptilinopus pulchellus","overview":"红顶果鸠（英文名：Beautiful Fruit Dove，学名：Ptilinopus pulchellus），是鸽形目鸠鸽科果鸠属的鸟类。以绿色为主色调，头顶鲜红，喉部白色，喙绿黄色，脚紫红色，胸蓝灰色，腹橙黄色，两色间有深红斑块。两性相似，常见于新几内亚和周边岛屿的雨林地带。","appearance":"成年红顶果鸠体长18至20厘米，体重68至76克。头部前额及头顶紫红色，头部两侧、前颈及胸部灰色，喉部及脸部前方白色，下胸羽毛边缘白色，形成灰胸盾的白色边缘。紧接其下有一条宽的暗红紫色带，下方橙色斑块，两侧绿色和黄色，腹部黄至橙色，覆下尾羽橙色，上体绿色，次级飞羽和内侧初级飞羽有淡黄色边缘。喙橄榄绿，腿紫色。雌雄相似，但雌鸟紫色和橙色腹部范围较小。幼鸟无红顶，腹部仅微现紫色和橙色。","call":"发出缓慢而哀伤的下降音调‘woo-ooo’，或加速的快速‘wooloo’叫声，音调变化，单个音符下滑或不变。","habits":"栖息于低地和丘陵的湿润森林，海拔主要在750米以下，偶尔低至平原或高达1370米。偏好高降雨量地区的中层森林。在树冠至树下各层活跃觅食，以果实为食，包括多种树木、灌木、棕榈和藤本植物的果实。飞行迅速而直接。","breeding":"繁殖季节活动的巢穴记录在6月至8月，但信息有限。在Port Moresby地区，全年都有精子发生。巢由树枝和少量叶子构成，位于细小下层树的顶部或离地面2至3米的棕榈叶或低平台。产一枚白色蛋。","identification":"与相似的丽色果鸠区别在于后者腹部黄色，与浅紫顶果鸠的区别在于其较深的帽色和灰色胸部。","protection":"IUCN：LC（无危）。物种分布广泛，适应人类改变的生境，报告数量众多，因此相对安全。","distribution":"分布在澳新界的新几内亚及周边岛屿，如Batanta、Waigeo、Salawati和Misool。主要在平坦地形的雨林中。"},{"name":"蓝顶果鸠","english_name":"Blue-capped Fruit Dove","scientific_name":"Ptilinopus monacha","overview":"蓝顶果鸠（英文名：Blue-capped Fruit Dove，学名：Ptilinopus monacha），是鸽形目鸠鸽科果鸠属的鸟类。主要栖息在低地森林、红树林和种植园中。","appearance":"蓝顶果鸠体长约16-18厘米，头部蓝色，前额尤其明显，有一条明亮的黄色条纹从眼睛前方穿过头顶。脸颊和胸部有蓝色斑块，喉咙条纹、腹部区域和下尾覆羽为淡黄色，其余羽毛为深绿色。尾羽外侧黑色带绿，末端有较浅的色带。喙呈绿色，腿红色。雌鸟的蓝色头部标记较淡，缺乏蓝色胸部斑块。幼鸟翼羽边缘黄色更为显眼。","call":"其鸣叫声为柔和的下降式持续‘woo-oo’声，是一种高音拉长的咕咕声，略带滑音，音调和音量在后半部分最高。","habits":"通常单独或成群出现在果实丰富的树木上，偏好低地和较低的山丘地带，栖息于各种木本环境中，包括森林、红树林和种植园。飞行特点和活动范围未知。","identification":"与其他果鸠的区别在于其深色头部上的蓝色前额，雄鸟的黄色边界线是进一步的识别特征。","protection":"IUCN：LC（无危）。全球数量未知，但在Halmahera的Lolobata保护区估计约有8,700只。受伐木导致的栖息地丧失威胁。","distribution":"分布于印尼摩罗泰岛至Obi（北摩鹿加群岛）和Damar（小巽他群岛东北部）。在Halmahera和Ternate较为常见。"},{"name":"白胸果鸠","english_name":"White-bibbed Fruit Dove","scientific_name":"Ptilinopus rivoli","overview":"白胸果鸠（英文名：White-bibbed Fruit Dove，学名：Ptilinopus rivoli），是鸽形目鸠鸽科果鸠属的鸟类。以其独特的白色或淡黄色胸带和紫红色腹部斑块而著称，雄鸟的头部前额呈红色。雌鸟全身鲜绿色，具有黄色腹底和尾羽覆羽。分布于澳新界的印尼摩鹿加群岛中部、南部，新几内亚和俾斯麦群岛卫星岛屿。","appearance":"白胸果鸠体型介于22至26厘米，体重约135至162克。全身暗绿色带金色光泽，雄鸟额头和前冠部呈紫红色，胸部有显著的白色或奶油色半月形斑块，腹部中央有一长椭圆形紫色斑块，腹底和尾羽覆羽亮黄色。雌鸟通体绿色，仅腹底和尾羽覆羽为黄色。幼鸟全身绿色，翅膀、胸部和下体羽毛边缘黄色。","call":"白胸果鸠会发出深沉的‘hooO’声，单独或快速加速连续发声，音调在结尾处下降。","habits":"栖息于原始雨林，有时也会出现在次生林中。在大岛上常见于山区，在小岛近海平面区域。在新几内亚大陆主要分布于海拔1000至3260米，偶尔低至300米。以果实为食，常在森林各层单独或成对觅食。","breeding":"繁殖季节可能全年皆有。巢为简单的树枝平台，置于2至15米高的树上。一窝产卵1至2枚，两枚卵的情况在这个属中较为罕见。在新几内亚高地塔里峡谷附近，发现雄鸟正在孵卵的巢穴，含有两枚卵。","identification":"雌鸟黄色腹底和尾羽覆羽区分其与Superb、黑颈和其他果鸠种类。幼鸟通过翅膀、胸部和下体羽毛的黄色边缘与成鸟相区别。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界的印尼摩鹿加群岛中部、南部，新几内亚和俾斯麦群岛卫星岛屿，以及新几内亚周边的多个岛屿，如马鲁古群岛的哈马黑拉岛、布卢岛、塞拉姆岛和卡卡尔岛。"},{"name":"紫红胸果鸠","english_name":"Claret-breasted Fruit Dove","scientific_name":"Ptilinopus viridis","overview":"紫红胸果鸠（英文名：Claret-breasted Fruit Dove，学名：Ptilinopus viridis），是鸽形目鸠鸽科果鸠属的鸟类。小型绿色果鸠，具有独特的暗紫红色胸部斑块，蓝灰色的头部和肩部有淡灰色斑点。分布于摩鹿加群岛、新几内亚及所罗门群岛的森林地带。","appearance":"该鸟体长约20-21厘米，重约96克。全身绿羽，下喉至胸上部有鲜明的深紫红斑块；脸、下巴、前额和前冠呈蓝灰色；肩部有银灰色小斑块，部分下背羽和三级飞羽中心形成翼内缘的斑点；大翼覆羽和外侧次级飞羽边缘狭窄黄色；尾下覆羽和肛周羽毛边缘宽黄；喙色黄绿或橙色，基部红色或深橙色；腿深红色。雌雄相似，但雌鸟胸部斑块较小，虹膜灰白色。幼鸟头部和胸部的灰红区域较暗淡，大部分翼覆羽边缘黄色。","call":"其广告鸣声为略带哀伤的‘hoo’系列，开始于三音节的‘a-huh-hoo’，随后是十个音调相同但在结尾处渐弱的‘woo’音符，间隔8-10秒重复。有时会更响亮、更快地发出同样的叫声。","habits":"栖息于原始森林、次生林和森林边缘，偶尔在轻度树木覆盖的农田和花园中出现。广泛分布在低地，但在新几内亚通常在600-1200米的亚山地高度，常见于Fakfak和Kumawa的山区，而低地则罕见。常在树冠活动，有时在开阔地边缘降下较低的高度。","breeding":"已知在塞拉姆岛12月时发现带有蛋的巢穴，以及在布干维尔岛8月时发现带有雏鸟的巢穴。巢穴由细枝构成的松散开放平台，置于大约3米高的水平叉枝上，一次产一枚蛋。","identification":"雌鸟通过肩部的灰色斑块和翅膀上的斑点与雌性白胸果鸠区分开。雄鸟与雌鸟的外观差异主要体现在胸部斑块的大小和颜色上。","protection":"IUCN：LC(无危)","distribution":"分布于澳新界：印尼摩鹿加群岛中部、鸟头半岛和Neck（新几内亚西北部）、新几内亚北部沿海及所罗门群岛卫星岛。","other":"在新几内亚大陆的分布奇特，物种在中央山脉未知，但在所有沿逆时针方向沿海岸线从北海岸山脉最东端（亚历山大王子山脉）向西至Vogelkop和南至Fakfaks及Kumawas的外围山脉均有记录。"},{"name":"白头果鸠","english_name":"White-headed Fruit Dove","scientific_name":"Ptilinopus eugeniae","overview":"白头果鸠（英文名：White-headed Fruit Dove，学名：Ptilinopus eugeniae），是鸽形目鸠鸽科果鸠属的鸟类。拥有醒目的白色头部和大型鲜红胸斑，为马基拉岛及其附近小岛的特有种。其独特外观使其在所处范围内无相似物种。常见于岛屿各地，包括退化林区和村落。","appearance":"体长18至22厘米，体型圆胖，尾部短小。头部及上喉部全白，带有轻微黄色调；背部橄榄绿，颈背处泛铜色光泽；肩部有明显的灰色斑块；胸部为深紫色边缘环绕的紫红色斑块；腹部呈暗绿色，常带蓝色或灰色调；臀部淡黄至白色。喙基部暗红，尖端转为黄色；腿脚为紫红色，带蓝调；虹膜橙红色，眼周皮肤蓝灰至深绿色。雌雄相似。幼鸟头部绿色，白色仅限于额头和上喉部，胸部红色斑块较小，仅限于胸中央。","call":"广告鸣声为重复的两音节呼喊，间隔3至6秒发出一次。首音短弱，次音较长（约0.5秒），并略带拖音，呈现为“hu..whoOo”。偶尔快速连续重复此鸣叫声。","habits":"栖息于低地、山丘及山顶森林，常在邻近农耕区被观察到。以小型果实和浆果为食，有时在远离森林的单独树木上觅食。飞行快速而直线，常在开阔地带飞行，此时比在林间更易被发现。","breeding":"关于繁殖习性的具体信息有限，但已知会在9月见到幼鸟。","identification":"与黄胸果鸠相比，白头果鸠的头部全白，胸斑边缘深紫，下体颜色较暗。与紫红胸果鸠的区别在于头部白色，胸斑边缘深紫，下体颜色更暗沉。幼鸟可通过头部绿色、胸斑缩小及下体色调辨别。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界，具体为马基拉岛（所罗门群岛）和其附近小卫星岛（所罗门群岛东南部）。常见于低地至海拔700米的山丘森林，尤其在山麓地带数量较多。"},{"name":"橙腹果鸠","english_name":"Orange-bellied Fruit Dove","scientific_name":"Ptilinopus iozonus","overview":"橙腹果鸠（英文名：Orange-bellied Fruit Dove，学名：Ptilinopus iozonus），是鸽形目鸠鸽科果鸠属的鸟类。身长约为21厘米，以其绿色羽毛上醒目的橙色腹部斑块著称，常在低地和丘陵的开阔林区聚集。在新几内亚和周边岛屿广泛分布。","appearance":"体型紧凑，尾部短小，整体绿色，腹部中央有一大块橙色，眼周淡色，翼弯处有小片灰紫斑。次级飞羽和大覆羽边缘黄色，初级飞羽呈深绿色光泽，背部下方有蓝灰色斑点，尾部暗绿带灰绿端纹。喙暗灰，尖端乳白色，腿脚亮紫色。雌鸟相似，但绿色羽毛略带青铜色调，下巴灰调更明显。幼鸟缺乏成鸟的灰橙标记，绿色羽毛边缘黄色，腹部斑块区域更宽。","call":"常见叫声为一系列加速上扬的‘wuup’音符，高音。","habits":"栖息于各种森林类型和林木地带，偏好开放环境，如次生林、森林边缘、红树林、画廊林地和森林附近的草原，偶尔见于原始森林。主要生活在低地，局部可达海拔1000米。以果实为主食，尤其依赖无花果，也吃棕榈、肉豆蔻和番荔枝科植物。群居，常成数十只的大群，在结果树冠上聚集，与其他种类共存。","breeding":"繁殖行为全年可见，巢筑于树梢，通常高达13至21米，也有记录到仅3米高的位置。巢为简单的枝条平台，每次产一枚白色蛋。","identification":"与白胸果鸠和紫红胸果鸠类似，但橙腹果鸠具有橙色腹部，眼周淡色，且无白胸果鸠眼与喙间的黄色条纹。亚种finschi喉部灰色，iobiensis喉部更绿，尾端纹不明显，humeralis和pseudohumeralis翼弯处的紫灰色羽毛边缘更宽。","protection":"IUCN：LC（无危）。在新几内亚大陆常见至丰富，卡里鲁岛上普遍，其他岛屿如卡卡尔则稀少。","distribution":"分布于新几内亚、阿鲁群岛和西部巴布亚群岛，包括澳大利亚领土北托雷斯海峡的博伊古岛。","other":"适应力强，偏好相对开放的区域和次生林，频繁出现在城镇附近，这有助于其物种的生存。"},{"name":"瘤鼻果鸠","english_name":"Knob-billed Fruit Dove","scientific_name":"Ptilinopus insolitus","overview":"瘤鼻果鸠（英文名：Knob-billed Fruit Dove，学名：Ptilinopus insolitus），是鸽形目鸠鸽科果鸠属的独特鸟类。其最显著的特征是头部前方有一个大红色肉质突起，腹部有一大片橙色斑块，肩部有灰色斑点。主要分布于新几内亚东北的俾斯麦群岛，除阿德默勒尔蒂群岛外。","appearance":"瘤鼻果鸠体长22至24厘米，体重115至144克。与橙腹果鸠相似，但头部前侧的肉质突起显著增大且呈红色；翼内缘和尾带上的斑点为淡银灰色，比更广泛；肩部有银灰色斑块，延伸成一条沿着折叠翼边缘的狭窄灰色线；喙为浅绿黄色；腿为紫红色。雌雄外观相同。幼鸟特征未详述。","call":"声音记录较少，有时会发出拉长的四音节‘whooOOoo-hu-ooo-huu’，其中第一个音节拖长且音调过高，第二个音节较短（总持续时间约3.5秒）。此外，还有类似高音调的加速音符系列，开始时为较长的咕咕声。","habits":"瘤鼻果鸠占据多种森林生境，包括林缘和受干扰的区域，有时靠近村庄。在新不列颠岛海拔可达1200米，在新爱尔兰岛至少可达700米。以果实为食，已知食用无花果，常在结果树上聚集。","breeding":"可能全年繁殖。巢筑于密叶树或灌木丛中的简单枝条平台上，产一枚白色卵。观察到一巢孵卵期为19天，雏鸟离巢时间为14天。","identification":"与红疣皇鸠相比，体型小得多，身体鲜绿色。与其他果鸠属物种的区别在于头部的红色肉质突起和肩部的银灰色斑块。","protection":"IUCN：LC（无危）。在其大部分范围内普遍常见，但在许多小岛上状态了解甚少；在圣马太群岛似乎较为罕见。","distribution":"分布于澳新界的俾斯麦群岛，包括新几内亚东北部，但阿德默勒尔蒂群岛除外。","other":"能够很好地适应受干扰的森林环境，经常出现在人类居住区附近。"},{"name":"灰头果鸠","english_name":"Grey-headed Fruit Dove","scientific_name":"Ptilinopus hyogastrus","overview":"灰头果鸠（英文名：Grey-headed Fruit Dove，学名：Ptilinopus hyogastrus），是鸽形目鸠鸽科果鸠属的小型而引人注目的鸟类，主要分布在印尼摩罗泰岛至Bacan（印尼摩鹿加群岛北部）。其特征在于头部呈淡灰蓝色，与绿色身体形成鲜明对比，腹部有一块深紫色斑块，尾巴下方为鲜黄色。","appearance":"体长约20-23厘米，全身主要为绿色，头部呈现淡蓝灰色，肩部和翅膀上有两块相同的淡蓝灰色斑块。腹部有一大块深紫色斑，尾羽下侧和臀部为亮黄色。喙基部灰色或蓝白色，尖端黄色，腿脚颜色为暗灰色至灰紫色。雌雄外观相似，幼鸟尚未详细描述。","call":"叫声为渐强的‘whooOOOo’声，音量逐渐增大。","habits":"通常在森林边缘、次生林、草地上的散树、轻度林木覆盖的农田以及红树林中发现，有时接近人类居住区。主要在低地活动，但在Bacan岛的记录显示它能到达海拔1000米的高度。在Halmahera岛上，它是最显眼和最容易观察到的果鸠，常在清晨和傍晚栖息于显眼的树枝上甚至电线杆上。","identification":"在其北摩鹿加群岛的有限分布范围内，灰头果鸠的独特性在于其头部的淡灰色和腹部的深紫色斑块，使其容易与其他果鸠种类区分开来。","protection":"IUCN：LC（无危）。总体上较为常见，尤其在Halmahera岛上，它是最常见的果鸠，而在Morotai岛上也很普遍。","distribution":"分布于印尼摩罗泰岛至Bacan（印尼摩鹿加群岛北部），主要栖息在低地至海拔1000米的地区。"},{"name":"花鼻果鸠","english_name":"Carunculated Fruit Dove","scientific_name":"Ptilinopus granulifrons","overview":"花鼻果鸠（英文名：Carunculated Fruit Dove，学名：Ptilinopus granulifrons），是鸽形目鸠鸽科果鸠属的鸟类。仅见于印尼摩鹿加群岛中的Obi岛。其最显著的特征是头部呈淡灰色，与全身主要的翠绿色形成鲜明对比，翅膀和背部带有灰色斑纹，腹部有一片深紫红色，尾下覆羽和臀部为柠檬黄色。喙上方有一组突出的黄色肉质瘤状物，称为‘caruncles’，十分独特。","appearance":"花鼻果鸠体长约20至23厘米，头部和肩胛骨区域、内翼覆羽的斑块为银灰色；腹部深紫色边缘带有深黄色，逐渐过渡到尾下覆羽和臀部的淡黄色；其余羽毛为强烈金色调的绿色，尤其是颈部和胸部；喙尖黄色，上颚前部鲜红色，‘caruncles’部分橙色。雄雌羽毛相似，但雌鸟的喙更偏绿色；雄鸟虹膜红色，雌鸟黄色。幼鸟特征尚未详细描述。","call":"花鼻果鸠发出独特的低沉、浑厚叫声，‘gu-rOW’，首个音节通常很轻，难以听见。","habits":"栖息于低地森林的树冠层、森林边缘及附近的次生林中。以群居方式在无花果树（Ficus）上觅食。","identification":"与极为相似，但可通过‘caruncles’、头部颜色和腹部颜色等特征进行区分。","protection":"IUCN：VU（易危）。估计种群数量在3500至15000只之间，依赖低地森林生存，因伐木和采矿导致栖息地减少而面临威胁。","distribution":"分布于印尼摩鹿加群岛中北部的Obi岛。","other":"生物学和生态学信息几乎未知，需要进行广泛研究和调查，以确定其种群规模和生态需求；必须保护岛上的一些低地森林区域。"},{"name":"黑项果鸠","english_name":"Black-naped Fruit Dove","scientific_name":"Ptilinopus melanospilus","overview":"黑项果鸠（英文名：Black-naped Fruit Dove，学名：Ptilinopus melanospilus），是鸽形目鸠鸽科果鸠属的鸟类。中等体型的绿果鸠，体长约24厘米，喙和虹膜呈黄绿色。雄鸟具有淡灰色头部，黑色颈背，黄色喉部，及金黄色与粉红底色的尾下覆羽；雌鸟和幼鸟全身绿色。广泛分布于印尼、马来西亚及菲律宾，尤其在爪哇、小巽他群岛、苏拉威西岛及菲律宾南部的低地和山林地带常见。","appearance":"体长21-27厘米，体重92-120克。雄鸟具银灰色头部，黑色颈背及黄色喉部斑块；下胸至背部绿色或黄绿色；腹下部黄色，尾下覆羽亮紫红色，较短的尾下覆羽为黄色或橙色带红色尖端；喙绿黄色，腿红色。雌鸟整体绿色，除尾下覆羽红色或黄色，及翼羽和下腹边缘黄色。幼鸟似雌鸟，但多数羽毛边缘更显黄色。不同亚种在体型和颜色上略有差异，主要表现在腹下部的橙色或黄色。","call":"其广告叫声为一系列重复的双音节，有时以几声单独的咕咕声开始。重复短语的第一个音节最长（约0.6-0.8秒），稍有变化，第二个音节较短，声音滑过，形成“ooouah.wuh...ooouah.wuh...”的韵律。还会发出连续的长单音咕咕声，但这些是否反映了地理变异尚不清楚。","habits":"栖息于森林、森林边缘和开阔地带的灌木丛或树林；会到开阔地带的孤立树木上觅食；亦频繁光顾农田、郊区公园和花园；在小型岛屿上，红树林尤为重要。分布海拔从海平面至800米，苏拉威西中部可达1600米。飞行迅速，伴随响亮的呼呼声。主要以果实、浆果为食，已知在北苏拉威西地区，成对或多达八只的小群会在榕树和其他植物上觅食。","breeding":"筑巢时间报道自2月至9月，以及12月在爪哇；9月在布顿岛；5月在松巴哇。12月和2月在苏拉威西托吉安群岛。巢通常置于较低处，由树枝构成简单的平台，属果鸠科的典型巢型。产白色卵一枚。在圈养条件下：孵化期18-26天；离巢期8-14天。","identification":"雄鸟的黑色颈背和黄色喉部斑块，以及雌鸟尾下覆羽的颜色和翼羽边缘的黄色，是识别该物种的关键特征。与同属其他果鸠的区别在于其独特的色彩组合。","protection":"IUCN：LC（无危）","distribution":"分布于远东、澳新界，具体包括爪哇岛、小巽他群岛西部和中部、印尼苏拉威西岛和菲律宾南部。","other":"尽管在大型岛屿上普遍且数量众多，但在一些中型岛屿上也能发现。结合其似乎游牧的生活习性，局部丰度似乎会波动，物种可能正在扩大其分布范围。"},{"name":"小绿果鸠","english_name":"Dwarf Fruit Dove","scientific_name":"Ptilinopus nainus","overview":"小绿果鸠（英文名：Dwarf Fruit Dove，学名：Ptilinopus nainus），是鸽形目鸠鸽科果鸠属的鸟类，是全球最短小的鸽子或果鸠，体长仅13-15厘米。该鸟主要栖息于新几内亚及四王群岛的低地和山脚雨林，以绿色为主色调，腹部和尾下覆羽鲜黄，雄鸟胸部有独特的紫色斑块。","appearance":"小绿果鸠体型小巧，总长13-15厘米，体重约49克，是全球最小的果鸠。全身主要呈绿色，翼羽边缘黄色，形成三道黄色条纹；肩羽和次级飞羽内部偏蓝绿色，尤其肩羽颜色最为鲜明。雄鸟腹部有深紫色斑块，上胸两侧有灰色斑，下腹和尾下覆羽亮黄色；喙淡黄绿色，腿紫红色。雌鸟相似，但无紫色腹部斑块，胸部灰色较淡。幼鸟似雌鸟，但多数羽毛边缘黄色。","call":"其鸣声为高音、缓慢、柔和的上扬音，类似‘哦哇！’，间隔一秒重复六次左右。","habits":"主要栖息于森林环境，也访问开阔地带和部分清理区域的果树。海拔分布自低地至1100米的丘陵，以果实为食，偶尔摄取花蜜。通常成对活动，有时与其他果鸠混群。","breeding":"已知繁殖时间为9月和11月，巢位于树梢，高度从地面3米至12米不等，由雌鸟搭建，雄鸟提供筑巢材料。具体繁殖细节尚待研究。","identification":"与雌鸟的紫红胸果鸠和白胸果鸠相似，但体型更小，翼羽边缘黄色，易于辨别。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的低地和山脚森林，包括四王群岛（西北新几内亚）、鸟头半岛和Neck（西北新几内亚）、新几内亚东北部、东南部，以及从中西部至中东部新几内亚的南部流域。"},{"name":"里氏果鸠","english_name":"Negros Fruit Dove","scientific_name":"Ptilinopus arcanus","overview":"里氏果鸠（英文名：Negros Fruit Dove，学名：Ptilinopus arcanus），是鸽形目鸠鸽科果鸠属的鸟类。仅发现于菲律宾中部的内格罗斯岛。这种果鸠以灰绿色为主色调，拥有独特的黄色眼环和翼部亮点，体形健壮。自1953年首次发现以来，其踪迹神秘，仅有两次历史记录，疑似数量极少，可能濒临灭绝。","appearance":"里氏果鸠体长约18厘米，已知仅有一雌鸟样本。全身呈深绿色，额头为灰色，翼部和尾下覆羽有明亮的黄色边缘，形成明显的黄色条纹。喉咙部分呈白色，尾下覆羽黄色，眼周裸露皮肤黄色，喙黑色，腿呈紫红色。","call":"叫声未知，尚无关于其鸣叫特征的记录。","habits":"栖息于海拔约1100米的大型果树林中，偏好清新的环境。有关其具体的生活习性和迁徙模式的信息极为有限。","identification":"与其他果鸠种类相比，里氏果鸠的独特之处在于其灰绿色的羽毛、黄色的眼环和翼部高光。在野外辨识时，这些特征是关键的识别点。","protection":"IUCN：CR（极危）","distribution":"仅知分布于菲律宾内格罗斯岛的Mount Canlaon，属于极端局限的分布范围。","other":"自1953年以来，尽管进行了多次搜寻，但未再发现该物种的确切证据，其生存状态令人担忧。"},{"name":"橙色果鸠","english_name":"Orange Fruit Dove","scientific_name":"Ptilinopus victor","overview":"橙色果鸠（英文名：Orange Dove，学名：Ptilinopus victor），是鸽形目鸠鸽科果鸠属的鸟类。色彩斑斓的果鸠，雄鸟具有独特的金色橄榄头部和明亮的橙色羽毛，而雌鸟则呈现暗绿色，尾部黑色，下尾覆羽橙黄色。幼鸟类似雌鸟，但毛羽质地略显松散。该物种仅见于斐济的多个岛屿，包括Vanua Levu、Taveuni、Rabi、Kioa、Qamea和Laucala。","appearance":"雄性橙色果鸠拥有鲜明的橙色羽毛，背部颜色略深，轮廓羽毛呈现蓬松的毛发状质感，翅膀边缘为鲜亮的黄色。头部呈较暗的黄绿色，喉咙部位颜色较淡。嘴喙和腿脚为黄绿色。雌鸟全身为深绿色，头部为淡绿黄色，下尾覆羽为深黄色，翅膀颜色较暗，仅微露蓬松的毛发质感。幼鸟通体绿色，年轻雄鸟在亚成年时期羽毛接近雌鸟，但在换羽为成年羽毛时，外观奇特，或绿色带橙色斑点，或橙色带有绿色斑块。","call":"橙色果鸠的叫声独特，远听似水滴落在水槽中的声音，近听则像是拇指和手指的轻弹声，节奏规律，每1.5秒左右发出一次短促的爆破音。","habits":"橙色果鸠栖息于林地，偏好较为开阔的森林环境，包括原始森林、次生林和廊道森林。它们主要分布在海拔420至980米的亚山地地带。飞行快速直接，翅膀拍打时产生呼呼声。以小果实和浆果为主食，偶尔被观察到捕食树叶上的毛虫。","breeding":"繁殖记录显示，筑巢时间在6月、9月、11月和12月。巢穴为简单的树枝平台，高度约2.5米。通常产一枚白色蛋，但也有报道发现两枚蛋的巢穴。据观察，仅雌鸟参与孵化。","identification":"雄性橙色果鸠的鲜艳橙色羽毛和蓬松的毛发质感使其易于识别。雌鸟与金果鸠和Velvet Dove相似，但这些物种的分布范围并不重叠。","protection":"IUCN：LC（无危）","distribution":"橙色果鸠特有于太平洋的斐济群岛，主要分布于中北部的多个岛屿，包括Vanua Levu、Taveuni、Kioa、Rabi、Qamea和Laucala。","other":"橙色果鸠与哨音果鸠和金色果鸠关系密切，共同构成Chrysoena亚属的一部分。"},{"name":"金果鸠","english_name":"Golden Fruit Dove","scientific_name":"Ptilinopus luteovirens","overview":"金果鸠（英文名：Golden Dove，学名：Ptilinopus luteovirens），是鸽形目鸠鸽科果鸠属的鸟类。体型小、约20厘米长的短尾果鸠。雄鸟的显著特征是其鲜艳的金色外观，而雌鸟则呈现深绿色。该物种广泛分布在斐济的森林中，主要以各种小型果实和浆果为食。","appearance":"雄性金果鸠拥有醒目的金色羽毛，带有独特的毛发状质感，头部略带绿意，喙、眼周皮肤和腿脚呈蓝绿色。雌鸟则为暗绿色，与雄鸟的特征相异。幼鸟与雌鸟相似。","call":"金果鸠的鸣叫声类似连续的短促呱呱声，每2至4秒发出一次，远听似犬吠，近闻则似鹭鸟的呱呱叫声。","habits":"金果鸠栖息于成熟森林、次生林和灌木丛，甚至靠近村落。它们能在海拔60至2000米的范围内活动，能快速穿越草地到达石灰岩峭壁。飞行迅速直接，翅膀拍打产生呼呼声。","breeding":"筑巢材料为细弱的枝条和藤蔓，位于较低的藤蔓丛或茂密灌木中，由雌鸟独自建造。每次产一枚白色蛋。","identification":"金果鸠雄鸟的金色羽毛和雌鸟的绿色羽毛是辨识关键，同时，其特有的鸣叫声也是识别的重要依据。","protection":"IUCN：LC（无危）","distribution":"金果鸠特有于太平洋中的Vitu Levu、Beqa、Ovalau和Gau等岛屿（斐济中西部，波利尼西亚西南部），在这些地区的开放森林、画廊森林和次生林中均有分布。","other":"金果鸠与哨音果鸠和橙色果鸠关系密切，这三种果鸠虽不共栖一处，但属于同一亚属Chrysoena。"},{"name":"黄头果鸠","english_name":"Whistling Fruit Dove","scientific_name":"Ptilinopus layardi","overview":"黄头果鸠（英文名：Whistling Dove，学名：Ptilinopus layardi），是鸽形目鸠鸽科果鸠属的小型鸟类，为斐济特有种，主要分布在斐济南部的Kadavu和Ono岛屿上。","appearance":"成年雄性黄头果鸠全身绿色，头部和尾下覆羽为鲜亮的黄色，肩羽、颈下部和上胸部的羽毛边缘呈金色，轮廓羽毛具有松散的天鹅绒质感。雌鸟外观与雄鸟相似，但头部为深橄榄绿色，比体羽更偏棕色。幼鸟像雌鸟，但翅膀羽毛有更宽的黄色边缘。","call":"两种独特的鸣声，一是响亮上升的旋律哨音，紧接着短促下降的金属音，例如“wheEE!-chit”。另一种类似爆炸性的喷嚏声，开始于鼻音，结束于高音的短促刺耳音，如“nyeh-tsik！”。","habits":"通常在低地茂密森林中发现，也会出现在山区。在Ono岛，仅限于森林残余地带，偶尔在花园中可见。飞行迅速直接，翅膀拍打产生呼呼声。主要以果实为食，也捕食毛虫和小昆虫。觅食范围从地面以上至树冠层。","breeding":"繁殖记录多见于下半年。巢为细枝或藤条碎片构成的微小平台，直径约10-12厘米，一个巢曾记录在离地3米处。每窝产一枚白色蛋，据有限信息显示，只有雌鸟孵化和照顾幼鸟。","identification":"雄性黄头果鸠的亮黄色头部和绿色身体组合是诊断特征。雌鸟与雄鸟相似，但头部颜色不同。与橙色果鸠和金果鸠的雌鸟相比，黄头果鸠的分布范围不重叠，通过其独特的头部颜色和叫声可加以区分。","protection":"IUCN：NT（近危）。虽然目前在Kadavu和Ono的常绿森林中较为常见，估计总数量至少10,000只，但由于森林损失和火灾破坏，数量可能正在减少。","distribution":"太平洋地区的Kadavu和Ono岛屿（斐济西南部，波利尼西亚西南部）。","other":"属于‘金色果鸽’小群体，这一群体曾经被分类为独立的Chrysoenas属。"},{"name":"赖岛果鸠","english_name":"Raiatea Fruit Dove","scientific_name":"Ptilinopus chrysogaster","overview":"赖岛果鸠（英文名：Raiatea Fruit Dove，学名：Ptilinopus chrysogaster），是鸽形目鸠鸽科果鸠属的独特鸟类。1853年首次科学命名，实则更早由René Primevère Lesson于1823年在La Coquille号上发现。2021年，国际鸟类联盟（IOC）将其从灰绿果鸠中独立出来，认定为单独物种。赖岛果鸠仅分布于法属波利尼西亚的社会群岛。","appearance":"此鸟头部、颈部和胸部银光闪闪，翅膀深绿色，腹部浅绿色，前额带有黄色调。喙部鲜亮的香蕉黄，色彩鲜明。全身羽毛色彩搭配独特，辨识度极高。","call":"其叫声为典型的鸽子咕咕声，开始时发出‘wooo wooo’的声音，随后像是嘲讽般的笑声。","habits":"赖岛果鸠栖息于亚热带或热带湿润低地森林中。它们的活动范围局限于特定岛屿，依赖于丰富的植被资源。","breeding":"具体繁殖细节尚不清楚，但推测与同属其他物种相似，可能在树冠层筑巢，以果实为主食。","identification":"赖岛果鸠的外观特征独特，与灰绿果鸠存在明显区别，主要在于头部和颈部的银色光泽，以及独特的喙部颜色。","protection":"IUCN：EN（濒危）","distribution":"赖岛果鸠仅分布于法属波利尼西亚的社会群岛中的Bora Bora、Huahine、Raiatea、Tahaa，以及曾经的Maupiti岛上。","other":"该物种面临栖息地破坏、外来物种入侵（如沼泽鹞、野猫、波利尼西亚鼠和黑鼠）的威胁，导致其数量持续下降。"},{"name":"吉温黄胸果鸠","english_name":"Geelvink Fruit Dove","scientific_name":"Ptilinopus speciosus","overview":"吉温黄胸果鸠（英文名：Geelvink Fruit Dove，学名：Ptilinopus speciosus），是鸽形目鸠鸽科果鸠属的特有鸟类。主要分布在西巴布亚的Geelvink湾周边岛屿，如Biak和Numfor等，这些岛屿位于新几内亚以北。","appearance":"雄性吉温黄胸果鸠头部和上体呈深绿色，腹部为淡紫色，胸部有一条明亮的黄色带，边缘白色，眼周裸皮为鲜亮的黄绿色。雌鸟和幼鸟几乎全身绿色，腹部羽毛边缘泛黄。","call":"其鸣声是一系列加速的两部分‘hoo-wooo’音符，通常由7至9个音符组成。","habits":"吉温黄胸果鸠栖息于低地热带雨林，也出现在岛屿的退化森林中。","identification":"与白胸果鸠相似，但体型和喙部更小，雄鸟的胸部图案独特，易于区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚的Numfor、Biak及其附近岛屿（Geelvink湾群岛，新几内亚西北部）。","other":"2021年，国际鸟盟（IOC）将其从黄胸果鸠中分离出来，认定为独立物种。"},{"name":"散羽鸠","english_name":"Cloven-feathered Dove","scientific_name":"Drepanoptila holosericea","overview":"散羽鸠（英文名：Cloven-feathered Dove，学名：Drepanoptila holosericea），是鸽形目鸠鸽科散羽鸠属的鸟类。体型硕大，外观奇特，拥有肥硕体态与短尾。雄鸟羽毛鲜绿，腹部呈黄色，尾下覆羽异常长且色彩更艳丽。雌鸟颜色略淡，绿色中带黄。广泛分布于新喀里多尼亚的Grande Terre与Ile des Pins，偏好中高海拔的湿润森林。","appearance":"雄性散羽鸠长约32厘米，重220克；雌鸟稍小，约28厘米，重160克。整体呈现圆胖型态，翅膀短圆，尾巴短而宽，主飞羽末端有凹陷。全身覆盖着富光泽的绿色羽毛，翼端和尾羽覆羽带有银白色斑点，形成独特的横纹。下巴至喉部有白色条纹，胸部与腹部间有一条不规则的白带，下腹部深绿偏黄，尾下覆羽鲜亮黄色。喙暗绿色，腿呈暗红色。雌鸟体型较小，羽毛色泽偏黄。幼鸟缺乏成年鸟的霜状斑纹，翼羽边缘宽阔且呈黄色。","call":"发出一系列低沉哀婉的呼啸声，音调略高于新喀里多尼亚帝鸽的鸣唱，由五个咕咕声组成的独特短语，先是一声短促低沉的咕咕，接着是拉长的双音节下降音，再跟三声低沉的咕咕声，如“whu...cooowUU..wUUU..wUUU..wUUU”。此旋律重复数次，中间穿插短暂停顿。此外，还发出一系列相似的单个低沉呼啸声。起飞时，翅膀会发出尖锐的哨声。","habits":"散羽鸠栖息于原生森林，尤其是海拔100至1000米的湿润森林。适应力强，也能在受扰动的环境、开阔林地和以Melaleuca quinquenervia为主的niaouli草原生存。在Riviere Bleu公园，它们特别倾向于茂密的Elaeocarpus angustifolius树林。飞行声音独特，被描述为半吹哨半呼啸的响声。食物以果实和浆果为主，包括无花果和aralid树的果实。","breeding":"繁殖季节为8月至11月。巢筑于树或灌木上，由细枝搭建的简易平台构成。据报告通常产卵两枚，但在圈养条件下仅产一枚卵；孵化期约为21天，仅由雌鸟独自孵卵并照料幼鸟；幼鸟在21天左右即可良好飞翔。","identification":"散羽鸠最显著的特征是其丰满体态和短尾，以及尾下覆羽的鲜亮黄色。与同属其他物种相比，其独特的羽色和体型使其容易辨认。","protection":"IUCN：LC（无危）","distribution":"散羽鸠主要分布于新喀里多尼亚的Grande Terre和Ile des Pins。在Grande Terre，它们尤其常见于适宜的森林环境中，同时在Ile des Pins也被描述为常见。","other":"尽管面临森林砍伐、镍矿开采和潜在的狩猎威胁，但由于其在适宜生境中的普遍分布和对受扰动环境的容忍性，散羽鸠在新喀里多尼亚主岛上的数量估计达到140,000只，显示了其种群的健康状态。"},{"name":"模里西斯蓝鸠","english_name":"Mauritius Blue Pigeon","scientific_name":"Alectroenas nitidissimus","appearance":"毛里求斯蓝鸠头部、颈部和胸部覆盖着银白色、长而尖的羽毛，眼周有鲜红色裸露皮肤，延伸至喙部。身体羽毛呈靛蓝色，背部、肩羽和翅膀带有金属光泽的蓝色。尾羽基部部分呈黑色，尾羽和尾覆羽为深红色。喙绿色，尖端较暗，腿呈深石板灰色，虹膜为红橙色，内环黄色。","call":"关于其鸣叫特征的描述资料稀缺。","habits":"可能以果实、坚果和软体动物为主食，常生活在潮湿的高山常绿森林中。其生态位与现今蓝鸠种类相似，季节性迁移到食物丰富的地区。","breeding":"关于其繁殖行为的详细资料缺失。","identification":"与其它蓝鸠种类相比，毛里求斯蓝鸠体型更大，羽毛色彩更为鲜艳，尤其头部的白羽和身体的蓝羽极为突出。","protection":"IUCN：EX（已灭绝）","distribution":"该物种仅分布于印度洋的毛里求斯岛（马斯克林群岛中部），现已在野外灭绝。","other":"毛里求斯蓝鸠于1830年代因人类活动导致的栖息地破坏和猎杀而灭绝。"},{"name":"马岛蓝鸠","english_name":"Madagascar Blue Pigeon","scientific_name":"Alectroenas madagascariensis","overview":"马岛蓝鸠（英文名：Madagascar Blue Pigeon，学名：Alectroenas madagascariensis），是鸽形目鸠鸽科蓝鸠属的鸟类。以深蓝色为主色调，尾羽呈酒红色，广泛分布在马达加斯加岛的东部、中部及北部雨林地区。","appearance":"马岛蓝鸠体型中等，长度约25至28厘米，其喉咙和颈部为银蓝灰色，背部为深蓝色，上背覆羽呈银灰色；腹部为深蓝色，胸部银蓝灰色，下尾覆羽血红色；尾羽除最外侧为蓝黑色带血红尖端外，其余均为血红色；翅膀上方深蓝色，下方棕灰色；虹膜绿黄色，周围有红环；眼周有大片裸露的红色皮肤；喙绿色带黄尖；跗跖部分被羽，红色，趾也为红色。雌雄外观相似，幼鸟眼周裸皮面积较小，体色主要为暗蓝绿色，许多羽毛边缘较浅，胸和颈无灰色调。","call":"马岛蓝鸠通常非常安静，偶尔会发出低沉的短促咕哝声。","habits":"主要栖息于马达加斯加东部，从海平面至海拔2000米的未受干扰的雨林和城镇周边退化森林。常见于树梢，常在森林冠层之上观察到，站立于突出的枯枝上。季节性迁移到岛西部，通常在雨季（11月至12月）到达，3月至7月可能降至平原，部分年份在岛西北部消失。以果实为食，通常成对或小群3至12只活动。","breeding":"繁殖期记录于10月至12月。巢为交织的树枝平台，置于离地面6至20米高的水平树叉上，每次产一枚白色蛋。","identification":"深蓝色的羽毛和红色的尾羽及眼周裸皮使其与马达加斯加其他鸽子种类明显区分开来。","protection":"IUCN：LC（无危）。在马达加斯加西北部和东部广泛分布，部分地区因狩猎压力可能导致局部种群减少。在多个保护区如Mantadia和Ranomafana国家公园以及Analamazaotra特别保护区（Perinet）较为常见。","distribution":"主要分布于马达加斯加岛的西北部、中部和东部，包括沿海平原至海拔2000米的热带湿润低地森林和山地森林，无论是未受干扰还是已退化的森林。","other":"马岛蓝鸠与另外两种现存的蓝鸠——科摩罗蓝鸠和红冠蓝鸠关系密切。"},{"name":"科摩罗蓝鸠","english_name":"Comoro Blue Pigeon","scientific_name":"Alectroenas sganzini","appearance":"科摩罗蓝鸠体型中等偏大，全长约27厘米，体重范围雄鸟134至158克，雌鸟171克。头部、颈部及上胸部为银灰色，颈羽特别长且深叉，全身羽毛以黑蓝色为主，翼羽和背羽带银色光泽。初级飞羽内侧边缘有明显凹陷，端部弯曲。眼睛黄色，周围有红色环，眼周皮肤紫红色，喙橄榄绿色，尖端淡色，腿脚灰蓝色。雌鸟通常颜色略暗，部分羽毛边缘浅黄。幼鸟银灰部位呈绿灰色，眼睛和眼周皮肤色泽较暗。","call":"科摩罗蓝鸠的常见鸣声是一系列快速低沉的呼噜声或低吼，由大约3至5个持续约0.5秒的咕咕音组成，音调可变，有时像吼叫，有时似呻吟。","habits":"科摩罗蓝鸠主要栖息于常绿森林，也能适应次生林和伐木后的森林环境，如香蕉树下层。它们倾向于选择海拔较高的地区，最高可达1800米，但在一些岛屿上，如奥尔达布拉，它们甚至能在海边的灌木丛中生存。它们通常在日间于主岛上觅食，晚上飞往无猫的岛屿休息。","breeding":"科摩罗蓝鸠的繁殖信息有限，但它们主要以各种浆果和肉质果实为食，尤其是无花果和塔卡马克树的坚果。在奥尔达布拉东侧，多达20只的小群体会在一棵树上觅食。","identification":"科摩罗蓝鸠与区域内其他鸽子的区别在于其深蓝色的羽毛和苍白的头部。","protection":"IUCN：NT（近危）","distribution":"科摩罗蓝鸠分布于科摩罗群岛和奥尔达布拉岛（西南塞舌尔）。在科摩罗群岛，它们主要分布在海拔500至1500米的热带湿润森林中，包括低地和山地森林。在奥尔达布拉，由于人类活动的影响，数量曾大幅下降，但随着山羊的清除，其数量已显著恢复。","other":"尽管科摩罗蓝鸠面临栖息地丧失和退化以及狩猎的威胁，但由于其种群数量估计高于10,000只，且分布面积大于20,000平方公里，因此被列为近危物种。"},{"name":"红冠蓝鸠","english_name":"Seychelles Blue Pigeon","scientific_name":"Alectroenas pulcherrimus","overview":"红冠蓝鸠（英文名：Seychelles Blue Pigeon，学名：Alectroenas pulcherrimus），是鸽形目鸠鸽科蓝鸠属的中型鸽子。该鸟以深蓝色的羽毛和头部银灰色为显著特征，主要分布于塞舌尔群岛的山林地带。","appearance":"红冠蓝鸠体长约24厘米，体重161至165克。喉部、面部两侧及颈背呈淡灰色，逐渐变为银灰色至颈部和胸部。其颈部羽毛分叉且尖细，其余羽毛呈现黑色带蓝，初级飞羽带银色光泽。眼周裸露皮肤具疣状突起，延伸至喙裂，下颌基部亦有疣状突起，整个眼周皮肤鲜红色，腿脚灰暗。两性相似。幼鸟主要呈青铜橄榄绿，羽毛边缘黄色，眼周皮肤棕色。","call":"红冠蓝鸠的叫声为一系列快速、低沉、含糊的咕咕声，每秒约四声，音调逐渐升高后突然停止。","habits":"栖息于剩余的山地森林中，尤其是普拉兰岛，但也出现在马埃岛、弗里盖特岛和希尔瓦岛的偏远地区。以果实和浆果为主食，包括野生番石榴、肉桂浆果和塔卡马克树的坚果。种子在肌肉质的砂囊中被研磨消化。","breeding":"关于繁殖季节的数据有限。筑巢为典型的鸽子平台，由雌鸟独立完成。通常产一枚蛋，偶尔产两枚；可能由于食种子习性导致偶尔产出双卵。孵化期28天，两性共同孵卵和喂养幼鸟；幼鸟离巢时间约为14天。","identification":"红冠蓝鸠的深蓝色羽毛和淡色头部使其与范围内其他鸽子种类明显区分开来。","protection":"IUCN：LC（无危）。全球种群数量未知，1996年希尔瓦岛上估计有600只。由于过度猎杀和当地农业不再重视果园，物种比过去稀少。然而，狩猎已不再是主要威胁，且该物种已返回阿瑞德岛。","distribution":"分布于塞舌尔群岛的所有较大花岗岩岛屿，包括丹尼斯岛和位于塞舌尔银行边缘的鸟岛。自人类食用猎捕停止后，数量大幅增加。"},{"name":"红腹皇鸠","english_name":"Pink-bellied Imperial Pigeon","scientific_name":"Ducula poliocephala","overview":"红腹皇鸠（英文名：Pink-bellied Imperial Pigeon，学名：Ducula poliocephala），是鸽形目鸠鸽科皇鸠属的鸟类。大型的果食性鸟类，体长可达42厘米。主要分布于菲律宾群岛，包括吕宋、卡坦端内斯、民都洛等地，但在巴拉望群岛除外。其显著特征包括淡灰色头部、粉色腹部以及带有棕色、黑色和灰色图案的尾巴。","appearance":"体长40-42厘米，体重510-564克。头部、前额灰白色，逐渐过渡至灰色后冠和紫色颈背；下巴和喉咙呈肉桂色，胸部边缘有一狭窄的白色边框，胸脯暗紫绿色；腹部淡粉色；两侧和臀部覆羽为栗色；其余羽毛为青铜绿或金绿色；后颈、颈侧和上肩为紫红色；尾部中央有明显的灰白色带；翅膀下部黑色并带有深绿色；尾羽下部黑色伴有灰白色带；眼圈、腿和脚均为红色；喙灰黑。雌鸟类似，但头冠有绿色调，喉部栗色斑块界限不明显，有时腹部粉红羽毛边缘为赤褐色。幼鸟似雌鸟，但腹部羽毛赤褐色边缘不那么突出。","call":"广告叫声为两声低沉、几乎相同的咕咕声，重复间隔发出，每声持续约0.4-0.5秒，尾音上扬：‘whoooUw..whoooUw’。还有一种更长系列的类似但较短的咕咕声，以更快的节奏给出。在苏禄岛记录到的声音有所不同，开始是干涩的咔哒声，随后是一系列减速的低沉咕咕声。","habits":"栖息于原始和老次生林，主要在海拔400-1500米的高山区，常出现在森林树顶。似乎会与红喉皇鸠和白喉林鸽等大鸽子混群栖息。","breeding":"暂无信息。","identification":"与红喉皇鸠相似，但红腹皇鸠具有暗色的颈部和胸部。苏禄岛上的个体叫声有明显差异。","protection":"IUCN：NT（近危）；在菲律宾红名单上被列为Critically Endangered（极危）。由于栖息地丧失、捕捉宠物贸易和狩猎，种群数量可能正在中速下降。","distribution":"分布于菲律宾群岛，包括吕宋、卡坦端内斯、民都洛、锡布延、马斯巴特、萨马、比里兰、班乃、内格罗斯、宿务（2003年重新发现）、保和、莱特、迪纳加特、棉兰老、巴西兰和苏禄群岛（塔威塔威）。在宿务岛上曾被认为灭绝，自2003年起在阿尔科伊森林有记录。","other":"尽管在菲律宾广泛分布，但由于猎杀和低地森林栖息地的丧失，该物种稀少且种群数量可能正中速减少。"},{"name":"斑尾皇鸠","english_name":"White-bellied Imperial Pigeon","scientific_name":"Ducula forsteni","overview":"斑尾皇鸠（英文名：White-bellied Imperial Pigeon，学名：Ducula forsteni），是鸽形目鸠鸽科皇鸠属的鸟类。大型、引人注目。头部呈淡灰色，眼圈红色，眼珠黄色，胸部至腹部白色，尾部带有宽阔的白色带纹，上体绿色，尾下覆羽栗色。分布于印尼苏拉威西岛山区、托吉安群岛、邦盖群岛和苏拉群岛东部。","appearance":"体型庞大，长度42.5至51.5厘米，平均重量510克。整体羽毛颜色从翡翠绿到金绿或青铜绿不等，肩部常显紫色，颈后部有铜色光泽。头部浅灰，前额及喉部白色，胸腹白色略带粉或乳白色，尾下覆羽为栗色，尾羽中央有一条明显的淡灰色宽带。虹膜黄或橙色，外围有深红或橙色环，喙黑色，腿脚紫红色。雌雄相似，但雌鸟灰色部位稍暗。","call":"发出深沉的两音节叫声，先高后低，如‘woop-mooo’，有时单独发出‘woop’声。","habits":"栖息于山地森林的上层或沿岸森林，偶尔出现在孤立的丘陵森林区，常见于树冠下层和中层，但也会在树冠上方的暴露枝条上栖息。活动范围在海拔150至2200米之间，以800至1600米最为常见。以水果为主食，尤其偏爱无花果，最多可达30只聚集在果实丰富的树上。","breeding":"关于繁殖行为的信息尚未记载。","identification":"与灰头皇鸽相比，体型更大，尾部带纹更宽且颜色更深，上体和头部颜色更为均匀。绿色皇鸽缺少白腹皇鸠的白色腹部和酒红色颈背，且没有尾部带纹。","protection":"IUCN：LC（无危）","distribution":"分布于印尼苏拉威西岛山区、托吉安群岛（位于苏拉威西东北部和中东部之间）、邦盖群岛和苏拉群岛东部（位于印尼苏拉威西岛东侧）。","other":"种群数量因栖息地破坏而逐渐减少，但在苏拉威西岛上仍广泛分布，某些地区甚至相当常见。"},{"name":"红喉皇鸠","english_name":"Mindoro Imperial Pigeon","scientific_name":"Ducula mindorensis","overview":"红喉皇鸠（英文名：Mindoro Imperial Pigeon，学名：Ducula mindorensis），是鸽形目鸠鸽科皇鸠属的大型鸟类，为菲律宾民都洛岛特有种，体长达50厘米，是菲律宾最大的鸽类。","appearance":"头部、颈部、胸部及下体呈淡蓝灰色，腹部及尾下覆羽带赤褐色；眼周有暗灰黑色环，延伸至后眼线；下脸及喉部为淡粉色；前额银灰色，有时泛粉红色；颈后部暗灰色，上背变为黑紫色；上体主要为翠绿色；肩羽和内翼覆羽紫铜色至红铜色；初级飞羽和尾羽绿黑色至蓝黑色；尾中央有明显灰色带；虹膜明亮黄色，外围有红色环；眼睑深红色；喙黑色；腿脚红粉色。雌鸟虹膜黄棕色，眼睑黄橙色。幼鸟羽毛描述未见报道。","call":"其叫声为两个低沉的轰鸣声，比其他同域皇鸠种类音调更低。","habits":"栖息于海拔1000米以上的山地森林，曾观察到与和混群栖息。通常单独或成对出现，偶尔小群体活动，最多四只一起。以大紫果为食。","breeding":"关于繁殖行为知之甚少，仅有一例雄鸟于八月被采集，四月一雄鸟睾丸增大。","identification":"与红腹皇鸠相比，红喉皇鸠缺乏深色颈胸；与绿皇鸠相似，但红喉皇鸠背部较暗，有红眼环。","protection":"IUCN：NT（近危），红喉皇鸠面临栖息地丧失和猎杀威胁。","distribution":"分布于菲律宾民都洛岛山区。","other":"迫切需要调查研究，以确定当前状况和保护需求。"},{"name":"灰头皇鸠","english_name":"Grey-headed Imperial Pigeon","scientific_name":"Ducula radiata","overview":"灰头皇鸠（英文名：Grey-headed Imperial Pigeon，学名：Ducula radiata），是鸽形目鸠鸽科皇鸠属的鸟类。大型鸽类，以其灰头和灰下体为显著特征。主要栖息在苏拉威西岛的山地森林，海拔200至2400米间，尤其在1600至2200米高度最为常见。","appearance":"体长36至39厘米，体重约295克。雄鸟头部、颈部侧面、胸部和下体为淡灰色，腹部和侧腹混有暗栗色；尾下覆羽为栗色；后颈有黑紫色斑块；肩部和翅膀为虹彩红紫色，背部和尾部则混有青铜绿色，某些光线条件下上体呈翡翠绿色；尾部中央有一条明显的灰色带，尾下为黑色，中央有灰色带；翅膀下方为深灰色；虹膜橙色，有时带有红色边缘；喙黑色，鼻甲暗灰色；腿和脚为紫色或紫红色。雌鸟的灰色区域更深，除上背外少有紫色或红光。","call":"极少鸣叫，仅描述过一次单调的单音节“huh”。","habits":"通常成对或小群体生活在山地森林的上层，有时会到低地寻找结果树。以果实为主食，尤其是无花果，属于典型的食果鸟。可在树冠中层和较低层觅食，常成群活动。","breeding":"繁殖记录见于12月和3月，每次产一枚蛋。筑巢于山林中的悬崖洞穴、树木凹陷处或受保护的岩石突出部分。有记录显示在1850米高度的一棵死树的空洞中发现巢，由几根树枝和叶子构成，幼鸟在33天时因受干扰而离巢。","identification":"与绿皇鸠相似，但可通过灰尾带和后颈上的青铜色斑块区分。雌雄差异在于颜色光泽和背部色调。","protection":"IUCN：LC（无危）","distribution":"分布于印尼苏拉威西岛的山区，主要栖息于山地森林。","other":"虽然广泛分布但总体数量不多，局部或季节性常见。"},{"name":"绿皇鸠","english_name":"Green Imperial Pigeon","scientific_name":"Ducula aenea","overview":"绿皇鸠（英文名：Green Imperial Pigeon，学名：Ducula aenea），是鸽形目鸠鸽科皇鸠属的鸟类。别名: 大绿斑鸠、绿南鸠、大绿鸠、大青咖追，大型的森林鸽类。主要特征为珍珠灰色头部与下体，背部与翅膀呈现深绿色金属光泽。分布范围广泛，从尼泊尔、印度南部至斯里兰卡，向东延伸至中国南部、印尼和菲律宾。在中国大陆，绿皇鸠是国家二级保护动物。","appearance":"绿皇鸠体型较大，长度可达45厘米。全身以珍珠灰为主色调，头部、颈部及下体颜色较淡，背部、翅膀和尾部则为深绿色金属光泽。肩部及翼覆羽铜绿色或墨绿色，雌雄鸟外形相似。具有暗栗色的尾下覆羽，飞行时可见其下翼为淡灰色，尾羽下方为黑褐色。部分亚种在颈后有明显的橙色或栗色斑块。","call":"绿皇鸠的叫声深沉且响亮，最常见的是喉音“rrruh-RUOOHH”，有时会发出变化或音调不同的版本。叫声在不同地理位置有所变化，如在安达曼群岛声音较低沉，斯里兰卡则较高音。","habits":"绿皇鸠栖息于低地至山脚的森林地带，包括边缘地带和人类居住区附近的次生林。主要在树冠层活动，以植物果实为食，尤其偏爱无花果和肉豆蔻。飞行迅速有力，多在树冠高度以上，但拍翼频率不高。通常单独或成对活动，冬季会形成小群体。","breeding":"繁殖季节通常在4月至7月，雄鸟通过挺胸、点头、展示颈部羽毛等方式向雌鸟求偶。营巢于树上，巢由枯枝构成，呈浅盘状，较为简陋。每窝产卵1至2枚，卵白色，大小约41-51 x 31-37毫米，由两性轮流孵化。","identification":"需与马来皇鸠、蓝尾皇鸠、山皇鸠等同属物种区分，主要依据上体颜色、下体色调、尾下覆羽颜色以及是否存在颈后橙色斑块。","protection":"IUCN：NT（近危）。在中国，绿皇鸠属于国家二级保护动物，受到栖息地破坏的影响，尤其是森林过度砍伐，导致数量近来急剧减少。","distribution":"绿皇鸠分布于南亚、东南亚和菲律宾，包括印度、斯里兰卡、中国南部、印尼诸岛和菲律宾。在中国，主要见于云南西双版纳、思茅和广东等地。","other":"绿皇鸠在某些地区可能面临过度狩猎和栖息地丧失的威胁，如在老挝和马来西亚半岛的部分地区。"},{"name":"尼柯巴皇鸠","english_name":"Nicobar Imperial Pigeon","scientific_name":"Ducula nicobarica","overview":"尼柯巴皇鸠（英文名：Nicobar Imperial Pigeon，学名：Ducula nicobarica），是鸽形目鸠鸽科皇鸠属的鸟类。主要分布在尼科巴群岛的热带雨林中。其上体呈绿色至棕色，头部和下体为灰色，腹部略带粉色调。这种皇鸠以果实和浆果为食，通常在树冠层结小群觅食。与绿皇鸠相似，但颜色更深，下体更灰，腹部呈棕色。","appearance":"尼柯巴皇鸠体型中等，雌雄同色。头部、颈部、上背、胸部和腹部为淡灰色，几乎不含粉色。眼周和喙基部有奶油白色羽毛，形成明显环带，下巴和髭纹基部也是白色。头顶和眉线更偏紫灰色，颈后和脖子更灰。上体（包括下背、肩羽、小翼羽和中覆羽）为金属光泽深蓝绿色，几乎无铜色反光，背部和尾上覆羽光泽减弱。大覆羽和三级飞羽光泽较少，绿色较浅。初级飞羽、次级飞羽和尾羽黑色，次级飞羽外缘有轻微绿或黑绿色光泽，尾羽光泽为深蓝绿色。肛门、大腿和胫骨上的羽毛比下体其他部分更苍白和灰。尾下覆羽暗褐色或非常深的棕色，向基部逐渐变淡和灰。尾腹面黑色。下翼淡灰色，飞行羽毛下方颜色变深和棕色。","call":"尼柯巴皇鸠的叫声包括悦耳的咕噜声和低沉的隆隆声，与绿皇鸠的叫声相比，更加柔和且不那么阴郁。","habits":"尼柯巴皇鸠栖息在热带雨林中，以果实和浆果为主要食物来源，常见于树冠层觅食。它们的飞行快速有力，通常在树冠上方飞行。","breeding":"尼柯巴皇鸠在1月至3月间繁殖。巢由松散排列的树枝构成的小平台，位于树冠或亚树冠层，高度在26至39米之间。通常产一枚白色、略带光泽的蛋，偶尔两枚，平均尺寸为48.6 x 36.2毫米。孵化由双亲共同承担，具体孵化期未知。","identification":"尼柯巴皇鸠与绿皇鸠相似，但尼柯巴皇鸠上体颜色更深，下体更灰，腹部呈棕色，叫声也有显著差异。","protection":"IUCN：NT（近危）。该物种受到限制，仅限于尼科巴群岛。尽管历史上非常常见，但在某些岛屿上由于过度猎杀而数量大幅下降。","distribution":"尼柯巴皇鸠的分布限于尼科巴群岛，包括主岛和其他一些小岛。","other":"尼柯巴皇鸠曾被视为绿皇鸠的亚种，但现在基于羽毛和叫声的巨大差异被认定为独立物种。"},{"name":"白眼皇鸠","english_name":"Spectacled Imperial Pigeon","scientific_name":"Ducula perspicillata","overview":"白眼皇鸠（英文名：Spectacled Imperial Pigeon，学名：Ducula perspicillata），是鸽形目鸠鸽科皇鸠属的鸟类。大型鸽类，背部绿色，腹部灰色，头部深灰，最显著特征为白色眼环。幼鸟色彩较为暗淡。分布于摩鹿加群岛的低地和山丘森林中，常见于树冠层，通常单独、成对或小群活动，偏好果实丰富的环境。","appearance":"体长41.5-43厘米，属于中到大型皇鸠，尾较长，体形较细长，前额陡峭。头部呈深蓝灰色，有醒目白色眼环和喙基部白色带纹；头颈部颜色由深灰渐变为浅灰至腹部粉灰；颈背绿色泛着蓝绿或青铜绿光泽；次级飞羽、主翼羽和尾羽呈深绿蓝色；尾下覆羽粉灰色；虹膜深棕色；喙灰蓝底色，基部红色；腿脚紫红色。雌雄外观相似，但雌鸟体型较小。幼鸟色彩略显暗淡。","call":"常发出一系列六至八个响亮、音调较低的下降式“hoo”音，首音最长并上扬，例如“whoo-woo-woo-woo-oo-oo-oo”，有时加速结束，间隔2-3秒重复。还发出柔和上升的“br-r-r”声和音高先升后降的低沉咕噜声。","habits":"偏好原始森林，尤其在低地，但也出现在高大次生林、种植园、椰子林、红树林和花园。通常单独或成对觅食，偶尔以小群体形式出现。主要以较大果实为食，于树冠层进食。","breeding":"繁殖信息知之甚少，但在2月-3月期间观察到繁殖行为，11月在布鲁岛记录到筑巢活动。","identification":"与Seram皇鸠区别明显，主要在于其更深的灰色头部、较少青铜绿的背部和翅膀，以及不同的鸣叫声。","protection":"IUCN：LC（无危）。全球数量估计超过50万只，1989年仅在布鲁岛估算有382,000只个体。在Halmahera东北部拟建的Lolobata保护区（1060平方公里）内，1990年代中期约有22,100只个体。","distribution":"分布于澳新界，具体包括印尼的摩罗泰岛至Obi岛（北摩鹿加群岛）、布鲁岛（中西部摩鹿加群岛）和Kofiau岛（四王群岛，位于新几内亚西北部）。","other":"在Kofiau岛上最近被发现，数量丰富，栖息于原始和次生森林的树冠层，以及花园中的残存树木，单独或形成多达30只的小群体。"},{"name":"赛兰皇鸠","english_name":"Seram Imperial Pigeon","scientific_name":"Ducula neglecta","overview":"赛兰皇鸠（英文名：Seram Imperial Pigeon，学名：Ducula neglecta），是鸽形目鸠鸽科皇鸠属的鸟类。其特征为绿色背部和尾巴，头部和下体呈淡灰色，眼周有显著的白色眼圈。特有于印度尼西亚的赛兰岛和安汶岛，栖息于低地森林和红树林。","appearance":"赛兰皇鸠身长42至44厘米，与近似物种白眼皇鸠相比，体型略大，整体颜色更浅。头部和颈部为浅灰色，腹部颜色稍深于白眼皇鸠。后颈呈纯灰色，喙基部羽毛延伸至两侧，上体羽毛具有金色绿调的光泽，翼羽带有银色光泽。雌雄外观相似，幼鸟细节未具体描述，无亚种区别。","call":"发出类似“ooWOO”的叫声，第二音节带有呼噜质感。此外，还会发出一系列下降的短促‘oo’音符。","habits":"赛兰皇鸠独居或成对出现在低地和山丘的森林及其边缘地带。它们以果实为主食，在树冠层觅食大型果实。","identification":"与白眼皇鸠相比，赛兰皇鸠的头部颜色更浅，背部和翅膀具有更多的青铜绿色光泽，声音也有所不同。","protection":"IUCN：LC（无全球性威胁）。1990年代在赛兰岛的原始和选择性砍伐森林中报告的密度为100-150只/平方公里。在Manusela国家公园（中赛兰）常见到丰盛。","distribution":"分布于澳新界的印尼斯兰岛，包括赛兰岛、Boano（西北部，印尼斯兰岛）、安汶岛和Saparua（南部，西赛兰岛；东中摩鹿加群岛）。","other":"历史上通常被认为与白眼皇鸠同种，但基于其独特性状和不同的声音，现在被视为独立物种。"},{"name":"蓝尾皇鸠","english_name":"Elegant Imperial Pigeon","scientific_name":"Ducula concinna","overview":"蓝尾皇鸠（英文名：Elegant Imperial Pigeon，学名：Ducula concinna），是鸽形目鸠鸽科皇鸠属的鸟类。大型鸽类，分布于小岛上的森林边缘和树植园中。其头部和下体呈淡灰色，背部绿色带有金属光泽，尾巴蓝色，下尾覆羽红棕色。","appearance":"蓝尾皇鸠体长约43厘米。头部、颈部和上背为淡银灰色，后冠和颈背带微粉色；上体大部分为深绿色，闪烁着金属光泽，翅膀和尾部上侧为暗紫蓝色（常看似黑色）；下体为淡银灰色，带有微弱的粉色；下尾覆羽红棕色；尾部下侧和翅膀下侧全黑，与淡灰色下体形成对比；喙黑色或蓝灰色；眼金黄色；腿脚粉红至鲜红色。两性相似，但雌鸟灰、粉色部位略暗。幼鸟外观似成鸟但较暗淡。","call":"发出响亮、沙哑类似犬吠的‘urrauw’声，间隔不规律，穿插着低沉、响亮、短促或拉长的哼哼声。通常一只鸟发出吠声，另一只以哼哼声回应。","habits":"栖息于原生林、次生林、林缘和树植园，主要位于低地，但有时可达海拔至少850米。群居，被认为会在小岛间迁徙寻找食物。已知饮食包括年轻椰子果实和多种水果。","breeding":"筑巢活动于8月在Damar岛观察到，巢位在原生常绿森林中距地面25至30米高处。","identification":"通过黄色眼球、淡灰色头部和下体、红棕色下尾覆羽以及绿色背部、翅膀和上尾区别的特征与同属物种区分。","protection":"IUCN：LC（无危）","distribution":"分布于华莱士区的小岛，包括Sangihe和Talaud群岛（苏拉威西东北北部）、佛洛勒斯海岛屿、东起Romang（帝汶东侧）的东小巽他群岛、班达群岛、马努克岛、Kai和Tanimbar群岛（南摩鹿加）、Aru群岛（新几内亚西南）以及Bombeari半岛和Bird's Neck（新几内亚西北）附近的岛屿。"},{"name":"太平洋皇鸠","english_name":"Pacific Imperial Pigeon","scientific_name":"Ducula pacifica","overview":"太平洋皇鸠（英文名：Pacific Imperial Pigeon，学名：Ducula pacifica），是鸽形目鸠鸽科皇鸠属的鸟类。主要栖息在南太平洋的小岛和大岛的热带森林中，常见于美国萨摩亚、库克群岛等地，是汤加的象征性鸟类。具有独特的黑肉瘤，体型较大，灰身绿翼。","appearance":"体长约36-41厘米，体重370-420克。头部和颈部呈淡灰色，胸部灰色带粉红调；背部、尾巴和翅膀黑色带绿色光泽；翼内侧板石灰色；尾下覆羽肉桂棕色；喙黑色，上喙基部有明显肉瘤；腿红棕色；虹膜红色。雌鸟略小。幼鸟相似但喙上无肉瘤，颜色较暗淡，胸部无粉色，虹膜棕色。","call":"发出延长的、快速泡泡状‘crrrroooooo’叫声。叫声包括五音系列的‘wooiiip-pu pu po po’，以及四种单音调叫声，有高音下降的‘br-r-r’声，断续音调上升后下降，有喉颤感，低音调缓慢上升后快速下降，以及升调的咆哮声。","habits":"栖息于大岛海拔1000米以下的山地雨林，小岛的干燥沿海森林和灌木丛，很少见于450米以上。季节性迁移以利用各岛的果林资源。主要以果实为食，偶尔吃嫩叶和花，偏好大型种子的水果。在树冠中觅食，有时倒挂或伸展以触及细枝上的果实，偶尔地面觅食。常形成大群在喜爱的果树上聚集。","breeding":"在图图伊拉岛，筑巢期为1月到9月，多数记录在5月至8月。巢隐蔽于高树冠，由树枝搭建，不加衬垫，通常高度20-25米，偶尔8米高。每窝产一枚白色卵，偶尔两枚；双亲共同孵卵和喂养雏鸟。成鸟可能持续守卫巢穴而不孵卵。","identification":"与灰皇鸠相比，太平洋皇鸠体型较小，整体颜色更深，尤其是翅膀；成年个体通过黑色喙上的肉瘤区别。幼鸟缺乏肉瘤，颜色较暗淡。","protection":"IUCN：LC（无危）。全球数量不明，但在巴布亚新几内亚和所罗门群岛普遍，瓦努阿图常见至丰富，托克劳、纽埃和美属萨摩亚罕见，新喀里多尼亚稀少，库克群岛局部常见。","distribution":"分布于美国萨摩亚、库克群岛、斐济东部小岛、基里巴斯、纽埃、巴布亚新几内亚卫星岛、萨摩亚、所罗门群岛、托克劳、汤加、图瓦卢、瓦努阿图、瓦利斯和富图纳群岛。","other":"历史上，太平洋皇鸠在汤加和萨摩亚具有文化重要性，人们使用复杂的陷阱捕获它们。尽管现在受到保护，但仍面临非法狩猎的威胁，特别是在小岛上。"},{"name":"密克皇鸠","english_name":"Micronesian Imperial Pigeon","scientific_name":"Ducula oceanica","overview":"密克皇鸠（英文名：Micronesian Imperial Pigeon，学名：Ducula oceanica），是鸽形目鸠鸽科皇鸠属的大型鸽类。体长约为36厘米，重340至406克，头部和颈部呈灰黑色，背部和翅膀覆羽为暗绿色，带有深蓝色光泽。腹部和臀部为红褐色，喙为石板黑色，蜡膜为黑色，眼睛为红棕色，脚为紫红色。雌鸟和幼鸟颜色较暗。该物种广泛分布于太平洋的帕劳、密克罗尼西亚联邦的雅浦岛、丘克州、波纳佩岛、科斯雷岛以及马绍尔群岛。","appearance":"密克皇鸠体型较大，全长约36厘米，体重介于340至406克之间。上体部分为黑色，带有一层蓝绿色光泽；头部、颈部及胸部为灰白色，腹部及下尾覆羽呈红褐色。成鸟具有显著的黑色角状蜡膜；腿为红黑色。雌鸟个体比雄鸟略小。幼鸟外观类似成鸟，但整体色调较淡，腿部颜色较深，且缺乏成鸟的角状蜡膜；非常年轻的鸟儿背部羽毛为棕色，翼羽边缘为锈色。亚种间主要通过体型大小和头部颜色差异进行区分。","call":"密克皇鸠的鸣叫声包括一系列逐渐缩短的嘶哑咆哮声，如'grrow... grrow... grow grow-gr-gr'，有时也会发出一系列节奏稳定的类似吠叫的声音，或者是一连串低沉的咕噜声。","habits":"密克皇鸠适应多种生境，但偏好未受干扰的森林环境。它们主要在树冠层活动，以果实和肉质种子为食。分布范围跨越太平洋的多个岛屿，包括帕劳、密克罗尼西亚联邦的雅浦岛、丘克州、波纳佩岛、科斯雷岛以及马绍尔群岛。在不被猎捕的区域，它们会出现在次生林、海滩森林和红树林中，甚至在椰子种植园中也能见到其身影。","breeding":"繁殖季节可能全年发生，但具体信息有限。巢由松散的枝条构成，搭建在高树的枝叉处，每次仅产一枚卵。","identification":"与其他皇鸠属鸟类相比，密克皇鸠可通过其较大的体型、灰黑色的头部和颈部、背部的蓝绿色光泽以及独特的黑色角状蜡膜来辨别。亚种之间的区别主要基于体型大小和头部颜色的差异。","protection":"IUCN：VU（易危）。在帕劳、雅浦岛、丘克州、波纳佩岛、科斯雷岛和马绍尔群岛等地都有分布，但数量自1983年以来在某些岛屿上已大幅减少。在波纳佩岛，1983年至1994年间种群减少了约70%，帕劳种群在1991年至2005年期间减少了40%，之后继续下降。丘克州的种群现在处于极度濒危状态，甚至可能已经灭绝。在瑙鲁的高地，2006年至2007年间估计仍有75至100只存活。然而，该物种可能已在基里巴斯和许多马绍尔群岛灭绝。","distribution":"密克皇鸠分布于太平洋地区的帕劳、密克罗尼西亚联邦的雅浦岛、丘克州、波纳佩岛、科斯雷岛以及马绍尔群岛。在帕劳和科斯雷岛，主要生活在山区。在不受猎捕的区域，它们可见于次生林、海滩森林和红树林，甚至在椰子种植园中。该物种曾经存在于马里亚纳群岛，但目前可能已经在许多马绍尔群岛灭绝。","other":"密克皇鸠面临的主要威胁是狩猎压力和栖息地丧失，尤其是森林砍伐导致的土地用于农业。虽然在其分布范围内有地方性的狩猎法规提供了一定程度的理论保护，但实际执行力度不足。"},{"name":"马克萨斯皇鸠","english_name":"Marquesan Imperial Pigeon","scientific_name":"Ducula galeata","overview":"马克萨斯皇鸠（英文名：Nuku Hiva Imperial Pigeon，学名：Ducula galeata），是鸽形目鸠鸽科皇鸠属的鸟类。大型鸽类，仅分布于法属波利尼西亚马克萨斯群岛的Nuku Hiva岛西部山谷。体长可达55厘米，头部大而长，背部绿光闪烁，体色以深灰色为主，胸腹略带褐色，尾羽下侧呈栗色。","appearance":"马克萨斯皇鸠体型庞大，雄鸟长度约55厘米，雌鸟稍小，长50至53.5厘米。头部突出，颈后有肉质鞍状突起，嘴基部白色羽毛环绕。上体绿色光泽，下体暗灰，尾翼下方黑色。嘴黑色，脚趾暗红，眼白。幼鸟羽毛色泽较淡，具红棕色边缘，质地松软。","call":"马克萨斯皇鸠的叫声特别，清晨时分常发出类似乌鸦的刺耳声'krrrahhh'，也有低沉的咕咕声'neah-ah-ah-ah-ah'或'naw-aw-aw'。","habits":"栖息于海拔700米以上的偏远森林山谷，偏好高树栖息。主要食物为果实，尤其是番石榴和Terminalia catappa的大果仁，有时也食用Ficus、Psidium guajava的果实及Sapindus saponaria的毛虫。白天大部分时间在树冠层活动，飞越森林山脊时翅膀拍打沉重。","breeding":"繁殖期不确定，可能全年皆可，或集中在年中。巢建于森林树中层，由枝条构成，高度13至20米，产单枚浅奶油色蛋。","identification":"与其他皇鸠相比，马克萨斯皇鸠体型更大，头部更长，尾羽较长，上体绿色光泽，胸腹深灰，尾下侧栗色。","protection":"IUCN：EN（濒危）","distribution":"太平洋地区，仅限于法属波利尼西亚东北部马克萨斯群岛中部的Nuku Hiva岛。","other":"历史上曾在库克群岛、社会群岛和皮特凯恩群岛存在，现已灭绝。"},{"name":"红疣皇鸠","english_name":"Red-knobbed Imperial Pigeon","scientific_name":"Ducula rubricera","overview":"红疣皇鸠（英文名：Red-knobbed Imperial Pigeon，学名：Ducula rubricera），是鸽形目鸠鸽科皇鸠属的鸟类。最显著的是其嘴上方的大红色瘤状物。广泛分布在各种生境中，偏好原始森林。在澳新界，包括俾斯麦群岛和所罗门群岛，可以找到它们的身影。","appearance":"成鸟具有灰紫色的头部、颈背和上胸，逐渐过渡到较深的粉红色下胸，至栗色的腹部、胁部和下尾覆羽。颈背呈淡银灰色，有一条窄白带环绕着嘴基和眼睛；背部、臀部和翼上覆羽呈现出耀眼的绿宝石色，青铜色或金色光泽；次级飞羽和尾羽为深绿色和黑蓝色；主飞羽为黑蓝色；下翼暗灰色；虹膜深红色；喙深灰色；瘤状的鼻甲樱桃红色，个别个体为黄色；腿脚紫红色。两性相似，但雌鸟的背部有时缺乏金属光泽。幼鸟外观类似成鸟，但缺乏红肿的鼻甲。rufigula亚种头部的粉色限于脸颊和喉部，冠部、颈部和胸部为浅灰色；下胸颜色更深，体下部更接近栗色。","call":"在所罗门群岛，发出低沉拉长的呼叫声，音量先增后减，带有轻微的频率调制，听起来像是“whooOOOoooh”（持续约2秒）。还有一种重复的、音调较高且粗糙的咕噜声，‘rrrhooou’（持续约0.5-1.0秒）。此外，还有一种奇特的吠叫声，由5-6个音节组成，‘kow..k-yow..k-yow..k-yow..k-yow’。这三种叫声也在新不列颠岛被听到，可能有些许差异。","habits":"主要栖息在原始森林和次生林中，偶尔出现在部分清理过的区域的果树林中。海拔分布从海平面至300米（布干维尔岛）、700米（新爱尔兰岛）、1000米（新不列颠岛）乃至1100米（所罗门群岛）。经常在树冠上方飞行，飞行能力强。以各种果实和浆果为食，通常单独或成对觅食，但曾记录到最多34只的群聚现象。","breeding":"关于繁殖的信息有限。据报道，在2月的中所罗门群岛，大量鸟群在低矮的灌木丛中筑巢；在布干维尔岛，收集到了处于繁殖状态的标本，时间跨度为7月至9月。每窝仅产一枚蛋。","identification":"幼鸟与成鸟相似，但缺少成鸟特有的红色鼻甲。与芬氏皇鸠相比，红疣皇鸠有更淡的红褐色体下部，缺乏白色眼环和尾部的白色带。","protection":"IUCN：LC（无危）。全球估计有15,000至30,000只个体。在大片森林未受破坏的地区仍然常见，但在退化生境中数量稀少。近年来，由于低地森林的持续清除，尤其是在新不列颠岛，其种群数量可能迅速下降。","distribution":"红疣皇鸠分布于俾斯麦群岛和所罗门群岛。在澳大利亚-新西兰生物地理区，它们在上述两个群岛中都有分布。","other":"红疣皇鸠通常成群结队地觅食，群体规模在5到10只之间。"},{"name":"黑疣皇鸠","english_name":"Spice Imperial Pigeon","scientific_name":"Ducula myristicivora","overview":"黑疣皇鸠（英文名：Spice Imperial Pigeon，学名：Ducula myristicivora），是鸽形目鸠鸽科皇鸠属的鸟类。分布于印度尼西亚东部摩鹿加群岛和拉贾安帕特群岛，栖息于热带低地森林和红树林中，以果实为食，对种子传播至关重要。","appearance":"黑疣皇鸠头部、颈部和胸部呈淡银灰色，略带粉色。喙基部有奶油白色环带，眼周白环在部分群体可见；后冠和颈背淡粉红色；下胸和腹部淡紫罗兰色或灰粉色，与上胸灰色和更深的灰粉色侧腹形成渐变；翼下覆羽深栗色；背部、翅膀和覆羽具有金属光泽的翡翠绿色，视角度呈现蓝色或青铜色光泽；主翼羽、次级飞羽和尾羽为深绿至深蓝黑色，尾羽最蓝，翼端最绿；虹膜红褐色、橙色或鲜红色；喙和膨大的瘤状额骨黑色；腿暗红色。两性相似，雌鸟稍小。幼鸟缺乏膨大的瘤状额骨，翼下覆羽较浅的栗色，上尾更绿。蓝尾皇鸠可能在该物种范围内游荡，外观似幼鸟，但体型更大，头部和下体颜色更浅，仅颈背有粉色，胸部和腹部无明显对比，虹膜黄色，翼下覆羽黑色，与初级飞羽无对比（而本物种翼下覆羽为板岩灰色，与黑色初级飞羽略有对比）。","call":"广告叫声为相对高音、泡泡般的“crrruooo”或“urwoow”，音调逐渐升高；另一种叫声为深沉、缓慢发出的“whooooo”，音调先上升后略微下降，间隔约7秒重复。","habits":"黑疣皇鸠栖息于各种森林环境，包括原始林、次生林和采伐过的森林，以及红树林。主要分布在小型岛屿和低地。定期在岛屿间短距离移动，偶尔长距离迁徙，到达邻近大陆，如在新几内亚西北部的沃格尔科普半岛索龙地区出现过流浪记录。","breeding":"关于繁殖信息未知。","identification":"与白眼皇鸠的区别在于后者眼周有白色眼圈，喙上无瘤状突起。与灰枕皇鸠的区别在于后者较小，缺乏后颈的淡紫色洗涤，头、胸和披肩颜色较暗，下体较脏、较深，虹膜黄色而非红色，且无膨大的黑色瘤状额骨。","protection":"IUCN：LC（无危）。在西巴布亚群岛稀少且局部分布，尤其在较大的岛屿上更为罕见。在辛纳庞岛报告为常见，但在相邻的较大岛屿巴坦塔和萨拉瓦蒂岛上罕见。Widi岛仅有单一旧记录，当前状态未知，需验证。","distribution":"分布于Widi岛（哈马黑拉岛东南方，北摩鹿加群岛；一条旧记录）、格贝岛（新几内亚西北）和拉贾安帕特群岛（新几内亚西北）。","other":"灰枕皇鸠曾被认为是同种，但2021年被IOC认定为独立物种。"},{"name":"紫尾皇鸠","english_name":"Purple-tailed Imperial Pigeon","scientific_name":"Ducula rufigaster","overview":"紫尾皇鸠（英文名：Purple-tailed Imperial Pigeon，学名：Ducula rufigaster），是鸽形目鸠鸽科皇鸠属的鸟类。广泛分布在新几内亚及其周边岛屿的低地和山脚雨林内部。其最显著的特征是拥有紫色的尾巴，淡粉色的头部，橙色的下体，翅膀和背部呈金属绿翡翠色，腹部为淡黄色，下尾羽为白色，尾部末端三分之一为灰色，上体部分带有蓝灰色。该物种通常单独行动，难以观察到，飞行高度通常不超过树冠层。","appearance":"紫尾皇鸠的体长约为33至39厘米，体重在414至582克之间。体型较圆润，翅膀和尾巴比许多其他皇鸠属物种短。头部和前颈为淡紫粉色，逐渐过渡到胸部和侧翼的金红色，腹部为淡黄色，下尾羽为白色。后颈和上背为蓝灰色，翅膀和背部有紫红色的金属光泽，臀部和尾基三分之二为紫红色，尾端三分之一为灰色，尾下覆羽为暗灰色，尾端有一条明显的浅灰色带。雌雄相似，但雌鸟头部颜色更深，上体的紫红光泽较少。幼鸟外观类似成鸟，但色泽较为暗淡。uropygialis亚种的上体颜色更加均匀，臀部和下体颜色更浅。","call":"紫尾皇鸠的叫声特征明显，开始时发出两声敲击般的‘tuk-tuk’音，随后是一段较长的、略显不和谐的上升再下降的‘ooo-woo-ooo’音调。","habits":"紫尾皇鸠栖息于森林内部及其边缘，主要分布在低地和山脚地带，海拔高度通常不超过600米，局部地区可达1200米。它们飞行时保持在树冠或树冠下层，不会长时间在树冠上方飞行。以果实为食，主要食物来源包括棕榈科、肉豆蔻科、月桂科、金合欢科和桑科的植物。通常独自在树冠较低的部分觅食。","breeding":"关于紫尾皇鸠的繁殖信息目前尚无具体数据。","identification":"紫尾皇鸠与红胸皇鸠相似，但紫尾皇鸠分布于更低的海拔，具有明显的灰白色尾部条纹。uropygialis亚种的上体颜色更为统一，臀部和下体颜色更浅，可作为亚种间的辨识要点。","protection":"IUCN：LC（无全球性威胁）。在新几内亚地区，紫尾皇鸠虽然在当地被认为是相对常见的，但由于其隐秘的生活习性，实际观察到的机会不多，需要进一步的研究。","distribution":"紫尾皇鸠主要分布在新几内亚及其周边岛屿，包括四王群岛（位于新几内亚西北部）、印尼亚彭岛（鸟头湾，新几内亚西北部）。"},{"name":"棕腹皇鸠","english_name":"Cinnamon-bellied Imperial Pigeon","scientific_name":"Ducula basilica","overview":"棕腹皇鸠（英文名：Cinnamon-bellied Imperial Pigeon，学名：Ducula basilica），是鸽形目鸠鸽科皇鸠属的大型、特色鲜明的鸠类。其头部和颈部为淡粉色，腹部呈深肉桂色，上体和尾巴为暗绿色，尾端有一宽阔的淡色带。分布于印尼摩鹿加群岛北部的森林地带，包括被破坏的森林和种植园。","appearance":"成年棕腹皇鸠体型中等偏大，体长约36至42厘米，体态丰满，尾巴较短。头部、颈部两侧和胸部为浅粉色；其余下体为浅金色红褐色；后颈为淡蓝灰色；背部、肩部、臀部、上尾覆羽、翼覆羽和次级飞羽为绿宝石或金绿色，仅带有少量红色金属光泽；初级飞羽和尾羽为蓝黑色；尾巴末端有一宽阔的灰白色带；虹膜深红色，眼周皮肤和眼睑红色，喙呈暗铅灰色，脚和趾珊瑚红色。雌雄相似，但雌鸟头部颜色更深，上体常缺乏红铜色光泽。幼鸟外观与成鸟类似，但色彩较为暗淡。","call":"棕腹皇鸠发出标志性的深沉两音节咕噜声，‘ku-woooo’，首音节短促上升，第二音节更长。","habits":"栖息于茂密的原始雨林和选择性砍伐的常绿森林，包括树木栽培区；通常在中层和下层树冠活动，但也栖息于高大的树梢上，有时出现在种植园中。海拔分布从海平面至1040米，偏好亚山地森林。在哈马黑拉岛上，常见于150至600米的高度。","breeding":"关于繁殖行为的信息未知。","identification":"与白眼皇鸠的区别在于粉色头部、无明显眼环、肉桂色腹部和尾端的淡色带。指名亚种与亚种 obiensis 相比，头部、颈部和胸部颜色更深，腹部和下体的锈色更深，延伸至腋下和内侧下翼覆羽；尾端灰白色带无金属光泽。","protection":"IUCN：LC（无危）。总数量未知，但在1994年估计在哈马黑拉东北部Aketajawe-Lolobata国家公园约有80,600只个体。总体上，在其有限的分布区内普遍较为常见，但在沿海地区罕见。","distribution":"分布于澳大利亚新几内亚区的印尼摩鹿加群岛北部。","other":"曾被认为是紫尾皇鸠的亚种。"},{"name":"芬氏皇鸠","english_name":"Finsch's Imperial Pigeon","scientific_name":"Ducula finschii","overview":"芬氏皇鸠（英文名：Finsch's Imperial Pigeon，学名：Ducula finschii），是鸽形目鸠鸽科皇鸠属的鸟类。又称芬氏皇鸽，大型皇鸠。其最显著的外部特征是拥有深栗色的腹部，亮绿色的背部与翅膀，淡粉色的胸部，灰色的颈部，以及一圈白色的眼环。在澳新界，分布于Lavongai（新汉诺威）、新爱尔兰、Umboi（西部新不列颠岛）和新不列颠岛（俾斯麦群岛东部）。此物种被评估为近危状态。","appearance":"体型较为饱满，长度约35至38厘米，体重383克。头部、颈部、上背及上胸为浅蓝灰色，带粉红晕染；眼周有白色环；主翼羽呈蓝黑色；尾羽蓝黑色，带有宽阔的白色亚端斑和较窄的绿色终端条纹；其余上部羽毛为翠绿或金色，肩部有金属青铜光泽；下部羽毛为赤褐色；虹膜红色，喙黑色，腿红色。性别差异不大，雌鸟头部偏暗灰，胸部有灰调。幼鸟特征未详述。","call":"声音记录不多，已知的鸣声为重复的低沉、略带模糊的长音呼噜声，类似蒸汽火车的哨声，但有时难以与同域的红疣皇鸠区分。","habits":"栖息于低地、山脚及较低海拔的山地森林，高度可达约1500米。在西新不列颠的山脉中，此物种被认为是罕见的，特别是在Whiteman山脉和Mt Talawe，仅限于低地和山脚森林。未见其频繁飞越树冠之上。以果实为食，具体觅食行为不详。","identification":"与幼年红疣皇鸠可能混淆，但后者缺乏明显的尾部图案。雄雌相似，但雌鸟头部颜色更深，胸部有灰洗色。","protection":"IUCN：NT（近危）","distribution":"主要分布在澳新界，包括Lavongai（新汉诺威）、新爱尔兰、Umboi（西部新不列颠岛）和新不列颠岛（俾斯麦群岛东部）。","other":"由于低地森林的持续清除，尤其是新不列颠岛上油棕种植园的扩张，其数量疑似迅速下降。"},{"name":"红胸皇鸠","english_name":"Rufescent Imperial Pigeon","scientific_name":"Ducula chalconota","overview":"红胸皇鸠（英文名：Rufescent Imperial Pigeon，学名：Ducula chalconota），是鸽形目鸠鸽科皇鸠属的鸟类。该鸟种通常独居或成对生活，主要栖息于新几内亚的高山森林中。","appearance":"成年红胸皇鸠体长可达37至39厘米，体重约613克。头部和颈部呈深蓝灰色，喉部粉棕色，逐渐变为深栗色的腹部和两胁，下尾羽覆羽浅栗色；背部闪亮的青铜绿色或绿宝石绿色，肩部、背部和臀部有广泛的紫红色虹彩；尾部蓝黑色，末端有暗灰色带；虹膜深红色；喙黑色，基部暗红色；腿紫红色。雄雌相似，但雌鸟可能表现出较少的红色虹彩。幼鸟相似但颜色较暗淡。亚种smaragdina体型略大，上体更绿，肩部、背部和臀部缺乏红色虹彩。","call":"红胸皇鸠不太爱鸣叫，叫声为缓慢、低沉、哀怨的哼鸣声，由三个音符模糊连在一起，以及哀伤的低沉‘hoo’声，受到惊吓时会发出空洞的敲击声。","habits":"主要栖息于新几内亚的原始山地森林内部，海拔范围通常在1400至2500米之间，偶尔低至1100米。以果实为食，尤其是无花果和大型水果，通常在森林的中层和上层觅食，独行或成对出现。","breeding":"繁殖细节尚不明确，但在二月和三月曾采集到处于繁殖状态的标本。","identification":"与紫尾皇鸠相比，红胸皇鸠出现在更高的海拔，颈部两侧有更多灰色。与裸眶山鸠相比，红胸皇鸠胸部无白色，背部为绿色而非灰色。","protection":"IUCN：LC（最不受关注）","distribution":"主要分布在新几内亚的山地森林中，繁殖区域一般位于1400至2500米的海拔高度。","other":"关于其系统学历史和具体保护措施的信息非常有限，需要进一步的研究和调查工作以确定当前的种群规模、趋势和潜在威胁。"},{"name":"灰皇鸠","english_name":"Island Imperial Pigeon","scientific_name":"Ducula pistrinaria","overview":"灰皇鸠（英文名：Island Imperial Pigeon，学名：Ducula pistrinaria），是鸽形目鸠鸽科皇鸠属的大型鸟类。主要分布在澳新界的岛屿上，包括新几内亚以北、以东至俾斯麦群岛和所罗门群岛。整体呈灰色，头部和颈部颜色较淡，翅膀和背部光泽绿灰色。","appearance":"成年灰皇鸠体长约38-44厘米，体重约470-500克。头部和颈部呈浅灰色，眼圈白色，上体具有金属光泽，翼覆羽和三级飞羽灰绿色，主飞羽和次级飞羽黑色带银色光泽，背部绿灰色。尾上覆羽深蓝绿色，尾下覆羽暗栗色，喉部酒红色，胸部灰酒红色，腹部灰驼色。喙蓝灰色，尖端黑色，眼睛暗红或褐色，脚红色。幼鸟较为暗淡，上体和翼部羽毛边缘带有窄边黄褐色。四个亚种在大小和光泽上有差异。","call":"其广告鸣声独特，高音“啊呼 啊呼 啊呼 啊呼 啊呼”，音调和音量逐渐下降；还会发出一种奇特的高音颤音。","habits":"栖息于原始森林和发育良好的次生林，也会访问部分被清理地区的果树。通常出现在小岛和大岛的沿海低地，最高记录海拔为新不列颠岛的250米和布干维尔岛的600米。至少部分迁徙，经常作长途海上飞行。飞行强劲而直线，常在树冠上方。","breeding":"繁殖期在布干维尔岛记录为7月至9月，尼桑岛全年皆有可能，确切记录在6月和8月。巢为较为结实的树枝平台，一巢位于南布干维尔岛30-35米高的水平枝末端，尼桑岛上的巢高度在3.5-17米。每窝产1枚卵，双亲共同孵卵。","identification":"与太平洋皇鸠相似，但整体更苍白。在阿德米拉尔蒂群岛的个体与幼年红疣皇鸠的区别在于腹面和下方为灰色而非肉桂色。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚以北、以东的小岛，以及俾斯麦群岛和所罗门群岛。具体包括Bismarck Archipelago和Solomon Islands等。"},{"name":"粉头皇鸠","english_name":"Pink-headed Imperial Pigeon","scientific_name":"Ducula rosacea","overview":"粉头皇鸠（英文名：Pink-headed Imperial Pigeon，学名：Ducula rosacea），是鸽形目鸠鸽科皇鸠属的鸟类。大型优雅的鸽子，以其独特的粉头著称。主要分布在印尼的爪哇海、巴厘海和弗洛勒斯海的小型岛屿上，如Seribu群岛、Karimunjawa、Bawean等地。该物种在一些岛屿上相对常见。","appearance":"成年粉头皇鸠体长39-44厘米，体重360-395克。头部及喉部上方为淡紫粉色或鲑鱼粉色；喉部和颈部其余部分为浅灰色；上胸为粉灰色，逐渐变为下胸和腹部的淡紫粉色；背部和翅膀为暗青铜绿色，带蓝色调，略显银灰；初级飞羽黑色带银灰；尾巴黑色带绿；下尾覆羽栗色；眼周有白色环圈和嘴基部的白色带，但不如灰皇鸠明显；虹膜深棕色，眼眶有一窄红环；喙蓝灰色，蜡膜红色或紫色；腿红色或红紫色。雌雄相似，幼鸟较为暗淡，翅膀和下体羽毛边缘呈淡褐色。","call":"其最常见的叫声是一系列加速的5-7个咕咕声，音调逐渐缩短，类似于“wooh..wooh..woh.wuh.wu”。还有低沉的呼呼声“whoooo”和类似的双音节呼呼声。","habits":"粉头皇鸠栖息于多种森林类型，从沿海的原始森林到低地和山地森林；也会出现在有树木的林地灌木丛和耕地上，主要在树冠层活动。它们通常生活在小型岛屿上，但也可能出现在较大岛屿的海岸线附近，如苏拉威西岛，甚至内陆地区；主要在低地，但在Bacan岛高达120米，Alor岛约200米，Timor岛可达1100米。它们可能进行岛屿间的移动以寻找果实。","breeding":"繁殖记录显示，粉头皇鸠在Wetar、Semau和Karimunjawa国家公园的树上筑巢，高度从11米到15米不等。巢中曾发现雏鸟，具体繁殖信息尚不详。","identification":"与绿皇鸠相比，粉头皇鸠的上部颜色更淡，缺乏后者明显的浅灰色“领”。","protection":"IUCN：NT（近危）","distribution":"主要分布于印尼的爪哇海、巴厘海和弗洛勒斯海的小型岛屿，包括Seribu群岛、Karimunjawa、Bawean等，以及苏拉威西岛南部、Satonda岛至Babar岛（小巽他群岛）、印尼摩鹿加群岛北部和南部的Tayandu、Kai和塔宁巴尔群岛。"},{"name":"圣诞岛皇鸠","english_name":"Christmas Imperial Pigeon","scientific_name":"Ducula whartoni","overview":"圣诞岛皇鸠（英文名：Christmas Imperial Pigeon，学名：Ducula whartoni），是鸽形目鸠鸽科皇鸠属的大型皇鸠。以灰蓝色为主色调，幼鸟比成鸟色彩暗淡。圣诞岛皇鸠是印度洋东北部圣诞岛上特有种，以其软绵绵的咕咕声和深沉的呼呼声闻名。每次繁殖仅产一枚光滑的白色蛋，可能以群居形式繁殖。","appearance":"成年圣诞岛皇鸠体长平均在435至470毫米之间，翼展宽约250至264毫米，体重介于383至700克。雄鸟和雌鸟外观相似，整体呈灰黑色，背部和上部羽毛颜色较深，胸部和腹部羽毛带有酒红色光泽。喙部黑色，眼色从黄色到橙色不等。颈背和背部有油绿色光泽，翅膀尖端呈现蓝绿色光泽，近基部则为灰褐色。尾羽尖端宽大，呈绿褐色，边缘有轻微的波纹状，腿和尾巴下方的羽毛为红棕色。脚为紫红色。幼鸟与成鸟外观类似，但色泽较为暗淡，胸部和腹部为棕色，头冠为灰色，脚为灰棕色，眼色为深棕色。","call":"圣诞岛皇鸠会发出柔和的咕噜声或咕咕声，也会发出深沉的呼呼声，这种声音有时被比喻为远处牛的哞哞声。","habits":"圣诞岛皇鸠主要栖息在热带内陆高原的原始和次生雨林中，包括种植有外来日本樱桃树(Muntingia calabura)的区域。它偶尔出现在海岸森林，尤其是在果实丰富的季节。圣诞岛皇鸠通常不会迁徙，但会进行局部移动以寻找食物和水源。它以果实为主食，偶尔食用花蕾和叶子，包括Carica papaya的叶子。它主要在树冠层觅食，当食物丰富时，会聚集大量同类。","breeding":"繁殖季节从8月底持续至次年2月，圣诞岛皇鸠可能以松散的群体形式筑巢。巢由少量细枝构成，通常位于树冠中，但也有低至4米的情况。每窝产卵一枚，孵化出的雏鸟裸身，4至5天后开始长毛；约24至27天后离巢。据观察，雄鸟在求偶时会展示一种被称为“栖枝咕咕”的求偶行为。","identification":"圣诞岛皇鸠以其独特的灰蓝色调、黄眼睛、胸下部的栗色覆羽和喙上方的浅色斑块区别于其他种类。幼鸟相比成鸟色泽更暗淡，胸部和腹部为棕色，头部为灰色，脚为灰棕色，眼色为深棕色。","protection":"IUCN：LC（无危）","distribution":"圣诞岛皇鸠仅分布在印度洋东北部的圣诞岛，包括其内陆高原的原始和次生雨林，以及沿海森林。虽然部分岛屿曾因磷酸盐矿开采而遭受破坏，但引入的Jamaican樱桃树已成功复垦许多区域。","other":"历史上，圣诞岛皇鸠面临的主要威胁是狩猎，但在1977年被禁止。1980年宣布成立的圣诞岛国家公园覆盖了岛屿约63%的面积，尽管并非所有皇鸠偏好的栖息地都包含在内。"},{"name":"马来皇鸠","english_name":"Grey Imperial Pigeon","scientific_name":"Ducula pickeringii","overview":"马来皇鸠（英文名：Grey Imperial Pigeon，学名：Ducula pickeringii），是鸽形目鸠鸽科皇鸠属的鸟类。大型鸽类，以其优雅、丝滑的外观著称。全身羽毛呈光滑的珍珠灰色，翼、背及尾部为深灰色，特定光照下可见绿色金属光泽。常见于离岸岛屿的森林中，独行或成对出现在树冠层。叫声为低沉的‘coOOOooouh’。","appearance":"体长约37至40厘米。头部呈淡紫或灰粉，眼周具细白环，喙基部有奶油白色带；颈、胸及下体浅粉灰，胸部颜色最艳，颈部后方颜色最灰；背部、翅膀呈绿灰，略带虹彩；尾羽黑色绿边，老羽渐变淡灰；下尾覆羽灰粉微带锈色；虹膜深红；眼周皮肤灰；喙蓝灰，根部较暗；腿紫红。两性相似，雌鸟头部和胸部颜色偏淡。幼鸟似成鸟，但下体羽毛边缘淡锈色。","call":"最常发出的声音为模糊的过滑音‘rroow’，一串最多七音节，描述为像在绳端不规则摆动的物体声，或类似的双音节‘ro-rroow’，首音短（0.2秒），第二音长（1.2秒），间以0.5秒停顿。还有低沉的‘whoooo’叫声。","habits":"栖息于小岛上的低地森林，包括原始和高大的次生林；也见于退化的季雨林和有树木的种植园。可能在一定程度上具有游荡性，进行岛屿间的飞行。主要以果实为食，已知食用无花果和Cananga odorata的果实，偶尔食用花朵。通常单独或成对出现，有时与绿皇鸠相伴，偶尔与斑皇鸠一起。","breeding":"繁殖资料稀少；在Miangas岛上，一月时发现携蛋个体；在沙巴，七月收集到幼鸟；在婆罗洲，八月可能有繁殖活动。","identification":"与绿皇鸠相似，但灰皇鸠的翼部更暗，整体色彩更暗淡。可通过颜色和分布区进行区分。","protection":"IUCN：VU（易危）。全球估计数量为2500至10,000只。分布在小岛屿上，偏好原始森林。自1980年后，菲律宾和婆罗洲附近岛屿的记录显示其范围和数量显著减少。受到栖息地丧失和狩猎威胁。","distribution":"分布于婆罗洲东北部离岸岛屿，塔劳群岛（印尼苏拉威西岛东北部），Miangas岛（印尼极北部，棉兰老岛东南），苏禄海小岛（菲律宾南部）。在一些岛屿上局部分布，可能在岛屿间游荡。","other":"马来皇鸠在一些受保护区域如Tunku Abdul Rahman国家公园、Similajau国家公园等地有记录，但仅可能是访问者。"},{"name":"皮氏皇鸠","english_name":"Barking Imperial Pigeon","scientific_name":"Ducula latrans","overview":"皮氏皇鸠（英文名：Barking Imperial Pigeon，学名：Ducula latrans），是鸽形目鸠鸽科皇鸠属的鸟类。大型皇鸠，以灰褐色的外观、独特的叫声和广泛的森林栖息地著称。在斐济的中型至大型岛屿上常见，是斐济特有种之一。","appearance":"成年皮氏皇鸠长约40-44厘米，上体呈灰褐色，背部和翅膀颜色更深。下体淡紫灰色，腹部变为淡黄色，尾下覆羽暗黄色，翼内侧呈栗色。喙黑色，眼睛紫红色。性别相似，幼鸟较暗淡，羽毛边缘带有微弱的红棕色。","call":"最常发出类似猫头鹰的‘呼！..呼！..呼！’声，有时伴有粗哑的前奏音，类似远处狗吠的声音。还会发出短促而有力的刮擦声。","habits":"通常独居或成对出现在广阔的成熟森林中，海拔高度可达1000米。偏好直径12-25毫米以上的大果实，如Cananga、Dysoxylum和Myristica（肉豆蔻）等树种的果实。飞行能力强。","breeding":"繁殖季节为5月至次年1月，筑巢于树枝分叉处，由细枝搭建，每次产一枚白色蛋。","identification":"与太平洋皇鸠相比，皮氏皇鸠体型较大，身体灰褐色，翅膀绿色，通常在较大的岛屿上发现。","protection":"IUCN：LC（无危）。尽管在Vanua Levu、Taveuni和Rabi岛内部仍然相对常见，但在Viti Levu岛因狩猎和栖息地丧失导致数量减少，需持续监测。","distribution":"分布于斐济的中型至大型岛屿，主要栖息在成熟的热带湿润低地森林和湿润山地森林。"},{"name":"栗腹皇鸠","english_name":"Chestnut-bellied Imperial Pigeon","scientific_name":"Ducula brenchleyi","overview":"栗腹皇鸠（英文名：Chestnut-bellied Imperial Pigeon，学名：Ducula brenchleyi），是鸽形目鸠鸽科皇鸠属的鸟类。大型暗色皇鸠。拥有深栗色腹部和尾巴下方，头颈部颜色由银灰色渐变为蓝灰色，背部及翅膀具金属光泽。分布于所罗门群岛的南部岛屿，包括瓜达尔卡纳尔岛、马基拉岛及周边卫星岛屿。","appearance":"体型大，全长约40厘米。头部银灰色，喉部和面部带粉红赤褐色，颈后部暗蓝灰色，背部、臀部、翅膀和中央尾羽黑色带银色光泽。外侧尾羽深栗色，翼下覆羽和尾下覆羽栗色，上胸暗紫粉色，其余下体部分深栗色。虹膜深红色，喙黑色，腿和脚暗红色。两性相似。幼鸟较成鸟暗淡，胸部灰色，羽尖和中心带淡黄色，喉部淡黄色，具有不明显的赤褐色条纹。","call":"最常见叫声为低沉、延长的‘whu-ooooow’，有时会以一系列类似但较短的音符形式发出。","habits":"偏好成熟未受干扰的山地森林，高度范围通常为200至700米，反映了沿海地区严重森林砍伐的影响。2003年禁枪令后，物种已返回马基拉岛的沿海森林，甚至出现在次生林、花园等除可可种植园外的多种栖息地中。以果实为食，尤其是无花果。","breeding":"关于繁殖信息有限。已知巢穴位于12月的海滩旁小枝红木（Pterocarpus indicus）分叉处，距离地面10米，隐藏在附生植物中。","identification":"其独特的栗色下体和翼下覆羽使其在相似鸽种中易于识别。","protection":"IUCN：NT（近危）。过去曾被列为EN（濒危），估计现存个体数量在1,000至2,499之间。由于森林砍伐压力和猎杀，其栖息地受到威胁。","distribution":"分布于所罗门群岛南部，包括瓜达尔卡纳尔岛、马基拉岛（San Cristobal）及其卫星岛屿。在马基拉岛上较为常见，但在其他岛屿上罕见。","other":"自2003年枪支禁令后，该物种在马基拉岛的数量有所恢复，尤其是在山地和沿海森林中。"},{"name":"贝氏皇鸠","english_name":"Vanuatu Imperial Pigeon","scientific_name":"Ducula bakeri","overview":"贝氏皇鸠（英文名：Vanuatu Imperial Pigeon，学名：Ducula bakeri），是鸽形目鸠鸽科皇鸠属的大型鸟类。其上体全黑，喉部呈紫色，头部灰色，腹部和翼下栗色。主要分布在班克斯群岛至Ambrym（北部至瓦努阿图中部）的高海拔大岛屿上。","appearance":"贝氏皇鸠长约40厘米，头部和前额淡灰蓝色，背部和翅膀深灰，具金属光泽，颈部暗紫红色，胸部暗紫红带光泽，腹部深nut色。尾羽上覆羽黑色，下覆羽rufous色，虹膜黄色，外圈红色，腿脚鲜红。雌雄相似，但雌鸟略小，色彩较暗淡。幼鸟色泽暗淡，缺乏光泽，背部和翅膀的羽毛边缘狭窄rufous。","call":"最常见鸣声是一系列约15个均匀音调的hoo声，逐渐缩短，加速发出。","habits":"栖息于主要大岛的原始山地雨林，海拔600米以上，偶尔出现在沿海地带。通常单独或成对活动，偶尔形成6鸟的小群。以本地树木、灌木和藤蔓的果实为食，可能还包括棕榈果。主要在树冠层觅食，偶尔在低矮灌木中觅食。","breeding":"繁殖生态未知。","identification":"在瓦努阿图地区，与生态相似的太平洋皇鸠按海拔分隔，太平洋皇鸠偏好低地和山麓森林。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界，自班克斯群岛至Ambrym（北部至瓦努阿图中部）。"},{"name":"巨皇鸠","english_name":"Goliath Imperial Pigeon","scientific_name":"Ducula goliath","overview":"巨皇鸠（英文名：Goliath Imperial Pigeon，学名：Ducula goliath），是鸽形目鸠鸽科皇鸠属的大型鸟类。体型庞大，尾巴较长，主要呈暗蓝灰色，腹部为深红色，分布于新喀里多尼亚的山地森林中，为当地最大的鸽子或鸽属物种。","appearance":"体长约50厘米，重600至716克，全身大致为暗蓝灰色，颈部和胸部羽毛长且分叉，形成绒毛状外观。初级飞羽基部银灰色，展开翅膀时可见大块淡色斑。翼内侧覆羽有暗紫色斑块，腹部为栗色，逐渐变为浅红棕色。尾巴基部和尖端暗蓝灰色，中央带有深栗色带。下尾覆羽淡栗色，尾端有灰色边缘。虹膜橙红色，喙红色，尖端角质色，脚和腿红色。雌雄羽毛相似，但雄鸟显著较大。幼鸟较暗淡，翼覆羽边缘锈色。","call":"发出类似猫头鹰的、有节奏的低音系列咕咕声，通常开始为3至7个加速的短咕咕声（结尾时结巴），以一个强调的长咕结束，‘whoo..whoo..who.whu.hu.hu.WHOOO’。偶尔简化为两个音符‘whu-WHOOO’。","habits":"栖息于原始山地森林，主要以果实和浆果为食，包括引进的辣椒。根据猎人捕获的63只鸟的消化道内容分析，它们食用了22种树木的果实以及树叶和蕨类植物。","breeding":"繁殖季节从三月到四月，也有报告在七月晚期。巢由枝条构成，深度约12厘米，直径30厘米，置于离地面约3米高的树杈上，内含一只几乎无毛的雏鸟。据当地人报道，多数巢建在大树干上的附生蕨类植物中。","identification":"与同属其他物种相比，巨皇鸠体型最大，色彩独特，特别是其长而分叉的颈部和胸部羽毛。","protection":"IUCN：NT（近危）","distribution":"分布于新喀里多尼亚的Grande Terre和Ile des Pins，主要栖息于湿润的山地森林，海拔可达1,500米。","other":"尽管受到栖息地破坏和狩猎的威胁，但种群数量估计约为10万只，比之前认为的要大。"},{"name":"裸眶皇鸠","english_name":"Pinon's Imperial Pigeon","scientific_name":"Ducula pinon","overview":"裸眶皇鸠（英文名：Pinon's Imperial Pigeon，学名：Ducula pinon），是鸽形目鸠鸽科皇鸠属的大型鸽类。以灰白色头部、背部和胸部，以及眼周裸露的红色皮肤和尾部的细白带为显著特征。常见于新几内亚及其周边岛屿的低地和山地森林冠层。","appearance":"体长44至48厘米，体重783至802克。头、背和胸呈淡灰色，翅膀和尾巴颜色较深，前额色浅，下胸和腹部变为深赤褐色。喙基部有一条狭窄的白色环带，环绕着红色眼周皮肤的明显白圈。肩胛羽形成背部宽大的V字形。尾部暗灰色，中央有窄的白色或淡灰色带。虹膜血红色，喙和脚呈淡灰色。","call":"常发出低沉但传播远的叫声“woo-wup wooo!”，起始音节上扬，结尾音较长且更低。","habits":"栖息于低地和山地森林的树冠层，经常在树梢群聚。以水果和浆果为食，通常在树冠中觅食，包括在农田景观中的大无花果树。飞行高度直达树冠之上。","breeding":"筑巢于高树上，巢由细枝交织而成，单产一白色蛋。繁殖季节记录从2月到4月，具体时间可能受地域影响。","identification":"与横斑皇鸠的区别在于后者具有淡色眼睛和胸部带纹。黑领皇鸠有白色喉部和黑色颈带，而幼鸟缺乏尾部带纹，体型更小且更纤细。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚及其周边岛屿，包括D’Entrecasteaux群岛和Louiside群岛。主要栖息于低地至海拔500米的森林，局部地区可达900米。","other":"物种得名于Rose de Freycinet née Pinon，自然栖息地为亚热带或热带湿润的低地森林。"},{"name":"黑皇鸠","english_name":"Black Imperial Pigeon","scientific_name":"Ducula melanochroa","overview":"黑皇鸠（英文名：Black Imperial Pigeon，学名：Ducula melanochroa），是鸽形目鸠鸽科皇鸠属的鸟类。大型鸠鸽科鸟类，由英国动物学家菲利普·斯克莱特于1878年首次描述。主要栖息于新爱尔兰和新不列颠岛的山地雨林及云雾森林，海拔500米以上，以黑色为主调，翼羽边缘银白，脚部红色，体型长约38至43厘米，体重约661至665克。","appearance":"成年黑皇鸠几乎全身呈石板黑色，翼覆羽和背部带有银灰色边缘，形成鳞片状图案；尾下覆羽深栗色，尾部下侧银灰色；虹膜红色，喙灰蓝色带黑色尖端，腿脚暗红紫色。两性相似，幼鸟与成鸟相比，尾下覆羽颜色更淡。换羽发生在11月至翌年1月。","call":"已知会发出低沉的轰鸣声，持续约0.5至0.7秒，有时音调略微上扬，以及类似角鸮的“arh”声。","habits":"栖息于新不列颠岛的未受干扰的旧生山地森林，季节性地出现在低地，海拔最低可达150米，最高至1850米。以果实为食，常在树冠层觅食，单独或小群活动，最多观察到40只群体在无花果树上取食。","breeding":"仅知一巢于1994年1月在新爱尔兰发现，直径23厘米，由枝条构成，位于距地面约4米的苔藓覆盖的树间，云雾森林内，含一枚新鲜白色卵。","identification":"与白喉林鸽和黄腿鸽在飞行中相似，但前者喉部无白色，后者腿脚粉色且头部全黑。幼鸟与成鸟的区别在于尾下覆羽颜色较浅。","protection":"IUCN：LC（无危）","distribution":"分布于新爱尔兰山脉，新不列颠岛及其卫星岛屿（俾斯麦群岛东部）。在新不列颠岛，海拔150至1850米，新爱尔兰海拔700至1800米，乌姆博伊岛300至700米。","other":"在新不列颠岛的低地丰度季节性变化，可能涉及海拔迁移。"},{"name":"黑领皇鸠","english_name":"Collared Imperial Pigeon","scientific_name":"Ducula mullerii","overview":"黑领皇鸠（英文名：Collared Imperial Pigeon，学名：Ducula mullerii），是鸽形目鸠鸽科皇鸠属的鸟类。大型的、游牧型的鸽子，常见于新几内亚及其邻近岛屿的红树林和河流森林中。其最显著的特征是环绕颈部的黑色领圈，与银灰色的喉部形成鲜明对比。分布于新几内亚的南北两侧及阿鲁群岛。","appearance":"体长38至41厘米，体重540至650克。前额、眼周及头顶灰粉，下面脸部、下巴及喉咙银灰色。独特的黑色领圈环绕颈项，宽度在颈后最大，与灰粉色的头顶之间有一条细银线隔开。背部暗红色，其余上体深灰色。尾巴黑色，中央带有宽阔的淡灰色带。下体深紫粉色，沿胸部变为暗红色。胸前有不完整的宽白至银灰色带，将黑色领圈与暗粉色下体分开。腹部及下尾覆羽深红栗色。尾下黑色，有明显的淡色中央带。虹膜棕色，喙灰色，脚紫色。","call":"发出低沉、模糊的‘woo-oo pooo’声，首两个音节下降，最后一个音节音调较低。","habits":"栖息于低地的原始雨林，尤其沿河地带，也会出现在沼泽森林和红树林中。可能因果实的可用性而进行广泛的本地移动。以各种水果为食，包括棕榈科、番荔枝科和无患子科的果实。单独或成对觅食，偶尔形成小群。","breeding":"繁殖发生在湿季和干季。在西省7月中旬、跨弗莱河区9月中旬至10月、R Sepik地区12月末发现巢穴。在Dar岛4月收集到巢中幼鸟。在伊里安查亚，3月中发现了三个被占领的巢。巢为简单的平树枝平台，通常置于水平枝上，通常位于水面上方，高度1.5至6米。每次产一枚白色蛋。","identification":"与裸眶皇鸠相似，但在红树林中更常见。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的北部和南部，阿鲁群岛，Boigu和Saibai岛屿。也可能作为迷鸟访问澳大利亚东北部的北托雷斯海峡岛屿。","other":"在Bintuni湾地区被认为是数量最多的鸽子种类。"},{"name":"横斑皇鸠","english_name":"Zoe's Imperial Pigeon","scientific_name":"Ducula zoeae","overview":"横斑皇鸠（英文名：Zoe's Imperial Pigeon，学名：Ducula zoeae），是鸽形目鸠鸽科皇鸠属的鸟类。以法国鸟类学家René-Primevère Lesson的妻子Zoë Lesson命名。大型鸽类，以其独特的黑色胸带和淡灰色头部著称，广泛分布于新几内亚及其周边岛屿的低地森林和山脚森林。","appearance":"横斑皇鸠体长38至41厘米，体重575至592克。头部呈淡灰色，颈、上背和上胸部为淡灰粉色，下背和翼覆羽呈紫栗色，其余上部包括尾巴为深绿色光泽或青铜绿色。有一条细窄的黑色胸带，下胸和腹部颜色较浅，胫部羽毛和尾下覆羽呈紫栗色带有白色斑点。虹膜白色，喙暗灰色，脚红色。性别相似，幼鸟与成鸟相似但黑色胸带不明显，上部无金属光泽，颈部颜色更偏黄褐色。","call":"具有独特的叫声，开始是一声长而沉闷的音符，随后是一系列的笑声‘wooo wuhuhuhu wuhuhuhu’。还有另一种叫声‘buk, buk, buk, buk, woo’。","habits":"栖息于雨林和季风林，主要在低地，偶尔可达海拔1450米。观察显示它可能进行季节性的高度迁移。喜在森林边缘活动，常在棕榈树或显眼的枯木上栖息。","breeding":"繁殖信息有限，但据观察，繁殖期可能始于旱季末。在新几内亚东部，筑巢活动报告在7月中旬和8月底。一对横斑皇鸠曾在9月中旬在Baiyer河地区的枯树‘碗’中筑巢。","identification":"通过其独特的黑色胸带与其它皇鸠物种区分开来。","protection":"IUCN：LC（无危）。在分布范围内广泛存在，特别是在山脚森林中最为常见。在新几内亚的东北和东部高地被描述为常见。","distribution":"分布于澳新界的新几内亚和其周边卫星岛屿。"},{"name":"山皇鸠","english_name":"Mountain Imperial Pigeon","scientific_name":"Ducula badia","overview":"山皇鸠（英文名：Mountain Imperial Pigeon，学名：Ducula badia），是鸽形目鸠鸽科皇鸠属的鸟类。别名: 大灰斑鸠，大型鸟类。在中国，分布于云南和海南岛，数量稀少，被列入国家重点保护野生动物名录，属国家二级保护鸟类。全球范围内，广泛分布于东南亚的山地森林。","appearance":"山皇鸠体长43-51厘米，拥有长尾、宽大的圆形翅膀和缓慢的翼拍。头部、颈部和下体为淡紫色灰色，与白色的喉咙形成对比，背部和翅膀呈棕色至紫红色。上体部分可能较暗淡。下翼为灰色，尾巴黑色带有一条灰色横线。雄雌相似，幼鸟的色彩较为暗淡，头部至胸部呈灰色（而非淡紫色），翅膀和背部为土褐色，翅膀尖端为栗色，背部和臀部为烟灰色。","call":"其叫声为深沉、回响的轰鸣声，通常只有近距离才能听到，声音像是“ouh-woOO WOO”。","habits":"通常单独行动，但在前往栖息地或在山区上下飞行时，有时会组成多达20只的小群。它们在高树冠中活动，飞行高度也相对较高。在繁殖季节，它们会在树上筑巢，巢通常位于较小的树木中，距离地面约5到8米，巢为简单的平台型。它们以果实和浆果为食，尤其是无花果和肉豆蔻，偶尔也会到地面饮水。在一些地区，可能会有局部的海拔移动，以寻找最佳的食物条件。","breeding":"繁殖期一般为3月至8月，但在印度南部和东南亚部分地区，繁殖期为1月至5月。每次繁殖通常产一枚蛋，偶尔产两枚，由双亲共同孵化。孵化期间，除非受到极大的压力，否则不会离开巢穴。","identification":"与黑背皇鸠相比，山皇鸠具有更明显的灰色冠羽和耳罩，与淡紫色的颈部和粉红色的喉咙形成对比，翅膀和背部完全为棕色，下尾覆羽颜色更深，呈栗色，喙色一致为深色；与和C. pulcricollis相比，山皇鸠体型更大，翅膀更短圆，尾巴末端有宽的灰色带纹。","protection":"IUCN：LC（无危）。在中国，山皇鸠仅分布于云南和海南岛，数量稀少，已列入国家重点保护野生动物名录，属国家二级保护鸟类。","distribution":"分布于喜马拉雅山脉从尼泊尔至中国南部，海南岛，亚洲东南部，马来半岛和大巽他群岛。在中国，分布于云南西南部的潞西、南部的西双版纳以及海南岛等地，以及西藏东南部。","other":"山皇鸠在一些地区的数量因森林砍伐和栖息地丧失而有所减少，但在建立森林保护区后，这种状况自1980年代以来已有改善。"},{"name":"黑背皇鸠","english_name":"Dark-backed Imperial Pigeon","scientific_name":"Ducula lacernulata","appearance":"成年黑背皇鸠体型大，体长39至45厘米。其前额、脸部和头顶为蓝灰色；喉咙、颈部和胸部为淡紫色，带有银灰色调，腹部逐渐变为浅灰色；上身呈深棕色，带青铜绿色光泽，尤其在翅膀上最为明显；尾羽为灰黑色，末端有一宽广的灰色带；尾巴下方为深灰色，带银色末端带；覆尾羽为栗色；虹膜为深红色；喙为黑色、深灰色或蓝灰色；腿为红色至紫红色。雌雄外观相似。幼鸟的描述未给出。威廉氏亚种(williami)头部无灰色；sasakensis亚种的脸侧和耳羽为粉红色，额头和头顶为灰色，腹部和覆尾羽为粉棕色，肩部和翅膀颜色更深，带有更明显的绿色光泽。","call":"黑背皇鸠最常发出的叫声是一段包含2至3个音节的均匀低吼声，第一个音节略短，听起来像'whu-whuu-whuu'。sasakensis亚种发出类似低吼声，可能持续时间较短。","habits":"黑背皇鸠生活在丘陵和山地森林中，通常栖息在树冠层；在弗洛勒斯岛上，也会出现在卡苏阿里纳木林地以及有树木的农田中。记录显示，它们的栖息高度在400至2500米之间，大多位于850米以上，偶尔下降到150米。在松巴哇岛，它们频繁出现在重度砍伐的杜邦加森林(1000至1200米)，以及未砍伐的杜邦加混合雨林和以卡苏阿里纳junghuhniana为主的季节性山地森林，最高可达2000米。物种数量在某些地区的变化表明，黑背皇鸠可能在一定程度上具有游荡习性。它们以果实为主食，包括无花果(Ficus)。通常在大型森林树木的树冠层觅食，有时单独或成对活动，但更多时候形成由5只鸟组成的小群。","breeding":"繁殖活动记录在3月、8月、10月和11月。巢是一个扁平的树枝平台，建在高处。每窝产一枚蛋。在弗洛勒斯岛，位于Keli Mutu(1530米)的季节性山地森林中，发现两个筑巢的鸟类在8月底坐在卡苏阿里纳树上10至15米高的位置。","identification":"黑背皇鸠与其他皇鸠属物种的区别在于其深色的背部和独特的头部颜色变化。sasakensis亚种与其他亚种的区别在于头部颜色和腹部色调。","protection":"IUCN：LC(无危)。黑背皇鸠在中海拔和山地森林中局部常见，尤其是在远离人类干扰的地区。在其分布范围内，它遭受着强烈的狩猎压力。在小巽他群岛海拔850米以上的地区较为常见；据报道，在弗洛勒斯岛上由于狩猎压力，显得害羞，可能被低估。在巴厘岛，尽管害羞，但在某些地区如Bedugul湖岭仍然局部频繁出现。","distribution":"黑背皇鸠主要分布在远东和澳新界的爪哇岛山区、巴厘岛、龙目岛至弗洛勒斯岛的小巽他群岛西部和中部。"},{"name":"斑皇鸠","english_name":"Pied Imperial Pigeon","scientific_name":"Ducula bicolor","overview":"斑皇鸠（英文名：Pied Imperial Pigeon，学名：Ducula bicolor），是鸽形目鸠鸽科皇鸠属的鸟类。大型、群居的白底黑边鸠鸽科鸟类。分布于东南亚，自缅甸和泰国南部至爪哇，向东至菲律宾和新几内亚的鸟头半岛和Neck地区。常栖息于沿海森林的小岛，偶尔前往大陆觅食和栖息。在分布区内较为常见。","appearance":"体长35-42厘米，体重365-510克，全身纯白，或多或少带有黄色调，除翼尖及尾部呈黑色；黑色部分有时带银灰色光泽；喙灰或蓝灰色，端部较暗；腿脚灰蓝。两性相似。幼鸟白色区域泛灰，羽毛边缘宽黄褐色。亚种emmelanura/em被报道有黑色尾下覆羽标记，尾部黑色更广泛，但个体差异明显。","call":"鸣叫声低沉，包含‘woo-oo-woooo’，最后一音节拉长，起初响亮而后渐弱。叫声多样，包括低沉的‘rruuu’、深沉的‘wuum wuum’、尖锐的‘check’、响亮的‘kuck’和轻柔的三音节‘coo’声。广告叫声为一系列五音下降的‘whoo whoo whoo hoo hoo’。","habits":"栖息于沿海森林、红树林和椰子种植园，常在小离岸岛屿上筑巢和栖息，但会造访大陆沿海地区觅食。主要生活在低地，但emmelanura/em亚种报告可达1100米高。在一些地区，如华莱士区，有季节性迁徙现象，但详细信息缺乏。","breeding":"繁殖季节数据稀缺，一般在12月至次年3月于安达曼群岛和尼科巴群岛繁殖；9月和11月在塞拉姆岛收集到半成熟幼鸟；苏门答腊所有四个繁殖记录来自4月；8月在爪哇繁殖；4月初在菲律宾法蒂玛岛采集的雌鸟含有完全发育的卵。通常在离岸小岛上集群繁殖；巢主要建在红树林中；巢平台简陋。","identification":"与苏拉斑皇鸠和澳洲斑皇鸠在重叠区域比较，斑皇鸠的白大腿和尾下覆羽无斑点，喙蓝底暗尖；苏拉斑皇鸠尾下覆羽和大腿有黑斑；澳洲斑皇鸠喙绿黄色；淡黄皇鸠和苏拉斑皇鸠喙基蓝而端黄，淡黄皇鸠羽毛有黄调，苏拉斑皇鸠翼上有银灰色。","protection":"IUCN：LC（无危）。全球种群数量庞大，澳大利亚估计有50万只。局部地区如马努塞拉国家公园（塞拉姆岛）和Belitung岛数量丰富，但在繁殖群落受到猎杀和干扰威胁。由于过度猎杀，在爪哇和巴厘岛现在罕见。","distribution":"分布于东南亚，从安达曼群岛和泰国南部至爪哇，东至菲律宾、新几内亚的鸟头半岛和Neck地区。在许多离岸小岛和苏门答腊（如Riau）、婆罗洲附近岛屿常见。","other":"在一些地区，如菲律宾，可能因过度猎杀已接近灭绝；在某些岛屿，如Haruku（中央苏拉威西）最近有记录。"},{"name":"苏拉斑皇鸠","english_name":"Silver-tipped Imperial Pigeon","scientific_name":"Ducula luctuosa","overview":"苏拉斑皇鸠（英文名：Silver-tipped Imperial Pigeon，学名：Ducula luctuosa），是鸽形目鸠鸽科皇鸠属的大型鸟类。特有于苏拉威西岛及其周边小岛的森林、林地和红树林地带。","appearance":"这种引人注目的鸟全身基本为奶油白色，翅膀和尾巴呈银黑色，尾羽基部有暗色斑点。幼鸟羽毛更灰，许多羽毛边缘为浅褐色。成年鸟的性别外观相似，翼羽为银灰色，边缘黑色，腿部和腹部区域的许多羽毛大部分为黑色，形成斑驳的效果。","call":"其叫声包括深沉的呼噜声，中间部分加重，发出类似“whooOOoo”的声音。","habits":"苏拉斑皇鸠常群居于低地的森林边缘和开阔林区，有时也会在红树林中栖息。它们通常以5到20只的小群体出现，以果实为食。","breeding":"关于繁殖的信息有限，已知在苏拉威西岛的Butung和Muna岛屿上，繁殖活动发生在9月和10月。","identification":"与斑皇鸠非常相似，但苏拉斑皇鸠的暗色翼纹具有银色光泽，尾羽基部有暗色标记，这是两者的主要区别。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳新界的苏拉威西岛及其周边的Banggai和Sula群岛（苏拉威西岛东部）。","other":"在苏拉威西岛上广泛分布，尽管总体数量不多，但在某些地区或季节可能会较为常见，如在Dumoga-Bone国家公园和Taliabu（苏拉群岛）可见大群聚集。"},{"name":"澳洲斑皇鸠","english_name":"Torresian Imperial Pigeon","scientific_name":"Ducula spilorrhoa","overview":"澳洲斑皇鸠（英文名：Torresian Imperial Pigeon，学名：Ducula spilorrhoa），是鸽形目鸠鸽科皇鸠属的鸟类。体型较大的白羽斑点鸽，广泛分布在澳大利亚北部（包括西澳东北部、北领地北部和昆士兰东北部）、新几内亚、托雷斯海峡群岛以及周边岛屿。其显著的特征为白色主羽与黑色翼羽和尾端，常在森林、灌木丛、红树林和开阔地带觅食。","appearance":"成年澳洲斑皇鸠体长38-44厘米，体重378-550克。通体羽毛以白色为主，头颈部位可能带有乳白色或灰色调。翼羽和次级飞羽为黑色，带有银灰色光泽，仅在近距离观察时可见。尾上覆羽白色，尾端宽黑，下腹有黑色斑点，逐渐过渡到尾下覆羽上的黑色条纹。嘴黄色或黄绿色，腿脚蓝灰色。雌雄相似，但雌鸟略小于雄鸟。幼鸟与成鸟相似，但头部、颈部和背部有更强的灰色调，下体呈淡黄色，缺乏成鸟的黑斑。","call":"发出低沉的、空洞的、下降音调的“hoooo”声，或双音节的“hoo-hoooo”，第二个音节更强调，重复约6次，间隔5-10秒。展示时，叫声变为响亮的‘coo-HOO-HOO’或‘who-WHOOO’，首音柔和短暂，后续音节更响亮有力。","habits":"栖息于多种森林环境，包括桉树、千屈菜和红树林，以及小岛上的低矮灌木丛。在澳大利亚金伯利地区，占据着丰富的藤蔓和树木组成的半落叶林。偏爱在森林边缘、沼泽森林或滨海森林觅食，而非雨林内部。形成大群，通常在低地活动，海拔不超过300米。迁徙模式复杂，部分群体季节性迁徙。","breeding":"繁殖季节性强，主要在8月末至次年1月，在昆士兰和北领地最为明显，而新几内亚可能全年都有繁殖活动。在澳大利亚，通常在离岸岛屿上的红树林或雨林中筑巢，有时独居或小群繁殖。一窝产一枚光滑的白色蛋，孵化期26-28天，由父母交替孵卵。雏鸟孵化后约23天离巢，几乎完全长满羽毛。","identification":"与淡黄皇鸠的区别在于前者羽毛白色，后者黄色；前者的初级飞羽下侧带灰色，后者的黑色；前者的尾端黑色较窄。与苏拉斑皇鸠和斑皇鸠也有类似差异。","protection":"IUCN：LC（无危）。虽然数量丰富，但在部分地区因栖息地破坏和过度猎杀而减少。自19世纪末和20世纪初的过度猎杀后，受保护状态下的数量有所恢复。","distribution":"分布于新几内亚西北部、东北部、南部、东南部以及托雷斯海峡群岛，澳大利亚西澳东北沿海至昆士兰中东部。在澳大利亚北部形成三个独立的种群。","other":"历史上曾因被视作害鸟或射击目标而遭到大规模猎杀，导致数量锐减。目前，由于在澳大利亚受到法律保护，数量正在缓慢回升。"},{"name":"淡黄皇鸠","english_name":"Yellowish Imperial Pigeon","scientific_name":"Ducula subflavescens","overview":"淡黄皇鸠（英文名：Yellowish Imperial Pigeon，学名：Ducula subflavescens），是鸽形目鸠鸽科皇鸠属的鸟类。大型皇鸠。其显著特征为淡黄色的羽毛与蓝灰色的嘴基，主要分布在Bismarck群岛的森林和林地中，面临栖息地丧失的威胁。","appearance":"体长约38厘米，相比同域内的其他皇鸠种类，体型较为紧凑，尾部较短。羽毛以淡黄色为主，头部、肩部、背部、翼覆羽和三级飞羽均为奶油白色，仅翅膀的初级飞羽、次级飞羽、翼指骨、初级飞羽覆羽及尾羽尖端为黑色，尾羽外侧黑色部分较窄。下体尾羽有明显的黑色末端带，翼下的颜色较其他皇鸠更偏黄白色，仅限于内侧翼覆羽。眼暗棕色，喙灰绿色尖端，腿和脚为石板色。两性相似，幼鸟头部和颈部可能略显灰色，缺乏成鸟尾羽外侧的黑色尖端。","call":"通常沉默，但在求偶时会发出深沉共鸣的双音节'oo-oom'声，首音上扬，第二音稍降调；也会发出鼻音般的'hooting vroo'声。","habits":"主要栖息于封闭树冠的原始森林、边缘地带、采伐区以及开阔地带的大树群中，可能偏好沿海或低地河流附近的森林。已知分布海拔最高可达940米（新不列颠岛）、560米（新爱尔兰岛）以及Manus全岛。","breeding":"关于繁殖信息知之甚少，但记录显示交配行为发生在7月。","identification":"与蓝眼凤头鹦鹉的奶油白羽毛相区别，与前同域物种澳洲斑皇鸠在羽毛颜色、翼下黑色区域和尾羽黑色尖端上有明显差异。","protection":"IUCN：NT（近危）","distribution":"主要分布于Bismarck群岛，包括Long Island和Umboi，以及Admiralty群岛。","other":"本种有时被视为澳洲斑皇鸠的亚种，而澳洲斑皇鸠有时又作为斑皇鸠的亚种。"},{"name":"灰枕皇鸠","english_name":"Geelvink Imperial Pigeon","scientific_name":"Ducula geelvinkiana","overview":"灰枕皇鸠（英文名：Geelvink Imperial Pigeon，学名：Ducula geelvinkiana），是鸽形目鸠鸽科皇鸠属的大型、健壮的鸽子。特有于印尼的Schouten群岛（又称Geelvink群岛）及Mios Num岛，位于新几内亚北部。以灰头、黄眼、绿背翅、蓝尾和锈色臀部为显著特征。","appearance":"该物种头部呈灰色，眼睛黄色，背部和翅膀为翡翠绿色，尾巴蓝色，臀部锈色。体型较大且体态丰满。","call":"其声音深沉、沙哑，发出两音节的“grrr-waw”声，第二音节高于第一音节。","habits":"栖息于低地雨林，有时会游荡于岛屿间，偶尔甚至到达大陆。生活在热带湿润的低地森林和红树林中。","identification":"在其小范围内具有独特性，与其他鸽子种类易于区分。","protection":"IUCN：LC（无危）。受狩猎和栖息地丧失威胁。","distribution":"分布于澳新界：Numfor，Meos Num和Biak（鸟头湾，新几内亚西北部）。","other":"2021年，国际鸟类联盟（IOC）将其认定为独立物种，此前曾被认为与黑疣皇鸠为同一物种。"},{"name":"马拉巴山皇鸠","english_name":"Malabar Imperial Pigeon","scientific_name":"Ducula cuprea","overview":"马拉巴山皇鸠（英文名：Malabar Imperial Pigeon，学名：Ducula cuprea），是鸽形目鸠鸽科皇鸠属的大型优雅鸟类，主要分布在印度西部的马拉巴山脉。其珍珠灰色的外观和独特的飞行姿态使其在热带雨林和落叶森林中格外显眼。","appearance":"马拉巴山皇鸠体型较大，全身呈现优雅的珍珠灰色，翅膀深棕色，尾端有一条宽阔的灰色带纹，尤其在飞行时更为明显。与灰头林鸽相比，它体型更大，颈部背面无黑白斑块。与绿皇鸠大小相似，但背部为棕色而非绿色，且下尾羽无栗色斑块。","call":"其鸣叫声深沉而回响，通常被描述为“ouh-woOO WOO”。","habits":"马拉巴山皇鸠主要栖息于成熟的热带雨林和落叶林中，常见于山脚和山区，有时也会降至海平面附近。它们常在森林上层觅食，以小群体的形式活动，飞行时力量十足，能够越过树冠。","breeding":"关于马拉巴山皇鸠的繁殖信息尚待详细研究。","identification":"与灰头林鸽和绿皇鸠相比，马拉巴山皇鸠在颜色、大小和结构上有明显的差异，尤其是背部的颜色和下尾羽的特征。","protection":"IUCN：LC（无危）","distribution":"马拉巴山皇鸠主要分布于印度西南部的马拉巴山脉，包括低地和山地的亚热带或热带湿润森林。","other":"马拉巴山皇鸠曾被认为是山皇鸠的一个亚种。"},{"name":"恩岛皇鸠","english_name":"Enggano Imperial Pigeon","scientific_name":"Ducula oenothorax","overview":"恩岛皇鸠（英文名：Enggano Imperial Pigeon，学名：Ducula oenothorax），是鸽形目鸠鸽科皇鸠属的鸟类。主要分布于印尼恩加诺岛。其特征为深绿色的翅膀和背部，其余部分呈浅灰色，颈部略暗，胸部带有独特的淡粉色。生活在森林、灌木丛和重度退化林地，被当地人捕猎作为食物。","appearance":"恩岛皇鸠为中等体型，全身以浅灰色为主，头部、颈部和腹部颜色一致，胸部可见淡紫色粉晕。上体呈现绿松石蓝的光泽，翼部和背部的绿色带反射。下体颜色较灰暗，尾巴基部和覆羽带有金属绿色，边缘有时显现出暗铜色。喙呈灰白色，脚和腿为暗紫红色。","call":"恩岛皇鸠非常活跃，声音丰富，包括类似咕噜声的“krooooo”。","habits":"栖息于热带低地森林，包括红树林、海岸森林、河岸森林和淡水沼泽，以及受干扰和农业区域。主要为留鸟，以水果为食。","breeding":"具体繁殖信息未知，但观察到它们在群体中觅食，可能涉及单个、成对或小群体。","identification":"与其他鸽子相比，恩岛皇鸠的独特之处在于其淡粉色的胸部和灰绿色的主色调。与绿皇鸠的区别在于胸部的紫色粉晕更明显，颈部灰度更深，腹侧更暗。","protection":"IUCN：NT（近危）","distribution":"恩岛皇鸠仅分布于印尼的恩加诺岛，位于苏门答腊岛南部西侧。","other":"恩岛皇鸠与绿皇鸠曾被认为是同一物种，但现在被视为独立的物种。"},{"name":"髻鸠","english_name":"Topknot Pigeon","scientific_name":"Lopholaimus antarcticus","overview":"髻鸠（英文名：Topknot Pigeon，学名：Lopholaimus antarcticus），是鸽形目鸠鸽科髻鸠属的鸟类。大型果鸠，原产于澳大利亚东部，从约克角半岛东北部至维多利亚州远东部。以其独特的头部发髻状羽冠而闻名，整体呈灰色，翼部暗灰，尾部具显著银灰色带。雌雄外观相似，但雌鸟顶冠较小。","appearance":"体长40-46厘米，体重475-600克。头部有独特的波浪状灰色羽冠，红棕色的顶冠羽毛从喙部卷曲向上并延伸至颈部，雌鸟顶冠较小，颜色较淡。全身羽毛以灰色为主，胸部和腹部的羽毛呈现尖锐状排列，背部和翅膀为深灰色，尾部黑色，有明显的银灰色横带。喙为红褐色，脚部粉红至紫红色。","call":"发出低沉的咕噜声，有时为一系列不规则的低吼，类似远处狗吠的声音，以及喂食时拉长的嘶嘶尖叫。","habits":"栖息于热带、亚热带和温带雨林，常在密闭的湿硬叶森林中发现，偶尔出现在高树梢或山顶上的开放硬叶森林。以直径5-25毫米的水果和浆果为食，尤其偏好樟科、桑科、芸香科、桃金娘科和棕榈科的果实。集群生活，迁徙模式受食物资源影响，可长距离移动。","breeding":"繁殖季节通常在春季和初夏，但可能持续数月。单独筑巢，巢位于至少15-30米高的树上，由雄鸟收集材料，雌鸟搭建。每窝产一枚白色卵，孵化期22-24天，由双亲共同承担。雏鸟孵化后约17天离巢。","identification":"与其他果鸠的区别在于其独特的发髻状羽冠和较大的体型。雌雄之间通过顶冠的大小和颜色差异辨识。","protection":"IUCN：LC（无危）。由于栖息地破坏和猎杀，数量已大幅减少，需保护其栖息地。","distribution":"分布于澳大利亚东部，从约克角半岛东北部到维多利亚州远东部。偶尔会超出常规南部范围，进入东部维多利亚。","other":"历史上曾因森林清理和狩猎导致数量急剧下降，现已被列为保护物种。"},{"name":"新西兰鸠","english_name":"New Zealand Pigeon","scientific_name":"Hemiphaga novaeseelandiae","overview":"新西兰鸠（英文名：New Zealand Pigeon，学名：Hemiphaga novaeseelandiae），是鸽形目鸠鸽科新西兰鸠属的鸟类。大型鸽类，仅在新西兰发现。其蓝绿色金属光泽的羽毛、白色的腹部和红色的眼睛极为醒目。常见于果实丰富的树木周围或春季新鲜叶子和花蕾丛中。分布广泛，尤其在食物充足的地方。发出柔和的‘oo’声，翼拍声音独特。","appearance":"体长46-50厘米，体重510-795克，翼展约75厘米。上身大部分呈深绿色金属光泽，胸部和肩部带有紫色和青铜色高光；背部较浅，带银灰色调；翅膀暗色与白色腹部界限分明；尾下覆羽银灰色，具宽幅暗棕色亚端斑；喙红色，尖端略淡；腿深红色。雌雄相似。幼鸟颜色较为暗淡，嘴、眼、腿脚的颜色也较淡。存在白化病和部分白化现象，以及其他颜色变异。已灭绝的spadicea亚种具有独特的栗色肩部。","call":"发出偶尔的、柔和但穿透力强的‘ooo’声，受惊时会发出更响亮的咕噜叫声。","habits":"偏好混合豆杉阔叶林，偶尔出现在纯Nothofagus森林，高度可达1100米。常在公园、花园和异国树种的种植园中出现，如Populus、Ulmus、Salix和Prunus等。在繁殖季节有显著的当地移动，最大记录移动距离为25公里。以熟果为主食，亦食叶片、嫩枝、花朵、花蜜和树液，偏好Prumnopitys和Podocarpus等果实。","breeding":"繁殖期主要在11月至3月，筑巢于树木中，通常离地面2.5至12米。单卵，孵化期28-30天，幼鸟36-45天后离巢，有时会连续育雏两次或三次。巢由树枝搭建，双亲共同参与筑巢、孵化和喂养幼鸟。","identification":"与查塔姆岛鸽相比，体型较小，翼拍声音独特。已灭绝的spadicea亚种具有明显的栗色肩部，可作区分。","protection":"IUCN：LC（无危）","distribution":"分布在新西兰北岛、南岛和斯图尔特岛，曾存在于诺福克岛（澳大利亚远东）。","other":"由于欧洲定居者的狩猎和森林砍伐，数量曾大幅下降。目前受到非法狩猎、外来物种如猫、鼠、黄鼠狼和澳洲钟鹊的威胁。在控制了这些外来物种后，数量有所恢复。"},{"name":"查岛鸠","english_name":"Chatham Pigeon","scientific_name":"Hemiphaga chathamensis","overview":"查岛鸠（英文名：Chatham Islands Pigeon，学名：Hemiphaga chathamensis），是鸽形目鸠鸽科新西兰鸠属的大型鸟类，特有于新西兰的查塔姆群岛。与新西兰鸠关系密切，但体型更大，重约800克，长55厘米。查岛鸠主要栖息于查塔姆岛南部森林，尤其是图库河周边的森林。","appearance":"查岛鸠体型庞大，羽毛色彩丰富，以灰绿色为主调，头部、喉咙、上胸部和背部呈黑灰色，下胸、腹部和腿部有明显的白色，红嘴尖带淡黄色，红棕色眼睛，橙粉色眼环，腿脚暗红色。幼鸟与成鸟相比，上部羽毛较暗淡，尾下覆羽呈淡褐色。相较于新西兰鸠，查岛鸠体型更壮硕，嘴喙更粗长，冠羽、喉部、胸部和颈侧羽毛色泽较暗，臀部灰色，胸部更深，带有更多紫色光泽。","call":"当栖息时，查岛鸠可能发出柔和的‘oo’声叫声。","habits":"查岛鸠栖息于本土森林、灌木丛和蕨类覆盖区，以及邻近森林或防风林带的牧场。它们主要以各种植物的叶芽、叶片、花蕾、花朵和果实为食，偏好富含脂肪和碳水化合物的果实。查岛鸠在地面上觅食的行为使它们容易成为捕食者的猎物。","breeding":"查岛鸠全年都可能繁殖，但主要集中在冬季和春季（6月至11月）。当果实充足时，许多配对会养育两窝幼鸟，涉及连续的筑巢事件。繁殖期间，配对鸽会表现出领地性，雄鸟通过展示飞行驱逐入侵者。筑巢平台由枯枝构成，每次产一枚白色蛋，孵化期约为26至28天。","identification":"与新西兰鸠相比，查岛鸠的臀部呈灰色而非蓝绿色，翼覆羽更暗淡，嘴喙更粗壮。幼鸟的上部羽毛颜色较暗，尾下覆羽颜色更深。","protection":"IUCN：VU（易危）","distribution":"查岛鸠主要分布在查塔姆群岛的查塔姆岛、皮特岛，可能还包括兰格蒂拉岛。目前物种数量已从1989年的45只恢复至600多只，主要归功于保护措施，如控制捕食者和划定保护区。","other":"查岛鸠曾经在曼格雷岛和皮特岛上普遍存在，但因栖息地破坏和哺乳动物入侵物种的捕食，数量大幅减少。自1990年以来，通过控制捕食者和在图库山谷周围设置围栏，查岛鸠的繁殖成功率提高，种群迅速增长。"},{"name":"苏拉乌鸠","english_name":"Sombre Pigeon","scientific_name":"Cryptophaps poecilorrhoa","overview":"苏拉威西乌鸠（英文名：Sombre Pigeon，学名：Cryptophaps poecilorrhoa），是鸽形目鸠鸽科苏拉乌鸠属的鸟类。本属唯一物种，分布于印尼苏拉威西岛的山区，大型灰鸽，以其眼周的小片红肉色皮肤和腹部与尾下覆羽的条纹为显著特征。","appearance":"该鸟长约46厘米，头部、颈部和胸部呈灰色，前额和下胸颜色较浅，向肩部逐渐加深；部分个体的灰色区域带有紫色调；肩背、背部、臀部、上尾覆羽和翅膀为深橄榄黑色，新生羽毛边缘为淡黄色，带有微弱的青铜绿色光泽；腹部为淡棕色，侧腹颜色更深，羽毛边缘呈淡黄色，形成斑驳效果；尾下覆羽为黑色，边缘为奶油黄色；翅膀下方为黑色，中央有一块栗色斑点；尾巴为黑色，末端狭窄处有淡黄色尖端；喙为蓝灰色，基部紫色，眼圈和虹膜红色，腿和脚为红色至紫红色。雌鸟灰色区域明显带有暗粉色，部分个体的胸羽边缘清晰呈棕色。","call":"不是非常活跃的鸣叫者，其广告叫声为单一低沉的呼叫声（持续时间约0.8至1秒，频率范围160至240赫兹），每隔2至4秒重复几次。","habits":"栖息于未受干扰的湿润原始丘陵和山地森林，倾向于在林冠下层安静地栖息；记录显示它在海拔950至2300米之间活动，最高记录在洛雷林杜国家公园（苏拉威西北部）。飞行被描述为类似鹃鸽（Macropygia）。通常单独观察到，偶尔成对出现。","breeding":"关于繁殖的信息不可得。","identification":"在苏拉威西岛上，它是唯一一种腹部有条纹和眼周有红色皮肤的大灰鸽，易于与其他鸽子区分。","protection":"IUCN：LC（无危）。虽然普遍分布但数量不多。在80年代的杜莫加-博内国家公园（米纳哈萨半岛）中较为罕见。由于羞怯、隐退和不显眼，即使在特定搜索下也很容易被忽视。若其主要食物来源藤本果实受到砍伐，可能会面临威胁。需要广泛研究以确定种群规模和趋势，识别可能的威胁。","distribution":"分布于印尼苏拉威西岛的山区，主要栖息于亚热带或热带湿润的山地森林。"},{"name":"裸眶山鸠","english_name":"Papuan Mountain Pigeon","scientific_name":"Gymnophaps albertisii","overview":"裸眶山鸠（英文名：Papuan Mountain Pigeon，学名：Gymnophaps albertisii），是鸽形目鸠鸽科山鸠属的鸟类。大型、长尾的群居鸽类。其显著特征包括眼周的红色皮肤、浅色尾尖、奶油色胸羽、深色腹部及蓝灰色上体、头部和喉部。这种山鸠广泛分布于Bacan山区、印尼亚彭岛、新几内亚及巴布亚新几内亚的当特尔卡斯托群岛。","appearance":"成年裸眶山鸠长约33至36厘米，重约259克。头部和颈部侧面呈深灰色；背部和翼覆羽边缘黑色，赋予鳞片状外观；下颈至下胸部粉白色，耳羽、喉部及腹部暗紫色；大腿和尾下覆羽灰色；眼睛红色，带有橙色、黄色或绿色环；眼周皮肤鲜红且扩张；喙红色，基部红色，尖端粉色；脚和腿红色或深粉色。雌鸟可能胸部灰化，喉部羽毛边缘灰色。幼鸟总体较暗淡，胸部棕色，下体浅奶油色带锈色；前额栗色；最内侧次级飞羽边缘栗色。","call":"通常保持安静，但在繁殖季节会发出低沉的升调‘wooooooo m’声，也会产生柔和的颤音哨声。","habits":"栖息于从海平面到海拔3350米以上的原始森林，主要出现在山区和丘陵地带，但也会造访邻近的低地。部分游牧习性，尤其在新几内亚的Schrader山脉，雨季期间（10月至次年3月）大量个体访问山毛榉林。可能会降至较低海拔觅食，偶尔可见其从陡峭山脊俯冲数百米。","breeding":"雄鸟在6月时会有增大的生殖腺。筑巢平台由树枝构成，位于小树3.7至5米高处；也有发现地面巢穴位于树线以上短干草中的凹陷处。繁殖期主要在10月至次年3月的Schrader山脉，但可能全年繁殖。每次产一枚蛋。","identification":"通过群居行为、扩展的红色面部皮肤、浅色尾尖和奶油色胸部可将其与白喉林鸽区分开来。","protection":"IUCN：LC（无危）","distribution":"分布在Bacan山区（印尼摩鹿加群岛北部）、印尼亚彭岛（鸟头湾，新几内亚西北部）、新几内亚和巴布亚新几内亚的当特尔卡斯托群岛（东部，新几内亚东南部）。主要在山区和丘陵地带，但也会季节性地造访附近的低地。","other":"裸眶山鸠在新几内亚广泛分布，数量不稳定；在新不列颠岛上局部和季节性丰富；在新爱尔兰岛上记录稀少。Bacan的亚种exsul被认为罕见，当前状况不明。"},{"name":"长尾山鸠","english_name":"Buru Mountain Pigeon","scientific_name":"Gymnophaps mada","overview":"长尾山鸠（英文名：Buru Mountain Pigeon，学名：Gymnophaps mada），是鸽形目鸠鸽科山鸠属的鸟类。以其淡灰色的冠部和颈背、蓝灰色至暗灰色的上体以及奶油色至鲑鱼粉红的腹部为显著特征。","appearance":"长尾山鸠体长33-38.5厘米，头冠、颈背及后颈为蓝灰色，逐渐变为较深的灰石板色上体；背部、肩羽及臀部的羽毛具有狭窄的黑色亚端缘和宽阔的银灰色边缘，这些边缘会逐渐磨损；翅膀和尾羽呈绿色黑；面颊、喉部及上胸白色至淡黄粉色，逐渐过渡到腹部的黄粉色；胫部羽毛呈淡黄粉色；虹膜灰色、淡棕色或黄色，外环橙色或红色；喙灰黄色带红基部；脚和腿紫色、紫红色或棕红色。雌鸟平均体型较小，喙和头部皮肤为深黑色，胸部更倾向于葡萄酒色。幼鸟上体更偏褐色，尤其是翅膀部分，喉部和胸部的浅色区域带有暗色斑点，腹部显得更加赭黄色，尾下覆羽为暗灰色带赭黄粉色边缘，翼下覆羽泛锈褐色；喙灰色带白尖，头部皮肤暗红色，脚和腿亦为暗红色。","call":"鸣叫尚未得到确认，但报道过一种深沉的‘wuooo’声。","habits":"长尾山鸠通常单独或成对出现，偶尔小群（最多11只）活动，主要栖息于山地森林，但也会偶尔造访低地受扰森林以觅食。它们在海拔0至2060米间活动，多数时间位于650至1760米的高度。早晨飞往低地觅食，傍晚返回高处栖息。","breeding":"繁殖季节可能从10月至12月，但具体细节未知。","identification":"长尾山鸠与白喉林鸽的区别在于其更为广泛的苍白喉咙和胸部区域，以及苍白的灰冠和颈背。","protection":"IUCN：LC（无危）","distribution":"长尾山鸠仅分布于印尼的布鲁岛山区，主要栖息于山地森林，偶尔进入低地受扰森林。","other":"直到最近，长尾山鸠被认为与塞兰山鸠为同一物种，但因多种形态特征差异而被认定为独立物种。"},{"name":"塞兰山鸠","english_name":"Seram Mountain Pigeon","scientific_name":"Gymnophaps stalkeri","overview":"塞兰山鸠（英文名：Seram Mountain Pigeon，学名：Gymnophaps stalkeri），是鸽形目鸠鸽科山鸠属的鸟类。分布于印尼摩鹿加群岛中东部的塞兰岛山区。该鸟以深粉色面部与胸部、酒红色下体、灰冠及独特的红眼圈为显著特征。","appearance":"塞兰山鸠体长33–38.5厘米，体重330–338克，具有深粉色面部至胸部，颜色渐变至酒红色下体。其喉咙和胸部呈淡粉色，冠、颈背为淡蓝灰色，腹部及尾下覆羽为深栗色，边缘略带酒灰色。眼睛为鲜红至黄色，眼周皮肤紫红至鲜红，喙黄色，鼻甲紫色，腿和脚为紫色。幼鸟上部和下部颜色更暗，尾下覆羽也更深，眼周皮肤、腿和喙的颜色较成鸟暗淡。","habits":"主要栖息于海拔400至2300米的山地森林，常见于亚冠层和树冠层次。它们通常在果实丰富的树木中成群出现，有时可达50只以上的大群体。塞兰山鸠是典型的果食性鸟类。","breeding":"唯一已知的巢穴记录发现于9月中旬，位于海拔2300米的原始山地森林中，巢建在一棵死掉的苔藓覆盖的水平树枝的裂缝中，离地面约2.5米，用小枝条和苔藓松散地铺垫，巢内有一枚白色蛋。展示飞行行为类似但低于Papuan山鸠。","identification":"与前同种的长尾山鸠在外观上有明显差异，如面部和胸部的深粉色，下体颜色的差异，以及眼圈和喙的颜色。体型上也显得较小。","protection":"IUCN：LC（无危）","distribution":"仅分布于印尼摩鹿加群岛的塞兰岛山区。","other":"直到最近才被视为独立物种，此前被认为是Buru山鸠的亚种。"},{"name":"所罗门山鸠","english_name":"Pale Mountain Pigeon","scientific_name":"Gymnophaps solomonensis","overview":"所罗门山鸠（英文名：Pale Mountain Pigeon，学名：Gymnophaps solomonensis），是鸽形目鸠鸽科山鸠属的鸟类。栖息于原始和次生的高山森林中。体长约38厘米，重约310至385克，头颈呈灰白色，下腹和胸部为淡粉色，背部和翅膀为银灰色，边缘带有黑色，具有显著的个体差异。","appearance":"所罗门山鸠的头部和颈部为灰白色，喉部和上胸部颜色较浅，下腹部和腹部呈淡粉色，臀部和尾羽覆羽为淡灰色。背部、肩羽和翅膀覆羽为银灰色，略带绿色，边缘呈黑色。初级飞羽和次级飞羽为黑色，闭合翅膀时可见绿色银色光泽。喙基部黄色，尖端黄或淡棕色，鼻孔区和喙缘有紫粉色调。虹膜橙红至红色，眼周皮肤红色或紫色，腿和脚为紫粉色。性别相似，幼鸟具蓝灰色虹膜。","call":"通常较为沉默，偶尔会发出鼻音似的喘息声 'vrrhu' 或轻柔的 'vruu' 声。亦有记录到双音节低沉的呼噜声。","habits":"所罗门山鸠生活在海拔750至1950米的山区森林，但曾在Kolombangara记录到100至940米的高度。通常在树冠层活动，进行局部垂直移动，白天会下至较低海拔觅食。以小种子果实为食，常在树冠层觅食，有时也在林下层。群居性鸟类，最多可达25只的群体被观察到。","breeding":"繁殖资料有限。在Kolombangara，发现8至10个巢穴位于狭窄山脊上的苔藓覆盖地面和矮化山地树木的突出茎部附近。巢穴为浅坑或简单的苔藓地面刮痕，几乎不加额外材料。单枚白色蛋，与Seram山鸠的蛋相似，记录到在10月、5月和6月产卵。","identification":"与其它鸽子相比，所罗门山鸠的淡黄色喙和鲜明的羽毛对比使其易于识别。与凤头杜鹃鸽的区别在于更喜群居，有较长的尖顶凤头，较长的尾巴，圆形的翅膀，缺乏鳞片状的上体和酒红色的下体，以及更粗壮的喙。","protection":"IUCN：LC（无危）","distribution":"所罗门山鸠分布于布干维尔岛、Kolombangara、Vangunu、瓜达尔卡纳尔岛（瓜岛）和Malaita（从所罗门群岛北部至中南部）。"},{"name":"麝雉","english_name":"Hoatzin","scientific_name":"Opisthocomus hoazin","overview":"麝雉（英文名：Hoatzin，学名：Opisthocomus hoazin），是麝雉目麝雉科麝雉属的独特鸟类，广泛分布于南美洲亚马孙和奥里诺科流域的热带低地。以其显著的外观和独特的生态习性而著称，常见于湖泊边缘和缓慢流动的河流旁。麝雉在该区域内分布广泛，数量相对稳定。","appearance":"麝雉体型细长，全长可达610毫米，体重约810克。头部较小，拥有如同鬃毛般的长直羽冠，颈部细长，与孔雀的头部轮廓相似。其嘴短且弯，翅膀虽大但飞行能力有限；尾羽长而宽，脚部强壮，具有四趾。上体暗褐色，杂以白斑；头冠红褐色，脸部裸露部分呈蓝色；下体为橘黄色，腹部为铁锈色。雌雄羽毛颜色相同，幼鸟翅膀上的指端长有爪，便于攀爬树木。","call":"麝雉是一种嘈杂的鸟类，会发出各种粗糙的叫声，包括咕哝声、嘶嘶声、呼噜声和哼声，这些叫声通常伴随着翅膀的展开。","habits":"麝雉栖息于热带雨林的边缘，偏好靠近水源的地带，如湖泊和河流。它们以叶片、花和果实为主要食物来源，偶尔也会摄食小鱼和虾蟹。麝雉倾向于群居，白天常集体栖息在河边的树上，天气炎热时则静止不动，黄昏和月夜较为活跃，会跳跃于树枝间寻找食物。","breeding":"麝雉在繁殖季节形成群落，通常在雨季期间，选择在距离水面2至6米高的树杈上搭建粗陋的巢穴。每窝产卵2至4枚，由雌雄双方共同孵化，孵化期约为28天。幼鸟出生时身上有稀疏的羽毛，翅膀上带有两个大爪，一周后即可游泳，遇到威胁会落入水中躲避。大约10周后，幼鸟的翅膀爪自行脱落，此时它们已经能够飞行以逃避敌人。","identification":"麝雉最显著的特征是其长而松散的羽冠、蓝色的裸露面部皮肤和红色的眼睛。在成年后，翅膀上的爪子会消失。与其他鸟类相比，麝雉的消化系统特别发达，具有发酵功能，类似哺乳动物的反刍作用。","protection":"IUCN：LC（无危）","distribution":"麝雉主要分布于南美洲亚马孙雨林地区，包括亚马逊盆地和奥里诺科河流域。","other":"麝雉是圭亚那的国鸟，因其独特的消化系统和幼鸟的爪子特征，成为了科学研究中的焦点物种。"},{"name":"蓝蕉鹃","english_name":"Great Blue Turaco","scientific_name":"Corythaeola cristata","overview":"蓝蕉鹃（英文名：Great Blue Turaco，学名：Corythaeola cristata），是蕉鹃目蕉鹃科蓝蕉鹃属的鸟类。是蕉鹃科中体型最大的物种，体长可达75厘米。其特征为灰蓝色羽毛，蓝黑色高约10厘米的竖立羽冠，黄色腹部逐渐转为深棕色，以及独特的黑黄相间的尾巴。广泛分布于非洲热带雨林，自几内亚比绍和几内亚至肯尼亚西部，坦桑尼亚西北部和安哥拉北部。","appearance":"成年蓝蕉鹃体长70-76厘米，体重800-1231克。上体主要呈灰蓝色，有高达10厘米的蓝黑色竖立羽冠；下巴白色，胸部下方黄色，逐渐变为深棕色至尾部。尾巴宽大，末端有黑色横带，尖端蓝色，腹下羽毛和尾下覆羽为栗色。喙部黄色，顶端红色；眼睛深红，眼周皮肤黑色；腿和脚黑色，脚底黄色。雌雄羽毛相似，幼鸟颜色较暗，羽冠较小，胸部灰色。","call":"发出两种独特叫声：一是深沉的‘jeeeow’声，二是快速连续的响亮‘kok’音，有时会混合出现。","habits":"栖息于低地、中间层和山地雨林以及浓密的河岸森林。通常以小群体出现，由6-7只鸟组成，偶尔更多。它们在一年中维护领地，偶尔移动到喜欢的果树，连续几天返回同一棵树，但接近树时通常无声，一只接一只离开。它们以水果为主食，但也吃芽、嫩叶、花朵和少量昆虫。在西非，它们偏好Musanga的果实，同时也会食用Cissus、Polyalthia等多种植物的果实。","breeding":"繁殖期在不同地区有所差异，如尼日利亚为5月，喀麦隆为2月、5-7月和9-12月。可能是一夫一妻制，但一对经常伴随第三个成年个体，且领土意识不强，有时在同一棵树上会有三对鸟筑巢。巢建在高8-25米的大树上，由干枝搭建，一般由两性共同完成。每窝通常产2枚蛋，孵化期为29-31天，由双亲轮流孵育。幼鸟出生后，父母全天候照顾直到27-29天大。幼鸟在第四周开始攀爬，27-33天时能短距离飞行，最终在31-38天离巢。父母会在幼鸟45天大、能够更强健飞行前保持密切接触，持续喂养幼鸟长达三个月。","identification":"蓝蕉鹃通过其巨大的体型、灰蓝色的羽毛、蓝黑色的高羽冠和独特的尾巴图案容易识别。与同属的其他鸟类相比，它的大小和色彩模式使其与众不同。","protection":"IUCN：LC（无危）。尽管在某些地区如尼日利亚由于持续的森林砍伐数量大大减少，但在大部分分布范围内并不罕见。在西乌干达和南乌干达局部地区较为常见。在加纳被列入CITES III级。","distribution":"分布于赤道非洲，从几内亚比绍、几内亚、塞拉利昂、利比里亚和科特迪瓦东至尼日利亚、中非共和国、喀麦隆、赤道几内亚（包括Bioko岛）、加蓬、北安哥拉、刚果、刚果民主共和国、南苏丹、乌干达、卢旺达、布隆迪、坦桑尼亚西北部和肯尼亚西部。","other":"在西非，蓝蕉鹃被视为美味佳肴，被当地人广泛猎杀食用。尽管如此，它在塞拉利昂仍然广泛分布且数量众多。"},{"name":"绿冠蕉鹃","english_name":"Guinea Turaco","scientific_name":"Tauraco persa","overview":"绿冠蕉鹃（英文名：Guinea Turaco，学名：Tauraco persa），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。非洲特有的一种冠蕉鹃，其分布广泛，遍布西非和中非的低地森林。","appearance":"成年绿冠蕉鹃长约40至43厘米，重约225至290克。头部、颈部、胸部和背部呈草绿色，下半背、臀部和尾巴呈暗黑带金属紫和蓝紫色光泽，腹部和尾下覆羽为暗黑色，飞羽鲜红，边缘和尖端黑色。眼周有棕色眼睑和白色眼斑，喙为红褐色，腿脚黑褐色。幼鸟的初级飞羽有更广泛的黑色尖端。不同亚种在头部标记上有所差异。","call":"发出一系列10至16个刺耳的呱呱叫声，起初声音较弱，随后逐渐增强，平均速度约为每秒2.6至3个音节。","habits":"常见于西非的低地和林带森林，偏好较为成熟的次生林，尤其在农田边缘和河流附近。主要以野生和栽培的水果、花朵和芽为食，偶尔也会食用果实。在加蓬，它们具有强烈的领域性，全年保持领地。","breeding":"繁殖期在喀麦隆为5月至6月和8月，在加蓬为12月至2月和6月至9月，在塞拉利昂为6月和10月。巢由树枝和细枝搭建，位于树丛或树的最茂密处，离地面1.5至5.3米高。通常产2枚蛋，孵化期21至23天，幼鸟在巢中停留26至28天，首次飞行在38天左右。","identification":"与其他红喙的冠蕉鹃相比，绿冠蕉鹃的头部标记不同，尤其是亚种间存在差异，如buffoni亚种在眼睛上方和前方有一条白线，而persa和zenkeri亚种在黑线下方还有一条额外的白线。","protection":"IUCN：LC（无危）；CITES II","distribution":"分布于西非和中非，包括塞内加尔至刚果民主共和国，南至安哥拉北部。具体国家有刚果共和国、安哥拉、贝宁、喀麦隆、中非共和国、刚果民主共和国、赤道几内亚、加蓬、冈比亚、加纳、几内亚、几内亚比绍、象牙海岸、利比里亚、马里、尼日利亚、塞内加尔、塞拉利昂和多哥。"},{"name":"利氏蕉鹃","english_name":"Livingstone's Turaco","scientific_name":"Tauraco livingstonii","overview":"利氏蕉鹃（英文名：Livingstone's Turaco，学名：Tauraco livingstonii），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。以其独特的羽冠和鲜艳的翼斑闻名。分布于非洲东南部的森林和茂密林地，包括从坦桑尼亚南部到马拉维东部、津巴布韦东部，广泛存在于莫桑比克，并沿南非的亚热带海岸线。此物种以Charles Livingstone命名，他是David Livingstone的兄弟。","appearance":"成年利氏蕉鹃长约45至46厘米，雄鸟体重280至380克，雌鸟262至350克。头部有长长的绿色羽冠，尖端白色。背部颜色因亚种而异，从绿色到蓝色不等；腹部和下尾覆羽呈暗黑色；飞羽鲜红，带有黑色尖端；从嘴角到眼前方有一条白色条纹，与眼下方延伸至耳羽的一条条纹由一小块黑色眼周斑隔开；眼睛棕色，眼周皮肤红色，喙粉红色。幼鸟色彩较暗淡，羽冠更短，喙色更深。亚种在颜色上差异显著：指名亚种为暗绿的肩羽、肩胛羽、翅膀和尾巴，边缘宽阔的翡翠色赋予鳞状效果，羽冠长度65至75毫米；emcabanisi/em亚种肩部绿色，肩胛羽、翅膀和尾巴呈淡蓝带紫晕；emreichenowi/em类似前者，但肩胛羽、翅膀、臀部和尾巴深蓝色，羽冠不足65毫米。","call":"主要鸣声是一系列10至15个粗糙的哇叫声，起初声音较弱，音符较短且不那么刺耳，随后音量增大，平均速度约为每秒2.4至2.65个音符。在互动中，也会发出喉音颤音和短促的吠叫音符系列。","habits":"主要栖息于沿海和山区的常绿森林，海拔从海平面到2500米。大部分时间保持定居状态。主要以果实为食，其饮食与沙氏蕉鹃有很大重叠，消费的物种中80%两者共有。","breeding":"在马拉维的繁殖期为10月至12月，在莫桑比克为12月至1月和6月，在津巴布韦为9月至2月。巢是由树枝和细枝精心编织的平台，通常位于灌木或树最茂密部分的地面以上3至10米处。产2枚白色光滑壳的蛋，孵化期22至23天，由双亲共同承担。","identification":"与尼斯那蕉鹃和沙氏蕉鹃相似，但与它们的分布范围重叠极小。羽冠比沙氏蕉鹃短，比尼斯那蕉鹃长。","protection":"IUCN：LC（无危）。CITES II。在其分布范围内普遍较为常见，但持续的森林砍伐将最终对所有亚种产生不利影响。坦桑尼亚部分地区曾遭受无差别捕猎和出口，尽管这一潜在威胁自1994年前已有所减少。","distribution":"分布于非洲东南部，包括布隆迪的孤立群体，从坦桑尼亚南部到马拉维东部、津巴布韦东部，广泛存在于莫桑比克，并沿南非的亚热带海岸线。"},{"name":"沙氏蕉鹃","english_name":"Schalow's Turaco","scientific_name":"Tauraco schalowi","overview":"沙氏蕉鹃（英文名：Schalow's Turaco，学名：Tauraco schalowi），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。以德国银行家兼业余鸟类学家赫尔曼·沙洛命名。拥有引人注目的翠绿色羽毛和长长的羽冠，分布于安哥拉至肯尼亚西南部，坦桑尼亚西部和马拉维一带。","appearance":"体长41–44厘米，体重在208–267克之间。羽毛呈现铜绿色，靠近尾部逐渐变为深蓝黑色至紫色，下体颜色较淡。头部具有长而尖的白色边饰羽冠，喙部和眼周皮肤红色，眼缘有白色羽毛。成熟个体的羽冠长度在所有蕉鹃种类中居首，翅膀短而圆，翼下有醒目的红色飞羽。","call":"发出一系列6–10个粗糙的叫声，前两个音节较短且柔和，间隔较长，随后声音加速，形成‘woh....woh....rrah..rraah..rraah..rraah..rraah’的序列，平均约每秒一音。","habits":"栖息于画廊森林、常绿林、灌木丛和河岸林地，海拔高度从600米到2500米。主要以水果和其他植物物质为食，幼鸟时期饮食更偏向昆虫。群居，但筑巢期间表现出领地性。","breeding":"繁殖期，一对配偶会共同筑巢于高树冠上，通常产卵两枚，双方轮流孵卵，孵化期持续20至22天。雏鸟在2至3周内能离巢攀爬，再过1至2周便开始飞行。","identification":"与利氏蕉鹃和尼斯那蕉鹃相似，但羽冠更长，尾部颜色更深，且分布区域差异明显，帮助区分。部分个体在坦桑尼亚北部可能缺乏眼下的白线。","protection":"IUCN：LC（无危）。被列入CITES II附录。在马拉维的Nyika高原上常见，157公顷的森林中有43个小区域，共含39对沙氏蕉鹃，平均领地面积约为4公顷。","distribution":"分布于西、中、东安哥拉（北至Malanje和Calandula）、刚果民主共和国南部、赞比亚至纳米比亚东北部（Caprivi地带）、博茨瓦纳东北部、津巴布韦西北部（Victoria Falls西侧）、莫桑比克、马拉维（Rift西侧）、坦桑尼亚西部从Ufipa至Gombe Stream国家公园；肯尼亚西南部和坦桑尼亚北部从Mara自然保护区和Loita山南至Serengeti国家公园北部和西部、Crater和Mbulu高地以及Hanang山，西至Mwanza区。"},{"name":"尼斯那蕉鹃","english_name":"Knysna Turaco","scientific_name":"Tauraco corythaix","overview":"尼斯那蕉鹃（英文名：Knysna Turaco，学名：Tauraco corythaix），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。是非洲东南部的一种大型蕉鹃，在南非被称为Knysna Loerie。该鸟以鲜明的绿色羽毛和独特的白尖头冠著称，常居住在成熟常绿森林中。","appearance":"尼斯那蕉鹃长约45至47厘米，体重在262至380克之间。成鸟具有圆顶状、可竖立的‘头盔’样绿色头冠，顶部白色；头部、颈部、胸部和披肩鲜绿色；尾巴、臀部、背部、肩羽和翼覆羽呈深金属绿色，带有翡翠和紫蓝色光泽；腹部和下尾覆羽暗黑色，略带绿色；翅膀主羽明亮的红色，尖端黑色；眼睛棕色，眼环红色；喙橙红色；腿黑色。幼鸟比成鸟暗淡，翅膀红色较少，头冠较短，喙橄榄棕色。","call":"尼斯那蕉鹃发出一系列10至25个粗糙的、沙哑的音符，最初声音微弱，音节短，随后音量增大，速度略微加快，平均节奏约为每秒2.5至3个音符。此外，还发出短促的喉音'grrrrrr'。","habits":"尼斯那蕉鹃主要生活在沿海和内陆的常绿森林，海拔从海平面到1800米。主要以水果为食，特别喜爱Rothmannia capensis、Rapanea melanophloeos、Apodytes dimidiata和Olea capensis的果实，也会吃Bushman's poison（Acokanthera spectabilis）的果实，这种果实对哺乳动物有毒。同时食用种子、Bauhinia和Ficus的叶芽，以及Cussonia的花序。在圈养条件下，每天摄入的水果总量为124克，父母在喂养雏鸟阶段会积极寻找昆虫和蚯蚓，但在其他时间不会。","breeding":"尼斯那蕉鹃在南开普省和东开普省于11月至1月繁殖，在纳塔尔省则于8月至11月繁殖。巢穴为浅平的棍子平台，类似于大型鸽子的巢，位于树上或茂密藤蔓中，离地面约2至9米高。通常产2枚，偶尔3枚光滑的白色卵；孵化期23至26天，由双亲共同孵化；雏鸟通过反刍喂养，留在巢中22至26天，首次飞行在28至35天，但数周内仍依赖父母。","identification":"与相似的利氏蕉鹃相比，尼斯那蕉鹃的头冠更圆润，白色尖端明显；紫冠蕉鹃的身体颜色更深。幼鸟的头冠较短，没有白色尖端。","protection":"IUCN：LC（无危）；CITES II。在分布范围内较为常见，但开普省沿海森林的持续缩小将最终影响指名亚种T. c. corythaix的数量。","distribution":"分布于非洲东南部，包括南非南部和东部，以及Eswatini。","other":"尼斯那蕉鹃曾被认为与西非的绿蕉鹃是同一物种的亚种。"},{"name":"黑嘴蕉鹃","english_name":"Black-billed Turaco","scientific_name":"Tauraco schuettii","overview":"黑嘴蕉鹃（英文名：Black-billed Turaco，学名：Tauraco schuettii），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。是非洲特有的一种中型蕉鹃，主要分布在中非的森林地带，包括刚果民主共和国、乌干达、肯尼亚西部、布隆迪、卢旺达和南苏丹。以其独特的绿色羽冠和鲜红的翼斑著称。","appearance":"成年黑嘴蕉鹃长约40厘米，体重介于199至272克之间。其特征在于小巧且几乎全黑的喙，以及圆润、顶部带有白色的羽冠。背部、臀部、上尾覆羽和折翼呈蓝紫色，下胸至尾下覆羽暗淡。眼睛前方和下方有一条白色线纹，与薄黑眼睑相隔。眼睛为榛褐色，眼睑和眼周皮肤红色。下颌基部深红色，腿和脚呈黑色。幼鸟与成鸟相似，但喙全黑。emini亚种的背部、臀部、上尾覆羽和折翼为深绿色，与蓝紫色的指名亚种存在中间过渡色。","call":"主叫声为一系列10到22个粗糙的呱呱声，起初微弱，随后加快节奏变响亮，平均每秒约2.5至2.75个音符。在刚果森林中，其响亮的'khaw, khaw, khaw...'叫声是一年四季中最典型的森林声音之一。","habits":"栖息于低地、中地和山地常绿森林的树冠层，海拔高度从500米至2800米。它以典型的蕉鹃方式在树间跳跃，偶尔以短促的振翅和长时间滑翔的方式飞行。食性主要包括果实和小型昆虫。","breeding":"黑嘴蕉鹃在树上约3至5米高的枝条平台上筑巢，每次产两枚蛋。雄鸟和雌鸟共同守护领地并分担孵卵职责。","identification":"与沙氏蕉鹃和绿冠蕉鹃相似，但分布区域重叠极少。与沙氏蕉鹃相比，其羽冠较短且顶端白色；与绿冠蕉鹃相比，羽冠顶端无白尖。幼鸟与成鸟的区别在于喙色全黑。","protection":"IUCN：LC（无危）。《濒危野生动植物种国际贸易公约》（CITES）二级附录物种。在其分布范围内数量丰富，特别是在刚果民主共和国。","distribution":"繁殖区域主要集中在中非的刚果民主共和国、乌干达、西肯尼亚、布隆迪、卢旺达和南苏丹的森林地带。"},{"name":"费氏蕉鹃","english_name":"Fischer's Turaco","scientific_name":"Tauraco fischeri","overview":"费氏蕉鹃（英文名：Fischer's Turaco，学名：Tauraco fischeri），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。壮观的蕉鹃，拥有闪亮的深蓝色翅膀和尾巴，头部和胸部为绿色。其独特的头部标记包括中等大小的白色和橙色沿背的羽冠，以及眼睛上方和下方的白色条纹。分布于东非沿海森林和林地，以成熟果实树的树冠和次生树冠为栖息地。","appearance":"费氏蕉鹃长约40厘米，体重介于227至283克之间，雄鸟略重。最显著的特点是白色尖端的红色羽冠，最高点处为黑色；颈背亦为红色；上体、翅膀、臀部和尾巴为蓝绿色；下腹部黑色；初级飞羽和部分次级飞羽为红色；眼线从眼前方延伸到喙，与眼下线通过一小块黑色面部斑点隔开，一直延伸到耳羽覆盖处；眼棕色，裸露的眶周皮肤红色，周围有一圈细黑环；喙鲜红色；腿和脚为黑色。幼鸟外观相似。Zanzibaricus亚种的上体、翅膀、臀部和尾巴为紫蓝色，而非蓝绿色。","call":"费氏蕉鹃的叫声为一系列粗糙的加速‘kow’音符，起初声音较轻，随后变响并略微加快，平均节奏约为每秒1.9至2.2个音符。","habits":"主要栖息于沿海森林和林地，偏好成熟果实树的树冠层。海拔高度从海平面至1250米，偶尔可达1450米。以水果为主食，特别偏好Pachystela brevipes的黄色浆果，也会吃Afzelia cuanzensis的花蕾和嫩叶，偶尔机会性地捕食昆虫。","breeding":"繁殖季节在肯尼亚为6月。巢建于离地面3至10米的浓密树丛中，由脆弱的树枝平台构成。产2枚几乎球形的淡白色卵，孵化期22至23天，由双亲共同孵化。新生雏鸟覆盖着深棕色绒毛，最早在10天大时就能在附近枝条间跳跃和爬行。","identification":"与利氏蕉鹃和蓝冠蕉鹃总体相似，但可通过羽冠中的橙色轻松区分。","protection":"IUCN：NT（近危）。被列入《濒危野生动植物种国际贸易公约》附录二。全球数量可能不超过2000只，其中在索马里南部朱巴河谷、肯尼亚和坦桑尼亚东北部仅存少数，Zanzibaricus亚种仅限于桑给巴尔岛。","distribution":"分布于非洲东部，具体包括肯尼亚、坦桑尼亚东北部和索马里南部。在肯尼亚和坦桑尼亚东北部，常见于Shimba Hills国家公园和E Usambara低地森林。","other":"该物种因栖息地丧失和非法贸易而受到威胁。"},{"name":"黄嘴蕉鹃","english_name":"Yellow-billed Turaco","scientific_name":"Tauraco macrorhynchus","overview":"黄嘴蕉鹃（英文名：Yellow-billed Turaco，学名：Tauraco macrorhynchus），是蕉鹃目蕉鹃科冠蕉鹃属的中等体型的绿色鸟类。其最显著的特点是拥有亮丽的黄色大喙，分布于非洲中西部和西部的低地森林。","appearance":"黄嘴蕉鹃体长40至43厘米，雄鸟体重约261至272克，雌鸟约216至234克。头部、颈部和胸部为绿色，具有一顶圆顶状的绿色羽冠，顶端点缀着黑白色。翼覆羽、内侧次级飞羽、肩羽、背部、臀部和尾巴呈现出光泽的蓝紫色；初级飞羽和外侧次级飞羽为鲜红色；腹部呈黑色，带有绿色调；下尾羽为黑色。眼睛为深棕色，周围有鲜红的皱褶环，边缘环绕着一条细黑线；喙为亮黄色，基部有时带有暗红色；腿和脚为黑色。幼鸟颜色较为暗淡。亚种emverreauxii/em的羽冠尖端为鲜红色和黑色，而非黑白相间，上体的蓝紫色被绿色大量覆盖。","call":"主要鸣声为一系列长达55个粗糙的嘎嘎声，起初音速加快，由一个较短、音质较柔和的音符和一段较长的停顿引出，例如：“whoh...groh-groh-groh-groh..groh..groh..groh...”（总时长可达21秒）。此外还会发出短促的沙哑音符和一连串类似乌鸦的呱呱声。","habits":"主要栖息于低地和山地画廊森林，严格限制在原始森林中，偶尔会进入次生林地带。海拔范围从海平面至1600米。生活方式定居，不迁徙。以水果为主食，尤其偏好Musanga、Coelocaryon、Polyalthia等植物的果实，也会食用树籽、嫩芽，以及蚂蚁群驱赶出的蜗牛和昆虫。","breeding":"繁殖期在塞拉利昂为12月和2月，在喀麦隆为6月至8月和12月至1月，在加蓬为5月至6月、8月和12月至1月。巢穴为由干树枝搭建的脆弱平台，隐藏在树冠中，离地面7至10米高；有关在比奥科岛地面筑巢的报道需待证实。产卵数为2枚椭圆形、乳白色的蛋，双亲共同孵卵。","identification":"与红嘴的近亲绿冠蕉鹃相比，更常出现在原始森林中。通过明亮的黄色大喙、绿色羽冠和蓝紫色翅膀及尾巴的独特组合来区分。","protection":"IUCN：LC（无危）。CITES II。在利比里亚的尼姆巴山、加蓬的马科库周围和塞拉利昂的适宜栖息地中，黄嘴蕉鹃报告为常见，但实际数量数据不多。在其他地方似乎较为罕见，可能因被忽视或与相似物种混淆。其对原始森林的依赖使其面临进一步的森林砍伐和局部伐木威胁。","distribution":"分布于安哥拉、喀麦隆、刚果共和国、刚果民主共和国、象牙海岸、赤道几内亚、加蓬、加纳、几内亚、利比里亚、尼日利亚和塞拉利昂。非洲中西部和西部地区。","other":"其分布范围因达荷美缺口的干旱气候而出现断层，将两种形态上不同的亚种分开，T. m. macrorhynchus从塞拉利昂到加纳，T. m. verreauxii从尼日利亚，穿过刚果民主共和国到安哥拉。有人提议基于生物地理学、形态学和分子系统发育，将其视为两个独立的物种，并将其转移到Musophaga属，因为它们与其他Tauraco物种在系统发育上不相关。"},{"name":"白冠蕉鹃","english_name":"White-crested Turaco","scientific_name":"Tauraco leucolophus","overview":"白冠蕉鹃（英文名：White-crested Turaco，学名：Tauraco leucolophus），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。美丽的冠蕉鹃属鸟类，以纯白色头部、眼上方黑色标记、深蓝色翅膀和尾巴、绿色背部和下体为显著特征。广泛分布于尼日利亚东部至肯尼亚西部的河流森林和木林地带。","appearance":"成年白冠蕉鹃长约40厘米，体重在198至226克之间。拥有鲜明的纯白色头冠、脸颊和颈部，与光泽紫蓝黑色的眼区、前额、前顶和眼后区形成强烈对比。眼睛下方有窄黑线，喉部呈淡绿色，肩部和胸部为草绿色，背部、折叠的翅膀、臀部和尾巴呈现光泽的紫蓝色，腹部和尾下覆羽为黑色。一级飞羽和外侧二级飞羽为鲜红色，尖端黑色。眼睛深棕色，眼睑和裸露的眶周皮肤鲜红，喙黄色基部淡绿色，腿和脚暗褐色。","call":"主叫声由一系列14至18个粗糙的呱呱声组成，以稳定的节奏发出，前有一个拉长的哀号音符，总时长6至8秒。","habits":"栖息于河流旁的森林和树木繁茂的草原，尤其是藤蔓和悬垂植物丰富的地区。活动范围从海拔100米到2200米。主要以果实和浆果为食，也会食用花序和一些蜗牛。","breeding":"繁殖季节在不同地区有所变化，如刚果为4月，乌干达为8月。巢穴构造简单，呈浅盘状。","identification":"与其他冠蕉鹃相比，其独特的白色头冠易于识别。","protection":"IUCN：LC（无危）","distribution":"分布于非洲尼日利亚东南部、喀麦隆北部（阿达马瓦高原）、乍得南部、中非共和国北部、南苏丹西南部和南部、刚果民主共和国东北部、乌干达北部和中部、肯尼亚西部。","other":"遗传研究表明，白冠蕉鹃与红冠蕉鹃和班氏蕉鹃关系密切，约在更新世晚期分化。"},{"name":"班氏蕉鹃","english_name":"Bannerman's Turaco","scientific_name":"Tauraco bannermani","overview":"班氏蕉鹃（英文名：Bannerman's Turaco，学名：Tauraco bannermani），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。主要栖息于喀麦隆西北部的Bamenda高原，生活于热带湿润山地森林中，是濒危物种。","appearance":"班氏蕉鹃身长可达43厘米，重约200至250克。其头部灰暗，橙红色的冠羽、红顶和颈背鲜明，上体呈深绿色，下体颜色较淡，尾羽蓝色。飞行时可见翼下的红色斑块，但因害羞而鲜少露面。","call":"鸣叫声独特，一系列粗犷的“kow-kow-kow”音符，能在一公里外被听见。","habits":"班氏蕉鹃主要栖息于喀麦隆Bamenda高原的山地森林，包括原始森林和保留有足够高树的次生林，海拔高度介于1700至2950米。它们通常以水果和浆果为主食，尤其是Podocarpus milanjensis的果实。","breeding":"繁殖季节在雨季初期的3月至6月，筑巢于孤立树木或灌木的最浓密部分，通常离地面1.5至10米，巢由细枝搭建，每次产2枚白色蛋，双亲共同孵化。","identification":"班氏蕉鹃在分布范围内是唯一拥有红色冠羽的蕉鹃种类。","protection":"IUCN：EN（濒危）。CITES I级附录物种。班氏蕉鹃面临严重威胁，主要来自森林砍伐，栖息地已减少一半，总估计数量在2500至10000只之间。","distribution":"非洲喀麦隆西北部，主要集中在Bamenda-Banso高原。","other":"班氏蕉鹃的生存依赖于Kilum-Ijim森林的保护，此森林是其最大的残存山地森林区域。"},{"name":"红冠蕉鹃","english_name":"Red-crested Turaco","scientific_name":"Tauraco erythrolophus","overview":"红冠蕉鹃（英文名：Red-crested Turaco，学名：Tauraco erythrolophus），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。拥有醒目的红色羽冠和黄色喙。其分布区域局限于安哥拉西部，是该国的国鸟。该鸟以红冠和白色脸部为显著特征。","appearance":"红冠蕉鹃体长约40至43厘米，体重210至325克。全身绿色，头部具有独特的红色羽冠，有时尖端呈白色，延伸至颈背。脸部为白色，喙黄色，部分个体基部带淡绿色。与班氏蕉鹃相比，其红色羽冠有白色尖端，颈背红色更明显。","call":"红冠蕉鹃的叫声独特，持续约10秒，先是一声深沉的‘hooooah’，随后是7到10个尖锐的‘khaaar’音符，比大多数其他蕉鹃的叫声更高。","habits":"红冠蕉鹃通常成对或小群体生活，栖息于常绿森林、河岸林和Miombo木林边缘。它们主要在安哥拉的悬崖地带活动，从刚果河下游至Chingoroi，向东至少到Malanje和上Cuanza河。活动范围包括从刚果河的原始和次生常绿森林到Bie省的Brachystegia区。","breeding":"繁殖生态未知，但推测与同属物种相似。曾在9月发现处于繁殖状态的个体，另有记录显示1月份观察到收集筑巢材料的行为。","identification":"红冠蕉鹃是其分布范围内唯一具有红色羽冠的蕉鹃，与班氏蕉鹃的区别在于后者羽冠颜色更深，且两者无地理重叠。与绿冠蕉鹃的区别在于后者头部和羽冠为绿色，喙为红色，眼周有黑白标记。","protection":"IUCN：LC（无危）。CITES II。在安哥拉的战争影响地区，红冠蕉鹃被报告为森林中最常见的蕉鹃，但在亚山地森林的清除和阔叶林的持续退化可能对其数量构成威胁。","distribution":"繁殖区域：安哥拉西部和中部，从刚果河下游至Chingoroi，向东至少至Malanje和上Cuanza河。非繁殖区域：无具体记录，但推测在已知范围和栖息地内为留鸟。","other":"红冠蕉鹃是安哥拉的国鸟，常见于Gabela和N'dalatando地区的森林以及Cuanza河沿岸的画廊森林和Quissama国家公园。"},{"name":"蓝冠蕉鹃","english_name":"Hartlaub's Turaco","scientific_name":"Tauraco hartlaubi","overview":"蓝冠蕉鹃（英文名：Hartlaub's Turaco，学名：Tauraco hartlaubi），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。头冠及上体蓝色，下体绿色，飞行时双翼呈现鲜艳的红色。主要分布在非洲东部的肯尼亚和坦桑尼亚，以蒙特森林、茂密的林地和花园为栖息地。蓝冠蕉鹃的平均寿命约为12年。","appearance":"蓝冠蕉鹃体长约43厘米，体重在210-275克之间。成鸟额头、圆润的羽冠和颈背为光亮的蓝黑色，眼前方有一显著的白色斑块，与从喙角延伸到耳羽的一条白线由黑色眼纹和紧贴眼下的细黑线隔开。下巴、脸颊、颈部、肩部、喉咙和胸部为绿色；背部下方、折叠的翅膀和尾巴呈深紫蓝色；臀部蓝黑色；主要飞羽和外侧次级飞羽为鲜红；大腿和腹部为暗黑色，略带绿色。眼睛棕色，眼眶环和裸露的眼后皮肤为红色；喙为深红色；腿和脚为黑色。幼鸟与成鸟相似。","call":"蓝冠蕉鹃的叫声为粗哑、加速的一系列‘kow’音符，尤其在早晨和傍晚发出。它们也会发出类似大猴子的粗犷咆哮声，嘶哑或断续的‘chut chut’或‘chek chek’声，焦虑时的低沉音符或‘puit puit’声，警报时的‘kak kak kwak kwak’声，求偶时连续的‘quark quark’声，起飞时单个的‘quark’声，以及巢中的鸟儿回应伴侣时重复的‘whii caraw’声。","habits":"蓝冠蕉鹃主要以果实和浆果为食，尤其是Chaetacme、Elaeodendron、Euclea等植物的果实，也能食用Acokanthera longiflora的大型有毒果实。在肯尼亚东南部，它们还会食用Allophylus abyssinicus、Canthium oligocarpum等植物的果实。在内罗毕郊区，它们常吃异国情调的水果，如Cotoneaster。除了果实，它们也会捕食毛虫、蛾和甲虫。蓝冠蕉鹃会成群聚集，最多可达20只，在结果树上觅食。","breeding":"蓝冠蕉鹃的繁殖季节为4月至12月，高峰期与降雨量高的时期相吻合。它们是单配偶制和领地性的。巢是一个直径约20厘米的浅平台，由松散交织的枝条构成，有时用更细的枝条衬里，位于离地面3-8米的浓密树丛中，如Rhus或Chaetacme。通常产卵数为两个（1-2枚），卵圆形，呈哑光白色，平均大小为38毫米×31.5毫米。孵化期大约为16-18天，由双方共同承担。新生雏鸟覆盖着黑色绒羽，以毛虫和反刍的果肉为食；大约在17-18天时，它们能在巢树周围攀爬，很少停留在巢中，大约在28天左右就能飞行。","identification":"蓝冠蕉鹃与其他冠蕉鹃的区别在于其暗蓝色的头冠和面部的白色标记。与紫冠蕉鹃相比，它具有独特的白色面部标记。","protection":"IUCN：LC（无危）；CITES II。在分布范围内普遍常见，许多海拔2000米以上的地区仍能发现大量蓝冠蕉鹃。坦桑尼亚北部的一些种群可能因无差别捕猎用于鸟类出口贸易而受到显著影响。","distribution":"蓝冠蕉鹃主要分布在非洲东部，包括肯尼亚中部至乌干达东部和坦桑尼亚北部。具体而言，其分布中心围绕肯尼亚高地，向乌干达东部（Morongole、Moroto、Kadam、Debasien和Elgon山）和坦桑尼亚北部（Loliondo、Longido、Meru山和乞力马扎罗山、北南Pares和Usambaras西部）延伸。"},{"name":"紫蕉鹃","english_name":"Violet Turaco","scientific_name":"Tauraco violaceus","overview":"紫蕉鹃（英文名：Violet Turaco，学名：Tauraco violaceus），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。是非洲特有的一种大型蕉鹃，最显著的特征是紫色光泽的羽毛，面部图案独特，包括红色和黄色的大喙、红眼圈、白色耳斑和头部后部的深红色。主要分布在西非，从塞内加尔和冈比亚到乍得和中非共和国。","appearance":"成年紫蕉鹃约50厘米长，体重约360克。头部的冠羽和颈背为鲜红色，短而丝绒般；耳羽为纯白色；下颌、喉部和颈部呈现光泽的蓝黑色；上体和翼覆羽为蓝紫色；尾羽也是蓝紫色，带有绿色光泽；胸部至上腹部为蓝黑色，带有苔绿色；下腹和大腿为哑光黑色；初级飞羽和外侧次级飞羽为鲜红色，尖端呈棕色；喙为红色，前额有凸起的黄色盾牌状结构，眼睛为深褐色，眼周裸露皮肤为红色；腿和脚为黑色或绿黑色。幼鸟较为暗淡，缺乏成鸟明显的头部和喙色彩。","call":"主叫声为一系列类似鸽子的柔和滚动音符，常由几只鸟同时发出，或交替发出一系列咯咯声，形成“korrroo..korrroo..korrroo..kah-kah-kah-kah..korrroo..korrroo…”的叫声。","habits":"紫蕉鹃主要栖息于画廊森林、森林边缘和水道旁的林带，位于湿润或干旱的草原中；偶尔出现在高大的城市公园和花园。它们主要以果实、浆果和种子为食，特别喜爱无花果（Ficus）。它们可能大部分时间保持固定栖息地，但在某些情况下会迁移到新的地区。","breeding":"紫蕉鹃在4月于塞内加尔和冈比亚繁殖，6月至10月在尼日利亚繁殖。它们的巢是一个脆弱的、由树枝和细枝搭建的鸽子型平台，离地面约6米。每窝产两枚灰白色、不光滑的卵，孵化期为25至26天，由双亲共同承担。","identification":"与罗斯蕉鹃相似，但分布范围重叠很少，紫蕉鹃可通过其面部细节轻松区分，包括双色喙和独特的面部图案。","protection":"IUCN：LC（无危）","distribution":"紫蕉鹃主要分布于西非，从塞内加尔和冈比亚向东延伸至尼日利亚北部和喀麦隆西北部，南至象牙海岸、加纳和多哥沿海地区（在塞拉利昂、利比里亚和尼日利亚内陆未发现）。在乍得南部和中非共和国北部也有孤立的种群。","other":"在几内亚、塞拉利昂、利比里亚和加纳，紫蕉鹃受到无差别捕猎用于鸟类出口贸易的影响，CITES III级保护物种（仅限加纳）。"},{"name":"短冠紫蕉鹃","english_name":"Ross's Turaco","scientific_name":"Tauraco rossae","overview":"短冠紫蕉鹃（英文名：Ross's Turaco，学名：Tauraco rossae），是蕉鹃目蕉鹃科冠蕉鹃属的鸟类。此鸟以深蓝紫色为主色调，头部具有醒目的红色羽冠，脸部黄色，体长51至54厘米，体重介于390至444克之间。广泛分布于非洲东部及中部，从喀麦隆至南苏丹和肯尼亚西部，南部至安哥拉和博茨瓦纳。","appearance":"成年短冠紫蕉鹃的头部呈深红宝石色，形成短而竖立的羽冠；下巴、喉咙、颈背及颈部为光亮的蓝黑色；上体、胸部、翼覆羽和尾巴为深紫蓝色；腹部和大腿为黑色；主翼羽和外侧次级飞羽为鲜红色，尖端带褐色；喙为黄色，前额有黄色凸起盾牌状结构，眼周皮肤为亮丽的黄色；腿和脚为黑色。幼鸟的喙和眼周裸露皮肤为黑色，没有前额盾牌，额头羽毛为黑色，头顶中央有一块鲜红色斑点。","call":"其叫声为低沉的起伏颤音，通常由一群鸟同步发出，尤其是在清晨和黄昏，或是进入和离开巢区、遭遇敌对互动时。","habits":"栖息于原始和次生常绿森林的树冠层，也出现在Mavunda森林和Marquesia灌丛、Euphorbia灌木丛、Cryptosephalum和Brachystegia林地。在乌干达的郊区花园中也有发现，偏好高大树木。偶尔会出现在较轻的Burkea树林中。高度分布范围从海平面至1800米，甚至可达2500米。它们经常在远离常规栖息地的区域寻找结果的树木，通常在2平方公里的家园范围内活动。","breeding":"繁殖期在肯尼亚为5月至11月，在乌干达全年（除9月），在赞比亚为8月至11月和2月，在扎伊尔为12月。一夫一妻制，领地意识强，会驱赶入侵的大型鸟类。巢穴建于离地面2至16米高的浓密树叶、槲寄生或藤蔓中，由两性共同建造，直径约20至21厘米的平台型巢，内铺小枝条。每窝产1至2枚几乎圆柱形的乳白色蛋，孵化期为24至26天，幼鸟出生时覆盖着深棕色绒毛，21天后羽毛丰满，头部仍保持绒毛状态，24天左右离巢，30天左右完全独立。","identification":"与紫蕉鹃相似，但可通过红冠、黄色喙尖和眼斑、暗色颈背以及耳羽下无白线来区分。两者分布重叠极小。","protection":"IUCN：LC（无危）","distribution":"分布于喀麦隆至南苏丹和肯尼亚西部，南部至安哥拉和博茨瓦纳。在乌干达常见，在其大部分分布范围内普遍到常见。","other":"适应能力强，能在森林退化和碎片化的环境中生存。在加蓬东北部的发现表明，可能在某些地方被低估。"},{"name":"白颊蕉鹃","english_name":"White-cheeked Turaco","scientific_name":"Menelikornis leucotis","overview":"白颊蕉鹃（英文名：White-cheeked Turaco，学名：Menelikornis leucotis），是蕉鹃目蕉鹃科 Menelikornis 属的鸟类。中等体型的蕉鹃，身长约43厘米，尾长19厘米，体重约200至315克。以独特的绿色羽衣和脸部两侧的白色标记著称，这些标记在地理上有所变化。分布于非洲东北部的埃塞俄比亚高地、厄立特里亚、南苏丹的波多卡普斯和杜松森林。","appearance":"成年白颊蕉鹃拥有绿色的额头、颈部、喉咙、胸部和背部。其圆顶状的冠羽和后冠区呈深蓝色光泽，脸部两侧有大型圆形的白色眼纹，眼下方有一条细小的黑色带纹延伸至耳羽，颈侧有一个突出且变异的弯月形白色斑块。背部下侧、折叠的翅膀和尾巴呈灰蓝色，臀部呈灰蓝色；初级飞羽和次级飞羽外缘为鲜红色；大腿和腹部为暗黑色；眼睛棕色，眼眶周围有明亮的红色肉垂；喙为红色，鼻孔周围被羽毛部分遮盖，腿和脚为黑色。幼鸟与成鸟相似，但亚种donaldsoni的后冠区和冠羽为暗红色。在埃塞俄比亚东部和裂谷西部的个体背部和翼覆羽更蓝，且有明显的颈斑，而裂谷东侧的个体色彩更鲜艳、更绿，颈部侧面的白色较少。","call":"主叫声是一系列粗糙的呱呱声，节奏独特，不同于同类的其他物种。通常由两到三个长音开始，随后是2至5个快速短音，接着是10至12个以稳定节奏发出的更刺耳的音符，例如“go..gwOh..gwOh..gogogogo.gro.groh..groh..groh..groh..groh..groh..”。此外，还会发出尖锐的颤音警报。","habits":"白颊蕉鹃主要栖息在海拔2200至3200米的波多卡普斯和杜松森林中，但在奥莫谷可低至850米。它们也出现在沿水道的高大树林和茂密灌木丛中。在厄立特里亚，几乎可以在任何密集的林地中发现，除了金合欢树，海拔可达900米。主要以波多卡普斯和杜松树的果实和浆果为食。大部分时间在固定范围内活动。","breeding":"繁殖季节在埃塞俄比亚为4月，在埃塞俄比亚为6月至11月。巢穴是一个相当厚实的干枝平台，结构松散，顶部稍凹，位于地面以上7至10米处。产2枚乳白色的蛋；孵化期22至23天，由双亲共同承担。新生雏鸟全身覆盖着黑色绒毛；18至19天后开始在巢周围的树枝上爬行，25至26天后能够飞行。","identification":"与王子蕉鹃相比，白颊蕉鹃容易通过其脸部的白色标记区分。亚种间的主要差异在于羽毛颜色，尤其是donaldsoni亚种的头部后冠区和冠羽为暗红色。","protection":"IUCN：LC（无危）。CITES II。在埃塞俄比亚高地的波多卡普斯和杜松森林中较为常见。目前没有已知的威胁，但其森林栖息地的破坏可能会导致当地数量严重减少。","distribution":"分布于东北非的埃塞俄比亚、厄立特里亚、南苏丹和苏丹南部。在埃塞俄比亚，主要分布在海拔2400米以上的波多卡普斯和杜松森林中。","other":"在某些地区，白颊蕉鹃是被最常饲养的蕉鹃种类之一。"},{"name":"王子蕉鹃","english_name":"Ruspoli's Turaco","scientific_name":"Menelikornis ruspolii","overview":"王子蕉鹃（英文名：Ruspoli's Turaco，学名：Menelikornis ruspolii），是蕉鹃目蕉鹃科 Menelikornis 属的鸟类。以独特的绿色外观和蓬松的灰白色羽冠著称，常在果实丰富的森林中活动。","appearance":"王子蕉鹃长约40厘米，体重介于200至290克之间。成鸟的前额和鼻孔前方的羽冠覆盖处呈绿灰色；圆形的浓密羽冠（约40毫米长）是灰白色，基部玫瑰粉色，颈背有一簇红色羽毛；眼下方区域、耳羽及脸颊亮黄绿色；下巴和喉部灰绿色；颈部、胸部和上背部为苔绿色；下背、折叠的翅膀和尾巴灰蓝；初级飞羽和外侧次级飞羽鲜红；腹部和大腿黑色；眼睛棕色，裸露的眼眶皮肤和眼上方肉垂深红；喙和腿脚黑色。幼鸟尚未详细描述。","call":"其主要鸣声为一系列粗哑的‘krow’音符，节奏类似Tauraco leucotis但更快，包含更多较短的音符：三声引子后是一连串断断续续的声音，逐渐减速至稳定节奏（总持续时间约4秒）。此外还有高音单音和类似的断续系列，以及拉长的咆哮声。","habits":"栖息于杜松（Juniperus）林地，伴有茂密的常绿灌木丛，偏好干燥的森林边缘、金合欢-松木林地和混合阔叶灌木丛，海拔高度从1250米至1860米。它会进行短程移动，从湿润的杜松林到周围较为干燥的林地。主要以果实为食，尤其是无花果（Ficus）、Juniperus procera和Podocarpus gracilior。","breeding":"关于繁殖的确切信息缺乏。最近有报道称，在Genale河附近（Sidamo省），繁殖期可能在12月至次年2月，需要进一步调查。","identification":"与白颊蕉鹃相似，但可通过其灰白色的羽冠和面部缺乏白色标记轻松区分。","protection":"IUCN：NT（近危）","distribution":"分布于埃塞俄比亚南部山区，具体包括Arero、Bobela、Sokora、Negele和Wadera周边。","other":"虽然之前被认为是极度濒危的物种，近期调查显示其实际数量和分布比预期更广泛。它能适应人类活动在其栖息地的存在，偏好干燥生境而非湿润的杜松林。"},{"name":"紫冠蕉鹃","english_name":"Purple-crested Turaco","scientific_name":"Gallirex porphyreolophus","overview":"紫冠蕉鹃（英文名：Purple-crested Turaco，学名：Gallirex porphyreolophus），是蕉鹃目蕉鹃科 Gallirex 属的鸟类。属于未完全分类的Turaco支系。以鲜艳的蓝紫、绿色羽毛和独特的红眼环著称，是斯威士兰的国鸟，其红色飞羽在Swazi皇室的仪式装束中占有重要地位。","appearance":"成年紫冠蕉鹃长42-46厘米，体重在218-328克之间。头部呈现光泽的翡翠绿，额头至耳羽处亦同色，紫冠亮丽，颈部和胸部以绿色为主，泛着玫瑰粉。背部上侧绿色，下侧及翅膀覆羽灰蓝，臀部暗蓝黑，翼端和外侧次级飞羽为鲜红，腹部淡蓝灰色。虹膜棕色，眼周裸露皮肤为鲜艳的红色，喙及腿脚呈黑色。幼鸟与成鸟相似，但翅膀的红色部分较为暗淡且覆盖面积小。","call":"紫冠蕉鹃发出一系列类似咯咯声的叫声，起初快速而低沉，随后音调渐长且音量增大，最终突然停止，整个过程持续10-14秒。此外，还会发出短促的单个或双个接触叫声。","habits":"栖息于湿润的林地、常绿灌木丛和沿河植被，偶尔也会出现在海岸森林、Brachystegia林地、城市公园、花园和异域植物园。活动范围广泛，从海平面到海拔1850米的地区都有它们的身影。以多种果实为食，如无花果、Strychnos、Lannea等，也吃多种其他植物的果实和Capparis的芽。在南非，它们会到鸟桌觅食木瓜、番石榴、桑葚和玉米面。","breeding":"繁殖季节在坦桑尼亚为1-3月，在马拉维为1月，在赞比亚为12月，在津巴布韦为10-1月，在南非为11-12月。巢建于地面3-9米高的树上，由交错的细枝构成，藏匿于茂密的藤蔓或寄生植物中。每窝产2-3枚光滑的白色蛋，间隔1-2天下一枚，孵化期约22-23天，由双亲共同承担。雏鸟出生时覆盖着灰褐色绒毛，最初一周几乎不间断地被亲鸟照顾，通过反哺喂养，亲鸟立即清理雏鸟的粪便。雏鸟约三周后开始活跃，离巢攀爬，首次飞行大约在38天左右。","identification":"与短冠紫蕉鹃相比，紫冠蕉鹃全身颜色更深，具有红冠和黄色面部特征。亚种emchlorochlamys/em缺少背部和胸部的粉色色调，眼周裸露的红色皮肤延伸更远，腹部和大腿为灰绿色，次级飞羽和尾巴缺乏绿色调。","protection":"IUCN：LC（无危）。CITES II。在南部非洲范围内，虽然分布有限，但紫冠蕉鹃在多个地区相对常见。然而，由于坦桑尼亚严重的栖息地丧失和无差别捕捉，emchlorochlamys/em亚种在其东非范围内已接近威胁状态，仅存几组孤立的小群体。","distribution":"分布在非洲东南部，包括布隆迪、肯尼亚、马拉维、莫桑比克、卢旺达、南非、斯威士兰、坦桑尼亚、乌干达、赞比亚和津巴布韦。最南端分布至夸祖鲁-纳塔尔省和东开普省边界附近的姆塔姆瓦纳河。","other":"紫冠蕉鹃在南部非洲被视为大型食果者，能将各种植物种子从觅食地远距离携带至筑巢地，有助于种子传播和生态系统的有效运行。"},{"name":"红胸蕉鹃","english_name":"Rwenzori Turaco","scientific_name":"Gallirex johnstoni","overview":"红胸蕉鹃（英文名：Rwenzori Turaco，学名：Gallirex johnstoni），是蕉鹃目蕉鹃科 Gallirex 属的美丽多色鸟类，分布于非洲中部的阿尔伯丁裂谷山地森林，以水果为主食，常以小群体形式活动。","appearance":"成鸟长约45厘米，重211-259克。头部前额和前冠区呈光泽的翠绿色，后冠区有短而光泽的蓝紫色或翠绿色的短羽冠，颈背为暗红色，下巴和喉部为深紫黑色，与绿色的脸颊和颈部形成鲜明对比。上背部和胸部为绿色，胸前有桃红色斑块；下背部、翼覆羽和尾羽为深紫蓝色至黑色；初级飞羽和外侧次级飞羽为暗尖端的鲜红色；腹部、大腿和尾下覆羽为灰色。喙为淡灰绿色，有时带蓝色调，基部细点状的紫红色，鼻孔至喙尖为黑色；眼睛为深棕色，眼睑狭窄红色；脸部裸露皮肤大部分为亮柠檬黄色，但某些个体后部和下缘为鲜红色；腿和脚为黑色。","call":"发出独特的类似猴子的‘chk-chk-chk...’或‘ik, ik, ik, krowng’叫声，不同于其他蕉鹃的主要叫声。在警戒时，会发出回响的‘chip-ip-ip-ip’声，一系列刺耳的‘caw’音符，音调比其他蕉鹃更高。","habits":"居住于海拔1770至3700米的山地森林，偏好竹子和Podocarpus为主的区域。以果实和浆果为主要食物来源，如无花果、Galineria、Maesa等，饮食中约6.3%为藤本和寄生植物的叶子。偶尔捕食昆虫、蜗牛、蛞蝓等。通常以4只左右的小群活动。","breeding":"繁殖季节为5月至11月，筑巢于地面3-5米高处，类似鸽子巢的平台状结构，多位于竹丛中。产1-2枚淡灰白色蛋，由双亲共同孵化。雏鸟覆盖黑色绒毛，眼周皮肤蓝色，耳羽周围皮肤粉色；喙尖黑色，基部粉色；腿灰色。","identification":"与紫冠蕉鹃有轻微地理重叠，但通过下巴、喉咙颜色、颈背颜色和面部皮肤等特征区分。","protection":"IUCN：LC（无危）","distribution":"分布于非洲中部的阿尔伯丁裂谷山地森林，包括乌干达的Rwenzori山脉国家公园、Mgahinga国家公园和Bwindi国家公园。","other":"在Rwenzori山脉可能会因极端降雨而向低海拔移动。"},{"name":"南非灰蕉鹃","english_name":"Grey Go-away-bird","scientific_name":"Crinifer concolor","overview":"南非灰蕉鹃（英文名：Grey Go-away-bird，学名：Crinifer concolor），是蕉鹃目蕉鹃科灰蕉鹃属的鸟类。是非洲南部常见的一种鸟类，活跃于干燥至湿润的开放林地和荆棘草原，尤其靠近水源地带。独特的外观和习性使其在分布范围内难以混淆。","appearance":"南非灰蕉鹃体长47-51厘米，体重约200至300克。全身呈均匀的烟灰色，尾巴长而飘逸，拥有一个约6-7.5厘米的细长、可竖立的顶冠。喙部强壮而向下弯曲，颜色为黑色，口角和舌头呈现醒目的粉红色。胸部羽毛略带橄榄色，最暗处位于下巴和喉咙，腹部颜色最浅。","call":"它们的叫声包括一系列鼻音十足的短促叫声，常常以一连串的方式重复。最著名的叫声是鼻音的'gweh'或稍长的'gorwAay'，后者即其绰号'go-away-bird'的由来，通常最后一个音节会拖长。","habits":"南非灰蕉鹃栖息在有刺灌木丛、草原和河岸树林，偏好有金合欢树的环境，常在郊区公园和花园中被发现。高度依赖水，海拔从海平面至1500米，偶尔可达2200米。它们的移动与食物和水源的季节性变化有关，没有规律的迁徙模式。以多种水果、花蜜、花、嫩芽、叶子、白蚁为食，有时会在地面饮水和觅食白蚁。","breeding":"繁殖期在安哥拉为7月至8月，在马拉维为4月至11月，在赞比亚为8月至9月，在纳米比亚为9月和12月至4月，在南非和津巴布韦全年均可繁殖。巢穴为松散的鸽子型平台，直径约18-24厘米，由双亲共同建造，高度3-20米，通常位于金合欢树上。每窝产卵通常3枚（1-4枚），白色或淡蓝灰色，孵化期26-28天，由双亲轮流孵卵，幼鸟出生时覆盖着密集的棕色绒毛。","identification":"与其他蕉鹃相比，南非灰蕉鹃的色彩更加均匀的烟灰色，且在分布范围上很少重叠，易于通过其一致的灰色外观进行区分。","protection":"IUCN：LC（无危）。在大部分分布区内，南非灰蕉鹃数量丰富，但在南非某些地区被视为果园和花园的害鸟，受到人类迫害。同时，它们也是猛禽如短尾雕和非洲鹰的猎物。","distribution":"分布于南部非洲，包括南部安哥拉、刚果民主共和国南部、赞比亚、坦桑尼亚南部、马拉维、莫桑比克、纳米比亚、博茨瓦纳、津巴布韦、南非和斯威士兰。","other":"尽管没有定期迁徙，南非灰蕉鹃会根据食物和水源的可获得性不规则地游荡。"},{"name":"棕脸灰蕉鹃","english_name":"Bare-faced Go-away-bird","scientific_name":"Crinifer personatus","overview":"棕脸灰蕉鹃（英文名：Bare-faced Go-away-bird，学名：Crinifer personatus），是蕉鹃目蕉鹃科灰蕉鹃属的鸟类。体长约48厘米，重约210至300克，主要分布于埃塞俄比亚、乌干达、肯尼亚、坦桑尼亚等地的开阔林地。","appearance":"成鸟前脸至眼后及下巴、喉部几乎无羽毛，显暗棕色；额头与松弛的羽冠为灰褐色带绿色光泽，羽冠长约60毫米；胸部淡绿，背部、翅膀和尾巴呈烟灰色，有轻微鳞状斑纹；上腹部深粉棕色，逐渐变为绿色于尾下覆羽；下翼和尾下部淡绿色；眼棕色；喙、腿和脚黑色。幼鸟羽毛蓬松绒毛状，羽冠暗灰棕色，上部带棕色，胸部绿色大大减少。","call":"发出响亮的双重“kow-kow”声，有时被描述为类似羊群的“go-ah, go-ah”声，通常由群体中的其他鸟儿反复回应，听起来像是狂野的笑声。","habits":"栖息于开阔林地、荆棘灌木丛、河岸植被、种植园散树、常绿灌木丛、雪松林和河岸金合欢树。海拔高度从1360米到1850米，南马拉维地区更广泛地分布于开放的莫博姆树丛，包括退化区域有金合欢、刺葵和水黄皮等物种。以单个、成对或最多八只的小群体出现。","breeding":"在乌干达南部、坦桑尼亚5月至10月，马拉维北部10月繁殖。一夫一妻制，单独筑巢。巢为浅平台，由松散交织的枝条构成，有时衬以根须和干草，距地面约5米，位于金合欢树叉或顶部。产2至3枚圆形、光泽的白色蛋，大小约42毫米×32毫米，双亲轮流孵化。","identification":"与白腹灰蕉鹃和东非灰蕉鹃相比，容易通过白色颈圈和翅膀、尾巴缺乏白色区分。可能与同域分布的Criniferoides leucogaster和Corythaixoides concolor混淆，后者全身灰色，前者有白色腹部，翅膀和尾巴黑白相间。","protection":"IUCN：LC（无危）","distribution":"分布在埃塞俄比亚的东非大裂谷，从迪雷达瓦和安科伯向南至阿巴亚湖和亚贝洛；乌干达南部、卢旺达、布隆迪、肯尼亚西南部和坦桑尼亚，南至马拉维北部、赞比亚东北部和刚果民主共和国东南部。","other":"历史系统分类中，曾与Crinifer leopoldi视为同一物种，但两者完全异域分布。"},{"name":"白腹灰蕉鹃","english_name":"White-bellied Go-away-bird","scientific_name":"Crinifer leucogaster","overview":"白腹灰蕉鹃（英文名：White-bellied Go-away-bird，学名：Crinifer leucogaster），是蕉鹃目蕉鹃科灰蕉鹃属的鸟类。非洲东部特有的蕉鹃。最显著的特征是白色的腹部和高耸的灰色羽冠。广泛分布于索马里、埃塞俄比亚到坦桑尼亚北部的干旱灌木丛和疏林草原。","appearance":"成鸟长约50厘米，尾长24-25厘米，体重介于170-250克。全身灰色，腹部和尾下覆羽白色，头部两侧、下巴、颈及胸部灰色，与上体颜色相似。具有突出的、长达60毫米的棕色灰色尖顶状羽冠，顶部呈暗褐色。飞行时可见黑色翅膀上的白色斑块。尾巴黑色，中央有宽阔的白色条带。雄鸟喙黑色，雌鸟喙豆绿色，繁殖季节变为黄色。眼睛榛褐色，腿和脚黑色。幼鸟外观类似成鸟，但羽毛更偏棕色，尤其是翼羽覆盖处。","call":"声音相当多样，包括鼻音的‘gwah’、较短促的‘wak’、拉长的‘nyaaah’以及标志性的‘gorrwAAay’叫声，后者为其‘go-away-bird’名称的由来。","habits":"栖息于低海拔的热草原、疏林草原，最高可达1700米。通常以小群体出现，活动范围固定，很少迁徙。主要以阿卡西亚树的果实、花朵、种子和嫩芽为食，偏好阿卡西亚tortilis的绿色嫩荚。","breeding":"繁殖季节为2月至7月（索马里和埃塞俄比亚）、2月至8月（肯尼亚和坦桑尼亚）、7月至8月（乌干达东北部）。巢穴由细枝搭建，位于3-12米高的树上，通常在阿卡西亚树型的树木中。每窝产2-3枚淡蓝色光泽的卵，孵化期约为27-28天，由双亲共同承担。","identification":"与东非灰蕉鹃形状相似，但白腹灰蕉鹃通过其洁净的白色腹部和黑色喙轻易区分。与棕脸灰蕉鹃的区别在于白色腹部、无深色面具以及更高的羽冠。","protection":"IUCN：LC（无危）","distribution":"分布局限于东非的阿卡西亚草原，具体包括索马里西北部、中部和南部、厄立特里亚、埃塞俄比亚、南苏丹、乌干达东北部（卡罗莫贾和提索）、肯尼亚北部和东部、坦桑尼亚东部高原（西至塔博拉，南至鲁阿哈国家公园）。","other":"尽管没有确切的种群数量数据，但观察显示该物种在许多区域相当丰富。"},{"name":"灰蕉鹃","english_name":"Western Plantain-eater","scientific_name":"Crinifer piscator","overview":"灰蕉鹃（英文名：Western Plantain-eater，学名：Crinifer piscator），是蕉鹃目蕉鹃科灰蕉鹃属的鸟类。体型庞大，长约50厘米，尾部特别长，羽毛以灰色为主，斑点状分布着棕色。头部、颈项和胸部呈褐色，带有银色条纹，下体白色，伴有棕色条纹。在热带西非的开放林地环境中常见，其声音响亮，容易引起注意。","appearance":"成年灰蕉鹃拥有约50厘米的身长，尾部长度可达24-25厘米。额头、头顶、脸颊和喉部为深棕色，颈部竖起的羽冠由窄而尖的后冠羽毛组成，每根长达45毫米，边缘泛白。颈部两侧和上胸部暗棕色，带银色晕染和条纹。背部呈银灰色，点缀着深棕色斑点；翼覆羽灰色，深棕色轴线和末端斑点，边缘淡灰色；臀部和尾上覆羽灰色，有深色轴线；中央尾羽灰色，尖端转为深棕色，其余尾羽黑棕色；次级飞羽和初级覆羽黑棕色；初级飞羽黑色，内侧网的中央三分之一为白色；下胸、腹部、胁部和下尾覆羽白色，带有灰色基部和宽达2毫米的棕色轴线条纹；喙大而强壮，鲜柠檬黄色，基部绿色；眼睛深棕色；腿和脚棕色至黑色。","call":"灰蕉鹃的声音非常响亮，通常会发出一系列急促加速且音量增大的叫声，常见的是成群的鸟儿进行二重唱或合唱。叫声包括快速的‘kok-kok-kok-kok…’系列和急促下降的‘kyEH!-kyEH!-kyEH!…’声段。","habits":"灰蕉鹃主要栖息于各种开阔的树林草原环境，从萨赫勒地区的金合欢草原到接近雨林地带的边缘，海拔高度从海平面至1300米。它们在塞拉利昂最常见的栖息地是棕榈树丛和衍生的草原，以及开阔草地或沼泽边缘的树木。它们基本定居在其分布范围内，不进行迁徙。","breeding":"繁殖季节在塞内加尔和冈比亚为1月至8月及10月，在马里为1月至6月，在尼日利亚为4月至5月，在加纳为3月至5月和9月至10月，在刚果为1月至4月。它们在茂密的树上建造直径约30厘米、深约12厘米的平台型巢穴，距离地面6至15米。每次产卵2至3枚，卵为卵圆形，颜色为浅灰色或淡蓝白色，具有轻微光泽，孵化期约为27至28天，由双亲共同孵化。","identification":"灰蕉鹃与近缘的东非灰蕉鹃相似，但可以通过尾部缺乏白色横纹和背部的黑色斑点而非横纹来区分。","protection":"IUCN：LC（无危）","distribution":"分布于毛里塔尼亚南部、塞内加尔、冈比亚、塞拉利昂和利比里亚沿海东至中非共和国（几乎到达南苏丹边境）；在刚果和刚果民主共和国沿着刚果河的斯坦利池以南也有零散分布。","other":"灰蕉鹃在塞内加尔和冈比亚地区局部丰度较高，某些Acacia scorpioides林地的密度可达1只/公顷。"},{"name":"东非灰蕉鹃","english_name":"Eastern Plantain-eater","scientific_name":"Crinifer zonurus","overview":"东非灰蕉鹃（英文名：Eastern Plantain-eater，学名：Crinifer zonurus），是蕉鹃目蕉鹃科灰蕉鹃属的鸟类。属于大型非洲特有鸟类，主要栖息于热带东非的开放林地，以树冠为家。体长50厘米，尾部长而显眼，体重介于392至737克之间。羽色以灰色为主，头部、颈背和胸部呈棕色，间杂银色条纹，下体则为白色，带有深色条纹。喙厚实，鲜黄色，飞行时可见明显的白色翼斑。两性相似，幼鸟头部黑色绒毛，无银色条纹。","appearance":"东非灰蕉鹃体长约50厘米，体重501-737克。全身主要为灰色，背部和翅膀覆羽呈灰色，有暗色纵纹，形成棕色鳞状斑点，下腹部无条纹。头部、颈背、胸部为暗棕色，带银色条纹。长而蓬松的后颈羽冠可达35毫米，暗棕色，尖端白色。翅膀和尾羽有白色斑点，飞行时尤为明显。喙大，绿色偏黄，眼睛深棕色，腿脚为棕黑色。雌雄外观一致，幼鸟头部黑色，无银色条纹。","call":"发出混合的咯咯声、吠声和类似歇斯底里的咯咯声，叫声快速且音调高，有时仅发出单独的“kwah”声，飞行时伴有低沉的“ka”声。","habits":"常栖息于各类开阔的灌木林和农田，亦常见于城市公园和花园。主要分布在海拔1500米以下，但在肯尼亚埃尔贡山可达1900米，埃塞俄比亚部分地区可达1630米。通常单独或成对出现，偶尔可见3-4只的家庭群。以果实为主食，包括无花果和Musanga，也会食用Daniellia oliveri的花朵。在苏丹、肯尼亚和坦桑尼亚有季节性迁移现象，可能受食物可用性影响。","breeding":"繁殖期在苏丹为3月至5月，埃塞俄比亚为2月至3月，刚果民主共和国为11月至3月，乌干达主要为2月，肯尼亚为8月至5月。筑巢于高大的叶茂树木顶部，巢由枯枝搭建。每次产卵2-3枚，卵为白色，大小约43mm×38mm，双亲共同孵化。","identification":"与灰蕉鹃相似，但可通过其较暗的腹部和淡绿色或黄色的喙轻松区分。灰蕉鹃尾羽有白色条纹，而灰蕉鹃胸腹有条纹，翼羽轴为深色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部，从乍得和苏丹西部，经厄立特里亚、埃塞俄比亚，南至刚果民主共和国东北部和坦桑尼亚西北部。"},{"name":"圭拉鹃","english_name":"Guira Cuckoo","scientific_name":"Guira guira","overview":"圭拉鹃（英文名：Guira Cuckoo，学名：Guira guira），是鹃形目杜鹃科圭拉鹃属的鸟类。源自Guarani语，意为‘鸟’。这种群居鸟类广泛分布于南美洲东北部、东部和南部的开阔地带，包括巴西、乌拉圭、巴拉圭、玻利维亚及阿根廷东北部。其显著特征为橙色松散的冠羽、淡白色的身体与深色的翅膀和尾巴形成鲜明对比。","appearance":"成年圭拉鹃身长约为34厘米，体重约140克，雌鸟略大于雄鸟。上体呈暗褐色，布满白色条纹；下体、喉部和腹部为白色至浅黄色，带有褐色条纹。尾部长而宽，基部及尖端为白色，其余部分呈深棕色。腿脚为深灰色，眼睛和喙为黄色到橙色，眼周有黄色裸皮。幼鸟的翼尖有小白点，喙为黑白相间，虹膜呈浅灰色。","call":"其叫声独特而响亮，介于长哨声和哀号之间，一系列下降的音调‘pio...pio...pio...pr...prr...prrr’，亦发出低沉的叫声、高亢的颤音和‘creep’声。","habits":"圭拉鹃栖息于次生灌木丛、较干燥的树木和灌木草原、潘帕斯草原、牧场、沿海沙丘以及城市边缘地带。它们常在寒冷的日子聚集成群，夜间共栖一树。白天在地面或树枝上觅食，以昆虫、蚱蜢、蝉、飞蚁、蜘蛛、青蛙、蜥蜴、蛇为主食，偶尔也会吃小鸟的蛋和雏鸟。群居性，群体大小通常为6-8只。","breeding":"繁殖期主要在雨季8月至11月，巴西部分地区的干季5月至8月也有繁殖。群体生活，春季时部分群体会分裂成配偶对进行繁殖。有时寄生于其他鸟类的巢中，如鸭嘴雀，但多数时间自己筑巢。巢为大型开放平台，由树枝构成，位于刺树的高处。每巢产卵数可多达20枚，平均十枚，由多只雌鸟共同产卵。孵化期为10-15天，雏鸟皮肤苍白，覆有白色绒毛，喙淡色，具黑色脊线和下颌支，口内壁淡色有突起，舌端有黑杠。幼鸟在受扰时于5-6日龄即可离巢，正常情况下约15日龄离巢。","identification":"与其他同属物种相比，圭拉鹃的橙色冠羽、黄色眼环和喙是其显著特征。与鸭嘴雀属（Crotophaga）物种的区别在于其不实行巢寄生或盗食。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东部和南部至玻利维亚、巴拉圭、阿根廷北部和乌拉圭。在近100年间，随着森林砍伐形成的开阔地带，其分布范围有所扩大。常见于巴西马托格罗索州、圣卡塔琳娜州以及玻利维亚东部。在亚马逊森林区域消失，但在秘鲁东南部的马德雷德迪奥斯可能正在扩张。","other":"已有人工繁殖记录，但幼鸟可能需人工喂养。"},{"name":"大犀鹃","english_name":"Greater Ani","scientific_name":"Crotophaga major","overview":"大犀鹃（英文名：Greater Ani，学名：Crotophaga major），是鹃形目杜鹃科犀鹃属的鸟类。分布于中美洲和南美洲，从巴拿马东部至阿根廷北部，尤其偏爱靠近水源的森林边缘。这种大型鸟类拥有独特的黄色眼睛和翅膀与尾巴上的蓝、绿、紫色光泽，是最为显眼的犀鹃种类。","appearance":"大犀鹃长约48厘米，体重约170克，其最显著的特征是白色的眼圈，粗大的刀片状喙，带有钩状尖端和盔突，这使它获得了犀鸟的昵称。背部羽毛为蓝黑色，尾巴长且宽，翅膀较短，羽毛蓬松，脚部为黑色。雌雄在外观上相似，但雌鸟平均体型略小于雄鸟。","call":"大犀鹃的叫声包括呱呱声和类似火鸡的咯咯声，声音独特。","habits":"大犀鹃主要栖息于红树林、沼泽地和河流附近的树林中，通常在低地热带雨林边缘，尤其沿河湖地带最为常见。它们以群居形式生活，成群结队觅食，主要食物来源为大型昆虫、蜘蛛、蜥蜴、青蛙等，偶尔也会食用果实和浆果。","breeding":"繁殖期间，大犀鹃会在树上构建深杯状的巢穴，巢穴通常离地面2-5米高，由两到五个成年对共同维护。雌鸟会在巢中产下深蓝色的卵，孵化期约为11-12天，雏鸟在出生五天后即可离开巢穴，但若选择留在巢中，将被持续喂养数周。","identification":"大犀鹃与其他犀鹃种类相比，最大的辨识点在于其更大的体型、独特的黄色眼睛以及翅膀和尾巴上的光泽。与大尾拟八哥相比，后者喙更细长，缺乏明显的喙缘，且尾巴形状不同。","protection":"IUCN：LC（无危）","distribution":"大犀鹃广泛分布在南美洲的低地地区，自哥伦比亚至巴拉圭，延伸至中美洲仅限于巴拿马东部。","other":"大犀鹃具有复杂的社会结构，巢穴由多个成年对共同建造和维护，体现了高度的社会合作。"},{"name":"滑嘴犀鹃","english_name":"Smooth-billed Ani","scientific_name":"Crotophaga ani","overview":"滑嘴犀鹃（英文名：Smooth-billed Ani，学名：Crotophaga ani），是鹃形目杜鹃科犀鹃属的鸟类。体型中等、全身乌黑的杜鹃科鸟类，以独特的扁平大嘴和长尾巴著称。常见于南美洲热带低地和山麓地带的开放或半开放生境中，如佛罗里达南部、加勒比海岛屿及中美洲至南美洲北部。该物种具有群居特性，通常以小型群体的形式活动。","appearance":"滑嘴犀鹃身长约30-36厘米，体重约100克，雄鸟略大于雌鸟。全身黑色，部分部位带绿或紫光泽。嘴型独特，呈拱形且侧扁，上喙基部有明显的隆起，似鹦鹉嘴。尾部长，约17.2厘米，由8根渐长的尾羽组成，外侧两对较短，容易脱落，使个体外观显得凌乱。颈部羽毛硬化，边缘呈红褐色；背部、胸部和小翼覆羽边缘呈暗蓝，形成鳞状图案。翅膀短而宽。眼周裸露。雌雄羽毛相似，全年羽毛变化不大。幼鸟羽毛混杂哑光和亮泽黑色，嘴稍浅。雏鸟羽毛完全哑光黑色，嘴较小，无隆起。","call":"鸣叫包括哀怨的‘啊-妮’声，通常重复1-4次，以及一系列猫叫般的叫声、哼哼声和吠叫声。","habits":"栖息于灌木丛、草地、农园和林间空地等开阔地带。主要以昆虫为食，如蚱蜢、毛虫和飞蛾，也会捕食小型蛙类和蜥蜴。果实是干旱季节的重要食物。非迁徙性，雨季开始繁殖，刺激昆虫数量增加。在降雨量不规律的地区，滑嘴犀鹃可能全年繁殖。","breeding":"繁殖期形成对或更大群体，最多可达17个个体。实行社群繁殖，多个雌鸟在同一巢穴产卵并共同孵化。晚产卵的雌鸟会用枝叶覆盖先产卵的雌鸟的蛋，形成多层蛋堆，仅顶层孵化。依据群体大小，单个巢穴可能含有多达36枚蛋。","identification":"与沟嘴犀鹃相似，主要通过叫声和嘴型细节区分。滑嘴犀鹃嘴部顶部有显著隆起，而沟嘴犀鹃嘴部下缘呈浅弧形，基部宽度均匀。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从美国佛罗里达南部至阿根廷北部，包括加勒比海岛屿。在南佛罗里达州、加勒比海和中美洲至南美洲北部繁殖。","other":"滑嘴犀鹃在社群繁殖系统中展现出复杂的行为，包括雌鸟间的竞争和合作。"}];
